INSERT INTO `la_source_docs` (`id`, `learning_area_id`, `content`, `updated_at`, `parsed_doc`) VALUES
(10, 6, 'SUMMARY OF STRANDS AND SUB STRANDS																																																\nStrands										Sub Strands																							Suggested Number of Lessons															\n1.0 Foundations of Pre -Technical Studies										I. 1 Introduction to Pre-Technical Studies																							4															\n										1.2 Safety in the Immediate Environment																							6															\n										1.3 Computer Concepts																							6															\n2.0 Communication in Pre-Technical Studies										2.1 Introduction to Drawing																							6															\n										2.2 Free-hand sketching																							10															\n										2.3 ICT Tools in Communication																							8															\n3.0 Materials for Production										3.1 Introduction to Materials																							6															\n										3.2 Metallic Materials																							10															\n										3.3 Non-Metallic Materials																							10															\n4.0 Tools and Production										4.1 Measuring and Marking Out Tools																							18															\n										4.2 Computer Hardware																							8															\n5.0 Entrepreneurship										5.1 Introduction to Entrepreneurship																							8															\n										5.2 Production Unit																							10															\n										5.3  Financial Goals																							10															\nTotal Number of Lessons																																	120															\nNote: The suggested number of lessons per sub strand may be less or more depending on the context.																																																\nSTRAND 1.0: FOUNDATIONS OF PRE -TECHNICAL STUDIES																																																\nStrand				Sub Strand									Specific Learning Outcomes														Suggested Learning Experiences											Suggested Key Inquiry Question(s)										\n1.0 Foundations of Pre -Technical Studies				1.1 Introduction to Pre-Technical Studies									\"By the end of the sub strand, the learner should be able to:\na)   identify the components of Pre-Technical Studies as a learning area,\nb)   explain the role of Pre-Technical Studies in day-to-day life,\nc)   embrace Pre-Technical Studies in career development.\"														\"The learner is guided to:\n•   brainstorm on the components of Pre-Technical Studies as a\nlearning area,\n•   discuss and present the role of Pre-Technical Studies in day-to-day life,\n•   debate on the role of Pre-Technical Studies in day-\nto-day life.\"											Why is Pre-Technical Studies important in day-to-day life?										\n				(4 lessons)																																												\n\"Core Competencies to be developed:\n•   Communication  and Collaboration: learner develops writing, speaking, listening, and teamwork skills when discussing, and presenting on the role of Pre-Technical Studies.\n•   Critical Thinking and Problem Solving: learner develops open-mindedness and creativity skills when brainstorming on Pre-\nTechnical Studies as a learning area.\"																																																\n\"Values:\n•   Unity: learner displays team spirit and collaboration  with others when discussing and presenting  the role of Pre-Technical Studies in day-to-day life.\n•   Respect:  learner displays  tolerance  for others\'  opinions  when debating on the role of Pre-Technical Studies  in day-to-day\nlife.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\nSocial Cohesion is enhanced when debating on the role of Pre-Technical Studies.\"																																																\n\"Link to Other Subjects:\nThe learner is able to relate career to trade and economic activities in Social Studies.\"																																																\nStrand				Sub Strand							Specific Learning Outcomes												Suggested Learning Experiences															Suggested Key Inquiry Question(s)										\n1.0 Foundations of Pre-Technical Studies				\"1.2 Safety in the Immediate Environment\n(6 lessons)\"							\"By the end of the sub strand, the learner should be able to:\na)   identify potential safety threats in the immediate environment,\nb)   outline safety rules and regulations for a given situation,\nc)   observe safety in the immediate environment,\nd)   appreciate the\nimportance of observing safety in the immediate environment.\"												\"The learner is guided to:\n•   brainstorm with peers on potential safety threats in the immediate environment\n(physical and online),\n•   use print or digital media to search for infomrntion on potential hazards to personal\nsafety in the immediate environment (falls, common road crashes, slips, trips, fires)\n•   use print or digital media to search for information on\nphysical threats to digital devices (theft, natural disasters, hardware failure) and online threats in the immediate environment and list them (cyberbullying, impersonation, phishing, hacking, friend requests from unknown people),\n•   share ideas and practice on how\nto protect self and others from\"															\"1. Why is safety in the immediate environment important?\n2. How can online threats be safeguarded against?\"										\n																							\"threats in the immediate environment.\n•     discuss safety rules and regulations to observe (wlhen performing tasks, handing materials and tools),\n•     role play on safety for self and\nothers in the immediate environment.\"																									\n\"Core Competencies to be developed:\n•     Learning to Learn: learner develops skills of sharing learnt knowledge when taking turns with peers to share ideas on safety for self and others in the immediate environment.\n•     Digital Literacy: learner develops skills of interacting with technology when searching for information on potential hazards to personal safety in the immediate environment.\"																																																\n\"Values:\n•     Respect: learner appreciates diverse opinions when sharing information with peers on the online threats.\n•     Responsibility: learner engages in assigned roles when role playing on safety for self and others in the immediate environment.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\n•     Disaster Risk Reduction: learner observes safety when role playing on safety of self and others in the immediate environment.\n•     Safety and Security: safety awareness on threats such as falls, road crashes, slips, trips, and fires is enhanced when sharing ideas and practices on how to protect self and others from threats in the immediate environment.\"																																																\n\"Link to other Subjects:\nIntegrated Science when the learner observes safety when working in a science laboratory.\"																																																\nStrand				Sub Strand							Specific Learning Outcomes											Suggested Learning Experiences																Suggested Key Inquiry Question(s)										\n1.0 Foundations of Pre-Technical Studies				\"1.3 Computer Concepts\n(6 lessons)\"							\"By the end of the sub strand the learner should be able to:\na)   explain the\ncharacteristics of a computer in a user environment,\nb)   classify computers used in day-to-day life,\nc)   use a computer to perform tasks in a user environment,\nd)   acknowledge the importance of different types of\ncomputers used in day-to-day life.\"											\"The learner is guided to:\n•  brainstorm on the meaning of the terms; computer, data, and\ninformation,\n•  discuss characteristics of a computer (speed, accuracy,\nversatility, reliability, diligence, storage, consistency),\n•  download and watch a video\nclip on classification of\ncomputers,\n•  discuss the classification of computers (functionality,\npurpose, and size) in a user environment,\n•  interact with different types of\ncomputers in the user\nenvironment to perfonn tasks.\"																\"1.   Why are\ncomputers classified differently?\n2.   How are computers used in day-to-day life?\"										\n\"Core Competencies to be developed:\n•   Critical Thinking and Problem Solving: learner develops interpretation and inference skills while brainstorming on the meaning of the terms; computer, data, and information.\n•   Communication and Collaboration: learner develops speaking, listening, and teamwork skills when discussing the\nclassification of computers in a user environment.\"																																																\n\"Values:\n•   Responsibility: learner shows accountability by caring for the print or digital media when interacting with different types of computers in the user environment to perform tasks.\n•   Peace: learner displays patience with peers when discussing the classification of computers.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\nCyber Security: learner observes online safety when downloading and watching a video clip on classification of computers.\"																																																\n\"Link to other Subjects:\nThe learner is able to relate the skills of interacting with different types of computers to the use of a calculator in Mathematics.\"																																																\nSUGGESTED ASSESSMENT RUBRIC																																																\nI�							Exceeds Expectations													Meets Expectations												\"Approaches\nExpectations\"					Below Expectations											\n\"Ability to explain the role of Pre-Technical Studies in day-to-day\nlife.\"							\"Explains the role of Pre-Technical Studies in day-to-day life and\nadds unique details.\"													Explains the role of Pre-Technical Studies in day-to-day life.												\"Explains the role of Pre-Technical Studies\nin day-to-day life omitting a few details.\"					\"Explains the role of Pre-Technical Studies\nin day-to-day life omitting many details.\"											\nAbility to observe safety in the immediate environment.							Always observes safety in the immediate environment.													Often observes safety in the immediate environment.												Occasionally observes safety in the immediate environment.					Rarely observes safety in the immediate environment.											\nAbility to use a computer to perform tasks in a user environment.							Uses a computer to perform all tasks in a user environment.													Uses a computer to perform most of the tasks in a user environment.												Uses a computer to perform some of the tasks in a user environment.					\"Uses a computer to perfom1 a few of the tasks in a user environment with\nassistance.\"											\nSTRAND 2: COMMUNICATION  IN PRE-TECHNICAL  STUDIES																																																\nStrand					Sub Strand									\"Specific Leaming\nOutcomes\"										\"Suggested Learning\nExperiences\"														\"Suggested Key\nInouirv Question(s)\"										\n\"2.0 Communication\nin Pre-Technical Studies\"					\"2.1 Introduction\nto Drawing\n(10 lessons)\"									\"By the end of the sub\nstrand, the learner should be able to:\na)   explain the importance of drawing as a means of communication,\nb)   distinguish between artistic and technical\ndrawings used in technical fields\'\nc)   print numbers and\nletters of the alphabet as used in drawing,\nd)   draw types of lines used in drawing,\ne)   illustrate symbols and abbreviations used in drawing,\nf)   appreciate the role of drawing in communication.\"										\"The learner is guided to:\n•   discuss the importance of drawing as a means of communication,\n•  brainstorm on the meaning of the terms \'technical drawing\'\nand \'artistic drawing,\n•   use print or online resources to search for information on\nartistic and technical drawing,\n•   practice printing numbers and letters of the alphabet,\n•  use visual aids to search for information on the types of\nlines and their application in drawing (thick and thin continuous, dashed, and chain).\n•   draw various types of lines\n(thick and thin continuous,\ndashed and chain)\n•   sketch basic symbols (0,   t, R,\n.l, □) and abbreviations\"														\"How are drawings\nused in technical communication?\"										\n																								\"(DRG, AIF, AIC, I/D, O/D)\nused in drawing\n•   use audio-visual aids to study the application of symbols and\nabbreviations in drawing.\"																								\n\"Core Competencies to be developed:\n•   Communication  and Collaboration: the learner acquires speaking, listening and teamwork skills when brainstorming on the meaning of the terms \'technical drawing\' and \'artistic drawing\'.\n•   Digital Literacy: learner develops the skill of interacting with technology when using online resources to search for\ninformation on artistic and technical drawing.\"																																																\n\"Values:\n•   Respect: learner demonstrates etiquette during discussion of basic symbols and abbreviations used in drawing.\n•   Responsibility: learner demonstrates accountability when using visual aids to search for information on the types of lines and\ntheir aoolication in drawing.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\nSafety and Security: the learner develops online safety skills during online search for information on different types of drawings\nused in the technical fields.\"																																																\n\"Link to other Subjects:\nCreative Arts: learner enhances knowledge of artistic drawing when drawing various types of lines in Pre-Technical studies.\"																																																\nStrand					Sub Strand							Specific Learning Outcomes											Suggested Learning Experiences																				Suggested Key Inquiry Question(s)					\n2.0 Communication in Pre-Technical Studies					\"2.2 Free-hand sketching\n(IO lessons)\"							\"By the end of the sub strand, the learner should be able to:\na)   Explain the principles of free-hand sketching\nb)   Identify techniques of free-hand sketching\nc)   sketch lines using free-hand,\nd)   sketch 2D shapes using free hand,\ne)   appreciate the importance of free-hand sketching in communication.\"											\"Learner is guided to:\n•   discuss the meaning of free-hand sketching as used in Pre-Technical\nStudies,\n•   use print and digital media to search for information on freehand\nsketching techniques (box method, centerline method, hand compass method),(hatching, cross-hatching, stippling, and blending)\n•   use pencils and drawing papers to sketch lines,\n•   use pencils and drawing papers to sketch two-dimensional shapes,\n•   use digital media, to observe how free-hand sketches express artistic ideas in different career fields,\"																				Why is free-hand sketching important?					\n\"Core Competencies to be developed:\n•  Communication and Collaboration: learner acquires speaking, listening, and teamwork skills when discussing the meaning of free-hand sketching as used in Pre-Technical Studies.\n•   Digital Literacy: learner develops the skill of interacting with technology when using digital media to observe how free-hand\nsketches express artistic ideas in different career fields.\"																																																\n\"Values:\n•   Respect: learner demonstrates etiquette during discussion of the meaning of free-hand sketching as used in Pre-Technical Studies\n•   Responsibility: learner demonstrates accountability when using digital media, to observe how free-hand sketches express\nartistic ideas in different career fields.\"																																																\n\"Pertinent and Contemporary Issues (PCl\'s):\nSafety and Security: learner develops online safety skills when using digital media to observe how free hand sketches express\nartistic ideas in different career fields.\"																																																\n\"Links to other Learning Areas:\nCreative arts: learner enhances skill of artistic drawing when using pencils and drawing papers to create lines.\"																																																\nStrand						Sub Strand								Specific Learning Outcomes											Suggested Learning Experiences													Suggested Key Inquiry Question(s)										\n2.0 Communication in Pre-Technical Studies						2.3 ICT Tools in Communication (6 lessons)								\"By the end of the sub strand, the learner should be able to:\na) explain the importance of ICT tools in communication,\nb) describe the ICT tools used in communication,\nc) use ICT tools to enhance communication,\nd) acknowledge the role of communication in Pre-Technical Studies.\"											\"The learner is guided to:\n•  brainstorm and present on the meaning and importance\nof ICT tools in communication,\n•  use print or digital media to\nsearch for information on\nICT tools used in communication (email, mobile phone, computers, video and web conferencing tools, social networking, and online collaboration) and present the findings,\n•  communicate using ICT tools (send and receive;\nemail, texts, calls, chats,\naudio, animations and video).\"													How are ICT tools used in communication?										\n\"Core Competencies to be developed:\n•  Communication and Collaboration: learner acquires speaking, writing, listening, and teamwork skills while brainstorming and presenting on the meaning and importance of JCT tools in communication.\n•   Leaming to Learn: learner acquires skills of organizing own learning and collaborating with others when using print or digital media to search for infonnation on JCT tools used in communication.\n•   Digital Literacy: learner develops skills of interacting with technology when using JCT tools to communicate.\"																																																\n\"Values:\n•   Respect: learner shows open-mindedness when brainstorming and presenting the meaning and importance of JCT tools in communication.\n•   Responsibility: learner shows accountability when handling JCT tools to communicate.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\nMental Health: learner develops emotional awareness to relate well with peers when brainstorming and presenting on the\nmeaning and importance of JCT tools in communication.\"																																																\n\"Link to other Subjects:\nThe learner is able to relate communication concepts to communication skills in English.\"																																																\nSUGGESTED ASSESSMENT RUBRIC																																																\n�I      c  to							Exceeds expectations											Meets expectations										Approaches expectations							Below expectations													\nAbility to explain the importance of drawing as a means of communication.							\"Explains the importance of drawing as a means of communication and\nadds more details.\"											Explains the importance of drawing as a means of communication.										\"Explains the importance of drawing as a means of communication leaving out a few\ndetails.\"							Explains the importance of drawing as a means of communication leaving out many details.													\nAbility to sketch 2D shapes using free hand.							\"Sketches 2D shapes using free hand with unique and clear\ndetails.\"											Sketches 2D shapes using free hand.										Sketches 2D shapes using free hand with a few unclear details.							Sketches 2D shapes using free band with many unclear details.													\n\"Ability to use ICT tools to enhance\ncommunication.\"							\"Uses more ICT tools than to enhance\ncommunication.\"											\"Uses ICT tools to enhance\ncornn1unication.\"										\"Uses some of the ICT tools to enhance\ncommunication.\"							\"Uses only a few of the ICT tools to enhance\ncommunication.\"													\nSTRAND 3: MATERIALS FOR PRODUCTION																																																\nStrand			Sub Strand								Specific Learning Outcomes															Suggested Learning Experiences																\"Suggested Key\nInquiry Question(s)\"						\n\"3.0 Materials\nfor Production\"			\"3.1 Introduction\nto Materials\n(6 lessons)\"								\"By the end of the sub strand,\nthe learner should be to:\na)   identify materials used in production,\nb)   distinguish between metallic and non-metallic materials found in the locality,\nc)   describe sustainable ways of using malerials in production,\nd)   appreciate the importance of materials in production.\"															\"The learner is guided to:\n•  discuss and present the meaning of materials used in production,\n•  use print or digital media to search for information on materials used in production and share with peers,\n•  discuss the differences between metallic and non-metallic materials,\n•  sort out materials in the locality as either metallic or non-metallic,\n•  brainstorm and present sustainable ways of using materials in production,\n•  discuss and make a presentation\non the importance of materials used in production.\"																\"How are\nmaterials used sustainably?\"						\n\"Core Competencies to be developed:\n•  Self-efficacy: learner develops effective communication skills when discussing and presenting the differences between metallic and non-metallic materials.\n•  Critical Thinking and Problem Solving: learner develops explanation, evaluation, and decision-making skills while sorting out materials in the localitv as either metallic or non-metallic.\"																																																\n\"Values:\n•  Responsibility: learner shows accountability as they use print or digital media to search for information on materials used in production.\n•  Peace: learner displays tolerance and respect for diversity when discussing and presenting the importance of materials used in production.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\n•  Environmental Education: learner acquires skills of protecting natural resources when brainstorming and presenting sustainable ways of using materials in production.\"																																																\n\"Link to other Subjects:\nSocial Studies: learner enhances knowledge on economic activities such as mining, fishing and trade as they search for information on materials used in production.\"																																																\nStrand			Sub Strand						Specific Learning Outcomes												Suggested Learning Experiences																	Suggested Key lnQuirv Question(s)										\n\"3.0 Materials\nfor Production\"			\"3.2 Metallic\nMaterials\n(10 lessons)\"						\"By the end of the sub strand,\nthe learner should be able to:\na)   identify types of metallic materials used in the immediate environment,\nb)   describe the physical properties of metallic materials found in the immediate environment,\nc)   relate metallic materials to their use in the immediate environment,\nd)   appreciate the use of metallic materials in production.\"												\"The learner is guided to:\n•  use print or digital media to search for infonnation on metallic materials,\n•  prepare a checklist for identifying types of metallic materials (steel, aluminium, copper),\n•  perform practical activities to examine the physical properties of metallic materials (magnetism, conductivity of heat and electricity, appearance),\n•  discuss the physical properties of metallic materials,\n•  match metallic materials to their use in the immediate environment.\"																	\"How are metallic\nmaterials used in day-to-day life?\"										\n\"Core Competencies to be developed:\n•   Digital Literacy: learner develops skills of interacting with technology when searching for information on metallic materials.\n•   Communication and Collaboration: learner acquires speaking, listening, and teamwork skills when discussing the uses of\nmetallic materials.\"																																																\n\"Values:\n•   Unity: learner displays team spirit and collaboration with others while discussing the uses of metallic materials.\n•   Responsibility: learner shows accountability by caring for the print or digital media when searching for information on\nmetallic materials.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\nPeer Education and Mentorship: the learner develops inter-personal relationships when performing practical activities to examine the physical properties of metallic materials.\"																																																\n\"Link to other Subjects:\nIntegrated Science: learner enhances knowledge on properties of materials during discussion of physical properties of metallic\nmaterials.\"																																																\nStrand			Sub Strand						Specific Learning Outcomes													Suggested Learning Experiences															Suggested Key Inauirv Question(s)											\n3.0 Materials for Production			\"3.3 Non-\nMetallic Materials\n(10 lessons)\"						\"By the end of the sub strand, the learner should be able to:\na)   identify non-metallic materials found in the locality,\nb)   categorise non-metallic materials as either synthetic or natural,\nc)   describe the physical properties of non-metallic materials found in the locality,\nd)   relate non-metallic materials to their uses in the locality,\ne)   appreciate the use of non-metallic materials in production.\"													\"The learner is guided to:\n•   use print or digital media to search for information on non-metallic materials,\n•   discuss the non-metallic materials (wood, stone,\nplastics, paper, rubber, cement, glass, ceramics),\n•   sort non-metallic materials as either synthetic or natural,\n•   perform practical activities to examine the physical\nproperties of non-metallic materials (color, texture, hardness, fire resistance),\n•   discuss the physical properties of non-metallic materials,\n•   match non-metallic materials\nto their use in the localitv.\"															Why are non-metallic materials important?											\n\"Core Competencies to be developed:\n•   Critical Thinking and Problem Solving: learner develops evaluation and decision skills when sorting non-metallic materials as either synthetic or natural.\n•   Creativity and Imagination: learner develops observation skills when performing practical activities to examine the physical\nproperties of non-metallic materials.\"																																																\n\"Values:\n•   Peace: learner displays respect for self and peers when discussing non-metallic materials.\n•   Unity: learner displays team spirit and collaboration with others when performing practical activities to examine the physical\nproperties of non-metallic materials.\"																																																\n\"Pertinent and Contemporary Issues (PCl\'s):\nPersonal Safety and Security: learner observes safety precautions when performing practical activities to examine the physical properties of non-metallic materials.\"																																																\n\"Link to other Subjects:\nIntegrated Science: learner enhances knowledge on use of matter during the matching of non- metallic materials to their use in the locality.\"																																																\nSUGGESTED ASSESSMENT RUBRIC																																																\nI�							Exceeds expectations													Meets expectations									Approaches expectations								Below expectations											\nAbility to identify materials used in production.							\"Identifies materials\nused in production and cites their applications.\"													Identifies materials used in production.									Identifies most materials used in production.								Identifies a few materials used in production.											\nAbility to describe the physical properties of metallic materials found in the immediate environment.							Describes the physical properties of metallic materials found in the immediate environment citing examples.													\"Describes the physical properties of metallic materials found in the immediate\nenvironment.\"									Describes some of the physical properties of metallic materials found in the immediate environment.								Describes only a few of the physical properties of metallic materials found in the immediate environment.											\n\"Ability to relate non-metallic materials to\ntheir uses in the locality.\"							\"Relates non-metallic materials to their uses\nin the locality and beyond locality.\"													Relates non-metallic materials to their uses in the locality.									Relates some of the non-metallic materials to their uses in the locality.								\"Relates a few of the non-metallic materials\nto their uses in the locality.\"											\nSTRAND 4: TOOLS AND PRODUCTION																																																\nStrand			Sub Strand							Specific Learning Outcomes													Suggested Learning Experiences																\"Suggested Key\nInquiry Question(s)\"									\n\"4.0   Tools and\nProduction\"			\"4.1  Measuring\nand Marking Out Tools\n(18 lessons)\"							\"By the end of the sub strand,\nthe learner should be able to:\na)  identify measuring and marking out tools used to perform tasks,\nb) select measuring and marking out tools for a given task,\nc)  use measuring and\nmarking out tools to perform a given task,\nd)  care for measuring and marking out tools to minimise damage,\ne)  recognise the importance of measuring and marking out tools when performing tasks.\"													\"The learner is guided to:\n•  use visual aids and realia to identify measuring tools (tape measure, steel rule, callipers, weighing balance, stopwatch, ammeter, voltmeter) and marking out tools (divider, try-square, marking gauge, dot punch, scriber, pencil, marking knife),\n•  choose the appropriate measuring and marking out tools to perform a given task,\n•  use available resources to search for information on the use of measuring and marking out tools,\n•  perform specific tasks using measuring and marking out tools,\n•  practice caring for measuring and marking out tools.\"																\"1.   Why are\nmeasuring and marking out tools important in day-to-day life?\n2.   How are\nmeasuring and marking out tools used when performing tasks?\"									\n\"Core Competencies to be developed:\n•   Critical Thinking and Problem Solving: learner develops explanation, evaluation, and decision-making skills when choosing the appropriate measuring and marking out tools to perform a given task.\n•   Self-efficacy: learner develops self-awareness skills by showing a concerted attention to detail when performing specific\ntasks using measuring and marking out tools.\"																																																\n\"Values:\n•   Respect: learner shows open-mindedness when discussing the use of measuring and marking out tools in the immediate environment.\n•   Responsibility: learner shows accountability bv caring for measuring and marking out tools in the immediate environment.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\nDisaster Risk Reduction: learner avoids situations that can lead to injuries when caring for measuring and marking out tools in the immediate environment.\"																																																\n\"Link to other Subjects:\nMathematics: lean1er enhances the skill of measurement when performing specific tasks using measuring and marking out tools.\"																																																\nStrand		Sub Strand						Specific Learning Outcomes													Suggested Learning Experiences																	Suggested Key Inquiry Question(s)										\n4.0 Tools and Production		4.2  Computer Hardware						\"By the end of the sub strand\nthe learner should be able to:\"													\"The learner is guided to:\n•  brainstorm and present the meaning of the term \'computer\nhardware,\n•  use available resources to search for information on categories of\ncomputer hardware: input devices (keying devices, pointing devices, scanning devices, voice input devices, touch screen, digitizer, digital cameras), output devices (hardcopy and softcopy), storage devices (fixed and removable devices),\n•  match available devices to their\nrespective categories,\n•  perform tasks using computer\ninput, outnut, and storage devices.\"																	How is computer hardware used?										\n		(14 lessons)						\"a)   classify computer hardware devices in a user environment,\nb)   use computer hardware devices to carry out a given task,\nc)   value the importance of computer hardware devices in a user environment.\"																																								\n\"Core Competencies to be developed:\n•  Communication  and Collaboration: learner acquires speaking, writing, listening, and teamwork skills when brainstorming and presenting on the meaning of the term \'computer hardware\'.\n•  Critical Thinking and Problem Solving:  learner develops skills of interpretation and inference when categorising computer\nhardware.\"																																																\n\"Values:\n•  Peace: learner displays tolerance when performing tasks using computer hardware.\n•  Responsibility: learner shows accountability when using available resources to search for information on categories of\ncomputer hardware.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\nPeer Education and Mentorship: learner enhances leadership skills when discussing the categories of computer hardware devices\nin a user environment.\"																																																\n\"Link to other Subjects:\nIntegrated Science: learner enhances skills of connecting electric devices when connecting hardware devices.\"																																																\nSUGGESTED ASSESSMENT RUBRIC																																																\n�I							Exceeds expectations													Meets expectations											Approaches expectations						Below expectations											\nAbility to identify measuring and marking out tools used to perform tasks.							\"Identifies measuring and marking out tools used to perform tasks\nand improvises more tools.\"													Identifies measuring and marking out tools used to perform tasks.											Identifies measuring and marking out tools used to perform tasks leaving out a few tools.						Identifies measuring and marking out tools used to perform tasks leaving out many tools.											\nAbility to use measuring and marking out tools to perform a given task.							\"Uses measuring and marking out tools to perform a given task with high precision and\nno errors.\"													Uses measuring and marking out tools to perform a given task.											Uses measuring and marking out tools to perform a given task with a few errors.						Uses measuring and marking out tools to perform a given task with many errors.											\n\"Ability to use computer hardware\ndevices to carry out a given task.\"							\"Uses computer hardware devices to carry out a given task\nand innovates more.\"													Uses computer hardware devices to carry out a given task.											\"Uses some of the computer hardware\ndevices to carry out a given task.\"						\"Uses only a few of the computer hardware\ndevices to carry out a given task.\"											\nSTRAND5:ENTREPRENEURSIDP																																																\nStrand							Sub Strand										Specific Learning Outcomes										Suggested Learning Experiences													Suggested Key Inquiry Question(s)								\n5.0 Entrepreneurship							\"5.1 Introduction to\nEntrepreneurship\n(4 lessons)\"										\"By the end of the sub\nstrand, the learner should be able to:\na)  explain the importance of entrepreneurship in the community,\nb)  describe the qualities of an enlrepreneur in business,\nc)  explore sources of business ideas for a business venture,\nd)  appreciate the role of entrepreneurship in a community.\"										\"The learner is guided to:\n•   brainstorm and present the meaning of the terms \'entrepreneur\' and\n\'entrepreneurship,\n•   discuss and present the importance of entrepreneurship in the\ncommunity,\n•   use print or digital resources to search for information on the qualities of an\nentrepreneur,\n•   conduct self-assessment on entrepreneurial qualities,\n•   use available resources to search for and present the\nmeaning and sources of business ideas,\n•   discuss the role of entrepreneurship in a\ncommunity.\"													\"1.Why is\nentrepreneurship important in the community?\n2.What are the qualities of an entrepreneur?\"								\n\"Core Competencies to be developed:\n•   Communication and Collaboration: learner acquires speaking, writing, listening, and teamwork skills when brainstorming and presenting on the meaning the meaning of the terms \'entrepreneur\' and \'entrepreneurship\'.\n•   Critical Thinking and Problem Solving: learner acquires evaluation and decision-making skills when conducting a self-assessment on entrepreneurial qualities.\"																																																\n\"Values:\n•  Unity: learner displays team spirit when discussing and presenting the importance of entrepreneurship to an individual and community.\n•   Responsibility: learner engages in the use of available resources to search for and present the meaning and sources of\nbusiness ideas.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\nFinancial Literacy: learner develops entrepreneurial skills when conducting self-assessment on entrepreneurial qualities.\"																																																\n\"Link to other Sub_jects:\nSocial Studies: learner enhances knowledge on trading activities when discussing the role of entrepreneurship in a communitv.\"																																																\nStrand							Sub Strand							Specific Learning Outcomes									Suggested Learning Experiences																	Suggested Key Inquiry Question(s)								\n5.0 Entrepreneurship							\"5.2 Production Unit\n(6 lessons)\"							\"By the end of the sub strand, the learner should be able to:\na)   explain the factors considered when locating a production unit,\nb)  analyse the factors detennining the size of a production unit,\nc)   value the importance of locating a production unit in a suitable area.\"									\"The learner is guided to:\n•   discuss the meaning of the term \'production unit\' and present it to peers,\n•   brainstorm and present the factors considered when choosing the location of a production unit,\n•   visit the local community to assess the factors that influenced the location of a particular production unit (Pasho mill, salon, barber shop, welding, cybercqfe),\n•   use print or digital media to search for information on the\nfactors that determine its size and share with peers.\"																	How is the size of a production unit determined?								\n\"Core Competencies to be developed:\n•   Communication and Collaboration: learner acquires speaking, writing, listening, and teamwork skills when discussing and presenting the meaning of the term \'production unit\'.\n•   Critical Thinking and Problem Solving: learner acquires interpretation and inference skills when visiting the local\ncommunity to assess the factors that influenced the location of a particular production unit.\"																																																\n\"Values:\n•   Responsibility:  learner shows accountability when using print or digital media to search for information on the factors that determine its size and share with peers.\n•   Respect: learner shows regard for the input of every member when brainstorming and presenting on the factors considered\nwhen choosing the location of a production unit.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\nFinancial Literacy: learner develops entrepreneurial skills when brainstorming and presenting the factors considered when choosing the location of a production unit.\"																																																\n\"Link to other Subjects:\nSocial Studies: learner enhances knowledge on trade when brainstorming on factors considered when choosing the location of a production unit.\"																																																\nStrand							Sub Strand							Specific Learning Outcomes												Suggested Learning Experiences															\"Suggested Key Inquiry\nQuestion(s)\"							\n5.0 Entrepreneurship							\"5.3 Financial\nGoals\n(IO lessons)\"							\"By the end of the sub\nstrand, the learner should be able to:\na)  explain the importance of setting goals in financial management,\nb)  analyse the factors to consider when setting financial goals,\nc)   formulate financial goals for individual development,\nd)  observe financial discipline in financial management.\"												\"The learner is guided to:\n•   discuss and present the meaning and importance of\nsetting goals in financial management,\n•   engage with a resource person on the importance of financial\ndiscipline,\n•   brainstorm and present the factors to consider when\nsetting financial goals,\n•   use print or digital media to search for information on\nsetting financial goals,\n•   set Specific Measurable Achievable Realistic and Time-bound (SMART)\nfinancial goals.\"															\"1.   Why is it\nimportant to set financial goals?\n2.   What are the factors to consider when setting financial goals?\"							\n\"Core Competencies to be developed:\n•   Self-efficacy: learner acquires the skill of task execution when setting SMART financial goals.\n•   Critical Thinking and Problem Solving: learner acquires interpretation and inference skills when brainstorming on the factors\nto consider when setting financial goals.\"																																																\n\"Values:\n•   Responsibility: learner engages in assigned roles and duties when discussing and presenting on the meaning and importance of goal setting as used in financial management.\n•   Respect: learner shows regard for the input of every member when brainstorming and presenting on the factors to consider\nwhen setting financial goals.\"																																																\n\"Pertinent and Contemporary Issues (PCis):\nFinancial Literacy: learner acquires financial skills when setting SMART financial goals.\"																																																\n\"Link to other Subjects:\nSocial Studies: learner enhances skills of personal goal setting when setting SMART financial goals.\"																																																\nSUGGESTED ASSESSMENT RUBRIC																																																\n�I      c  to							Exceeds expectations												Meets expectations											Approaches expectations						Below expectations												\n\"Ability to describe the qualities of an entrepreneur in\nbusiness.\"							Describes all the qualities of an entrepreneur.												Describes most of the qualities of an entrepreneur.											Describes some qualities of an entrepreneur.						Describes a few qualities of an entrepreneur with assistance.												\nAbility to explore sources of generating business ideas for a business venture.							Explores all sources of generating business ideas for a business venture.												Explores most sources of generating business ideas for a business venture.											Explores some of the sources of generating business ideas for a business venture.						\"Explores a few of the sources of generating business ideas for a business venture with\nguidance.\"												\n\"Ability to analyse factors determining the size of a production\nunit.\"							Analyses all the factors determining the size of a production unit.												\"Analyses most of the factors determining the size of a production\nunit.\"											\"Analyses some of the factors determining the size of a production\nunit.\"						\"Analyses a few of the factors determining the size of a production unit\nwith oromot.\"												\n\"APPENDIX 1: GUIDELINES FOR INTEGRATING  COMMUNITY SERVICE LEARNING PROJECT\nIntroduction\nCommunity  Service  Leaming  (CSL)  is  an  experiential  learning  strategy  that  integrates  classroom  learning  and  community service, enabling learners to reflect on, experience, and learn from the community. The CSL activity is hosted as a strand within Social Studies. The Social Studies teacher will be responsible for coordinating teachers from other learning areas to carry out the integrated  CSL  class  activity.  Learners  will  be  expected  to apply  knowledge,  skills,  attitudes  and  values from  the  different Learning Areas to carry out the integrated CSL class activity. Learners will undertake one common integrated class CSL activity following a 6-step milestone approach that is:\"																																																\nMilestone			Description																																													\nMilestone  I			\"Problem Identification\nLearners study their community to understand the challenges faced and their effects on community members.\"																																													\nMilestone 2			\"Designing a solution\nLearners create an intervention to address the challenge identified.\"																																													\nMilestone 3			\"Planning for the Project\nLearners  share  roles, create  a  list  of activities  to be  undertaken,  mobilise  resources  needed  to create  their intervention, and set timelines for execution.\"																																													\nMilestone 4			\"Implementation\nThe learners execute the project and keep evidence of work done.\"																																													\nMilestone 5			\"Showcasing /Exhibition and Report Writing\nExhibitions involve showcasing learners\' project items to the community and reflecting on the feedback. Learners write a report detailing their project activities and learnings from feedback.\"																																													\nMilestone 6			\"Reflection\nLearners review all project work to learn from the challenges faced.\nThey  link  project  work  with  academic  concepts,  noting  how  the  concepts  enabled  them  to  do  their project as well as how the project helped to deepen learning of the academic concepts.\"																																													\n\"Assessment of CSL integrated Activity\nAssessment for the integrated CSL activity will be conducted formatively. The assessment will consider both the process and the end product.  This  entails assessing  each  of  the  milestone  stages  of the  integrated  CSL  class  activity.  It  will  focus  on  three components  namely: skills from various learning  areas applied  in carrying out the activity, core competencies developed, and\nvalues nurtured.\"																																																\n\"APPENDIX 2: SUGGESTED ASSESSMENT METHODS, LEARNING RESOURCES, AND NON-FORMAL\nACTIVITIES\"																																																\nStrands						Sub Strands														\"Suggested\nAssessment Methods\"								Suggested Learning Resources									Suggested Non-Formal Activities											\n1.0 Foundations of Pre-Technical Studies						1.1 Introduction to Pre-Technical Studies														\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Practical Work\n•   Peer and Self-Assessment\"								\"•   Pre-Technical Studies curriculum design\n•   Pre-Technical Studies handbook\n•   Digital devices such as; computers laptops, smartphones, and\ntablets among others\n•   Relevant approved textbooks and reference materials\n•   Photographs and pictures\n•   Charts\"									\"•   Discuss the role of Pre-Technical\nstudies in clubs and societies.\"											\n						1.2 Safety in the Immediate Environment														\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Practical Work\n•   Peer and Self-Assessment\"								\"•   Workshop attires such as; overcoats, aprons,\nshoes, and goggles, among others.\n•   Career brochures, career magazmes\n•   Digital devices such as; computers, laptops,\nsmartphones, and tablets, among others\"									\"•   Learners visit the locality to observe\nhow workers practice safety as they perform tasks\n•   Debate in clubs and societies on safety\nin the immediate environment\"											\n						1.3 Computer Concepts														\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Practical Work\n•   Peer and Self-Assessment\"								\"•   Course books,\n•   Computer user manuals,\n•   Internet,\n•   Video clips\n•   Digital devices such as; computers, laptops,\nsmart phones, tablets among others.\"									\"•   Demonstrate how to use JCT tools\n(Calculators, Smartphones, Tablets, DVD players, Digital watches) during clubs and societies\"											\n2.0 Communication in Pre-Technical Studies						2.1 Introduction to Drawing														\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Peer and Self-Assessment\"								\"•   Drawing charts\n•   Drawing papers/books\n•   brochures and magazrnes\n•   Geometrical set\"									\"•   Learners visit the locality to observe how different types\nof drawings are done and how they are used in the community learners discuss types of drawing in out-of-class school\norom-amrnes\"											\n						2.2 Freehand sketching														\"•   Checklist\n•   Observation\n•   Peer and self-\nassessment\"								\"•   Drawing charts\n•   Drawing pencils,\n•   Drawing papers/books\"									•   Learners to practise freehand drawing during clubs											\n						2.3 JCT tools in communication														\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Peer and Self-Assessment\"								\"•   Digital devices such as; computers, laptops,\nsmartphones, and tablets, among others.\n•   Internet\n•   Social media\naoolications\"									\"•   Social media charting\n•   Video conferencing\"											\n3.0 Materials for Production						3.1 introduction to materials										\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Peer and Self-Assessment\"							\"•   Pre-Technical Studies curriculum design\n•   Pre-Technical Studies handbook\n•   Digital devices such as� computers, laptops,\nsmartphones, and tablets, among others\n•   Metallic and non-metallic materials\n•   Relevant approved textbooks and reference materials\n•   Photographs and pictures\n•   Charts\"											\"•   Carry out activity involving sorting\nmaterials during clubs and societies\"														\n						3.2 Metallic Materials										\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Peer and Self-Assessment\n•   Practical Work\"							\"•   Metallic materials (steel, aluminium, copper)\n•   brochures and magazmes\n•   Digital devices such as� computers, laptops,\nsmartphones, and tablets, among others\"											\"•   Learners visit the local community to collect metallic materials and\nwrite down how each is used by the local community\n•   Discuss the uses of metallic materials in\nclubs and societies\"														\n						3.3 Non-Metallic Materials										\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Peer and Self-Assessment\n•   Practical Work\"							\"•   Non-Metallic materials (wood, plastics, ceramic, paper, rubber,\nglass, cement, stone)\n•   brochures and magazmes\n•   Digital devices such as; computers, laptops,\nsmartphones, and tablets, among others Digital devices such as; computer, laptop,\nsmartphone, tablets among others\"											\"•   Learners visit a local community collect non-metallic materials and\nwrite down how each is used by the local community\n•   Discuss the uses of non-metallic materials\nin clubs and societies\"														\n4.0 Tools and Production						4.1 Measuring and Marking Out Tools										\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Peer and Self-assessment\n•   Practical Work\"							\"•   Measuring tools (Tape measure, steel rule,\ncallipers, weighing balance, stopwatch, ammeter, voltmeter)\n•   Marking out tools (divider, try-square,\nmarking gauge, dot punch, scriber, pencil, marking knife) in the i1nmediate environment\n•   brochures and\nmagazines\"											\"•   Learners visit locality to observe the use of\nmeasuring and marking out tools in performing different tasks\n•   Discuss the uses of measuring and marking out tools in clubs and\nsocieties\"														\n																							\"•   Digital devices such as; computers, laptops, smartphones, and\ntablets. among others.\"																									\n						4.2 computer hardware										\"•  Question and Answer\n•  Observation\n•  Written Test\n•  Practical Work\n•  Learner\'s Profile\n•  Peer and Self-\nAssessment\n•  Portfolio\"							\"•  Computer hardware\n•  Approved textbooks\n•  Internet connectivity\n•  video and audio clips\n•  Charts and pictures\"											\"•  Community sensitisation on the use of computer\nhardware\n•  Field visits\"														\n\"5.0\nEntrepreneurship\"						5.1 Introduction to Entrepreneurship										\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Peer and Self-Assessment\"							\"•   Pre-Technical Studies curriculum design\n•   Pre-Technical Studies handbook\n•   Digital devices such as; computers, laptops,\nsmartphones, and tablets among others\n•   Relevant approved textbooks and reference\nmaterials\n•   Photographs and pictures\n•   Charts\"											\"•   Discuss business ideas and opportunities in\nfinancial literacy and other school clubs and societies\n•   Organised and planned field visits in the local\ncommunity to engage with entrepreneurs\n•   Participate in a talk by a volunteer resource\nperson on the qualities of an entrepreneur\"														\n						5.2 production unit										\"•  Question and answer\n•  learner\'s profile\n•  written tests\n•  observation\n•   Peer and self-\nassessment\"							\"•  Approved textbooks\n•  Digital devices,\n•  brochures\n•  pictures\n•  charts\"											\"•  Field visits activities\n•  Business clubs\"														\n						5.3 Financial Goals										\"•   Question and Answer\n•   Observation\n•   Written Test\n•   Peer and Self-Assessment\n•   Practical Work\"							\"•   Pre-Technical Studies curriculum design\n•   Pre-Technical Studies handbook\n•   Digital devices such as; computers, laptops,\nsmartphones, and tablets, among others\n•   Relevant approved textbooks and reference\nmaterials\n•   Photographs and pictures\n•   Charts\"											\"•   Discuss factors to consider when setting\nfinancial goals in financial literacy and other school clubs and societies\n•   Participating in a talk by a volunteer resource\nperson setting financial goals\n•   Posters with messages on SMART financial\ngoals\"', '2026-04-12 12:35:58', '{\"meta\":{\"parsed_at\":\"2026-04-12T14:28:49+02:00\",\"version\":1},\"strands\":[{\"code\":\"1.0\",\"name\":\"Foundations of Pre-Technical Studies\",\"sub_strands\":[{\"code\":\"1.1\",\"name\":\"Introduction to Pre-Technical Studies\",\"key_inquiry_questions\":[\"Why is Pre-Technical Studies important in day-to-day life?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand, the learner should be able to:\",\"identify the components of Pre-Technical Studies as a learning area,\",\"explain the role of Pre-Technical Studies in day-to-day life,\",\"embrace Pre-Technical Studies in career development.\"],\"learning_experiences\":[\"The learner is guided to:\",\"brainstorm on the components of Pre-Technical Studies as a learning area,\",\"discuss and present the role of Pre-Technical Studies in day-to-day life,\",\"debate on the role of Pre-Technical Studies in day-to-day life.\"],\"core_competencies\":[\"Communication and Collaboration: learner develops writing, speaking, listening, and teamwork skills when discussing, and presenting on the role of Pre-Technical Studies.\",\"Critical Thinking and Problem Solving: learner develops open-mindedness and creativity skills when brainstorming on Pre-Technical Studies as a learning area.\"],\"values_and_attitudes\":[\"Unity: learner displays team spirit and collaboration with others when discussing and presenting the role of Pre-Technical Studies in day-to-day life.\",\"Respect: learner displays tolerance for others\' opinions when debating on the role of Pre-Technical Studies in day-to-day life.\"],\"pertinent_contemporary_issues\":[\"Social Cohesion is enhanced when debating on the role of Pre-Technical Studies.\"],\"links_to_other_learning_areas\":[\"The learner is able to relate career to trade and economic activities in Social Studies.\"],\"learning_resources\":[\"Pre-Technical Studies curriculum design\",\"Pre-Technical Studies handbook\",\"Digital devices such as; computers laptops, smartphones, and tablets among others\",\"Relevant approved textbooks and reference materials\",\"Photographs and pictures\",\"Charts\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Practical Work\",\"Peer and Self-Assessment\"]},{\"code\":\"1.2\",\"name\":\"Safety in the Immediate Environment\",\"key_inquiry_questions\":[\"1. Why is safety in the immediate environment important?\",\"2. How can online threats be safeguarded against?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand, the learner should be able to:\",\"identify potential safety threats in the immediate environment,\",\"outline safety rules and regulations for a given situation,\",\"observe safety in the immediate environment,\",\"appreciate the importance of observing safety in the immediate environment.\"],\"learning_experiences\":[\"The learner is guided to:\",\"brainstorm with peers on potential safety threats in the immediate environment (physical and online)\"],\"core_competencies\":[\"Learning to Learn: learner develops skills of sharing learnt knowledge when taking turns with peers to share ideas on safety for self and others in the immediate environment.\",\"Digital Literacy: learner develops skills of interacting with technology when searching for information on potential hazards to personal safety in the immediate environment.\"],\"values_and_attitudes\":[\"Respect: learner appreciates diverse opinions when sharing information with peers on the online threats.\",\"Responsibility: learner engages in assigned roles when role playing on safety for self and others in the immediate environment.\"],\"pertinent_contemporary_issues\":[\"Disaster Risk Reduction: learner observes safety when role playing on safety of self and others in the immediate environment.\",\"Safety and Security: safety awareness on threats such as falls, road crashes, slips, trips, and fires is enhanced when sharing ideas and practices on how to protect self and others from threats in the immediate environment.\"],\"links_to_other_learning_areas\":[\"Integrated Science when the learner observes safety when working in a science laboratory.\"],\"learning_resources\":[\"Workshop attires such as; overcoats, aprons, shoes, and goggles, among others.\",\"Career brochures, career magazines\",\"Digital devices such as; computers, laptops, smartphones, and tablets, among others\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Practical Work\",\"Peer and Self-Assessment\"]},{\"code\":\"1.3\",\"name\":\"Computer Concepts\",\"key_inquiry_questions\":[\"1. Why are computers classified differently?\",\"2. How are computers used in day-to-day life?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand the learner should be able to:\",\"explain the characteristics of a computer in a user environment,\",\"classify computers used in day-to-day life,\",\"use a computer to perform tasks in a user environment,\",\"acknowledge the importance of different types of computers used in day-to-day life.\"],\"learning_experiences\":[\"The learner is guided to:\",\"brainstorm on the meaning of the terms; computer, data, and information,\",\"discuss characteristics of a computer (speed, accuracy, versatility, reliability, diligence, storage, consistency),\",\"download and watch a video clip on classification of computers,\",\"discuss the classification of computers (functionality, purpose, and size) in a user environment,\",\"interact with different types of computers in the user environment to perform tasks.\"],\"core_competencies\":[\"Critical Thinking and Problem Solving: learner develops interpretation and inference skills while brainstorming on the meaning of the terms; computer, data, and information.\",\"Communication and Collaboration: learner develops speaking, listening, and teamwork skills when discussing the classification of computers in a user environment.\"],\"values_and_attitudes\":[\"Responsibility: learner shows accountability by caring for the print or digital media when interacting with different types of computers in the user environment to perform tasks.\",\"Peace: learner displays patience with peers when discussing the classification of computers.\"],\"pertinent_contemporary_issues\":[],\"links_to_other_learning_areas\":[],\"learning_resources\":[\"Course books,\",\"Computer user manuals,\",\"Internet,\",\"Video clips\",\"Digital devices such as; computers, laptops, smart phones, tablets among others.\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Practical Work\",\"Peer and Self-Assessment\"]}]},{\"code\":\"2.0\",\"name\":\"Communication in Pre-Technical Studies\",\"sub_strands\":[{\"code\":\"2.1\",\"name\":\"Introduction to Drawing\",\"key_inquiry_questions\":[\"How are drawings used in technical communication?\"],\"specific_learning_outcomes\":[\"By the end of the sub-strand, the learner should be able to:\",\"explain the importance of drawing as a means of communication,\",\"distinguish between artistic and technical drawings used in technical fields,\",\"print numbers and letters of the alphabet as used in drawing,\",\"draw types of lines used in drawing,\",\"illustrate symbols and abbreviations used in drawing,\",\"appreciate the role of drawing in communication.\"],\"learning_experiences\":[\"The learner is guided to:\",\"discuss the importance of drawing as a means of communication,\",\"brainstorm on the meaning of the terms \'technical drawing\' and \'artistic drawing\',\",\"use print or online resources to search for information on artistic and technical drawing,\",\"practice printing numbers and letters of the alphabet,\",\"use visual aids to search for information on the types of lines and their application in drawing (thick and thin continuous, dashed, and chain).\",\"draw various types of lines (thick and thin continuous, dashed and chain)\",\"sketch basic symbols (0, t, R, .l, □) and abbreviations (DRG, AIF, AIC, I\\/D, O\\/D) used in drawing\",\"use audio-visual aids to study the application of symbols and abbreviations in drawing.\"],\"core_competencies\":[\"Communication and Collaboration: the learner acquires speaking, listening and teamwork skills when brainstorming on the meaning of the terms \'technical drawing\' and \'artistic drawing\'.\",\"Digital Literacy: learner develops the skill of interacting with technology when using online resources to search for information on artistic and technical drawing.\"],\"values_and_attitudes\":[\"Respect: learner demonstrates etiquette during discussion of basic symbols and abbreviations used in drawing.\",\"Responsibility: learner demonstrates accountability when using visual aids to search for information on the types of lines and their application in drawing.\"],\"pertinent_contemporary_issues\":[\"Safety and Security: the learner develops online safety when using online resources to search for information on artistic and technical drawing.\"],\"links_to_other_learning_areas\":[],\"learning_resources\":[\"Drawing charts\",\"Drawing papers\\/books\",\"brochures and magazines\",\"Geometrical set\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Peer and Self-Assessment\"]},{\"code\":\"2.2\",\"name\":\"Free-hand sketching\",\"key_inquiry_questions\":[\"Why is free-hand sketching important?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand, the learner should be able to:\",\"Explain the principles of free-hand sketching\",\"Identify techniques of free-hand sketching\",\"sketch lines using free-hand,\",\"sketch 2D shapes using free hand,\",\"appreciate the importance of free-hand sketching in communication.\"],\"learning_experiences\":[\"Learner is guided to:\",\"discuss the meaning of free-hand sketching as used in Pre-Technical Studies,\",\"use print and digital media to search for information on freehand sketching techniques (box method, centerline method, hand compass method),(hatching, cross-hatching, stippling, and blending)\",\"use pencils and drawing papers to sketch lines,\",\"use pencils and drawing papers to sketch two-dimensional shapes,\",\"use digital media, to observe how free-hand sketches express artistic ideas in different career fields,\"],\"core_competencies\":[\"Communication and Collaboration: learner acquires speaking, listening, and teamwork skills when discussing the meaning of free-hand sketching as used in Pre-Technical Studies.\",\"Digital Literacy: learner develops the skill of interacting with technology when using digital media to observe how free-hand sketches express artistic ideas in different career fields.\"],\"values_and_attitudes\":[\"Respect: learner demonstrates etiquette during discussion of the meaning of free-hand sketching as used in Pre-Technical Studies\",\"Responsibility: learner demonstrates accountability when using digital media, to observe how free-hand sketches express artistic ideas in different career fields.\"],\"pertinent_contemporary_issues\":[\"Safety and Security: learner develops online safety skills when using digital media to observe how free hand sketches express artistic ideas in different career fields.\"],\"links_to_other_learning_areas\":[\"Creative arts: learner enhances skill of artistic drawing when using pencils and drawing papers to create lines.\"],\"learning_resources\":[\"Drawing charts\",\"Drawing pencils,\",\"Drawing papers\\/books\"],\"assessment\":[\"Checklist\",\"Observation\",\"Peer and self-assessment\"]},{\"code\":\"2.3\",\"name\":\"ICT Tools in Communication\",\"key_inquiry_questions\":[\"How are ICT tools used in communication?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand, the learner should be able to:\",\"explain the importance of ICT tools in communication,\",\"describe the ICT tools used in communication,\",\"use ICT tools to enhance communication,\",\"acknowledge the role of communication in Pre-Technical Studies.\"],\"learning_experiences\":[\"The learner is guided to:\",\"brainstorm and present on the meaning and importance of ICT tools in communication,\",\"use print or digital media to search for information on ICT tools used in communication (email, mobile phone, computers, video and web conferencing tools, social networking, and online collaboration) and present the findings,\",\"communicate using ICT tools (send and receive; email, texts, calls, chats, audio, animations and video).\"],\"core_competencies\":[\"Communication and Collaboration: learner acquires speaking, writing, listening, and teamwork skills while brainstorming and presenting on the meaning and importance of ICT tools in communication.\",\"Learning to Learn: learner acquires skills of organizing own learning and collaborating with others when using print or digital media to search for information on ICT tools used in communication.\",\"Digital Literacy: learner develops the skill of interacting with technology when using print or digital media to search for information on ICT tools used in communication.\"],\"values_and_attitudes\":[\"Respect\",\"Responsibility\"],\"pertinent_contemporary_issues\":[\"Mental Health\"],\"links_to_other_learning_areas\":[\"English\"],\"learning_resources\":[\"Digital devices such as; computers, laptops, smartphones, and tablets, among others.\",\"Internet\",\"Social media applications\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Peer and Self-Assessment\"]}]},{\"code\":\"3.0\",\"name\":\"Materials for Production\",\"sub_strands\":[{\"code\":\"3.1\",\"name\":\"Introduction to Materials\",\"key_inquiry_questions\":[\"How are materials used sustainably?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand, the learner should be to:\",\"identify materials used in production,\",\"distinguish between metallic and non-metallic materials found in the locality,\",\"describe sustainable ways of using materials in production,\",\"appreciate the importance of materials in production.\"],\"learning_experiences\":[\"The learner is guided to:\",\"discuss and present the meaning of materials used in production,\",\"use print or digital media to search for information on materials used in production and share with peers,\",\"discuss the differences between metallic and non-metallic materials,\",\"sort out materials in the locality as either metallic or non-metallic,\",\"brainstorm and present sustainable ways of using materials in production,\",\"discuss and make a presentation on the importance of materials used in production.\"],\"core_competencies\":[\"Self-efficacy\",\"Critical Thinking and Problem Solving\"],\"values_and_attitudes\":[\"Responsibility\",\"Peace\"],\"pertinent_contemporary_issues\":[\"Environmental Education\"],\"links_to_other_learning_areas\":[],\"learning_resources\":[\"Pre-Technical Studies curriculum design\",\"Pre-Technical Studies handbook\",\"Digital devices such as; computers, laptops, smartphones, and tablets, among others\",\"Metallic and non-metallic materials\",\"Relevant approved textbooks and reference materials\",\"Photographs and pictures\",\"Charts\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Peer and Self-Assessment\"]},{\"code\":\"3.2\",\"name\":\"Metallic Materials\",\"key_inquiry_questions\":[\"How are metallic materials used in day-to-day life?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand, the learner should be able to:\",\"identify types of metallic materials used in the immediate environment,\",\"describe the physical properties of metallic materials found in the immediate environment,\",\"relate metallic materials to their use in the immediate environment,\",\"appreciate the use of metallic materials in production.\"],\"learning_experiences\":[\"The learner is guided to:\",\"use print or digital media to search for information on metallic materials,\",\"prepare a checklist for identifying types of metallic materials (steel, aluminium, copper),\",\"perform practical activities to examine the physical properties of metallic materials (magnetism, conductivity of heat and electricity, appearance),\",\"discuss the physical properties of metallic materials,\",\"match metallic materials to their use in the immediate environment.\"],\"core_competencies\":[\"Digital Literacy\",\"Communication and Collaboration\"],\"values_and_attitudes\":[\"Unity\",\"Responsibility\"],\"pertinent_contemporary_issues\":[\"Peer Education and Mentorship\"],\"links_to_other_learning_areas\":[\"Integrated Science\"],\"learning_resources\":[\"Metallic materials (steel, aluminium, copper)\",\"brochures and magazines\",\"Digital devices such as; computers, laptops, smartphones, and tablets, among others\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Peer and Self-Assessment\",\"Practical Work\"]},{\"code\":\"3.3\",\"name\":\"Non-Metallic Materials\",\"key_inquiry_questions\":[\"Why are non-metallic materials important?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand, the learner should be able to:\",\"identify non-metallic materials found in the locality,\",\"categorise non-metallic materials as either synthetic or natural,\",\"describe the physical properties of non-metallic materials found in the locality,\",\"relate non-metallic materials to their uses in the locality,\",\"appreciate the use of non-metallic materials in production.\"],\"learning_experiences\":[\"The learner is guided to:\",\"use print or digital media to search for information on non-metallic materials,\",\"discuss the non-metallic materials (wood, stone, plastics, paper, rubber, cement, glass, ceramics),\",\"sort non-metallic materials as either synthetic or natural,\",\"perform practical activities to examine the physical properties of non-metallic materials (color, texture, hardness, fire resistance),\",\"discuss the physical properties of non-metallic materials,\",\"match non-metallic materials to their use in the locality.\"],\"core_competencies\":[\"Critical Thinking and Problem Solving\",\"Creativity and Imagination\"],\"values_and_attitudes\":[\"Peace\",\"Unity\"],\"pertinent_contemporary_issues\":[\"Environmental Education\"],\"links_to_other_learning_areas\":[\"Social Studies\"],\"learning_resources\":[\"Non-Metallic materials (wood, plastics, ceramic, paper, rubber, glass, cement, stone)\",\"brochures and magazines\",\"Digital devices such as; computers, laptops, smartphones, and tablets, among others Digital devices such as; computer, laptop, smartphone, tablets among others\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Peer and Self-Assessment\",\"Practical Work\"]}]},{\"code\":\"4.0\",\"name\":\"Tools and Production\",\"sub_strands\":[{\"code\":\"4.1\",\"name\":\"Measuring and Marking Out Tools\",\"key_inquiry_questions\":[\"Why are measuring and marking out tools important in day-to-day life?\",\"How are measuring and marking out tools used when performing tasks?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand, the learner should be able to:\",\"identify measuring and marking out tools used to perform tasks,\",\"select measuring and marking out tools for a given task,\",\"use measuring and marking out tools to perform a given task,\",\"care for measuring and marking out tools to minimise damage,\",\"recognise the importance of measuring and marking out tools when performing tasks.\"],\"learning_experiences\":[\"The learner is guided to:\",\"use visual aids and realia to identify measuring tools (tape measure, steel rule, callipers, weighing balance, stopwatch, ammeter, voltmeter) and marking out tools (divider, try-square, marking gauge, dot punch, scriber, pencil, marking knife),\",\"choose the appropriate measuring and marking out tools to perform a given task,\",\"use available resources to search for information on the use of measuring and marking out tools,\",\"perform specific tasks using measuring and marking out tools,\",\"practice caring for measuring and marking out tools.\"],\"core_competencies\":[\"Critical Thinking and Problem Solving\",\"Self-efficacy\"],\"values_and_attitudes\":[\"Respect\"],\"pertinent_contemporary_issues\":[\"Disaster Risk Reduction: learner avoids situations that can lead to injuries when caring for measuring and marking out tools in the immediate environment.\"],\"links_to_other_learning_areas\":[\"Mathematics: learner enhances the skill of measurement when performing specific tasks using measuring and marking out tools.\"],\"learning_resources\":[\"Measuring tools (Tape measure, steel rule, callipers, weighing balance, stopwatch, ammeter, voltmeter)\",\"Marking out tools (divider, try-square, marking gauge, dot punch, scriber, pencil, marking knife) in the immediate environment\",\"brochures and magazines\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Peer and Self-assessment\",\"Practical Work\"]},{\"code\":\"4.2\",\"name\":\"Computer Hardware\",\"key_inquiry_questions\":[\"How is computer hardware used?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand the learner should be able to:\",\"classify computer hardware devices in a user environment,\",\"use computer hardware devices to carry out a given task,\",\"value the importance of computer hardware devices in a user environment.\"],\"learning_experiences\":[\"The learner is guided to:\",\"brainstorm and present the meaning of the term \'computer hardware\',\",\"use available resources to search for information on categories of computer hardware: input devices (keying devices, pointing devices, scanning devices, voice input devices, touch screen, digitizer, digital cameras), output devices (hardcopy and softcopy), storage devices (fixed and removable devices),\",\"match available devices to their respective categories,\",\"perform tasks using computer input, output, and storage devices.\"],\"core_competencies\":[\"Communication and Collaboration: learner acquires speaking, writing, listening, and teamwork skills when brainstorming and presenting on the meaning of the term \'computer hardware\'.\",\"Critical Thinking and Problem Solving: learner develops skills of interpretation and inference when categorising computer hardware.\"],\"values_and_attitudes\":[\"Peace: learner displays tolerance when performing tasks using computer hardware.\",\"Responsibility: learner shows accountability when using available resources to search for information on categories of computer hardware.\"],\"pertinent_contemporary_issues\":[\"Peer Education and Mentorship: learner enhances leadership skills when discussing the categories of computer hardware devices in a user environment.\"],\"links_to_other_learning_areas\":[\"Integrated Science: learner enhances skills of connecting electric devices when connecting hardware devices.\"],\"learning_resources\":[\"Digital devices such as; computers, laptops, smartphones, and tablets. among others.\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Practical Work\"]}]},{\"code\":\"5.0\",\"name\":\"Entrepreneurship\",\"sub_strands\":[{\"code\":\"5.1\",\"name\":\"Introduction to Entrepreneurship\",\"key_inquiry_questions\":[\"Why is entrepreneurship important in the community?\",\"What are the qualities of an entrepreneur?\"],\"specific_learning_outcomes\":[\"By the end of the sub-strand, the learner should be able to:\",\"explain the importance of entrepreneurship in the community,\",\"describe the qualities of an entrepreneur in business,\",\"explore sources of business ideas for a business venture,\",\"appreciate the role of entrepreneurship in a community.\"],\"learning_experiences\":[\"Learner is guided to:\",\"brainstorm and present the meaning of the terms \'entrepreneur\' and \'entrepreneurship\',\",\"discuss and present the importance of entrepreneurship in the community,\",\"use print or digital resources to search for information on the qualities of an entrepreneur,\",\"conduct self-assessment on entrepreneurial qualities,\",\"use available resources to search for and present the meaning and sources of business ideas,\",\"discuss the role of entrepreneurship in a community.\"],\"core_competencies\":[\"Communication and Collaboration: learner acquires speaking, writing, listening, and teamwork skills when brainstorming and presenting on the meaning of the terms \'entrepreneur\' and \'entrepreneurship\'.\",\"Critical Thinking and Problem Solving: learner acquires evaluation and decision-making skills when conducting a self-assessment on entrepreneurial qualities.\"],\"values_and_attitudes\":[\"Unity: learner displays team spirit when discussing and presenting the importance of entrepreneurship to an individual and community.\",\"Responsibility: learner engages in the use of available resources to search for and present the meaning and sources of business ideas.\"],\"pertinent_contemporary_issues\":[\"Financial Literacy: learner develops entrepreneurial skills when conducting self-assessment on entrepreneurial qualities.\"],\"links_to_other_learning_areas\":[\"Social Studies: learner enhances knowledge on trading activities when discussing the role of entrepreneurship in a community.\"],\"learning_resources\":[\"Pre-Technical Studies curriculum design\",\"Pre-Technical Studies handbook\",\"Digital devices such as; computers, laptops, smartphones, and tablets among others\",\"Relevant approved textbooks and reference materials\",\"Photographs and pictures\",\"Charts\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Peer and Self-Assessment\"]},{\"code\":\"5.2\",\"name\":\"Production Unit\",\"key_inquiry_questions\":[\"How is the size of a production unit determined?\"],\"specific_learning_outcomes\":[\"By the end of the sub strand, the learner should be able to:\",\"explain the factors considered when locating a production unit,\",\"analyse the factors determining the size of a production unit,\",\"value the importance of locating a production unit in a suitable area.\"],\"learning_experiences\":[\"Learner is guided to:\",\"discuss the meaning of the term \'production unit\' and present it to peers,\",\"brainstorm and present the factors considered when choosing the location of a production unit,\",\"visit the local community to assess the factors that influenced the location of a particular production unit (posho mill, salon, barber shop, welding, cyber cafe),\",\"use print or digital media to search for information on the factors that determine its size and share with peers.\"],\"core_competencies\":[\"Communication and Collaboration: learner acquires speaking, writing, listening, and teamwork skills when discussing and presenting the meaning of the term \'production unit\'.\",\"Critical Thinking and Problem Solving: learner acquires interpretation and inference skills when visiting the local community to assess the factors that influenced the location of a particular production unit.\"],\"values_and_attitudes\":[\"Responsibility: learner shows accountability when using print or digital media to search for information on the factors that determine its size and share with peers.\"],\"pertinent_contemporary_issues\":[\"Financial Literacy: learner develops entrepreneurial skills when brainstorming and presenting the factors considered when choosing the location of a production unit.\"],\"links_to_other_learning_areas\":[\"Social Studies: learner enhances knowledge on trade when brainstorming on factors considered when choosing the location of a production unit.\"],\"learning_resources\":[\"Approved textbooks\",\"Digital devices,\",\"brochures\",\"pictures\",\"charts\"],\"assessment\":[\"Question and answer\",\"learner\'s profile\",\"written tests\",\"observation\",\"Peer and self-assessment\"]},{\"code\":\"5.3\",\"name\":\"Financial Goals\",\"key_inquiry_questions\":[\"Why is it important to set financial goals?\",\"What are the factors to consider when setting financial goals?\"],\"specific_learning_outcomes\":[\"By the end of the sub-strand, the learner should be able to:\",\"explain the importance of setting goals in financial management,\",\"analyse the factors to consider when setting financial goals,\",\"formulate financial goals for individual development,\",\"observe financial discipline in financial management.\"],\"learning_experiences\":[\"Learner is guided to:\",\"discuss and present the meaning and importance of setting goals in financial management,\",\"engage with a resource person on the importance of financial discipline,\",\"brainstorm and present the factors to consider when setting financial goals,\",\"use print or digital media to search for information on setting financial goals,\",\"set Specific Measurable Achievable Realistic and Time-bound (SMART) financial goals.\"],\"core_competencies\":[\"Self-efficacy: learner acquires the skill of task execution when setting SMART financial goals.\",\"Critical Thinking and Problem Solving: learner acquires interpretation and inference skills when brainstorming on the factors to consider when setting financial goals.\"],\"values_and_attitudes\":[\"Responsibility: learner engages in assigned roles and duties when discussing and presenting on the meaning and importance of goal setting as used in financial management.\",\"Respect: learner shows regard for the input of every member when brainstorming and presenting on the factors to consider when setting financial goals.\"],\"pertinent_contemporary_issues\":[\"Financial Literacy: learner acquires financial skills when setting SMART financial goals.\"],\"links_to_other_learning_areas\":[\"Social Studies: learner enhances skills of personal goal setting when setting SMART financial goals.\"],\"learning_resources\":[\"Pre-Technical Studies curriculum design\",\"Pre-Technical Studies handbook\",\"Digital devices such as; computers, laptops, smartphones, and tablets, among others\",\"Relevant approved textbooks and reference materials\",\"Photographs and pictures\",\"Charts\"],\"assessment\":[\"Question and Answer\",\"Observation\",\"Written Test\",\"Peer and Self-Assessment\",\"Practical Work\"]}]}]}');
