INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(1, 509, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.1 Whole Numbers', '', '', NULL, '35', NULL, '', 'a) Identify the place value of digits up to millions in a given number.', 'b) State the position of any digit in a seven-digit number.', 'How can we determine the value and position of each digit in a number up to millions?', 'Critical thinking and problem solving - learners determine digit value and position by rearranging numbers', 'Social cohesion - learners work cohesively with peers to identify place values', 'Unity - learners harmoniously work in pairs or groups using place value apparatus', '* Learners textbook\r\n* Chalkboard and chalk\r\n* Place value chart drawn on manila paper or cardboard\r\n* Number cards made from pieces of paper (showing digits 0-9)', 'Recap of last lesson: reading and writing large numbers. Who can remind us what we learned? Today\'s lesson is: Determining the place value and position of digits in numbers up to millions. Imagine you are counting the total population of a large county. The number has many digits, and each digit\'s position tells us its value. Why is it important to know the value of each digit in such a number?', 'Engage in an interactive demonstration of place value by responding to guiding questions and completing steps using the chalkboard or tablet.', 'Perform or solve place value exercises in exercise books individually using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main skill we practised today? Can someone give an example of a digit\'s place value in a seven-digit number? Today we learned how to identify the place value of digits and state their positions in numbers up to millions. Remember to complete the extended activity at home to practise what you have learned today.', '* How well did learners identify the place value of digits up to millions?* Did learners correctly state the position of digits in a seven-digit number?* Were learners able to connect place value to real-life situations?', 'At home, find a large number from a newspaper, a receipt, or a product label. Write it down and identify the place value of three different digits in that number. Share your findings with a family member.', '2026-04-11 09:49:46', '2026-04-12 08:23:24'),
(2, 622, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.1 Safety on Raised Platforms', '', '', NULL, '40', NULL, 'a) Identify potential risks associated with working on raised platforms.', 'b) Describe specific hazards encountered when working at different heights.', '', 'What dangers can workers face when performing tasks on raised platforms such as ladders, scaffolds, or rooftops?', 'Critical thinking and problem solving: learners identify, assess and evaluate risks associated with working on raised platforms and propose appropriate safety measures.\r\nSelf-efficacy: learners demonstrate confidence in applying personal protective equipment and safe practices when working at heights.', 'Safety education: learners study hazards of working at heights and apply precautionary measures including use of PPE.\r\nOccupational safety and health (OSH): learners connect safety on raised platforms to broader workplace health and safety standards.\r\nEnvironmental education: learners appreciate the importance of safe, sustainable working environments.', 'Responsibility: learners take personal responsibility for their own safety and the safety of others when working on raised platforms.\r\nCare: learners show concern for the wellbeing of colleagues by following and promoting safety protocols at the workplace.', '* Learners textbook\r\n* Smartphones or tablets for group research (teacher\'s or shared)\r\n* Charts or manila paper for recording findings\r\n* Pictures or drawings of raised platforms (ladders, scaffolds, buildings under construction)', 'The teacher begins by asking learners to look up at the classroom ceiling or roof and imagine they need to repair it. The teacher then asks: \'If you had to climb up there to fix a leak, what could go wrong?\' After 2-3 learners share their thoughts, the teacher explains that today they will investigate the specific dangers workers face when performing tasks on raised platforms such as ladders, scaffolds, and rooftops.', '• Search for information on risk associated with working on raised platforms, in groups.  Write down findings and share them in class.', '', '', 'The teacher summarizes that workers on raised platforms face serious risks including falls, equipment failure, unstable surfaces, and environmental hazards, and that identifying these dangers is the first step toward workplace safety. The teacher then asks: \'What are three specific hazards a worker might encounter when working on a scaffold?\' and \'Why is it important to identify risks before starting work at height?\' The teacher invites 2-3 learners to respond before closing the lesson.', '* Were all learners able to identify at least three potential risks associated with working on raised platforms during the group activity?\r\n* Did the group research and sharing activity provide enough depth for learners to describe specific hazards at different heights, or do some learners still confuse general risks with specific hazards?\r\n* Which learners struggled to participate in group discussions and how can I support them to engage more actively in the next lesson on safety measures?', 'Learners should observe any construction, repair, or maintenance work happening in their community (on buildings, roofs, or trees) and write down three specific dangers they notice the workers might face. They should be prepared to share their observations in the next lesson.', '2026-04-11 10:50:24', '2026-04-11 10:50:24'),
(3, 621, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.1 Safety on Raised Platforms', '', '', NULL, '', NULL, 'a) Define the term \"raised platforms.\"', 'b) Identify various types of raised platforms used in performing tasks.', 'c) Describe the characteristics of different raised platforms.', 'What are raised platforms and why are they used in different tasks at home, school, and in our community?', 'Critical thinking and problem solving: learners identify, assess and evaluate risks associated with working on raised platforms and propose appropriate safety measures.\nSelf-efficacy: learners demonstrate confidence in applying personal protective equipment and safe practices when working at heights.', 'Safety education: learners study hazards of working at heights and apply precautionary measures including use of PPE.\nOccupational safety and health (OSH): learners connect safety on raised platforms to broader workplace health and safety standards.\nEnvironmental education: learners appreciate the importance of safe, sustainable working environments.', 'Responsibility: learners take personal responsibility for their own safety and the safety of others when working on raised platforms.\nCare: learners show concern for the wellbeing of colleagues by following and promoting safety protocols at the workplace.', '* Learners textbook\n* Photographs or drawings of ladders, scaffolds, stools, and stages\n* Actual examples: classroom desk, chair, or stool\n* Chart paper and markers for group presentations', 'Recap of last lesson: What did we learn about tools? Today\'s lesson is: Raised Platforms. Imagine working on a tall building, what do you stand on? What is it called?', '• Define what is raised platforms thro question and answer.', '• Explore types of raised platforms, in groups, note down findings and share with the class.', '• Brainstorm on the types of raised platforms used in day-to-day life, in groups, and share findings with the rest of the class.', 'The teacher asks: \'What is a raised platform?\' and \'What types of raised platforms did we identify?\' After responses, the teacher confirms: \'Well done, raised platforms are used in various tasks.\' Today we learned to define raised platforms, a skill we use to ensure safety.', '* What is raised platform? * Types of platforms? * Safety importance?', 'Use items at home to create a model of a raised platform, demonstrating its characteristics and safety features.', '2026-04-11 11:22:34', '2026-04-12 07:01:16'),
(4, 623, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.1 Safety on Raised Platforms', '', '', NULL, '', NULL, 'a) Discuss effective methods of minimizing risks when working on raised platforms.', 'b) Propose safety measures for preventing falls and injuries.', '', 'What safety measures should be put in place to minimize risks and prevent falls when working on raised platforms?', 'Critical thinking and problem solving: learners identify, assess and evaluate risks associated with working on raised platforms and propose appropriate safety measures.\nSelf-efficacy: learners demonstrate confidence in applying personal protective equipment and safe practices when working at heights.', 'Safety education: learners study hazards of working at heights and apply precautionary measures including use of PPE.\nOccupational safety and health (OSH): learners connect safety on raised platforms to broader workplace health and safety standards.\nEnvironmental education: learners appreciate the importance of safe, sustainable working environments.', 'Responsibility: learners take personal responsibility for their own safety and the safety of others when working on raised platforms.\nCare: learners show concern for the wellbeing of colleagues by following and promoting safety protocols at the workplace.', '* Learners textbook\n* Pictures or drawings of raised platforms (scaffolding, ladders, roofs)\n* Chart paper and markers for group presentations\n* Smartphone/tablet for showing safety scenarios or videos (optional)', 'The teacher shows learners a stick or chair and asks a volunteer to stand on it carefully while others observe. The teacher then asks the class: \'What dangers could this person face if they were working on a raised platform like this for a long time, and what could go wrong?\' Learners share their immediate thoughts, and the teacher links their responses to today\'s lesson on minimizing risks and preventing falls when working on raised platforms.', '• Discuss in groups, ways of minimising risks when working on raised platforms.', '', '', 'Today we have learned that minimizing risks on raised platforms requires proper planning, use of safety equipment, securing the platform, and following safety procedures to prevent falls and injuries. Now answer these questions: What are three important safety measures you would put in place before starting work on a raised platform? Why is it the responsibility of every worker to follow safety protocols when working at heights?', '* Were all learners able to discuss and propose at least two effective methods of minimizing risks when working on raised platforms during the group activity?\n* Did the group discussions reveal any misconceptions about fall prevention that need to be addressed in the next lesson?\n* Which learners struggled to connect personal responsibility and care for others to workplace safety practices, and how can I support them?', 'Learners should observe any raised structure or platform in their home or community (roof, tree house, ladder, raised granary) and write down three safety hazards they notice and three safety measures that could prevent falls or injuries in that specific situation.', '2026-04-11 11:22:46', '2026-04-11 11:22:46'),
(5, 624, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.1 Safety on Raised Platforms', '', '', NULL, '', NULL, 'a) Demonstrate safe practices for using raised platforms through role play.', 'b) Critique safety behaviors observed during the role play session.', '', 'How can we work safely on raised platforms to prevent accidents and injuries?', 'Critical thinking and problem solving: learners identify, assess and evaluate risks associated with working on raised platforms and propose appropriate safety measures.\nSelf-efficacy: learners demonstrate confidence in applying personal protective equipment and safe practices when working at heights.', 'Safety education: learners study hazards of working at heights and apply precautionary measures including use of PPE.\nOccupational safety and health (OSH): learners connect safety on raised platforms to broader workplace health and safety standards.\nEnvironmental education: learners appreciate the importance of safe, sustainable working environments.', 'Responsibility: learners take personal responsibility for their own safety and the safety of others when working on raised platforms.\nCare: learners show concern for the wellbeing of colleagues by following and promoting safety protocols at the workplace.', '* Learners textbook\n* Stable desks, benches, or tables (to simulate raised platforms)\n* Manila paper or chalkboard for listing safety rules\n* Teacher\'s smartphone/tablet (for showing safety images if available)', 'The teacher begins by asking learners to recall the hazards they identified in previous lessons when working on raised platforms such as ladders, scaffolds, or rooftops. The teacher then shows a stick or pointer and asks a volunteer to demonstrate how someone might unsafely reach for something while standing on a raised chair or table, followed by asking the class what could go wrong in that scenario. This creates curiosity about how to perform such tasks safely, leading into today\'s role play activity.', '• Role play safety practices for working on raised platforms and share what they have learnt from each other in class.', '', '', 'The teacher summarizes that safe practices on raised platforms include maintaining three points of contact, using appropriate PPE, securing the platform, and being aware of surroundings to prevent falls and injuries. The teacher then asks: What are two safe practices you demonstrated or observed during today\'s role play? How would you correct an unsafe behavior you saw during the role play to prevent an accident?', '* Were all learners able to demonstrate at least one safe practice during the role play activity and provide meaningful critique of their peers\' safety behaviors?\n* Did the role play scenarios provide sufficient variety of raised platform situations for learners to identify and evaluate different types of risks and safety measures?\n* Which learners struggled to critique the safety behaviors constructively, and how can I support them to develop better observation and evaluation skills in the next lesson?', 'Learners should observe and sketch one real raised platform structure in their home or community (such as a ladder against a wall, a raised water tank stand, or a loft), then write three safety concerns they notice and three safety improvements they would recommend for someone working on it.', '2026-04-11 11:22:58', '2026-04-11 11:22:58'),
(6, 125, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.1 Safety on Raised Platforms', '', '', NULL, '', NULL, 'a) Explain the significance of observing safety protocols while working at heights.', 'b) Justify the use of Personal Protective Equipment (PPE) on raised platforms.', '', 'Why is it critical to observe safety protocols and use Personal Protective Equipment when working on raised platforms?', 'Critical thinking and problem solving: learners identify, assess and evaluate risks associated with working on raised platforms and propose appropriate safety measures.\nSelf-efficacy: learners demonstrate confidence in applying personal protective equipment and safe practices when working at heights.', 'Safety education: learners study hazards of working at heights and apply precautionary measures including use of PPE.\nOccupational safety and health (OSH): learners connect safety on raised platforms to broader workplace health and safety standards.\nEnvironmental education: learners appreciate the importance of safe, sustainable working environments.', 'Responsibility: learners take personal responsibility for their own safety and the safety of others when working on raised platforms.\nCare: learners show concern for the wellbeing of colleagues by following and promoting safety protocols at the workplace.', '* Learners textbook\n* Pictures or illustrations of workers on scaffolding, ladders, or rooftops (from textbook or teacher\'s smartphone)\n* Sample PPE items or pictures (helmets, harnesses, gloves, safety boots)\n* Chart paper and markers for group presentations', 'The teacher asks learners to observe the classroom ceiling or roof structure and imagine they are workers fixing or painting it, then poses the question: \'What dangers could you face if you had to work up there without any safety measures?\' The teacher invites 2–3 learners to share their thoughts aloud, then explains that today\'s lesson will explore why safety protocols and Personal Protective Equipment are critical when working on raised platforms such as scaffolds, ladders, or rooftops.', '• Discuss in groups, the need for observing safety while working on raised platforms and share findings in class.', '', '', 'The teacher summarizes that observing safety protocols and using PPE when working on raised platforms prevents serious injuries and saves lives, and that every worker has a responsibility to protect themselves and others. The teacher then asks: \'Can you explain two reasons why wearing a safety harness is important when working at heights?\' and \'What might happen if safety protocols are ignored on a raised platform?\' before inviting brief responses from learners.', '* Were all learners able to explain at least two specific reasons why safety protocols are critical when working at heights?\n* Did the group discussions in the lesson body effectively engage all learners, or did some groups dominate while others remained passive?\n* Which learners struggled to justify the use of PPE and what additional examples or demonstrations might help them understand its importance?', 'Learners should interview a parent, guardian, or community member who works in construction, roofing, or any job involving heights, and ask them about one safety measure they use and why it is important. They should write a short paragraph (5–7 sentences) in their exercise books summarizing what they learned from the interview.', '2026-04-11 11:23:11', '2026-04-11 11:23:11'),
(7, 126, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.1 Safety on Raised Platforms', '', '', NULL, '', NULL, 'a) Evaluate personal understanding of safety on raised platforms through an assessment.', '', '', 'How effectively can I demonstrate my understanding of safety practices and precautions when working on raised platforms?', 'Critical thinking and problem solving: learners identify, assess and evaluate risks associated with working on raised platforms and propose appropriate safety measures.\nSelf-efficacy: learners demonstrate confidence in applying personal protective equipment and safe practices when working at heights.', 'Safety education: learners study hazards of working at heights and apply precautionary measures including use of PPE.\nOccupational safety and health (OSH): learners connect safety on raised platforms to broader workplace health and safety standards.\nEnvironmental education: learners appreciate the importance of safe, sustainable working environments.', 'Responsibility: learners take personal responsibility for their own safety and the safety of others when working on raised platforms.\nCare: learners show concern for the wellbeing of colleagues by following and promoting safety protocols at the workplace.', '* Learners textbook\n* Assessment question papers/worksheets\n* Chalkboard and chalk\n* Exercise books and pens', 'The teacher begins by asking learners to recall three key safety practices they learned in the previous lesson about working on raised platforms, writing their responses on the chalkboard. The teacher then explains that today learners will demonstrate their understanding through an assessment exercise that will help them evaluate how well they have grasped safety on raised platforms. The teacher emphasizes that this assessment is an opportunity to show responsibility for their own learning and identify areas that may need more attention.', '• Work individually on assessment exercise on safety on raised platforms.', '', '', 'The teacher collects the assessment exercises and reminds learners that understanding safety on raised platforms is crucial for protecting themselves and others in real workplace situations. The teacher asks: What was the most challenging part of today\'s assessment for you, and why? Can you name two personal protective equipment items that are essential when working at heights? The teacher encourages learners to review any topics they found difficult.', '* Were all learners able to evaluate their personal understanding of safety on raised platforms through the assessment exercise?\n* Did the assessment questions adequately cover the key safety practices, hazards, and PPE use that learners studied in previous lessons?\n* Which learners struggled to complete the assessment in the time given and what additional support or review do they need before moving to the next sub-strand?\n* Was the assessment exercise appropriately challenging for Grade 9 level, and did it effectively measure learners\' grasp of safety concepts?', 'Learners should interview a family member or neighbor who works in construction, farming, or any job involving heights, and write down three safety measures that person uses to prevent falls or injuries. They should be prepared to share their findings in the next lesson and compare workplace practices with what they have learned about safety on raised platforms.', '2026-04-11 11:23:23', '2026-04-11 11:23:23'),
(8, 127, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', '', '', NULL, '', NULL, 'a) Define the term \"hazardous substances.\"', 'b) Identify common hazardous substances found in the school environment.', 'c) Describe how specific local substances can cause harm.', 'What substances in our school and local environment can cause harm to our health and safety, and how do they cause this harm?', 'Critical thinking and problem solving: learners classify hazardous substances by their properties and determine appropriate safe-handling procedures for each class.\nDigital literacy: learners use print and digital media to research safety data sheets and hazard symbols for various substances.', 'Safety education: learners interpret hazard warning symbols, safety labels and MSDS information on hazardous containers.\nEnvironmental education: learners discuss improper disposal of hazardous substances and its impact on the environment.\nHealth education: learners relate exposure to hazardous substances to health risks including chemical burns, poisoning and respiratory problems.', 'Responsibility: learners observe safety procedures when handling hazardous substances to protect themselves and the community.\nCare: learners demonstrate concern for environmental health by disposing of hazardous waste correctly.\nIntegrity: learners honestly follow prescribed safety instructions rather than taking shortcuts.', '* Learners textbook\n* Samples or pictures of common hazardous substances (bleach, acids, pesticides, batteries, paraffin)\n* Chart paper and markers for group presentations\n* Empty labeled containers of cleaning agents from school stores', 'The teacher displays three common items found around the school: a bottle of bleach or disinfectant (if available), a container of kerosene or pesticide, and a battery. The teacher asks learners to observe these items carefully and think about what might happen if someone drinks them, spills them on their skin, or throws them into a water source. Learners share their ideas briefly, creating curiosity about why some everyday substances can be dangerous and how to recognize them.', '• Define what are hazardous substances thro question and answer.', '• Identify hazardous substances found in the environments, in groups.', '• Mention hazardous substances found in the locality and how they cause harm.', 'Today we have learned that hazardous substances are materials that can cause harm to our health, safety or the environment, and we identified several common ones in our school and local area such as cleaning chemicals, pesticides, batteries, and fuels. Now answer these two questions: What does the term \'hazardous substance\' mean? Can you name three hazardous substances found in our school or home and explain one way each can cause harm to people or the environment?', '* Were all learners able to correctly define hazardous substances and distinguish them from ordinary safe materials?\n* Did the group activity for identifying hazardous substances in the environment engage all learners, or did some groups struggle to participate fully?\n* Which learners need additional support in describing specific ways that local hazardous substances cause harm to health and the environment?', 'Learners should walk around their home compound and carefully observe (without touching) any containers, chemicals, or substances stored there. They should list at least five items they think might be hazardous and write one sentence for each explaining why they believe it could cause harm, then share their findings in the next lesson.', '2026-04-11 11:23:34', '2026-04-11 11:23:34'),
(9, 128, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', '', '', NULL, '', NULL, 'a) Categorize hazardous substances into poisonous, flammable, and corrosive groups.', 'b) Distinguish between different classes of hazardous materials based on their properties.', '', 'How can we group hazardous substances found in our homes, schools, and community according to the dangers they pose?', 'Critical thinking and problem solving: learners classify hazardous substances by their properties and determine appropriate safe-handling procedures for each class.\nDigital literacy: learners use print and digital media to research safety data sheets and hazard symbols for various substances.', 'Safety education: learners interpret hazard warning symbols, safety labels and MSDS information on hazardous containers.\nEnvironmental education: learners discuss improper disposal of hazardous substances and its impact on the environment.\nHealth education: learners relate exposure to hazardous substances to health risks including chemical burns, poisoning and respiratory problems.', 'Responsibility: learners observe safety procedures when handling hazardous substances to protect themselves and the community.\nCare: learners demonstrate concern for environmental health by disposing of hazardous waste correctly.\nIntegrity: learners honestly follow prescribed safety instructions rather than taking shortcuts.', '* Learners textbook\n* Empty containers or labels from household products (kerosene, bleach, battery acid, pesticides, matchboxes)\n* Chart paper or manila paper for group classification charts\n* Pictures or printed symbols of hazard warning signs (poison, flammable, corrosive)', 'The teacher displays three common household items on the desk: a matchbox, a bottle of cleaning acid (or vinegar as a safer substitute), and a container labeled with a skull symbol (e.g., pesticide or rat poison). The teacher asks learners to observe each item and discuss in pairs: \'What danger does each of these substances pose if mishandled?\' After one minute, the teacher invites two or three learners to share their observations, then announces that today they will learn to group hazardous substances based on the specific dangers they present.', '• Group hazardous substances, in groups (Flammable, Corrosive and Poisonous substances).', '', '', 'The teacher summarizes that hazardous substances in our homes, schools, and community can be grouped into three main categories: flammable substances that can catch fire easily, corrosive substances that can burn or eat away materials and skin, and poisonous substances that can harm or kill when swallowed, inhaled, or absorbed. The teacher then asks: \'If you found a bottle labeled with a flame symbol at home, which group does it belong to and what safety measure would you take?\' and \'Why is it important to correctly identify whether a substance is corrosive or poisonous before handling it?\'', '* Were all learners able to correctly categorize the hazardous substances into flammable, corrosive, and poisonous groups during the group activity?\n* Did the group activity allow sufficient time for learners to distinguish between the different classes based on properties, or did some groups need more guidance?\n* Which learners struggled to differentiate between corrosive and poisonous substances, and what additional examples or explanations might help them in the next lesson?', 'Learners should conduct a safe survey of their homes to identify three hazardous substances (without touching or moving them), noting the name of each substance and determining whether it is flammable, corrosive, or poisonous based on labels, symbols, or known properties. They should record their findings in their exercise books and be prepared to share one example in the next lesson.', '2026-04-11 11:23:49', '2026-04-11 11:23:49'),
(10, 129, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', '', '', NULL, '', NULL, 'a) Discuss safe methods for handling hazardous substances.', 'b) Identify appropriate Personal Protective Equipment (PPE) for handling chemicals.', '', 'How can we protect ourselves and others when handling hazardous substances in our homes, schools, and communities?', 'Critical thinking and problem solving: learners classify hazardous substances by their properties and determine appropriate safe-handling procedures for each class.\nDigital literacy: learners use print and digital media to research safety data sheets and hazard symbols for various substances.', 'Safety education: learners interpret hazard warning symbols, safety labels and MSDS information on hazardous containers.\nEnvironmental education: learners discuss improper disposal of hazardous substances and its impact on the environment.\nHealth education: learners relate exposure to hazardous substances to health risks including chemical burns, poisoning and respiratory problems.', 'Responsibility: learners observe safety procedures when handling hazardous substances to protect themselves and the community.\nCare: learners demonstrate concern for environmental health by disposing of hazardous waste correctly.\nIntegrity: learners honestly follow prescribed safety instructions rather than taking shortcuts.', '* Learners textbook\n* Pictures or labels from common household chemicals (bleach, pesticides, detergents, battery acid)\n* Chart paper and markers for group presentations\n* Sample PPE items or pictures (gloves, goggles, masks, aprons)', 'The teacher begins by holding up two common household containers: a bottle of bleach (or kerosene/jik) and a bottle of cooking oil, asking learners which one they would handle more carefully and why. The teacher invites three learners to share experiences or stories they have heard about accidents involving dangerous substances like acids, pesticides, or cleaning chemicals at home or in the community. This discussion leads directly into today\'s key inquiry question about protecting ourselves when handling hazardous substances.', '• Discuss in groups, safe ways of handling hazardous substances and share findings with the class.', '', '', 'Today we learned that safe handling of hazardous substances requires knowing the dangers, using proper methods like reading labels and wearing protective equipment, and following storage and disposal rules to protect ourselves and our environment. Can you name three types of Personal Protective Equipment that should be used when handling chemicals? What are two safe methods you would use when handling a container marked with a skull and crossbones symbol?', '* Were all learners able to identify at least three appropriate types of PPE for handling different hazardous substances?\n* Did the group discussion activity on safe handling methods engage all learners, or did some groups struggle to contribute meaningful ideas?\n* Which learners need additional support in understanding the connection between hazard symbols and the correct safety procedures to follow?', 'Learners should walk around their homes and identify three containers or substances that may be hazardous (such as kerosene, pesticides, batteries, or cleaning chemicals), then write down what warning labels or symbols are present and what PPE or safety measures should be used when handling each one. They should be prepared to share their findings in the next lesson.', '2026-04-11 11:24:03', '2026-04-11 11:24:03'),
(11, 130, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', '', '', NULL, '', NULL, 'a) Interpret safety instructions and conditions for use on chemical labels.', 'b) Explain the meaning of various safety symbols found on hazardous containers.', '', 'How can we stay safe when using hazardous substances by understanding the safety symbols and instructions on their labels?', 'Critical thinking and problem solving: learners classify hazardous substances by their properties and determine appropriate safe-handling procedures for each class.\nDigital literacy: learners use print and digital media to research safety data sheets and hazard symbols for various substances.', 'Safety education: learners interpret hazard warning symbols, safety labels and MSDS information on hazardous containers.\nEnvironmental education: learners discuss improper disposal of hazardous substances and its impact on the environment.\nHealth education: learners relate exposure to hazardous substances to health risks including chemical burns, poisoning and respiratory problems.', 'Responsibility: learners observe safety procedures when handling hazardous substances to protect themselves and the community.\nCare: learners demonstrate concern for environmental health by disposing of hazardous waste correctly.\nIntegrity: learners honestly follow prescribed safety instructions rather than taking shortcuts.', '* Learners textbook\n* Empty containers with labels (detergents, insecticides, batteries, fertilizers, paints)\n* Teacher\'s smartphone/tablet (to show images of common hazard symbols)\n* Chart paper and markers for group presentations', 'The teacher displays three common household containers (e.g., a bleach bottle, a used pesticide container, and a cleaning product bottle) and asks learners to observe any symbols, warnings, or special instructions printed on them. The teacher then poses the question: \'What do you think these symbols and words are trying to tell us, and why do manufacturers put them on these containers?\' After brief sharing of ideas, the teacher explains that today\'s lesson will help them correctly interpret safety symbols and instructions so they can protect themselves and others when handling hazardous substances.', '• Interpret, in groups, safety instructions on conditions for using hazardous substances and share findings with class.', '', '', 'Today we have learned how to interpret safety instructions and understand the meaning of various safety symbols found on hazardous substance containers. The teacher asks: \'Can someone explain what the skull and crossbones symbol means and what action you should take when you see it?\' and \'Why is it important to read the safety instructions on a container before using any chemical product?\' The teacher then emphasizes that understanding these labels and symbols is our first line of defense against accidents and health hazards.', '* Were all learners able to correctly interpret at least three different safety symbols and explain the corresponding safety actions required?\n* Did the group activity on interpreting safety instructions engage all learners equally, or did some groups struggle to extract key information from the labels?\n* Which learners need additional support in understanding technical terms commonly found on chemical labels, such as \'flammable,\' \'corrosive,\' or \'ventilated area\'?', 'Learners should identify at least three containers with hazardous substances at home or in their community (such as cleaning products, pesticides, or fuels), sketch or write down the safety symbols and instructions they find, and prepare to share what safety precautions each symbol or instruction requires during the next lesson.', '2026-04-11 11:24:15', '2026-04-11 11:24:15'),
(12, 131, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', '', '', NULL, '', NULL, 'a) Demonstrate safe ways of handling hazardous substances through a simulated activity.', 'b) Critique the handling techniques used by peers during the practice.', '', 'How can we safely handle hazardous substances to protect ourselves and others from harm?', 'Critical thinking and problem solving: learners classify hazardous substances by their properties and determine appropriate safe-handling procedures for each class.\nDigital literacy: learners use print and digital media to research safety data sheets and hazard symbols for various substances.', 'Safety education: learners interpret hazard warning symbols, safety labels and MSDS information on hazardous containers.\nEnvironmental education: learners discuss improper disposal of hazardous substances and its impact on the environment.\nHealth education: learners relate exposure to hazardous substances to health risks including chemical burns, poisoning and respiratory problems.', 'Responsibility: learners observe safety procedures when handling hazardous substances to protect themselves and the community.\nCare: learners demonstrate concern for environmental health by disposing of hazardous waste correctly.\nIntegrity: learners honestly follow prescribed safety instructions rather than taking shortcuts.', '* Learners textbook\n* Labels and markers for creating hazard warning signs\n* Empty containers (bottles, tins) to represent hazardous substances\n* Locally available materials to simulate protective equipment (cloth pieces for gloves, paper masks)\n* Chart showing common hazard symbols and safety procedures', 'The teacher displays or draws common hazard symbols (skull and crossbones, flame, corrosive liquid) on the chalkboard and asks learners to identify where they have seen these symbols in their homes or community, such as on bottles of bleach, paraffin, insecticides, or battery acid. The teacher then asks, \'What do you think could happen if someone handles these substances carelessly?\' and allows 2–3 learners to share brief experiences or observations. This leads into the day\'s focus: practicing safe handling techniques to prevent harm.', '• Practise, in groups, safe ways of handling hazardous substances and allow other learners to ask questions after the play.', '', '', 'The teacher summarizes that safe handling of hazardous substances requires following specific procedures such as wearing protective equipment, reading labels carefully, ensuring proper ventilation, and storing substances securely away from children and food. The teacher then asks: \'What are three safe handling practices you demonstrated in your group activity today?\' and \'How would you correct a peer who is handling a hazardous substance incorrectly?\' After listening to responses, the teacher emphasizes that responsibility and care protect both ourselves and our environment.', '* Were all learners able to demonstrate at least two safe handling techniques during the group simulations and provide constructive feedback to peers?\n* Which groups struggled with critiquing their peers\' handling techniques, and how can I scaffold peer assessment skills in future lessons?\n* Did learners connect the simulated safe handling practices to real hazardous substances they encounter at home, or do I need to provide more concrete local examples?', 'Learners should walk around their home compound and identify three containers or substances with hazard symbols or warning labels, then write down the substance name, the hazard symbol present, and one safety instruction written on the label. They should prepare to share their findings in the next lesson without touching or opening any containers.', '2026-04-11 11:24:29', '2026-04-11 11:24:29'),
(13, 132, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', '', '', NULL, '', NULL, 'a) Explain the importance of following safety protocols when handling hazardous materials.', 'b) Propose ways to promote safety awareness in the community.', '', 'Why is it critical to follow safety protocols when handling hazardous substances, and how can we promote safety awareness in our community?', 'Critical thinking and problem solving: learners classify hazardous substances by their properties and determine appropriate safe-handling procedures for each class.\nDigital literacy: learners use print and digital media to research safety data sheets and hazard symbols for various substances.', 'Safety education: learners interpret hazard warning symbols, safety labels and MSDS information on hazardous containers.\nEnvironmental education: learners discuss improper disposal of hazardous substances and its impact on the environment.\nHealth education: learners relate exposure to hazardous substances to health risks including chemical burns, poisoning and respiratory problems.', 'Responsibility: learners observe safety procedures when handling hazardous substances to protect themselves and the community.\nCare: learners demonstrate concern for environmental health by disposing of hazardous waste correctly.\nIntegrity: learners honestly follow prescribed safety instructions rather than taking shortcuts.', '* Learners textbook\n* Pictures or labels from hazardous household products (bleach, pesticides, rat poison, kerosene containers)\n* Community health worker or local safety volunteer as guest speaker\n* Chart paper and markers for group presentations', 'The teacher displays or draws common hazard warning symbols (skull and crossbones, corrosive, flammable) on the chalkboard and asks learners to recall what each symbol means from previous lessons. The teacher then tells a brief story of a local incident where someone was harmed by mishandling a hazardous substance (e.g., pesticide, bleach, battery acid) because they ignored safety warnings, prompting learners to think about why following safety protocols is so important. The teacher then poses the key inquiry question: Why is it critical to follow safety protocols when handling hazardous substances, and how can we promote safety awareness in our community?', '• Discuss in groups, the importance of observing safety when handling hazardous substances and present their findings.', '', '', 'The teacher summarizes that following safety protocols protects us, our families, and the environment from serious harm such as poisoning, burns, and pollution, and that raising awareness in our communities requires clear communication, proper labeling, and leading by example. The teacher then asks: What are two important safety protocols you must follow when handling a corrosive substance like battery acid? How can you help promote safety awareness about hazardous substances in your home or village?', '* Were all learners able to explain at least three reasons why following safety protocols when handling hazardous materials is important?\n* Did the group discussions effectively enable learners to propose practical and realistic ways to promote safety awareness in their own communities?\n* Which learners struggled to connect hazard symbols and safety labels to real-life scenarios, and how can I provide additional support in the next lesson?', 'Learners should identify three hazardous substances found in their homes or community (such as kerosene, pesticides, cleaning agents, or paint) and write down the safety warnings or symbols on their containers, noting whether the warnings are clear and what safety measures their family currently follows. They should be prepared to share one example and suggest how safety awareness could be improved for that substance.', '2026-04-11 11:24:42', '2026-04-11 11:24:42'),
(14, 133, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', '', '', NULL, '', NULL, 'a) Evaluate personal proficiency in safety procedures through a structured assessment exercise.', '', '', 'How can I demonstrate that I can safely identify, handle, and respond to hazardous substances in everyday situations?', 'Critical thinking and problem solving: learners classify hazardous substances by their properties and determine appropriate safe-handling procedures for each class.\nDigital literacy: learners use print and digital media to research safety data sheets and hazard symbols for various substances.', 'Safety education: learners interpret hazard warning symbols, safety labels and MSDS information on hazardous containers.\nEnvironmental education: learners discuss improper disposal of hazardous substances and its impact on the environment.\nHealth education: learners relate exposure to hazardous substances to health risks including chemical burns, poisoning and respiratory problems.', 'Responsibility: learners observe safety procedures when handling hazardous substances to protect themselves and the community.\nCare: learners demonstrate concern for environmental health by disposing of hazardous waste correctly.\nIntegrity: learners honestly follow prescribed safety instructions rather than taking shortcuts.', '* Learners textbook\n* Sample labels and pictures of common hazardous substances (cleaning products, pesticides, chemicals)\n* Assessment worksheets or printed scenario cards\n* Chart showing hazard symbols and safety procedures', 'The teacher displays three common household containers (e.g., a used disinfectant bottle with hazard symbols, a container of paraffin/kerosene, and a packet of rat poison or insecticide) and asks learners to identify which symbols or labels warn them of danger. The teacher then asks, \'If you had to handle or dispose of these substances today, how confident are you that you could do so safely without harming yourself, others, or the environment?\' This question sets the stage for learners to evaluate their own proficiency through today\'s assessment exercise on handling hazardous substances.', '• Work individually on assessment exercise on handling hazardous substances.', '', '', 'The teacher reminds learners that today\'s assessment has helped them evaluate their own understanding of safely identifying, handling, and responding to hazardous substances in everyday situations. The teacher then asks, \'Based on today\'s assessment, what is one safety procedure you now know you must follow when handling a corrosive substance?\' and \'How would you evaluate your ability to interpret hazard symbols and apply the correct safety measures—what areas do you still need to strengthen?\' These questions help learners reflect on their performance and identify personal areas for improvement.', '* Were all learners able to honestly evaluate their own proficiency in safety procedures through the structured assessment exercise?\n* Which specific questions or tasks in the assessment revealed gaps in learners\' understanding of hazard identification, safe handling, or emergency response?\n* Which learners demonstrated difficulty interpreting hazard symbols or safety data information and require targeted remedial support before moving to practical handling activities?', 'Learners should conduct a safety audit at home, identifying at least five hazardous substances (cleaning agents, pesticides, fuels, medicines), recording the hazard symbols present, noting whether they are stored safely, and writing a brief plan for how their household could improve storage or disposal practices. They should bring their written findings to the next lesson for discussion.', '2026-04-11 11:24:56', '2026-04-11 11:24:56');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(15, 134, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', '', '', NULL, '', NULL, 'a) Define the terms \"talents\" and \"abilities.\"', 'b) Discuss various ways of nurturing talents and abilities.', 'c) Outline how talent development contributes to self-growth.', 'How can you identify and develop your own talents and abilities to support your personal growth and future career?', 'Self-efficacy: learners reflect on personal talents and abilities and develop confidence in pursuing relevant career pathways.\nCommunication and collaboration: learners discuss career options in groups, listen to resource persons and present findings to the class.\nCitizenship: learners understand how individual talents contribute to national development and the economy.', 'Career guidance and counselling: learners map personal talents and abilities to Pre-Technical Studies career pathways (construction, manufacturing, ICT, entrepreneurship).\nLife skills education: learners develop self-awareness, goal-setting and decision-making skills related to career choices.\nCitizenship education: learners appreciate how technical careers contribute to the social and economic development of Kenya.', 'Respect: learners appreciate the diverse talents and abilities of their peers and treat all career pathways with equal value.\nResponsibility: learners commit to nurturing their talents and making informed career decisions.\nUnity: learners collaborate in identifying shared talents and supporting each other\'s aspirations.', '* Learners textbook\n* Chart paper or manila paper and markers\n* Examples of local role models (invited guest or teacher story)\n* Learners\' exercise books', 'The teacher begins by asking learners to stand if they can sing, draw, solve math problems quickly, repair broken items, cook well, or play sports. The teacher then asks two or three standing learners to briefly share what they think makes them good at that activity and whether they were born with it or learned it. This activity sets the stage for exploring the difference between talents and abilities and how they can be nurtured for personal and career growth.', '• Discuss in groups, ways of nurturing talents and abilities.', '• Share findings with the class.', '', 'Today we have learned that talents are natural gifts we are born with while abilities are skills we develop through practice, and that nurturing both through training, practice, mentorship and education helps us grow personally and prepares us for meaningful careers. To check your understanding: Can someone explain the difference between a talent and an ability using an example from your own life? How does developing your talents and abilities help you contribute to your community and Kenya\'s economy?', '* Were all learners able to clearly distinguish between talents and abilities and provide personal examples during the group discussions?\n* Did the group sharing activity allow every group to adequately present their findings on ways of nurturing talents, or did time constraints limit participation?\n* Which learners struggled to identify their own talents and abilities, and how can I provide additional guidance or counselling to support their self-exploration?', 'Learners should interview one adult in their family or community who uses a technical skill in their work (such as a carpenter, tailor, mechanic, farmer, or shopkeeper) and write a short paragraph describing what talents or abilities that person has, how they developed them, and how those skills help them earn a living and serve the community.', '2026-04-11 11:25:09', '2026-04-11 11:25:09'),
(16, 135, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', '', '', NULL, '', NULL, 'a) Identify different career pathways available in Senior School.', 'b) Relate specific talents and abilities to their corresponding career pathways.', '', 'How can you match your personal talents and abilities to the career pathways available in Senior School?', 'Self-efficacy: learners reflect on personal talents and abilities and develop confidence in pursuing relevant career pathways.\nCommunication and collaboration: learners discuss career options in groups, listen to resource persons and present findings to the class.\nCitizenship: learners understand how individual talents contribute to national development and the economy.', 'Career guidance and counselling: learners map personal talents and abilities to Pre-Technical Studies career pathways (construction, manufacturing, ICT, entrepreneurship).\nLife skills education: learners develop self-awareness, goal-setting and decision-making skills related to career choices.\nCitizenship education: learners appreciate how technical careers contribute to the social and economic development of Kenya.', 'Respect: learners appreciate the diverse talents and abilities of their peers and treat all career pathways with equal value.\nResponsibility: learners commit to nurturing their talents and making informed career decisions.\nUnity: learners collaborate in identifying shared talents and supporting each other\'s aspirations.', '* Learners textbook\n* Chart paper or manila paper\n* Markers or crayons\n* Sample career pathway charts (teacher-prepared or textbook reference)', 'The teacher begins by asking learners to think silently for one minute about one thing they are really good at or enjoy doing (drawing, fixing things, talking to people, using phones, building, cooking, etc.). The teacher then invites three learners to share what they thought of and writes these talents on the chalkboard. The teacher poses the key inquiry question: \'How can you match your personal talents and abilities to the career pathways available in Senior School?\' and explains that today they will discover how their unique talents connect to real career pathways they can choose.', '• Relate, in groups, talents and abilities to career pathways.', '• Share talent and ability in class and mention the career pathway.', '', 'The teacher summarises by stating that every learner has unique talents and abilities that can guide them toward specific career pathways in Senior School such as construction, manufacturing, ICT, or entrepreneurship, and that recognizing these connections helps them make informed decisions for their future. The teacher then asks: \'Can someone give an example of a talent and the career pathway it matches?\' and \'Why is it important to know your talents before choosing a career pathway in Senior School?\'', '* Were all learners able to relate their personal talents and abilities to at least one specific career pathway available in Senior School?\n* Did the group discussions in the lesson body allow every learner to participate and share their talent, or did some learners remain silent?\n* Which learners showed difficulty identifying their own talents or understanding the career pathways, and what additional support or examples can I provide in the next lesson?', 'Learners should interview one adult in their home or community (parent, guardian, neighbour, or relative) about the talent or ability that helped them in their work or livelihood, and write a short paragraph describing the talent and the type of work it led to. They should be ready to share this in the next lesson.', '2026-04-11 11:25:23', '2026-04-11 11:25:23'),
(17, 136, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', '', '', NULL, '', NULL, 'a) List various career opportunities related to specific talents.', 'b) Evaluate information from a resource person regarding career progression.', '', 'How can you match your personal talents with real career opportunities and pathways available in your community and beyond?', 'Self-efficacy: learners reflect on personal talents and abilities and develop confidence in pursuing relevant career pathways.\nCommunication and collaboration: learners discuss career options in groups, listen to resource persons and present findings to the class.\nCitizenship: learners understand how individual talents contribute to national development and the economy.', 'Career guidance and counselling: learners map personal talents and abilities to Pre-Technical Studies career pathways (construction, manufacturing, ICT, entrepreneurship).\nLife skills education: learners develop self-awareness, goal-setting and decision-making skills related to career choices.\nCitizenship education: learners appreciate how technical careers contribute to the social and economic development of Kenya.', 'Respect: learners appreciate the diverse talents and abilities of their peers and treat all career pathways with equal value.\nResponsibility: learners commit to nurturing their talents and making informed career decisions.\nUnity: learners collaborate in identifying shared talents and supporting each other\'s aspirations.', '* Learners textbook\n* Chart paper and markers for listing talents and careers\n* Invited resource person from the community (teacher, health worker, artisan, entrepreneur, or farmer)\n* Sample career information materials (newspaper clippings, printed articles, or smartphone for video if available)', 'The teacher asks learners to quickly name one thing they are good at (talent) and writes 5–6 responses on the chalkboard. The teacher then poses the key question: \'If someone is good at building things with their hands, what jobs could they do in our community or in Kenya?\' and invites 2–3 learners to share ideas. This activates prior knowledge about talents and sets the stage for exploring how talents connect to real career opportunities.', '• Make a list of talents and corresponding career pathways.', '• Engage with a resource person (guest, video, or article) on career opportunities.', '', 'The teacher summarizes by stating that every talent can open doors to multiple career pathways in Pre-Technical fields like construction, manufacturing, ICT and entrepreneurship, and that learning from resource persons helps us understand how to progress in these careers. The teacher then asks: \'Can you name three career opportunities that match a talent you have?\' and \'What is one important thing you learned from today\'s resource person about career progression?\' Learners respond briefly to confirm understanding.', '* Were all learners able to list at least three career opportunities related to specific talents from the lesson?\n* Did the engagement with the resource person (guest, video, or article) effectively help learners evaluate career progression information, or did some learners struggle to extract key points?\n* Which learners showed low confidence in identifying their own talents and matching them to careers, and how can I support them in the next lesson?', 'Learners should interview one adult in their home or community who works in a technical field (construction worker, tailor, mechanic, phone repair technician, etc.) and ask them: \'What talent or skill helped you get this job?\' and \'What steps did you take to learn this work?\' They should write a short paragraph summarizing the responses in their exercise books to share in the next lesson.', '2026-04-11 11:25:35', '2026-04-11 11:25:35'),
(18, 137, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', '', '', NULL, '', NULL, 'a) Analyze case studies on the use of talents and abilities.', 'b) Distinguish between ethical and unethical practices in the application of talents.', '', 'How can talents and abilities be used ethically or unethically, and what are the consequences of each choice?', 'Self-efficacy: learners reflect on personal talents and abilities and develop confidence in pursuing relevant career pathways.\nCommunication and collaboration: learners discuss career options in groups, listen to resource persons and present findings to the class.\nCitizenship: learners understand how individual talents contribute to national development and the economy.', 'Career guidance and counselling: learners map personal talents and abilities to Pre-Technical Studies career pathways (construction, manufacturing, ICT, entrepreneurship).\nLife skills education: learners develop self-awareness, goal-setting and decision-making skills related to career choices.\nCitizenship education: learners appreciate how technical careers contribute to the social and economic development of Kenya.', 'Respect: learners appreciate the diverse talents and abilities of their peers and treat all career pathways with equal value.\nResponsibility: learners commit to nurturing their talents and making informed career decisions.\nUnity: learners collaborate in identifying shared talents and supporting each other\'s aspirations.', '* Learners textbook\n* Case study handouts or written scenarios (prepared by teacher or from textbook)\n* Chart paper and markers for group presentations\n* Examples from local community (sports persons, artisans, business people)', 'The teacher begins by asking learners to think of a talented person in their community—perhaps a skilled carpenter, a talented footballer, or a gifted cook—and pose the question: \'Can this talent be used in both good and bad ways?\' The teacher then gives a quick example: a skilled carpenter can build quality furniture for clients honestly or can use inferior materials while charging full price, leading to a brief discussion on how the same talent can be applied ethically or unethically. This sets the stage for today\'s exploration of ethical and unethical use of talents and abilities.', '• Discuss, in groups, case studies on ethical and unethical practices related to the use of talents and abilities and share with the class.', '', '', 'The teacher summarizes that every talent and ability can be used to benefit or harm others, and the choice we make determines whether we build trust and contribute to development or cause harm and lose respect. The teacher then asks: \'From the case studies we discussed today, what is one consequence of using talents unethically?\' and \'How can someone in a Pre-Technical career like construction or ICT ensure they are using their skills ethically?\' These questions help learners consolidate understanding of the link between ethical practice and career success.', '* Were all learners able to clearly distinguish between ethical and unethical practices in the case studies discussed during group work?\n* Did the group discussions allow every learner to contribute, or did some learners dominate while others remained silent?\n* Which case study examples resonated most with learners, and should I include more locally relevant scenarios in future lessons on ethical talent use?', 'Learners should interview a family member or neighbor who uses a technical skill in their work (such as a mechanic, tailor, mason, or shopkeeper) and ask them to describe one situation where they had to make an ethical choice about how to use their talent. They should write a short paragraph summarizing the interview to share in the next lesson.', '2026-04-11 11:25:50', '2026-04-11 11:25:50'),
(19, 138, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', '', '', NULL, '', NULL, 'a) Select a preferred career based on personal talents and abilities.', 'b) Explain the reasons for the chosen career in relation to self-development.', '', 'How can understanding your personal talents and abilities guide you in selecting a career path that supports your self-development?', 'Self-efficacy: learners reflect on personal talents and abilities and develop confidence in pursuing relevant career pathways.\nCommunication and collaboration: learners discuss career options in groups, listen to resource persons and present findings to the class.\nCitizenship: learners understand how individual talents contribute to national development and the economy.', 'Career guidance and counselling: learners map personal talents and abilities to Pre-Technical Studies career pathways (construction, manufacturing, ICT, entrepreneurship).\nLife skills education: learners develop self-awareness, goal-setting and decision-making skills related to career choices.\nCitizenship education: learners appreciate how technical careers contribute to the social and economic development of Kenya.', 'Respect: learners appreciate the diverse talents and abilities of their peers and treat all career pathways with equal value.\nResponsibility: learners commit to nurturing their talents and making informed career decisions.\nUnity: learners collaborate in identifying shared talents and supporting each other\'s aspirations.', '* Learners textbook\n* Chart paper or newsprint for group presentations\n* Markers or colored chalk\n* Sample career profiles or posters (teacher-prepared or from newspapers/magazines)', 'The teacher begins by asking learners to think silently for one minute about something they are really good at doing, whether it is farming, repairing things, drawing, organizing events, or helping others solve problems. The teacher then invites three learners to share what they are good at and asks the class: \'How could these talents help someone choose a job or career in the future?\' This creates curiosity about how personal abilities connect to career choices, which is the focus of today\'s lesson.', '• Choose, in groups, careers based on talents and abilities.', '• Share chosen careers with the class.', '', 'The teacher summarizes by reminding learners that understanding their own talents and abilities is the first step in choosing a career path that will help them grow and contribute to society. The teacher then asks: \'Can someone explain how their chosen career matches their personal talents?\' and \'Why is it important to select a career based on what you are good at rather than just copying what others choose?\'', '* Were all learners able to select a preferred career based on their personal talents and abilities during the group activity?\n* Did the group discussions allow quieter learners to participate fully, or did some voices dominate the career selection process?\n* Which learners struggled to explain the reasons for their chosen career in relation to self-development, and what additional support or examples do they need?', 'Learners should interview one adult in their community (parent, neighbor, or local artisan) who works in construction, manufacturing, ICT, or entrepreneurship, and ask them what talents or abilities helped them succeed in that career. They should write a short paragraph summarizing what they learned and be ready to share it in the next lesson.', '2026-04-11 11:26:00', '2026-04-11 11:26:00'),
(20, 139, 'Grade 9', 'Pre-Technical Studies', '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', '', '', NULL, '', NULL, 'a) Evaluate personal career goals through a self-exploration assessment exercise.', '', '', 'How can understanding your strengths, interests, and values help you make informed decisions about your future career path?', 'Self-efficacy: learners reflect on personal talents and abilities and develop confidence in pursuing relevant career pathways.\nCommunication and collaboration: learners discuss career options in groups, listen to resource persons and present findings to the class.\nCitizenship: learners understand how individual talents contribute to national development and the economy.', 'Career guidance and counselling: learners map personal talents and abilities to Pre-Technical Studies career pathways (construction, manufacturing, ICT, entrepreneurship).\nLife skills education: learners develop self-awareness, goal-setting and decision-making skills related to career choices.\nCitizenship education: learners appreciate how technical careers contribute to the social and economic development of Kenya.', 'Respect: learners appreciate the diverse talents and abilities of their peers and treat all career pathways with equal value.\nResponsibility: learners commit to nurturing their talents and making informed career decisions.\nUnity: learners collaborate in identifying shared talents and supporting each other\'s aspirations.', '* Learners textbook\n* Self-exploration assessment worksheets or questionnaires\n* Exercise books and pens\n* Chart showing different career pathways and required skills', 'The teacher asks learners to quickly write down on a piece of paper one thing they believe they are good at and one thing they enjoy doing, then invites two or three volunteers to share their responses with the class. The teacher then explains that today\'s lesson will help them explore their own strengths, interests, and values more deeply through a self-exploration assessment to guide their future career decisions in Pre-Technical Studies fields.', '• Work individually on assessment exercise on self-exploration and career development.', '', '', 'Today you have completed a self-exploration assessment that helped you identify your personal strengths, interests, and values as they relate to career pathways in construction, manufacturing, ICT, and entrepreneurship. Can you name two of your strengths or interests that you discovered through the assessment? How might understanding your values help you choose between different technical career options in the future?', '* Were all learners able to honestly evaluate their personal career goals through the self-exploration assessment exercise, or did some struggle with self-awareness?\n* Did the assessment tool provide sufficient guidance for learners to identify connections between their talents and specific Pre-Technical Studies career pathways?\n* Which learners appeared uncertain about their strengths and interests and would benefit from additional career guidance and counselling support?', 'Learners should interview one adult in their community (parent, guardian, neighbour, or local artisan) about how that person discovered their talents and chose their current work, then write a short paragraph comparing that person\'s experience with their own self-exploration findings from today\'s assessment.', '2026-04-11 11:26:10', '2026-04-11 11:26:10'),
(21, 140, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', '', '', NULL, '', NULL, 'a) Define the term \"oblique projection.\"', 'b) Identify different types of oblique drawings (Cavalier and Cabinet).', 'c) Explain the use of oblique drawings in technical fields.', 'How can we represent three-dimensional objects on a flat surface using oblique projection to communicate technical ideas clearly?', 'Creativity and imagination: learners produce neat oblique projection drawings of given objects, applying correct angles, proportions and line types.\nCritical thinking and problem solving: learners interpret oblique drawings to visualise three-dimensional objects and solve spatial problems.', 'Education for sustainable development (ESD): learners use drawing skills to design and communicate ideas for sustainable building and product design.\nICT integration: learners use digital drawing tools where available to create oblique projection drawings.\nInnovation and creativity: learners apply oblique projection to communicate innovative design ideas.', 'Responsibility: learners take care of drawing tools and produce accurate, tidy work.\nIntegrity: learners present original drawings and acknowledge sources of reference.', '* Learners textbook\n* Rectangular boxes or cartons (matchboxes, chalk boxes)\n* Ruler and pencil\n* Samples of technical drawings or diagrams from textbooks showing oblique views', 'The teacher displays a simple rectangular box (e.g., a matchbox or chalk box) and asks learners to observe it from different angles, then attempts to draw what they see on the chalkboard showing how difficult it is to show all three dimensions clearly on a flat surface. The teacher then explains that today learners will discover a special drawing method called oblique projection that solves this problem by allowing us to represent three-dimensional objects on paper in a way that clearly shows length, width, and height all at once. The teacher poses the key inquiry question: How can we represent three-dimensional objects on a flat surface using oblique projection to communicate technical ideas clearly?', '• Search for information on meaning of oblique projection, examples of oblique drawings, and characteristics.', '• Share findings with the class.', '', 'The teacher summarizes that oblique projection is a method of drawing three-dimensional objects on a flat surface where one face is drawn true to size and depth lines are drawn at an angle, and that the two main types are Cavalier projection (depth at full scale) and Cabinet projection (depth at half scale), both used widely in furniture design, architecture, and product manufacturing. The teacher then asks: What is the main difference between Cavalier and Cabinet oblique projections? Can you name two technical fields where oblique drawings are commonly used and explain why?', '* Were all learners able to correctly define oblique projection and distinguish between Cavalier and Cabinet projections by the end of the lesson?\n* Did the information search activity provide learners with sufficient examples and clear characteristics of oblique drawings, or did some groups struggle to find relevant information?\n* Which learners need additional support in understanding how oblique projection differs from other drawing methods, and what strategies can I use in the next lesson to reinforce this concept?', 'Learners should observe and sketch three different rectangular objects at home (such as a book, a stool, or a container) using simple oblique projection, labeling each sketch to show which face is drawn true to size and indicating the direction of the depth lines. They should be prepared to share their sketches and explain which type of oblique projection they attempted to use.', '2026-04-11 11:26:24', '2026-04-11 11:26:24'),
(22, 141, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', '', '', NULL, '', NULL, 'a) Describe the key characteristics of oblique drawings (sloping axes and front face).', 'b) Distinguish between oblique and other pictorial drawings.', '', 'What makes an oblique drawing different from other types of pictorial drawings you have seen?', 'Creativity and imagination: learners produce neat oblique projection drawings of given objects, applying correct angles, proportions and line types.\nCritical thinking and problem solving: learners interpret oblique drawings to visualise three-dimensional objects and solve spatial problems.', 'Education for sustainable development (ESD): learners use drawing skills to design and communicate ideas for sustainable building and product design.\nICT integration: learners use digital drawing tools where available to create oblique projection drawings.\nInnovation and creativity: learners apply oblique projection to communicate innovative design ideas.', 'Responsibility: learners take care of drawing tools and produce accurate, tidy work.\nIntegrity: learners present original drawings and acknowledge sources of reference.', '* Learners textbook\n* Chalkboard and chalk\n* Geometric set (ruler, set squares)\n* Cardboard boxes or wooden blocks of different shapes\n* Manila papers and pencils', 'The teacher displays a small rectangular box (such as a matchbox or chalk box) on the table and asks learners to observe it from different angles. The teacher then draws a simple flat rectangle on the chalkboard and asks: \'If I want to show this box so that you can see its front, top, and side all at once in one drawing, how would I do it?\' The teacher invites two or three learners to attempt a quick sketch on the chalkboard, then explains that today they will learn about oblique projection, a special way to draw objects showing three dimensions at the same time.', '• Brainstorm, in groups, on the characteristics of oblique drawings and share with the class.', '', '', 'The teacher summarises that oblique drawings are unique because the front face is drawn in its true shape and size, while the receding lines go backwards at an angle (usually 45°) to show depth. The teacher then asks: \'What is the key difference between the front face in an oblique drawing and the side faces?\' and \'Why would a carpenter or designer choose to use oblique projection instead of a flat, two-dimensional drawing?\' The teacher invites brief responses from two or three learners to confirm understanding.', '* Were all learners able to correctly describe the key characteristics of oblique drawings, especially the treatment of the front face and the sloping receding axes?\n* Did the group brainstorming activity in the lesson body allow every learner to participate, or did some groups dominate while others remained passive?\n* Which learners struggled to distinguish between oblique and other pictorial drawings, and what additional examples or comparisons do they need in the next lesson?', 'Learners should identify three objects at home (such as a book, a stool, or a small box) and make a simple freehand oblique sketch of one of them in their exercise books, ensuring the front face is drawn accurately and the receding lines go backwards at an angle. They should label the front face and the sloping lines to show they understand the characteristics of oblique projection.', '2026-04-11 11:26:37', '2026-04-11 11:26:37'),
(23, 142, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', '', '', NULL, '', NULL, 'a) Identify the starting point for sketching an oblique drawing.', 'b) Sketch simple shaped blocks in oblique projection using freehand.', '', 'How can you represent the depth and three-dimensional form of a simple block object on a flat surface using oblique projection?', 'Creativity and imagination: learners produce neat oblique projection drawings of given objects, applying correct angles, proportions and line types.\nCritical thinking and problem solving: learners interpret oblique drawings to visualise three-dimensional objects and solve spatial problems.', 'Education for sustainable development (ESD): learners use drawing skills to design and communicate ideas for sustainable building and product design.\nICT integration: learners use digital drawing tools where available to create oblique projection drawings.\nInnovation and creativity: learners apply oblique projection to communicate innovative design ideas.', 'Responsibility: learners take care of drawing tools and produce accurate, tidy work.\nIntegrity: learners present original drawings and acknowledge sources of reference.', '* Learners textbook\n* Chalkboard and chalk\n* Plain paper or exercise books\n* Pencils\n* Simple rectangular wooden blocks or small cardboard boxes', 'The teacher displays a physical rectangular wooden block or a small matchbox on a table and asks learners to observe it from different angles, noticing how they can see the front, side, and top faces simultaneously when viewing from a corner. The teacher then holds up a previously prepared oblique drawing of the same block on paper and asks learners to compare what they see in the drawing with the actual object. The teacher poses the key inquiry question: \'How can you represent the depth and three-dimensional form of this simple block object on a flat surface using oblique projection?\'', '• Sketch drawings in oblique projection without using instruments.', '', '', 'The teacher summarizes that in oblique projection, we start by drawing the front face of the object as a true shape, then add depth lines at 45 degrees going backwards to show the third dimension, creating a realistic three-dimensional appearance on flat paper. The teacher asks: \'Where do you begin when sketching an oblique drawing of a block?\' and \'At what angle do we draw the receding lines to show depth in oblique projection?\' The teacher invites two or three learners to show their freehand sketches and explain their starting points.', '* Were all learners able to identify the correct starting point (front face) for sketching oblique drawings of simple blocks?\n* Did learners struggle with maintaining the 45-degree angle for depth lines during freehand sketching, and what additional guidance or practice might help?\n* Which learners produced neat and proportionate oblique sketches and which ones need extra support with freehand drawing techniques in the next lesson?', 'Learners should identify three simple rectangular objects at home (such as a book, a brick, or a small box) and practice sketching each one in oblique projection freehand in their exercise books, remembering to start with the front face and add depth lines at 45 degrees. They should label each drawing with the name of the object.', '2026-04-11 11:26:50', '2026-04-11 11:26:50'),
(24, 143, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', '', '', NULL, '', NULL, 'a) Refine freehand oblique sketches for proportion and clarity.', 'b) Sketch complex shaped blocks in oblique projection.', '', 'How can you accurately sketch complex shaped blocks in oblique projection freehand while maintaining correct proportions and clarity?', 'Creativity and imagination: learners produce neat oblique projection drawings of given objects, applying correct angles, proportions and line types.\nCritical thinking and problem solving: learners interpret oblique drawings to visualise three-dimensional objects and solve spatial problems.', 'Education for sustainable development (ESD): learners use drawing skills to design and communicate ideas for sustainable building and product design.\nICT integration: learners use digital drawing tools where available to create oblique projection drawings.\nInnovation and creativity: learners apply oblique projection to communicate innovative design ideas.', 'Responsibility: learners take care of drawing tools and produce accurate, tidy work.\nIntegrity: learners present original drawings and acknowledge sources of reference.', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Erasers\n* Rulers (for checking proportions, not for drawing)', 'The teacher displays a simple L-shaped block sketch in oblique projection on the chalkboard that was covered in previous lessons, then holds up a locally available object with a more complex shape such as a brick with a cut-out corner or a wooden block with multiple steps. The teacher asks learners to observe the object carefully and think about how they would show all its faces and depths in one drawing, reminding them that today they will apply their oblique projection skills to sketch more complex shaped blocks freehand while keeping correct proportions and clear lines.', '• Sketch more complex shaped blocks in oblique projection without using instruments.', '', '', 'The teacher summarizes that sketching complex shaped blocks in oblique projection freehand requires careful attention to proportions, consistent receding angles, and clear line work to show depth and form accurately. The teacher then asks: Can you explain how you maintained correct proportions when sketching the stepped block today? What specific techniques did you use to keep your oblique sketch clear and easy to understand?', '* Were all learners able to sketch complex shaped blocks in oblique projection while maintaining correct proportions and clarity?\n* Which learners struggled with keeping consistent receding angles during freehand sketching and what additional support or practice can I provide?\n* Did the examples of complex shaped blocks I chose help learners understand how to break down difficult shapes into simpler components for sketching?', 'Learners should find three different complex-shaped objects at home such as a carved stool, a stepped stone, or a brick arrangement, and practice sketching each one freehand in oblique projection in their exercise books, paying attention to proportions and using light construction lines before darkening the final outlines.', '2026-04-11 11:27:01', '2026-04-11 11:27:01'),
(25, 144, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', '', '', NULL, '', NULL, 'a) Outline the step-by-step procedure for drawing oblique blocks.', 'b) Discuss the importance of using a 45-degree set square in oblique drawing.', '', 'How do we use the 45-degree angle and a step-by-step procedure to accurately draw shaped blocks in oblique projection?', 'Creativity and imagination: learners produce neat oblique projection drawings of given objects, applying correct angles, proportions and line types.\nCritical thinking and problem solving: learners interpret oblique drawings to visualise three-dimensional objects and solve spatial problems.', 'Education for sustainable development (ESD): learners use drawing skills to design and communicate ideas for sustainable building and product design.\nICT integration: learners use digital drawing tools where available to create oblique projection drawings.\nInnovation and creativity: learners apply oblique projection to communicate innovative design ideas.', 'Responsibility: learners take care of drawing tools and produce accurate, tidy work.\nIntegrity: learners present original drawings and acknowledge sources of reference.', '* Learners textbook\n* Geometric set (45-degree set square, ruler, compass, protractor)\n* Drawing paper or exercise books\n* Pencils and erasers\n* Chalkboard and chalk for demonstration', 'The teacher displays a simple rectangular block drawn in oblique projection on the chalkboard and asks learners to observe how the front face looks flat while the receding edges slant backwards. The teacher then uses a 45-degree set square to trace one of the receding lines and asks, \'Why do you think we use exactly 45 degrees for these slanting lines instead of any other angle?\' This question prompts learners to recall previous lessons on oblique angles and prepares them to explore the systematic steps needed to create accurate oblique drawings of shaped blocks.', '• Discuss, in pairs, the steps for drawing shaped blocks in oblique projection.', '', '', 'The teacher summarises that drawing shaped blocks in oblique projection requires following a clear step-by-step procedure: drawing the front face first, using a 45-degree set square to construct receding lines, and maintaining correct proportions and line types throughout. The teacher then asks, \'Can someone outline the first three steps we follow when starting an oblique drawing of a block?\' and \'Why is it important to use a 45-degree angle rather than estimating the slant by eye?\' These questions help confirm that learners understand both the procedure and the role of accurate angle measurement in oblique projection.', '* Were all learners able to correctly outline the step-by-step procedure for drawing oblique blocks, or did some struggle with sequencing the steps?\n* Did the pair discussion activity give learners enough time to articulate and understand the importance of the 45-degree set square, and should I provide more guided practice with the set square in future lessons?\n* Which learners need additional support in using the 45-degree set square accurately, and what hands-on strategies can I use to help them master this skill?', 'Learners should identify one rectangular or L-shaped object at home (such as a matchbox, book, or brick) and sketch it using oblique projection on paper, paying close attention to drawing the front face accurately and using an estimated 45-degree angle for receding lines. They should label the front face and receding edges, then bring their sketches to the next lesson for peer review.', '2026-04-11 11:27:17', '2026-04-11 11:27:17'),
(26, 145, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', '', '', NULL, '', NULL, 'a) Construct accurate oblique drawings of shaped blocks using a geometrical set.', 'b) Demonstrate the correct use of drawing instruments for cabinet projection.', '', 'How can we accurately represent three-dimensional shaped blocks on a two-dimensional surface using oblique projection with correct proportions and angles?', 'Creativity and imagination: learners produce neat oblique projection drawings of given objects, applying correct angles, proportions and line types.\nCritical thinking and problem solving: learners interpret oblique drawings to visualise three-dimensional objects and solve spatial problems.', 'Education for sustainable development (ESD): learners use drawing skills to design and communicate ideas for sustainable building and product design.\nICT integration: learners use digital drawing tools where available to create oblique projection drawings.\nInnovation and creativity: learners apply oblique projection to communicate innovative design ideas.', 'Responsibility: learners take care of drawing tools and produce accurate, tidy work.\nIntegrity: learners present original drawings and acknowledge sources of reference.', '* Learners textbook\n* Geometrical set (ruler, set squares, compass, protractor, divider)\n* Drawing paper or graph paper\n* Pencils (HB and 2H)\n* Eraser', 'The teacher displays a small rectangular box (such as a matchbox or chalk box) and asks learners to observe it from different angles, noting how they can see the top, front, and side simultaneously from certain viewpoints. The teacher then sketches a quick freehand oblique drawing of the box on the chalkboard, pointing out how this drawing method shows three faces at once, and asks learners how this differs from the orthographic drawings they learned previously. The teacher announces that today they will learn to construct accurate oblique projection drawings of shaped blocks using their drawing instruments.', '• Draw, in pairs, shaped blocks in oblique projection using drawing instruments.', '', '', 'The teacher summarizes that oblique projection allows us to represent three-dimensional shaped blocks on paper by drawing the front face true to size and shape, then projecting receding lines at 45 degrees (cabinet projection uses half the actual depth). The teacher asks: What angle should the receding lines make with the horizontal in your oblique drawing? How does cabinet projection differ from cavalier projection in terms of depth representation? The teacher invites two pairs to display their best drawings for class observation.', '* Were all learners able to construct oblique drawings with the correct 45-degree angle for receding lines using their set squares and protractors?\n* Did learners in pairs demonstrate proper use of drawing instruments, or did some struggle with maintaining clean, accurate lines and proportions?\n* Which learners need additional practice with distinguishing between cabinet projection (half depth) and cavalier projection (full depth), and how can I provide targeted support in the next lesson?', 'Learners should identify one shaped block object at home (such as a brick, a book, a small stool, or a wooden block) and sketch it freehand using oblique projection, ensuring they show the front face clearly and receding lines at approximately 45 degrees. They should label the object and bring the sketch to the next lesson for discussion.', '2026-04-11 11:27:32', '2026-04-11 11:27:32'),
(27, 146, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', '', '', NULL, '', NULL, 'a) Construct individual figures in oblique projection with precision.', 'b) Apply line types correctly (outlines and construction lines) in oblique drawings.', '', 'How can you accurately represent three-dimensional objects on a flat surface using oblique projection while applying correct line types?', 'Creativity and imagination: learners produce neat oblique projection drawings of given objects, applying correct angles, proportions and line types.\nCritical thinking and problem solving: learners interpret oblique drawings to visualise three-dimensional objects and solve spatial problems.', 'Education for sustainable development (ESD): learners use drawing skills to design and communicate ideas for sustainable building and product design.\nICT integration: learners use digital drawing tools where available to create oblique projection drawings.\nInnovation and creativity: learners apply oblique projection to communicate innovative design ideas.', 'Responsibility: learners take care of drawing tools and produce accurate, tidy work.\nIntegrity: learners present original drawings and acknowledge sources of reference.', '* Learners textbook\n* Drawing board or firm cardboard backing\n* Geometric set (ruler, set squares, protractor, compass)\n* Drawing paper or squared paper\n* Pencils (HB and 2H) and eraser', 'The teacher displays a simple rectangular box (such as a matchbox or chalk box) on the table and asks learners to observe it from different angles, noting how they can see the front, side, and top faces simultaneously from certain viewpoints. The teacher then sketches a quick oblique projection of the box on the chalkboard, pointing out that this drawing method shows three dimensions on a flat surface just like what they observed. The teacher links this to last week\'s lesson on oblique projection basics and announces that today learners will construct their own precise oblique drawings using correct line types and drawing instruments.', '• Work individually, using appropriate drawing instruments, draw figures in oblique projection.', '', '', 'The teacher summarizes that oblique projection allows us to represent three-dimensional objects accurately on flat paper by using specific angles and applying correct line types—continuous thick lines for visible outlines and thin lines for construction. The teacher asks: What type of line should you use to draw the visible edges of an object in oblique projection? How does the angle of the receding lines help make the drawing look three-dimensional? The teacher invites two learners to show their completed drawings and explain the line types they used.', '* Were all learners able to construct individual figures in oblique projection with correct proportions and angles using their drawing instruments?\n* Did learners demonstrate clear understanding of the difference between outline lines and construction lines, and did they apply them correctly in their drawings?\n* Which learners struggled with maintaining the 45-degree angle for receding lines, and what additional support or practice do they need in the next lesson?', 'Learners should identify one simple three-dimensional object at home (such as a book, a stool, or a small box) and sketch it freehand using oblique projection, clearly showing the front face and receding lines at 45 degrees. They should label the continuous thick outlines and any construction lines used, then bring the sketch to the next lesson for review.', '2026-04-11 11:27:46', '2026-04-11 11:27:46');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(28, 147, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', '', '', NULL, '', NULL, 'a) Analyze how oblique projection is applied in technical communication.', 'b) Discuss the advantages of using oblique projection over other drawing methods.', '', 'How does oblique projection help technicians and engineers communicate their design ideas clearly, and what makes it more useful than other drawing methods in certain situations?', 'Creativity and imagination: learners produce neat oblique projection drawings of given objects, applying correct angles, proportions and line types.\nCritical thinking and problem solving: learners interpret oblique drawings to visualise three-dimensional objects and solve spatial problems.', 'Education for sustainable development (ESD): learners use drawing skills to design and communicate ideas for sustainable building and product design.\nICT integration: learners use digital drawing tools where available to create oblique projection drawings.\nInnovation and creativity: learners apply oblique projection to communicate innovative design ideas.', 'Responsibility: learners take care of drawing tools and produce accurate, tidy work.\nIntegrity: learners present original drawings and acknowledge sources of reference.', '* Learners textbook\n* Chart paper or manila paper\n* Samples of technical drawings from textbooks or magazines\n* Ruler and pencil\n* Teacher\'s smartphone/tablet (for showing real-world technical drawings if available)', 'The teacher displays two drawings of the same simple object (such as a matchbox or chalk box) on the chalkboard: one drawn in oblique projection and one drawn in orthographic projection (showing only the front view). The teacher asks learners to observe both drawings and discuss in pairs which drawing shows more information about the object\'s shape and depth, and why a technician might choose one method over the other when communicating a design idea to a client or builder.', '• Discuss the application of oblique projection in technical communication and present findings.', '', '', 'Today we have analyzed how oblique projection is used in technical communication to show three-dimensional objects clearly in a single view, and we have discussed its advantages such as ease of drawing and better visualization compared to orthographic views. Can you explain two specific situations where a technician would prefer oblique projection over orthographic projection? What is one main advantage of oblique projection when communicating design ideas to someone who cannot read technical drawings?', '* Were all learners able to clearly articulate at least two advantages of oblique projection over other drawing methods during the class discussion?\n* Did the comparison activity between oblique and orthographic projections effectively help learners understand when oblique projection is most useful in technical communication?\n* Which learners struggled to explain the applications of oblique projection in real-world technical communication, and what additional examples or support do they need?', 'Learners should identify three objects at home or in their community (such as a wooden stool, a water container, or a simple building structure) and write a brief explanation for each object describing why oblique projection would or would not be the best method to communicate its design to someone else. They should be ready to share their reasoning in the next lesson.', '2026-04-11 11:27:57', '2026-04-11 11:27:57'),
(29, 148, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', '', '', NULL, '', NULL, 'a) Evaluate personal drawing skills through a practical assessment exercise.', '', '', 'How well can I apply the principles of oblique projection to accurately represent three-dimensional objects in my technical drawings?', 'Creativity and imagination: learners produce neat oblique projection drawings of given objects, applying correct angles, proportions and line types.\nCritical thinking and problem solving: learners interpret oblique drawings to visualise three-dimensional objects and solve spatial problems.', 'Education for sustainable development (ESD): learners use drawing skills to design and communicate ideas for sustainable building and product design.\nICT integration: learners use digital drawing tools where available to create oblique projection drawings.\nInnovation and creativity: learners apply oblique projection to communicate innovative design ideas.', 'Responsibility: learners take care of drawing tools and produce accurate, tidy work.\nIntegrity: learners present original drawings and acknowledge sources of reference.', '* Learners textbook\n* Drawing sheets or plain pages\n* Pencils (HB and 2H)\n* Ruler and set squares\n* Eraser', 'The teacher displays two or three oblique projection drawings completed in previous lessons on the chalkboard and asks learners to silently observe them for one minute, identifying which drawing shows the best application of correct angles, proportions, and line types. The teacher then asks two learners to share their observations and explain what makes a quality oblique projection drawing, linking their responses to the assessment criteria they will use today. The teacher announces that today learners will evaluate their own drawing skills through a practical assessment exercise that tests everything they have learned about oblique projection.', '• Work individually on assessment exercise on oblique projection.', '', '', 'The teacher asks learners to put down their drawing instruments and reminds them that today they demonstrated their ability to apply oblique projection principles independently through a practical assessment. The teacher then asks: How confident do you feel about the accuracy of the angles and proportions in your oblique drawing today, and what specific aspect of oblique projection do you now understand better after completing this assessment? The teacher collects all assessment exercises and encourages learners to continue practicing their technical drawing skills.', '* Were all learners able to complete the assessment exercise within the allocated time and demonstrate accurate application of oblique projection principles?\n* Which specific drawing skills (angles, proportions, or line types) appeared most challenging for learners during the assessment, and how can I provide targeted support?\n* Did the assessment exercise adequately evaluate learners\' mastery of oblique projection concepts taught across the previous lessons in this sub-strand?', 'Learners should identify one three-dimensional object at home (such as a matchbox, brick, or small stool) and sketch it using oblique projection on a plain page in their exercise book, applying the correct 45-degree angle and maintaining accurate proportions. They should label the sketch with the object\'s name and bring it to the next lesson for peer review.', '2026-04-11 11:28:10', '2026-04-11 11:28:10'),
(30, 149, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', '', '', NULL, '', NULL, 'a) Define the term \"visual programming.\"', 'b) Identify various application areas of visual programming in problem-solving.', 'c) Outline the benefits of visual programming over text-based coding.', 'How does visual programming help people solve everyday problems differently from traditional text-based coding?', 'Digital literacy: learners use block-based visual programming environments (e.g., Scratch, MIT App Inventor) to create simple programs and animations.\nCritical thinking and problem solving: learners design, test and debug visual programs to solve given problems.\nCreativity and imagination: learners create original animations, stories or games using visual programming tools.', 'ICT integration: learners apply digital literacy skills through hands-on use of visual programming software.\nInnovation and creativity: learners use computational thinking to design creative solutions to everyday problems.\nLife skills education: learners develop logical sequencing, persistence and collaborative problem-solving skills through programming.', 'Responsibility: learners handle ICT equipment with care and follow acceptable use policies.\nIntegrity: learners produce original programs and give credit for shared code resources.', '* Learners textbook\n* Teacher\'s smartphone or tablet (for demonstrating visual programming examples if internet available)\n* Manila papers and markers for creating visual programming concept maps\n* Sample screenshots or printed images of visual programming interfaces (Scratch, Blockly, MIT App Inventor)', 'The teacher begins by asking learners to recall how they give instructions to someone to perform a task, such as directing a friend to the school library or explaining how to prepare tea. The teacher then draws a simple flowchart on the chalkboard showing steps to wash hands (start → fetch water → apply soap → scrub → rinse → dry → end) and explains that just as we use pictures and arrows to show steps clearly, visual programming uses blocks and shapes instead of typing code words. The teacher poses the key inquiry question: How does visual programming help people solve everyday problems differently from traditional text-based coding?', '• Search for information on application area of visual programming.', '• Write short notes and give examples of websites and mobile applications.', '', 'The teacher summarises that visual programming uses graphical blocks or icons to create programs instead of typing text commands, making it easier for beginners to learn coding concepts and solve everyday problems through drag-and-drop interfaces. The teacher asks: Can someone define visual programming in their own words? The teacher then asks: What is one benefit of visual programming over text-based coding that we discussed today?', '* Were all learners able to clearly define visual programming and distinguish it from text-based coding?\n* Did the search activity on application areas of visual programming work effectively given our limited internet access, and should I prepare printed examples or screenshots in advance next time?\n* Which learners struggled to identify real-world application areas of visual programming and how can I provide additional concrete examples to support their understanding?', 'Learners should interview a family member or neighbor about a daily problem they face (such as remembering medicine times, organizing market days, or watering crops) and write a short paragraph describing how a simple mobile app or animation could help solve that problem. They should bring their written ideas to the next lesson to share with classmates.', '2026-04-11 11:28:23', '2026-04-11 11:28:23'),
(31, 150, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', '', '', NULL, '', NULL, 'a) Identify examples of mobile applications developed using visual programming.', 'b) Discuss how web development utilizes visual programming tools.', '', 'How do visual programming tools make it easier to create mobile applications and websites that we use every day?', 'Digital literacy: learners use block-based visual programming environments (e.g., Scratch, MIT App Inventor) to create simple programs and animations.\nCritical thinking and problem solving: learners design, test and debug visual programs to solve given problems.\nCreativity and imagination: learners create original animations, stories or games using visual programming tools.', 'ICT integration: learners apply digital literacy skills through hands-on use of visual programming software.\nInnovation and creativity: learners use computational thinking to design creative solutions to everyday problems.\nLife skills education: learners develop logical sequencing, persistence and collaborative problem-solving skills through programming.', 'Responsibility: learners handle ICT equipment with care and follow acceptable use policies.\nIntegrity: learners produce original programs and give credit for shared code resources.', '* Learners textbook\n* Teacher\'s smartphone or tablet with sample visual programming apps (e.g. MIT App Inventor, Scratch)\n* Charts showing screenshots of visual programming interfaces\n* Examples of popular mobile apps (WhatsApp, M-PESA) written on the chalkboard', 'The teacher begins by asking learners to take out their smartphones or think about smartphones they have seen and name three mobile applications they use or know about (e.g., WhatsApp, M-Pesa, games). After learners share their examples, the teacher poses the key inquiry question: \'How do you think these applications were created? Could someone without advanced coding skills build a simple app?\' The teacher then explains that today they will explore how visual programming tools make it possible for anyone to create mobile apps and websites using drag-and-drop blocks instead of typing complex code.', '• Discuss, in groups, the application areas in visual programming - Mobile programming and Web development.', '', '', 'The teacher summarizes that visual programming tools like MIT App Inventor and Scratch allow people to create mobile applications and websites by dragging and dropping code blocks, making app development accessible to beginners and students. The teacher then asks: \'Can you name two examples of mobile applications that can be developed using visual programming tools?\' and \'How does visual programming for web development differ from traditional text-based coding?\' The teacher invites two or three learners to share their answers before closing the lesson.', '* Were all learners able to identify at least two examples of mobile applications developed using visual programming tools?\n* Did the group discussions on mobile programming and web development engage all learners, or did some groups dominate while others remained passive?\n* Which learners struggled to understand the difference between visual programming for mobile apps versus web development, and what additional examples or explanations might help them?', 'Learners should interview a family member, neighbor, or friend who uses a smartphone and ask them to name three mobile apps they use daily, then write a short paragraph explaining which of those apps they think could be created using visual programming tools like MIT App Inventor and why. They should be ready to share their findings in the next lesson.', '2026-04-11 11:28:35', '2026-04-11 11:28:35'),
(32, 151, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', '', '', NULL, '', NULL, 'a) Demonstrate how to download and install Scratch on a digital device.', 'b) Identify the system requirements for running visual programming software.', '', 'How can we download and install Scratch software on a digital device to create visual programs?', 'Digital literacy: learners use block-based visual programming environments (e.g., Scratch, MIT App Inventor) to create simple programs and animations.\nCritical thinking and problem solving: learners design, test and debug visual programs to solve given problems.\nCreativity and imagination: learners create original animations, stories or games using visual programming tools.', 'ICT integration: learners apply digital literacy skills through hands-on use of visual programming software.\nInnovation and creativity: learners use computational thinking to design creative solutions to everyday problems.\nLife skills education: learners develop logical sequencing, persistence and collaborative problem-solving skills through programming.', 'Responsibility: learners handle ICT equipment with care and follow acceptable use policies.\nIntegrity: learners produce original programs and give credit for shared code resources.', '* Learners textbook\n* Teacher\'s smartphone or tablet with internet connection\n* Projector or large screen (if available, otherwise device passed around)\n* Scratch installation guide (printed or displayed)\n* Sample screenshots of Scratch interface drawn on chart paper', 'The teacher begins by asking learners to recall what they learned about visual programming and Scratch in previous lessons, then asks \'What do you think we need before we can start creating our own programs in Scratch?\' The teacher displays a smartphone or tablet and explains that today learners will learn how to prepare a digital device to run Scratch by understanding system requirements and learning the steps to download and install the software. The teacher writes the key inquiry question on the chalkboard and invites learners to share what they already know about installing apps or software on phones or computers.', '• How to download and install Scratch in a device.', '• Watch a video of a resource person.', '', 'The teacher summarizes that installing Scratch requires checking system requirements such as operating system version, storage space, and RAM, then following specific download and installation steps from the official Scratch website or app store. The teacher then asks: \'What are two system requirements you must check before downloading Scratch?\' and \'What is the first step in downloading Scratch software onto a computer or tablet?\' Learners respond orally or write answers in their exercise books for quick assessment.', '* Were all learners able to identify at least three system requirements for running Scratch software?\n* Did the video demonstration clearly show the download and installation steps, or did learners need additional explanation using diagrams on the chalkboard?\n* Which learners seemed confused about the difference between system requirements and installation steps, and how can I provide extra support in the next lesson?', 'Learners should visit a computer lab, cybercafé, or ask an adult with a smartphone or computer to show them where to check the device\'s operating system version, available storage space, and RAM specifications. They should write down these specifications in their exercise books and compare them with Scratch system requirements discussed in class.', '2026-04-11 11:28:48', '2026-04-11 11:28:48'),
(33, 152, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', '', '', NULL, '', NULL, 'a) Identify the components of the Scratch user interface (Stage, Sprites, Blocks Palette).', 'b) Describe the functions of different interface areas.', '', 'How do the different parts of the Scratch user interface work together to help us create programs?', 'Digital literacy: learners use block-based visual programming environments (e.g., Scratch, MIT App Inventor) to create simple programs and animations.\nCritical thinking and problem solving: learners design, test and debug visual programs to solve given problems.\nCreativity and imagination: learners create original animations, stories or games using visual programming tools.', 'ICT integration: learners apply digital literacy skills through hands-on use of visual programming software.\nInnovation and creativity: learners use computational thinking to design creative solutions to everyday problems.\nLife skills education: learners develop logical sequencing, persistence and collaborative problem-solving skills through programming.', 'Responsibility: learners handle ICT equipment with care and follow acceptable use policies.\nIntegrity: learners produce original programs and give credit for shared code resources.', '* Learners textbook\n* Teacher\'s smartphone or tablet with Scratch installed (offline or online)\n* Chart paper and markers to draw interface components\n* Exercise books for sketching and note-taking', 'The teacher draws a simple three-panel diagram on the chalkboard showing a stage (large rectangle), a character/sprite (stick figure), and a set of instruction blocks (small labeled rectangles) arranged vertically. The teacher asks: \'When we want to give instructions to a computer character to make it move or speak, what parts do we need—the character itself, the place where it performs, or the instructions we give it?\' The teacher invites two learners to come forward and point to each part on the diagram while explaining in their own words what they think each part might do, creating curiosity about how these parts work together in Scratch.', '• Familiarise yourself with Scratch programming, in groups.', '• Explore the Scratch interface.', '', 'The teacher summarizes by pointing to the three main areas on the chalkboard diagram or on the Scratch interface if available: \'Today we learned that Scratch has three key parts—the Stage where our programs run and we see the action, the Sprites which are the characters or objects we control, and the Blocks Palette where we find all the instruction blocks to command our sprites.\' The teacher then asks: \'Can someone name the area where you would see your animation or program running?\' and \'Which part of the Scratch interface contains all the coding blocks we use to give instructions?\'', '* Were all learners able to correctly identify and name the three main components of the Scratch user interface (Stage, Sprites, Blocks Palette) by the end of the lesson?\n* Did the group exploration activity provide enough hands-on time for each learner to interact with the Scratch interface, or did some learners remain passive observers?\n* Which learners struggled to describe the function of each interface area, and what additional visual aids or analogies could help them understand better in the next lesson?', 'Learners should draw and label a diagram of the Scratch user interface in their exercise books, showing the Stage, Sprites area, and Blocks Palette, then write one sentence describing what each part does. If they have access to a computer or smartphone at home or in the community, they should open Scratch and spend 10 minutes exploring each area by clicking and observing what happens.', '2026-04-11 11:48:02', '2026-04-11 11:48:02'),
(34, 153, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', '', '', NULL, '', NULL, 'a) Categorize Scratch blocks based on their colors and functions (Motion, Events, Control).', 'b) Demonstrate how to snap blocks together to form a script.', '', 'How can we organize and combine different colored blocks in Scratch to create instructions that make a sprite perform actions?', 'Digital literacy: learners use block-based visual programming environments (e.g., Scratch, MIT App Inventor) to create simple programs and animations.\nCritical thinking and problem solving: learners design, test and debug visual programs to solve given problems.\nCreativity and imagination: learners create original animations, stories or games using visual programming tools.', 'ICT integration: learners apply digital literacy skills through hands-on use of visual programming software.\nInnovation and creativity: learners use computational thinking to design creative solutions to everyday problems.\nLife skills education: learners develop logical sequencing, persistence and collaborative problem-solving skills through programming.', 'Responsibility: learners handle ICT equipment with care and follow acceptable use policies.\nIntegrity: learners produce original programs and give credit for shared code resources.', '* Learners textbook\n* Smartphone or tablet with Scratch app (teacher\'s device for demonstration)\n* Chart paper and colored markers (to draw and label block categories)\n* Printed screenshots of Scratch interface (if available from textbook or pre-printed)', 'The teacher draws three large overlapping circles on the chalkboard using colored chalk (blue, yellow, and brown) and labels them \'Motion\', \'Events\', and \'Control\'. The teacher then writes simple action words like \'move\', \'start\', \'repeat\', \'when clicked\' on small pieces of paper or cardboard and asks volunteers to come forward and place each word inside the circle where they think it belongs, explaining that today they will learn how these categories work like colored puzzle pieces in Scratch that fit together to give instructions to characters on the screen.', '• Familiarise yourself with Scratch programming environment.', '', '', 'Today we learned that Scratch uses different colored blocks grouped by function—Motion blocks move sprites, Events blocks start actions, and Control blocks manage how and when things happen—and that these blocks snap together like puzzle pieces to create scripts that give instructions. Can you name one type of block and its color, and tell me what it does? Can you explain in your own words how blocks snap together to form a script?', '* Were all learners able to correctly categorize at least three Scratch blocks by their color and function during the lesson activities?\n* Did the chalkboard demonstration of block categories and the hands-on snapping activity provide enough clarity for learners who have limited or no prior exposure to computers?\n* Which learners struggled to understand how blocks connect in sequence, and what additional concrete examples or analogies could I use in the next lesson to support them?', 'Learners should draw and color at least five different Scratch blocks in their exercise books (using the correct colors for Motion, Events, and Control categories), label each block with its function, and then sketch how three of these blocks would snap together to make a sprite move across the stage when the green flag is clicked.', '2026-04-11 11:48:16', '2026-04-11 11:48:16'),
(35, 154, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', '', '', NULL, '', NULL, 'a) Formulate a logical sequence of steps (algorithm) for a simple game.', 'b) Write down the planned steps for a personal game project.', '', 'How can you break down a game into a clear, step-by-step sequence that a computer can follow?', 'Digital literacy: learners use block-based visual programming environments (e.g., Scratch, MIT App Inventor) to create simple programs and animations.\nCritical thinking and problem solving: learners design, test and debug visual programs to solve given problems.\nCreativity and imagination: learners create original animations, stories or games using visual programming tools.', 'ICT integration: learners apply digital literacy skills through hands-on use of visual programming software.\nInnovation and creativity: learners use computational thinking to design creative solutions to everyday problems.\nLife skills education: learners develop logical sequencing, persistence and collaborative problem-solving skills through programming.', 'Responsibility: learners handle ICT equipment with care and follow acceptable use policies.\nIntegrity: learners produce original programs and give credit for shared code resources.', '* Learners textbook\n* Exercise books and pencils\n* Sample game examples (drawn or described on paper)\n* Chart paper or manila paper for displaying algorithm steps', 'The teacher asks learners to explain the steps they follow every morning to prepare for school, writing 3–4 responses on the chalkboard (e.g., wake up, wash face, dress, eat breakfast). The teacher then connects this everyday sequence to today\'s lesson by explaining that just as we break down our morning routine into clear steps, we must break down a game into clear steps that a computer can follow. The teacher poses the key inquiry question: How can you break down a game into a clear, step-by-step sequence that a computer can follow?', '• Write down the steps to follow to develop your game.', '', '', 'The teacher summarizes that creating a game requires formulating a logical algorithm—a clear sequence of steps that tells the computer exactly what to do, just like a recipe or morning routine. The teacher then asks: What is the first step you would write in your algorithm if you were creating a simple guessing game? Why is it important to write down each step in the correct order before programming? Learners respond orally or by writing one answer in their exercise books.', '* Were all learners able to formulate a logical sequence of steps (algorithm) for their simple game, or did some struggle to break the game into clear steps?\n* Did learners understand the difference between describing a game idea and writing down specific, ordered steps that a computer could follow?\n* Which learners need additional support in writing down their planned game steps in a logical, sequential manner, and what scaffolding can I provide in the next lesson?', 'At home, learners should write down the complete step-by-step algorithm for a simple traditional game they know (e.g., skipping rope counting game, hide-and-seek, or a guessing game), using numbered steps as if explaining it to someone who has never played before. They should bring this written algorithm to the next lesson to compare with their digital game plan.', '2026-04-11 11:48:29', '2026-04-11 11:48:29'),
(36, 155, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', '', '', NULL, '', NULL, 'a) Construct a simple interactive game using Motion and Events blocks.', 'b) Test and play the game to ensure functionality.', '', 'How can you use motion and event blocks in Scratch to create an interactive game that responds to player actions?', 'Digital literacy: learners use block-based visual programming environments (e.g., Scratch, MIT App Inventor) to create simple programs and animations.\nCritical thinking and problem solving: learners design, test and debug visual programs to solve given problems.\nCreativity and imagination: learners create original animations, stories or games using visual programming tools.', 'ICT integration: learners apply digital literacy skills through hands-on use of visual programming software.\nInnovation and creativity: learners use computational thinking to design creative solutions to everyday problems.\nLife skills education: learners develop logical sequencing, persistence and collaborative problem-solving skills through programming.', 'Responsibility: learners handle ICT equipment with care and follow acceptable use policies.\nIntegrity: learners produce original programs and give credit for shared code resources.', '* Learners textbook\n* Smartphones or tablets with Scratch installed (shared in groups)\n* Computer lab (if available) or teacher\'s device with projector/screen sharing\n* Exercise books for planning game flowcharts and pseudocode\n* Chart paper and markers for designing game storyboards', 'The teacher asks learners to recall the motion blocks they learned in previous lessons (move, glide, turn) and demonstrates a quick physical game: clap your hands when I say \'Go!\' to show how events trigger actions. The teacher then explains that today learners will combine motion blocks with event blocks in Scratch to create games that respond to player actions, just like the clapping game responded to the spoken command.', '• Create and play a fun game, following steps.', '• Develop, in groups, interactive games using Scratch.', '', 'Today you have learned to construct interactive games in Scratch by combining motion blocks with event blocks to make sprites respond to player actions. Can you name two event blocks that can trigger motion in a Scratch game? How did testing and playing your game help you find and fix problems in your program?', '* Were all learners able to successfully construct a simple interactive game using both Motion and Events blocks in Scratch?\n* Did the group work during game development allow every learner to contribute, or did some learners dominate the computer while others remained passive?\n* Which learners struggled with testing and debugging their games, and what additional support or scaffolding do they need in the next lesson?', 'Learners should sketch on paper a design for a new Scratch game idea, drawing at least three sprites and writing down which event blocks (like \'when green flag clicked\' or \'when space key pressed\') would trigger which motion blocks for each sprite. They should be ready to share their game design in the next lesson.', '2026-04-11 11:48:40', '2026-04-11 11:48:40'),
(37, 156, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', '', '', NULL, '', NULL, 'a) Construct an interactive story using conversation (Say) blocks and multiple backdrops.', 'b) Demonstrate the story to peers for feedback.', '', 'How can you use visual programming blocks to create a story that responds to user interaction and changes scenes?', 'Digital literacy: learners use block-based visual programming environments (e.g., Scratch, MIT App Inventor) to create simple programs and animations.\nCritical thinking and problem solving: learners design, test and debug visual programs to solve given problems.\nCreativity and imagination: learners create original animations, stories or games using visual programming tools.', 'ICT integration: learners apply digital literacy skills through hands-on use of visual programming software.\nInnovation and creativity: learners use computational thinking to design creative solutions to everyday problems.\nLife skills education: learners develop logical sequencing, persistence and collaborative problem-solving skills through programming.', 'Responsibility: learners handle ICT equipment with care and follow acceptable use policies.\nIntegrity: learners produce original programs and give credit for shared code resources.', '* Learners textbook\n* Teacher\'s smartphone or tablet with Scratch installed\n* Exercise books and pencils for story planning\n* Chalkboard and chalk for demonstrating block sequences', 'The teacher begins by asking learners to recall a favorite story they have heard or read and to describe how the story changed from one scene to another. The teacher then poses the key inquiry question: \'How can you use visual programming blocks to create a story that responds to user interaction and changes scenes?\' The teacher briefly demonstrates or describes (using a smartphone if available, or through verbal illustration on the chalkboard) how a simple interactive story might look in Scratch, showing how clicking a sprite or pressing a key can make characters speak and backgrounds change.', '• Write down steps to follow to develop the story.', '• Develop interactive stories using Scratch.', '', 'The teacher summarizes that today learners have constructed interactive stories using Say blocks and multiple backdrops in Scratch, and demonstrated their work to peers for feedback. The teacher then asks: \'What blocks did you use to make your characters speak in your story?\' and \'How did you change the backdrop to create different scenes in your interactive story?\' The teacher invites two or three learners to share one challenge they overcame during the lesson.', '* Were all learners able to construct an interactive story using Say blocks and multiple backdrops, or did some struggle with sequencing the blocks correctly?\n* Did learners have enough time to demonstrate their stories to peers and receive meaningful feedback, and how can peer review be structured better next time?\n* Which learners need extra support with changing backdrops or using event blocks to trigger user interaction, and what scaffolding strategies will I use in the next lesson?', 'Learners should plan on paper a new three-scene interactive story with at least two characters, writing down the dialogue for each character and describing what backdrop will appear in each scene. They should bring this written plan to the next lesson to develop it in Scratch.', '2026-04-11 11:48:53', '2026-04-11 11:48:53'),
(38, 157, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', '', '', NULL, '', NULL, 'a) Apply \"Costumes\" and \"Sound\" blocks to create a simple animation.', 'b) Demonstrate the finished animation to the class.', '', 'How can you use costumes and sound blocks in visual programming to tell a story or show movement through animation?', 'Digital literacy: learners use block-based visual programming environments (e.g., Scratch, MIT App Inventor) to create simple programs and animations.\nCritical thinking and problem solving: learners design, test and debug visual programs to solve given problems.\nCreativity and imagination: learners create original animations, stories or games using visual programming tools.', 'ICT integration: learners apply digital literacy skills through hands-on use of visual programming software.\nInnovation and creativity: learners use computational thinking to design creative solutions to everyday problems.\nLife skills education: learners develop logical sequencing, persistence and collaborative problem-solving skills through programming.', 'Responsibility: learners handle ICT equipment with care and follow acceptable use policies.\nIntegrity: learners produce original programs and give credit for shared code resources.', '* Learners textbook\n* Computer lab or teacher\'s smartphone/tablet with Scratch or similar visual programming app\n* Projector or screen for demonstration (or learners gather around device)\n* Exercise books for planning animation storyboards', 'The teacher begins by asking learners to recall the basic visual programming blocks they used in previous lessons, then displays or draws on the chalkboard simple stick-figure animations showing a character in different positions (costume changes) and asks: \'How can we make our sprite characters change appearance or make sounds to tell a story?\' The teacher then briefly explains that today learners will use Costumes and Sound blocks to bring their animations to life, making characters move and interact through costume changes and audio effects.', '• Develop, in groups, animations using visual programming.', '• Play the animation for the class to see.', '', 'The teacher summarizes that Costumes blocks allow sprites to change appearance for animation effects while Sound blocks add audio to make programs more engaging and storytelling more realistic. The teacher then asks: \'Which block did you use to change your sprite\'s appearance during animation?\' and \'How did adding sound blocks improve your animation story?\' before inviting two learners to share one challenge they overcame while creating their animations.', '* Were all learners able to successfully apply both Costumes and Sound blocks to create a functioning animation by the end of the lesson?\n* Did the group work arrangement allow every learner hands-on time with the visual programming environment, or did some learners remain passive observers?\n* Which learners struggled with sequencing costume and sound blocks correctly, and what additional scaffolding or peer support can I provide in the next lesson?', 'Learners should sketch on paper a storyboard for a new animation showing at least four different scenes, labeling where costume changes would occur and noting what sounds they would add at each stage. They should write a brief description of their animation story to share in the next lesson.', '2026-04-11 11:49:06', '2026-04-11 11:49:06'),
(39, 158, 'Grade 9', 'Pre-Technical Studies', '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', '', '', NULL, '', NULL, 'a) Discuss how visual programming can be used to solve real-life challenges.', 'b) Evaluate personal understanding of programming through an assessment exercise.', '', 'How can visual programming be applied to solve everyday challenges in our homes, schools, and communities?', 'Digital literacy: learners use block-based visual programming environments (e.g., Scratch, MIT App Inventor) to create simple programs and animations.\nCritical thinking and problem solving: learners design, test and debug visual programs to solve given problems.\nCreativity and imagination: learners create original animations, stories or games using visual programming tools.', 'ICT integration: learners apply digital literacy skills through hands-on use of visual programming software.\nInnovation and creativity: learners use computational thinking to design creative solutions to everyday problems.\nLife skills education: learners develop logical sequencing, persistence and collaborative problem-solving skills through programming.', 'Responsibility: learners handle ICT equipment with care and follow acceptable use policies.\nIntegrity: learners produce original programs and give credit for shared code resources.', '* Learners textbook\n* Teacher\'s smartphone or tablet with visual programming app (e.g. Scratch, Blockly)\n* Charts showing visual programming blocks and examples\n* Exercise books and pens', 'The teacher begins by asking learners to recall the visual programming blocks and tools they explored in previous lessons (e.g., Scratch or block-based programming concepts). The teacher then poses the key inquiry question: \'How can visual programming be applied to solve everyday challenges in our homes, schools, and communities?\' and invites 2–3 learners to share one problem they face daily (e.g., reminding people to save water, tracking borrowed books, alerting when a gate is left open) and how a simple program might help solve it.', '• Discuss the uses of visual programming.', '• Work individually on assessment exercise on visual programming.', '', 'The teacher summarises that visual programming is a powerful tool for creating solutions to real-life problems in homes, schools and communities by using logical sequences and creative thinking. The teacher then asks: \'Can you name two everyday challenges that could be solved using visual programming?\' and \'What is one thing you learned about yourself as a programmer during today\'s assessment exercise?\' to check understanding of the lesson outcomes.', '* Were all learners able to discuss at least one real-life application of visual programming and demonstrate understanding during the assessment exercise?\n* Did the assessment exercise reveal specific programming concepts (such as loops, conditionals, or sequencing) that need reinforcement in future lessons?\n* Which learners struggled with evaluating their own programming understanding and how can I provide targeted support or additional examples for them?', 'Learners should identify one specific problem in their home or community (e.g., reminding family members to turn off lights, sorting waste, watering plants on schedule) and write a short paragraph describing how they would use visual programming blocks to create a solution, including at least three steps or commands their program would need.', '2026-04-11 11:49:18', '2026-04-11 11:49:18'),
(40, 159, 'Grade 9', 'Pre-Technical Studies', '3.0 Materials for Production', '3.1 Wood', '', '', NULL, '', NULL, 'a) Identify available types of wood in the local environment.', 'b) Describe the physical properties of different wood types.', 'c) Distinguish between softwood and hardwood.', 'What different types of wood can we find in our local environment, and how can we tell softwood from hardwood by observing their physical properties?', 'Critical thinking and problem solving: learners evaluate different wood types based on properties such as hardness, grain and durability, then select the most appropriate for a given task.\nCreativity and imagination: learners design and plan wood-based products that meet specified requirements.', 'Environmental education: learners discuss sustainable timber harvesting, afforestation and the impact of deforestation on the environment.\nESD: learners relate responsible use of wood to sustainable production and consumption practices.\nSafety education: learners apply safe tool and material handling practices when working with wood.', 'Responsibility: learners handle wood and woodworking tools safely, following all prescribed safety procedures.\nCare: learners demonstrate respect for natural resources by using wood economically and avoiding wastage.\nPatriotism: learners appreciate local Kenyan wood species and promote sustainable use of forest resources.', '* Learners textbook\n* Samples of different wood types from the local environment (branches, timber offcuts, firewood pieces)\n* Chart paper or chalkboard for recording observations\n* Access to trees in the school compound and surrounding community', 'The teacher begins by holding up two pieces of wood (or wooden objects) commonly found in the school or community, such as a piece of cypress and a piece of mango wood, and asks learners to observe and touch them carefully. The teacher then poses the question: \'Why do you think one piece feels harder and heavier than the other, and what might that tell us about the trees they came from?\' Learners share their initial observations while the teacher writes key words like \'hard,\' \'soft,\' \'heavy,\' and \'light\' on the chalkboard to build curiosity about wood properties.', '• Search for information on types of wood available, physical property of each type of wood and example of each type of wood.', '• Share findings with the class.', '• Walk around the school or community and identify the trees in the environment while observing physical characteristics.', 'The teacher summarises by stating that wood types in our environment can be classified as softwood or hardwood based on physical properties such as hardness, weight, grain pattern, and density, and that recognising these differences helps us choose the right wood for different uses. The teacher then asks: \'Can you name two examples of hardwood trees found in our local area and describe one physical property that makes them hardwood?\' and \'How would you quickly test whether an unknown piece of wood is likely to be softwood or hardwood?\'', '* Were all learners able to confidently distinguish between softwood and hardwood based on observable physical properties during the community walk?\n* Did the information search and sharing activity provide learners with enough local examples, or do I need to supplement with more region-specific tree species next time?\n* Which learners struggled to describe physical properties accurately, and what hands-on comparison activities can I use to support their understanding in the next lesson?', 'Learners should identify and collect small samples (fallen twigs or branches, not cutting live trees) of at least three different wood types from their homestead or neighbourhood, then observe and record in their exercise books the name of the tree, whether it appears to be softwood or hardwood, and two physical properties they noticed such as weight, colour, grain, or texture.', '2026-04-11 11:49:31', '2026-04-11 11:49:31');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(41, 160, 'Grade 9', 'Pre-Technical Studies', '3.0 Materials for Production', '3.1 Wood', '', '', NULL, '', NULL, 'a) Describe the process of wood conversion.', 'b) Illustrate different wood conversion methods through drawing.', '', 'How is a tree trunk converted into usable timber for construction and furniture making?', 'Critical thinking and problem solving: learners evaluate different wood types based on properties such as hardness, grain and durability, then select the most appropriate for a given task.\nCreativity and imagination: learners design and plan wood-based products that meet specified requirements.', 'Environmental education: learners discuss sustainable timber harvesting, afforestation and the impact of deforestation on the environment.\nESD: learners relate responsible use of wood to sustainable production and consumption practices.\nSafety education: learners apply safe tool and material handling practices when working with wood.', 'Responsibility: learners handle wood and woodworking tools safely, following all prescribed safety procedures.\nCare: learners demonstrate respect for natural resources by using wood economically and avoiding wastage.\nPatriotism: learners appreciate local Kenyan wood species and promote sustainable use of forest resources.', '* Learners textbook\n* Drawing materials (pencils, rulers, erasers)\n* Sample wood pieces or logs from the school compound\n* Charts or diagrams showing wood conversion methods', 'The teacher displays a rough piece of timber (or a large stick) and a finished piece of wood such as a plank or furniture part, then asks learners to observe the difference in shape and finish. The teacher poses the key inquiry question: \'How is a tree trunk converted into usable timber for construction and furniture making?\' and explains that today they will learn the specific methods used to convert logs into timber of different sizes and shapes.', '• Discuss, in groups, methods of wood preparation - Conversion.', '• Draw images, individually, to represent each conversion method.', '', 'The teacher summarizes that wood conversion involves sawing logs into usable timber using different methods such as plain sawing, quarter sawing, and radial sawing, each producing timber with different grain patterns and properties. The teacher then asks: \'Which conversion method produces the strongest timber and why?\' and \'If you were making furniture for outdoor use, which conversion method would you choose and what is your reason?\'', '* Were all learners able to accurately describe at least two methods of wood conversion and explain the differences between them?\n* Did the group discussions on conversion methods engage all learners, or did some groups dominate while others remained passive?\n* Which learners struggled with drawing the different conversion methods, and what additional support or visual aids could help them illustrate the sawing patterns more clearly?', 'Learners should visit a local carpentry workshop, timber yard, or observe any wood construction in their community, then sketch and label one real example of converted timber they see, noting the visible grain pattern and guessing which conversion method was used. They should write a short paragraph describing what they observed and present it in the next lesson.', '2026-04-11 11:49:43', '2026-04-11 11:49:43'),
(42, 161, 'Grade 9', 'Pre-Technical Studies', '3.0 Materials for Production', '3.1 Wood', '', '', NULL, '', NULL, 'a) Describe the process of wood seasoning.', 'b) Explain the importance of seasoning wood before production.', '', 'Why is it necessary to season wood before using it to make furniture or other products?', 'Critical thinking and problem solving: learners evaluate different wood types based on properties such as hardness, grain and durability, then select the most appropriate for a given task.\nCreativity and imagination: learners design and plan wood-based products that meet specified requirements.', 'Environmental education: learners discuss sustainable timber harvesting, afforestation and the impact of deforestation on the environment.\nESD: learners relate responsible use of wood to sustainable production and consumption practices.\nSafety education: learners apply safe tool and material handling practices when working with wood.', 'Responsibility: learners handle wood and woodworking tools safely, following all prescribed safety procedures.\nCare: learners demonstrate respect for natural resources by using wood economically and avoiding wastage.\nPatriotism: learners appreciate local Kenyan wood species and promote sustainable use of forest resources.', '* Learners textbook\n* Samples of seasoned and unseasoned wood pieces from the local environment\n* Chart showing wood seasoning methods\n* Sticks or timber offcuts from local carpentry workshop', 'The teacher displays two pieces of wood: one freshly cut (if available) or a green twig, and one that is old and dry. Learners are asked to handle both pieces and observe differences in weight, moisture, and firmness. The teacher then poses the question: \'If you were a carpenter making a chair, which piece of wood would you choose and why?\' to spark discussion about wood preparation and lead into the concept of seasoning.', '• Discuss, in groups, methods of wood preparation - Seasoning.', '• Share findings with the class.', '', 'Today we have learned that wood seasoning is the process of removing moisture from wood to make it suitable for construction and furniture making, and that seasoning prevents warping, cracking, and increases strength and durability. To check your understanding, answer these questions: What is wood seasoning and what are the two main methods used? Why must wood be seasoned before making furniture or building structures?', '* Were all learners able to clearly describe the process of wood seasoning and distinguish between air-drying and kiln-drying methods?\n* Did the group discussions on methods of wood seasoning allow every learner to participate, or did some groups dominate while others remained passive?\n* Which learners struggled to explain the importance of seasoning wood, and what additional examples or demonstrations could help them understand the consequences of using unseasoned wood?', 'Learners should visit a local carpenter, furniture maker, or building site in their community and ask how they prepare wood before use, then write a short paragraph describing the seasoning method observed and how long the wood is left to season. Alternatively, learners can place a fresh twig in a dry place at home and observe changes in weight and appearance over the next week, recording their observations daily.', '2026-04-11 11:49:57', '2026-04-11 11:49:57'),
(43, 162, 'Grade 9', 'Pre-Technical Studies', '3.0 Materials for Production', '3.1 Wood', '', '', NULL, '', NULL, 'a) Identify the uses of specific wood types in the community.', 'b) Relate various wood types to specific trades and industries.', '', 'How do different types of wood serve specific purposes in our community\'s trades and industries?', 'Critical thinking and problem solving: learners evaluate different wood types based on properties such as hardness, grain and durability, then select the most appropriate for a given task.\nCreativity and imagination: learners design and plan wood-based products that meet specified requirements.', 'Environmental education: learners discuss sustainable timber harvesting, afforestation and the impact of deforestation on the environment.\nESD: learners relate responsible use of wood to sustainable production and consumption practices.\nSafety education: learners apply safe tool and material handling practices when working with wood.', 'Responsibility: learners handle wood and woodworking tools safely, following all prescribed safety procedures.\nCare: learners demonstrate respect for natural resources by using wood economically and avoiding wastage.\nPatriotism: learners appreciate local Kenyan wood species and promote sustainable use of forest resources.', '* Learners textbook\n* Sample wood pieces from the local community (mango, pine, eucalyptus, mvule, cypress, etc.)\n* Chart paper or manila papers for group presentations\n* Resource persons (local carpenter, furniture maker, or woodworker)', 'The teacher displays or asks learners to observe three different wooden objects commonly found in the community, such as a wooden cooking spoon, a piece of furniture, and a farm tool handle. The teacher then asks: \'Why do you think craftsmen chose these particular types of wood for each of these items? Could any wood be used for any purpose?\' Learners share their initial thoughts in a brief pair-and-share for two minutes before the teacher transitions to the day\'s brainstorming activity on how different wood types serve specific purposes in local trades and industries.', '• Brainstorm on the uses of specific wood, in groups.', '• Brainstorm on the uses of wood in various trades and share findings.', '', 'The teacher summarizes by emphasizing that different wood types possess unique properties such as hardness, grain, and durability that make them suitable for specific trades like carpentry, carving, construction, and tool-making in our community. The teacher then asks: \'Can you name two wood types used in our community and explain why each is chosen for its particular trade or industry? What might happen if a carpenter used soft wood instead of hardwood for making a bed frame?\' Learners respond briefly, demonstrating their understanding of matching wood properties to specific uses.', '* Were all learners able to identify at least three specific uses of different wood types in the community and relate them to particular trades?\n* Did the group brainstorming activity allow every learner to contribute their knowledge of local wood uses, or did some learners remain passive?\n* Which learners struggled to connect wood properties (hardness, grain, durability) to the reasons why specific trades select certain wood types, and how can I provide additional support in the next lesson?', 'Learners should interview a carpenter, furniture maker, or other woodworker in their community to find out which wood types they use most often, why they prefer those woods, and what challenges they face in obtaining quality timber. Learners should write a short paragraph summarizing their findings to share in the next lesson.', '2026-04-11 11:50:11', '2026-04-11 11:50:11'),
(44, 163, 'Grade 9', 'Pre-Technical Studies', '3.0 Materials for Production', '3.1 Wood', '', '', NULL, '', NULL, 'a) Explain the socio-economic importance of wood in daily life.', 'b) Evaluate the importance of wood conservation.', '', 'Why is wood important in our community and how can we ensure it remains available for future generations?', 'Critical thinking and problem solving: learners evaluate different wood types based on properties such as hardness, grain and durability, then select the most appropriate for a given task.\nCreativity and imagination: learners design and plan wood-based products that meet specified requirements.', 'Environmental education: learners discuss sustainable timber harvesting, afforestation and the impact of deforestation on the environment.\nESD: learners relate responsible use of wood to sustainable production and consumption practices.\nSafety education: learners apply safe tool and material handling practices when working with wood.', 'Responsibility: learners handle wood and woodworking tools safely, following all prescribed safety procedures.\nCare: learners demonstrate respect for natural resources by using wood economically and avoiding wastage.\nPatriotism: learners appreciate local Kenyan wood species and promote sustainable use of forest resources.', '* Learners textbook\n* Sample wood products from the community (furniture piece, tool handle, firewood, charcoal)\n* Chart paper or chalkboard for group presentations\n* Tree branches or wood samples from the school compound', 'The teacher displays or holds up a common wooden object from the classroom (a desk, chair, or wooden ruler) and asks learners to observe it carefully. The teacher then asks, \'How many different wooden items did you use before coming to school today?\' and gives learners one minute to quietly count and think. The teacher invites three learners to share their counts and examples, then states, \'Today we will explore why wood is so important to our community and how we can ensure future generations also benefit from it.\'', '• Discuss, in groups, the importance of wood in day-to-day life.', '', '', 'The teacher summarises by stating that wood plays a vital socio-economic role in our daily lives for shelter, fuel, furniture, and income, and that conservation through sustainable harvesting and tree planting ensures wood remains available for future generations. The teacher then asks: \'Can you name three ways wood contributes to the economy of our community?\' and \'Why must we practice wood conservation even when trees seem plenty today?\' The teacher invites two or three learners to respond before closing the lesson.', '* Were all learners able to explain at least two socio-economic uses of wood from their own community context?\n* Did the group discussions reveal any misconceptions about wood conservation or sustainability that need to be addressed in the next lesson?\n* Which learners struggled to evaluate the importance of wood conservation and how can I provide additional support or examples for them?', 'Learners should interview one adult at home (parent, guardian, or elder) to find out which wood species they prefer for building, cooking, or making tools, and why. They should write down the name of the wood species and at least two reasons for its preference, then bring this information to the next lesson.', '2026-04-11 11:50:24', '2026-04-11 11:50:24'),
(45, 164, 'Grade 9', 'Pre-Technical Studies', '3.0 Materials for Production', '3.1 Wood', '', '', NULL, '', NULL, 'a) Assess personal understanding of wood properties and preparation through an exercise.', '', '', 'How well do I understand the properties, types, seasoning methods, defects, and preparation processes of wood for production?', 'Critical thinking and problem solving: learners evaluate different wood types based on properties such as hardness, grain and durability, then select the most appropriate for a given task.\nCreativity and imagination: learners design and plan wood-based products that meet specified requirements.', 'Environmental education: learners discuss sustainable timber harvesting, afforestation and the impact of deforestation on the environment.\nESD: learners relate responsible use of wood to sustainable production and consumption practices.\nSafety education: learners apply safe tool and material handling practices when working with wood.', 'Responsibility: learners handle wood and woodworking tools safely, following all prescribed safety procedures.\nCare: learners demonstrate respect for natural resources by using wood economically and avoiding wastage.\nPatriotism: learners appreciate local Kenyan wood species and promote sustainable use of forest resources.', '* Learners textbook\n* Previous notes and exercises on wood properties\n* Sample wood pieces showing different properties and defects\n* Assessment exercise sheets or questions written on chalkboard', 'The teacher displays samples or pictures of different wood types (or draws them on the chalkboard if samples are unavailable) and asks learners to recall one property and one defect they have studied in previous lessons. The teacher then explains that today learners will assess how well they understand everything they have learned about wood properties, types, seasoning methods, defects, and preparation processes through an individual assessment exercise. This exercise will help each learner identify their strengths and areas needing improvement.', '• Work individually on assessment exercise on wood.', '', '', 'The teacher collects the assessment exercises and reminds learners that understanding wood properties, seasoning methods, defects, and preparation processes is essential for selecting the right wood for production and ensuring quality products. The teacher then asks: What is one wood property you now feel confident explaining to someone else? Which topic about wood (properties, types, seasoning, defects, or preparation) do you think you need to review more?', '* Were all learners able to complete the assessment exercise within the allocated time, and did the questions adequately cover properties, types, seasoning methods, defects, and preparation processes?\n* Which specific section of the assessment (properties, seasoning, defects, or preparation) did most learners struggle with, and what reteaching strategies should I plan?\n* Did the assessment exercise effectively reveal individual learner understanding, and how will I provide feedback and support to those who performed poorly?', 'Learners should identify three different wood pieces or wooden objects at home or in their community, then write down the probable wood type and two observable properties (such as colour, hardness, grain pattern, or weight) for each in their exercise books. They should also note whether the wood shows any visible defects like cracks, knots, or warping.', '2026-04-11 11:50:37', '2026-04-11 11:50:37'),
(46, 165, 'Grade 9', 'Pre-Technical Studies', '3.0 Materials for Production', '3.2 Handling Waste Materials', '', '', NULL, '', NULL, 'a) Identify different types of waste materials in the school environment.', 'b) List the identified waste materials in categories.', '', 'What different types of waste materials can we find in our school environment and how can we group them?', 'Citizenship: learners take collective responsibility for waste management and promote environmentally responsible production practices in school and community.\nCritical thinking and problem solving: learners identify categories of waste generated in production workshops and propose effective waste-reduction strategies.', 'Environmental education: learners study the impact of waste on the environment and propose sustainable waste management solutions (reduce, reuse, recycle).\nESD: learners relate responsible waste handling to sustainable production, consumption and the Green Economy.\nHealth education: learners discuss health hazards of improper waste disposal in production environments.', 'Responsibility: learners dispose of production waste correctly and follow workshop waste-management procedures.\nCare: learners demonstrate concern for the environment by minimising waste and recycling usable materials.\nPatriotism: learners contribute to a clean, safe community environment by practising responsible waste disposal.', '* Learners textbook\n* Exercise books and pencils\n* Waste materials found in the school compound (paper, plastics, organic matter, metals, glass)\n* Containers or baskets for collecting samples', 'The teacher displays a small collection of real waste items found around the school compound (e.g., a plastic bottle, a piece of paper, a banana peel, a broken pen, and a metal can) on the table or desk at the front of the class. The teacher asks learners, \'Look at these items I collected this morning—what do they have in common, and where do you think they came from?\' After a few responses, the teacher explains that today learners will explore the different types of waste materials found in their school environment and learn how to group them into categories.', '• Walk around the school compound, in groups, to identify waste materials.', '• Write the waste materials you see in exercise book and read the list in class.', '', 'The teacher asks each group to quickly name one type of waste material they identified and the category it belongs to, reinforcing that waste can be grouped into categories such as organic, plastic, metal, paper, and glass. The teacher then asks two closing questions: \'Why is it important to identify and categorize waste materials in our school?\' and \'Can you name one category of waste and give two examples you found today?\' The teacher reminds learners that responsible waste handling begins with knowing what types of waste we produce.', '* Were all learners able to identify at least three different types of waste materials during the school compound walk?\n* Did learners demonstrate understanding of how to categorize waste materials, or did some groups struggle to differentiate between categories like organic and non-organic waste?\n* Which learners need additional support in listing and organizing the waste materials they observed, and how can I provide clearer examples in the next lesson?', 'Learners should observe and list at least five different waste materials they find at home or in their immediate community, then write down which category each item belongs to (organic, plastic, metal, paper, or glass) in their exercise books. They should be ready to share their findings in the next lesson.', '2026-04-11 11:50:49', '2026-04-11 11:50:49'),
(47, 166, 'Grade 9', 'Pre-Technical Studies', '3.0 Materials for Production', '3.2 Handling Waste Materials', '', '', NULL, '', NULL, 'a) Identify safe ways of handling different waste materials.', 'b) Describe the methods of reducing, reusing, and recycling waste.', '', 'How can we handle different types of waste materials safely and apply the 3Rs (reduce, reuse, recycle) to manage waste in our homes and school?', 'Citizenship: learners take collective responsibility for waste management and promote environmentally responsible production practices in school and community.\nCritical thinking and problem solving: learners identify categories of waste generated in production workshops and propose effective waste-reduction strategies.', 'Environmental education: learners study the impact of waste on the environment and propose sustainable waste management solutions (reduce, reuse, recycle).\nESD: learners relate responsible waste handling to sustainable production, consumption and the Green Economy.\nHealth education: learners discuss health hazards of improper waste disposal in production environments.', 'Responsibility: learners dispose of production waste correctly and follow workshop waste-management procedures.\nCare: learners demonstrate concern for the environment by minimising waste and recycling usable materials.\nPatriotism: learners contribute to a clean, safe community environment by practising responsible waste disposal.', '* Learners textbook\n* Samples of different waste materials from school compound (plastic bottles, paper scraps, organic waste, metal cans)\n* Chart paper or chalkboard for recording findings\n* Gloves or pieces of cloth for safe handling demonstration', 'The teacher displays a collection of different waste materials commonly found in the school workshop and home (e.g., metal scraps, wood offcuts, plastic bottles, broken glass wrapped in paper, food waste). The teacher then asks learners to observe the materials and discuss in pairs: \'Which of these waste materials could be dangerous to handle, and why?\' After one minute, the teacher invites two pairs to share their observations, linking their answers to today\'s focus on safe handling and the 3Rs.', '• Search for information on safe handling of waste materials and discuss findings in class.', '', '', 'The teacher summarises by stating: \'Today we learned that different waste materials require different safe handling methods, and that we can reduce, reuse, and recycle waste to protect our environment and health.\' The teacher then asks: \'Can someone explain one safe way to handle sharp metal or glass waste?\' and \'Give one example of how you can reuse waste material from a production workshop instead of throwing it away.\' The teacher listens to responses and praises correct answers.', '* Were all learners able to identify at least two safe ways of handling different waste materials specific to production workshops?\n* Did the information search activity provide sufficient depth for learners to describe the 3Rs methods, or do some learners still confuse reduce, reuse, and recycle?\n* Which learners struggled to link safe waste handling to real production environments, and what additional examples or demonstrations can I provide in the next lesson?', 'Learners should observe waste disposal practices at home and identify one type of waste material that their family currently throws away but could be reused or recycled. They should write a short paragraph in their exercise books describing the waste material, why it is currently discarded, and a practical idea for reusing or recycling it.', '2026-04-11 11:51:03', '2026-04-11 11:51:03'),
(48, 167, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.1 Holding Tools', '', '', NULL, '', NULL, 'a) Identify common holding tools used in the environment.', 'b) Illustrate various holding tools through drawing.', 'c) Label the parts of identified holding tools.', 'What tools are commonly used in our homes and workshops to hold, grip, or clamp materials during work, and how are they designed?', 'Critical thinking and problem solving: learners select the most appropriate holding tool for a given material and task, justifying their choices based on tool function and material properties.\nSelf-efficacy: learners demonstrate correct and confident use of holding tools during practical activities.', 'Safety education: learners identify hazards associated with incorrect use of holding tools and apply safe operating procedures.\nOccupational safety and health (OSH): learners relate proper tool use to workplace injury prevention.\nCareer guidance: learners connect correct use of hand tools to careers in carpentry, welding and metal fabrication.', 'Responsibility: learners use, clean and store holding tools correctly to prolong tool life and prevent accidents.\nCare: learners show concern for peers by working safely and observing workshop rules when using holding tools.\nIntegrity: learners honestly report any damage to tools rather than concealing it.', '* Learners textbook\n* Actual holding tools from school workshop or borrowed from community (pliers, vice, clamps, tongs, tweezers)\n* Chart paper and markers for group presentations\n* Rulers for accurate drawing', 'The teacher begins by holding up a common object such as a piece of wood or metal and asks learners, \'If I wanted to saw this piece of wood or file this metal safely, how would I keep it still without using my hands?\' The teacher invites two or three learners to share their experiences of watching carpenters, welders, or family members doing repairs at home, specifically asking what tools were used to hold materials in place. The teacher then introduces today\'s lesson by stating that they will identify, draw, and label the parts of holding tools commonly found in homes and workshops.', '• Identify, in groups, the pictures of holding tools in the environment.', '• Draw and name the identified tools.', '', 'The teacher summarizes by reminding learners that holding tools such as vices, clamps, pliers, and tongs are essential for gripping and securing materials safely during work, and that each tool has specific parts that enable it to function properly. The teacher then asks: \'Can someone name three holding tools we identified today and explain what each one is used to hold?\' followed by \'Why is it important to know the correct names of the parts of a holding tool?\' The teacher invites responses from different groups and commends learners for their participation.', '* Were all learners able to correctly identify at least three common holding tools from their environment and distinguish them from cutting or measuring tools?\n* Did the group drawing activity allow every learner to participate, or did some learners dominate while others remained passive?\n* Which learners struggled with labeling the parts of holding tools, and what additional support or visual aids can I provide in the next lesson to help them master this skill?', 'Learners should visit a workshop, construction site, or observe a craftsperson at home (carpenter, welder, mechanic, or tailor) and sketch two holding tools they see being used, labeling at least three parts of each tool. They should write one sentence describing what material each tool was holding during the work.', '2026-04-11 11:51:17', '2026-04-11 11:51:17'),
(49, 168, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.1 Holding Tools', '', '', NULL, '', NULL, 'a) Choose the most appropriate holding tool for a specific task.', 'b) Justify the selection of a holding tool based on the nature of the work.', '', 'How do you decide which holding tool is best suited for a particular task?', 'Critical thinking and problem solving: learners select the most appropriate holding tool for a given material and task, justifying their choices based on tool function and material properties.\nSelf-efficacy: learners demonstrate correct and confident use of holding tools during practical activities.', 'Safety education: learners identify hazards associated with incorrect use of holding tools and apply safe operating procedures.\nOccupational safety and health (OSH): learners relate proper tool use to workplace injury prevention.\nCareer guidance: learners connect correct use of hand tools to careers in carpentry, welding and metal fabrication.', 'Responsibility: learners use, clean and store holding tools correctly to prolong tool life and prevent accidents.\nCare: learners show concern for peers by working safely and observing workshop rules when using holding tools.\nIntegrity: learners honestly report any damage to tools rather than concealing it.', '* Learners textbook\n* Assorted holding tools (pliers, vice, clamps, tweezers, tongs borrowed from workshop or home)\n* Work samples or materials to be held (wood pieces, metal strips, wires, fabric)\n* Charts or pictures showing different holding tools and their uses', 'The teacher displays a collection of holding tools (vise, clamps, pliers, tongs) along with different materials (a piece of wood, metal rod, wire, and a plastic pipe) on the demonstration table. The teacher then asks learners: \'If I want to saw this piece of wood straight, which of these holding tools should I use and why?\' and invites two learners to come forward and demonstrate their choice, creating a brief discussion about why certain tools work better than others for specific tasks.', '• Choose, in groups, holding tools for different tasks.', '• Select the most appropriate tools for given tasks and give reasons for the choice.', '', 'Today we have learned that choosing the right holding tool depends on the material being worked on, the task to be performed, and the need for safety and precision. The teacher asks: \'What factors should you consider when choosing between a vise and a clamp for holding wood during sawing?\' and \'Why would using the wrong holding tool be both unsafe and ineffective for your work?\'', '* Were all learners able to justify their selection of holding tools based on the nature of the work and material properties?\n* Did the group activities allow every learner to participate in choosing and discussing appropriate holding tools, or did some learners remain passive?\n* Which learners struggled to explain the reasoning behind their tool choices and how can I provide additional support in the next lesson?', 'Learners should observe a carpenter, metalworker, or craftsperson in their community and record in their exercise books at least three different holding tools they use and explain why each tool is appropriate for the specific tasks being performed.', '2026-04-11 11:51:29', '2026-04-11 11:51:29'),
(50, 169, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.1 Holding Tools', '', '', NULL, '', NULL, 'a) Describe tasks being performed using holding tools from visual aids.', 'b) Outline safe procedures for using pliers, clamps, and vices.', '', 'How can we safely use different holding tools to perform specific tasks in our workshops and daily activities?', 'Critical thinking and problem solving: learners select the most appropriate holding tool for a given material and task, justifying their choices based on tool function and material properties.\nSelf-efficacy: learners demonstrate correct and confident use of holding tools during practical activities.', 'Safety education: learners identify hazards associated with incorrect use of holding tools and apply safe operating procedures.\nOccupational safety and health (OSH): learners relate proper tool use to workplace injury prevention.\nCareer guidance: learners connect correct use of hand tools to careers in carpentry, welding and metal fabrication.', 'Responsibility: learners use, clean and store holding tools correctly to prolong tool life and prevent accidents.\nCare: learners show concern for peers by working safely and observing workshop rules when using holding tools.\nIntegrity: learners honestly report any damage to tools rather than concealing it.', '* Learners textbook\n* Pictures or charts showing people using pliers, clamps, and vices\n* Actual samples of holding tools (pliers, clamps, vices) if available from school workshop or borrowed from community\n* Teacher\'s smartphone/tablet for showing videos on safe use of holding tools', 'The teacher displays three common holding tools (a pair of pliers, a G-clamp, and if available, a small vice or picture of one) and asks learners to observe them carefully. The teacher then poses the question: \'If you wanted to hold a piece of metal firmly while filing it smooth, which of these tools would you choose and why?\' Learners share their initial ideas briefly, creating interest in understanding the specific purposes and safe use of different holding tools.', '• Study pictures, in groups, of people using different holding tools and describe the tasks.', '• Search for information or watch a video on how to safely use holding tools.', '', 'Today we learned that different holding tools—pliers, clamps, and vices—are designed for specific holding tasks, and that using them safely prevents injuries and damage to materials. Can someone describe one safe procedure when using a vice to hold wood? Can another learner explain why it is dangerous to use pliers with loose or damaged handles?', '* Were all learners able to outline at least two safe procedures for using pliers, clamps, or vices during group discussions?\n* Did the pictures or video provide clear enough examples of holding tool tasks, or did learners struggle to describe what they observed?\n* Which learners need additional hands-on practice to confidently describe the differences between when to use pliers versus clamps versus vices?', 'Learners should observe at least two holding tools being used at home or in their community (by a parent, neighbour, or artisan) and write a short paragraph describing the task being performed and one safety measure they noticed or would recommend.', '2026-04-11 11:51:40', '2026-04-11 11:51:40'),
(51, 170, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.1 Holding Tools', '', '', NULL, '', NULL, 'a) Demonstrate the correct use of a specific holding tool to perform a practical task.', 'b) Apply safety measures while using holding tools in the environment.', '', 'How can we safely select and use the right holding tool to complete different tasks in our workshop and environment?', 'Critical thinking and problem solving: learners select the most appropriate holding tool for a given material and task, justifying their choices based on tool function and material properties.\nSelf-efficacy: learners demonstrate correct and confident use of holding tools during practical activities.', 'Safety education: learners identify hazards associated with incorrect use of holding tools and apply safe operating procedures.\nOccupational safety and health (OSH): learners relate proper tool use to workplace injury prevention.\nCareer guidance: learners connect correct use of hand tools to careers in carpentry, welding and metal fabrication.', 'Responsibility: learners use, clean and store holding tools correctly to prolong tool life and prevent accidents.\nCare: learners show concern for peers by working safely and observing workshop rules when using holding tools.\nIntegrity: learners honestly report any damage to tools rather than concealing it.', '* Learners textbook\n* Assorted holding tools (pliers, clamps, vices, tongs, tweezers)\n* Work pieces or materials to hold (wood pieces, metal rods, wires, fabric)\n* Safety gloves and goggles\n* Workshop or practical area', 'The teacher displays three common holding tools (a G-clamp, a vice grip, and a pair of pliers) alongside three different tasks written on the chalkboard: holding a metal pipe for cutting, gripping a wooden plank for sawing, and holding wire for bending. The teacher asks learners to quickly discuss in pairs which tool would be safest and most effective for each task, then invites two pairs to share their reasoning aloud. This activates prior knowledge from the previous lesson on types of holding tools and sets the stage for today\'s practical demonstration and application.', '• Identify suitable tasks in the environment that require holding tools.', '• Perform the identified task using the most appropriate holding tool.', '', 'The teacher gathers all learners and summarizes that selecting the correct holding tool depends on the material, the task, and applying safety measures such as securing the workpiece firmly, checking the tool for defects, and keeping hands clear of cutting or working areas. The teacher then asks: \'What two safety checks must you perform before using any holding tool?\' and \'Why is it dangerous to use a damaged or loose holding tool during a task?\' Learners respond briefly to confirm their understanding of today\'s practical safety application.', '* Were all learners able to demonstrate the correct use of at least one holding tool during the practical task, and did they apply the key safety measures discussed?\n* Which learners struggled with selecting the appropriate holding tool for their task, and what additional guidance or peer support can I provide in the next lesson?\n* Did the practical tasks I identified in the environment engage all learners effectively, or should I diversify the range of tasks to match different skill levels and interests?', 'Learners should identify one task at home or in their community that requires a holding tool (such as repairing a gate, fixing a bicycle, or holding wood for cutting), observe how an adult safely uses the tool, and write three safety measures they noticed in their exercise books to share in the next lesson.', '2026-04-11 11:59:39', '2026-04-11 11:59:39'),
(52, 171, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.1 Holding Tools', '', '', NULL, '', NULL, 'a) Describe methods for cleaning and maintaining holding tools.', 'b) Demonstrate proper storage of holding tools to prevent damage.', '', 'How can we ensure that holding tools remain safe, functional, and ready for use over a long period of time?', 'Critical thinking and problem solving: learners select the most appropriate holding tool for a given material and task, justifying their choices based on tool function and material properties.\nSelf-efficacy: learners demonstrate correct and confident use of holding tools during practical activities.', 'Safety education: learners identify hazards associated with incorrect use of holding tools and apply safe operating procedures.\nOccupational safety and health (OSH): learners relate proper tool use to workplace injury prevention.\nCareer guidance: learners connect correct use of hand tools to careers in carpentry, welding and metal fabrication.', 'Responsibility: learners use, clean and store holding tools correctly to prolong tool life and prevent accidents.\nCare: learners show concern for peers by working safely and observing workshop rules when using holding tools.\nIntegrity: learners honestly report any damage to tools rather than concealing it.', '* Learners textbook\n* Actual holding tools (pliers, clamps, vices, tongs) from school workshop or borrowed from community\n* Cleaning materials (cloth rags, wire brush, old toothbrush, water, oil)\n* Tool storage examples (toolbox, wall racks, cloth wraps)', 'The teacher displays a rusty pair of pliers and a clean, well-oiled vise side by side and asks learners to observe the difference in their condition. Learners are then asked: \'Why do you think one tool looks ready to use while the other is damaged? What might have caused this difference?\' The teacher briefly discusses that today\'s lesson will focus on how proper cleaning, maintenance, and storage practices keep holding tools safe and functional for a long time.', '• Study and discuss pictures or videos on how to care for and maintain tools.', '• Share findings with the class on maintenance practices.', '', 'Today we have learned that regular cleaning, oiling, and proper storage are essential to keep holding tools in good working condition and prevent rust, damage, and accidents. The teacher asks: \'What are two methods you should use to maintain holding tools after use?\' and \'Why is it important to store holding tools in a dry place away from moisture?\' Learners respond orally or write brief answers in their exercise books.', '* Were all learners able to describe at least two methods for cleaning and maintaining holding tools?\n* Did learners demonstrate understanding of proper storage practices during the practical demonstration, and which learners struggled with this concept?\n* Was the discussion on maintenance practices engaging enough, and how can I incorporate more hands-on cleaning demonstrations in future lessons?', 'Learners should observe and list three hand tools or holding tools at home or in their community, noting their current condition (clean, rusty, well-stored, or poorly stored). They should write a short paragraph explaining what maintenance steps could improve the condition of any neglected tools they observed.', '2026-04-11 11:59:51', '2026-04-11 11:59:51'),
(53, 172, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.1 Holding Tools', '', '', NULL, '', NULL, 'a) Explain the significance of holding tools in community trades.', 'b) Evaluate personal proficiency in using holding tools through an exercise.', '', 'Why are holding tools essential for quality work and safety in different trades practiced in our community?', 'Critical thinking and problem solving: learners select the most appropriate holding tool for a given material and task, justifying their choices based on tool function and material properties.\nSelf-efficacy: learners demonstrate correct and confident use of holding tools during practical activities.', 'Safety education: learners identify hazards associated with incorrect use of holding tools and apply safe operating procedures.\nOccupational safety and health (OSH): learners relate proper tool use to workplace injury prevention.\nCareer guidance: learners connect correct use of hand tools to careers in carpentry, welding and metal fabrication.', 'Responsibility: learners use, clean and store holding tools correctly to prolong tool life and prevent accidents.\nCare: learners show concern for peers by working safely and observing workshop rules when using holding tools.\nIntegrity: learners honestly report any damage to tools rather than concealing it.', '* Learners textbook\n* Sample holding tools from the community (pliers, clamps, vices, tongs, tweezers, or locally made holding devices)\n* Examples of work pieces or materials that require holding tools (wood offcuts, metal pieces, fabric)\n* Chart paper and markers for group presentation', 'The teacher displays a common holding tool such as a G-clamp or a pair of pliers and asks learners to observe a peer attempting to saw or file a piece of wood or metal without holding it in place, then repeating the task with the workpiece properly secured. The teacher then poses the question: \'What difference did you notice in the quality and safety of the work when the material was held firmly compared to when it was not?\' and invites two or three learners to share their observations before linking this to today\'s focus on evaluating the significance of holding tools in community trades and assessing personal proficiency.', '• Discuss, in groups, the importance of holding tools in the community.', '• Share experiences and work individually on assessment exercise.', '', 'The teacher summarizes that holding tools are essential in community trades such as carpentry, welding and metal fabrication because they ensure quality work, improve safety and prevent material damage or injury. The teacher then asks: \'Can you explain two reasons why a carpenter in our community must use a vice or clamp when cutting timber?\' and \'How would you rate your own ability to select and use the correct holding tool for a given task after today\'s assessment exercise?\' before collecting learners\' assessment exercises.', '* Were all learners able to explain at least two specific ways holding tools contribute to quality and safety in community trades during group discussions?\n* Did the individual assessment exercise effectively allow learners to evaluate their own proficiency in selecting and using holding tools, or did some learners struggle with the self-assessment criteria?\n* Which learners showed difficulty justifying their choice of holding tools for specific materials and tasks, and what additional support or practical demonstration do they need in the next lesson?', 'Learners should visit a local carpenter, welder or metal fabricator in the community and interview them about two holding tools they use daily, asking specifically how these tools help them produce quality work and stay safe. Learners write a brief report (half page) summarizing the tradesperson\'s responses and bring it to the next lesson for sharing.', '2026-04-11 12:00:04', '2026-04-11 12:00:04');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(54, 173, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.2 Driving Tools', '', '', NULL, '', NULL, 'a) Identify pictures of driving tools used in the community.', 'b) State where various driving tools are commonly found.', '', 'What tools do people in our community use to drive or force objects together, and where can we find them being used?', 'Critical thinking and problem solving: learners evaluate different driving tools (hammers, mallets, screwdrivers, wrenches) to determine the most suitable tool for a given fastening task.\nSelf-efficacy: learners confidently demonstrate correct grip, posture and technique when using driving tools on practical tasks.', 'Safety education: learners identify hazards of using damaged or incorrectly selected driving tools and describe precautions.\nOSH: learners apply occupational health and safety standards to driving-tool use in the workshop.\nCareer guidance: learners relate driving-tool skills to careers in construction, motor vehicle mechanics and manufacturing.', 'Responsibility: learners maintain driving tools in good working condition and store them correctly after use.\nCare: learners observe safety rules that protect themselves and their peers from tool-related injuries.\nIntegrity: learners report any defective or damaged tools immediately to prevent accidents.', '* Learners textbook\n* Pictures or actual samples of driving tools (hammers, mallets, nails, screwdrivers)\n* Chart paper or chalkboard for group presentations\n* Local carpentry workshop or construction site (for field observation or inviting a craftsperson)', 'The teacher displays or holds up a few common driving tools (a hammer, screwdriver, and wrench borrowed from a local carpenter or brought from home) and asks learners, \'Who has seen these tools being used at home, in the market, or by a fundi in our community?\' After a few learners share brief examples, the teacher poses the key inquiry question: \'What tools do people in our community use to drive or force objects together, and where can we find them being used?\' This sets the stage for today\'s exploration of driving tools and their uses in the locality.', '• Identify, in groups, pictures of driving tools used in the community.', '• Mention where these tools can be found within the locality.', '', 'The teacher summarises by stating, \'Today we identified common driving tools such as hammers, mallets, screwdrivers, and wrenches from pictures, and we discussed where these tools are found in our community—such as carpentry workshops, motor vehicle garages, construction sites, and even at home.\' The teacher then asks two closing questions: \'Can someone name three driving tools we identified today and tell us one place each is commonly found?\' and \'Why is it important to know where these tools are used in our community?\'', '* Were all learners able to correctly identify the pictures of driving tools and state at least one location where each tool is commonly found?\n* Did the group activity allow every learner to participate, or did some learners dominate while others remained passive?\n* Which learners struggled to link driving tools to real community contexts, and how can I provide additional examples or support in the next lesson?', 'Learners should walk around their home, neighbourhood, or local market and list at least five driving tools they observe being used, noting the specific task each tool is performing (for example, \'Hammer – used by a carpenter to nail timber\'). They should bring this list to the next lesson to share with their peers.', '2026-04-11 12:00:16', '2026-04-11 12:00:16'),
(55, 174, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.2 Driving Tools', '', '', NULL, '', NULL, 'a) Match driving tools to specific tasks on flashcards.', 'b) Defend the choice of a specific driving tool for a given task.', '', 'How do you decide which driving tool is best for a specific task?', 'Critical thinking and problem solving: learners evaluate different driving tools (hammers, mallets, screwdrivers, wrenches) to determine the most suitable tool for a given fastening task.\nSelf-efficacy: learners confidently demonstrate correct grip, posture and technique when using driving tools on practical tasks.', 'Safety education: learners identify hazards of using damaged or incorrectly selected driving tools and describe precautions.\nOSH: learners apply occupational health and safety standards to driving-tool use in the workshop.\nCareer guidance: learners relate driving-tool skills to careers in construction, motor vehicle mechanics and manufacturing.', 'Responsibility: learners maintain driving tools in good working condition and store them correctly after use.\nCare: learners observe safety rules that protect themselves and their peers from tool-related injuries.\nIntegrity: learners report any defective or damaged tools immediately to prevent accidents.', '* Learners textbook\n* Flashcards showing different tasks (hammering nails, tightening screws, prying boards, etc.)\n* Actual driving tools or pictures (hammer, screwdrivers - flat and star, mallet, nail punch)\n* Chart showing driving tools and their uses', 'The teacher displays a real nail, a screw, and a bolt on the desk and asks learners: \'If I gave you each of these fasteners and asked you to join two pieces of wood, which tool would you choose and why?\' After brief pair discussion (1 minute), the teacher invites two learners to share their answers, then explains that today\'s lesson will focus on matching the correct driving tool to specific fastening tasks and defending those choices using clear reasons.', '• Select the most appropriate driving tools for tasks shown on flashcards.', '• Give reasons for the choice of tool selected in each case.', '', 'Today we learned that selecting the right driving tool depends on the type of fastener, the material being worked on, and the specific task requirements. The teacher asks: \'Why would using a mallet instead of a claw hammer be better when assembling wooden furniture joints?\' and \'What two reasons would you give to justify choosing a crosshead screwdriver over a flathead screwdriver for a particular screw?\' The teacher invites three learners to respond and affirms correct reasoning.', '* Were all learners able to defend their choice of driving tool with at least two valid reasons during the flashcard activity?\n* Which specific tool-to-task match caused the most confusion, and what additional explanation or demonstration is needed in the next lesson?\n* Which learners struggled to articulate reasons for their tool choices and would benefit from paired peer support or visual reasoning aids?', 'Learners should identify three fastening tasks at home (such as repairing a door hinge, tightening a loose chair leg, or fixing a farm tool handle) and write down which driving tool would be most suitable for each task and why, bringing their notes to the next lesson for discussion.', '2026-04-11 12:00:29', '2026-04-11 12:00:29'),
(56, 175, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.2 Driving Tools', '', '', NULL, '', NULL, 'a) Identify tasks observed in the community that require driving tools.', 'b) Demonstrate the safe use of a driving tool to perform a specific task.', '', 'How can we safely use driving tools to accomplish tasks we see in our homes and community?', 'Critical thinking and problem solving: learners evaluate different driving tools (hammers, mallets, screwdrivers, wrenches) to determine the most suitable tool for a given fastening task.\nSelf-efficacy: learners confidently demonstrate correct grip, posture and technique when using driving tools on practical tasks.', 'Safety education: learners identify hazards of using damaged or incorrectly selected driving tools and describe precautions.\nOSH: learners apply occupational health and safety standards to driving-tool use in the workshop.\nCareer guidance: learners relate driving-tool skills to careers in construction, motor vehicle mechanics and manufacturing.', 'Responsibility: learners maintain driving tools in good working condition and store them correctly after use.\nCare: learners observe safety rules that protect themselves and their peers from tool-related injuries.\nIntegrity: learners report any defective or damaged tools immediately to prevent accidents.', '* Learners textbook\n* Assorted driving tools (hammers, mallets, screwdrivers from school workshop or borrowed from community)\n* Nails, screws, and wood pieces\n* Pictures or drawings of driving tools in use from magazines or drawn on charts', 'The teacher displays a collection of real driving tools (hammer, screwdriver, wrench, and mallet if available) and poses the question: \'Yesterday when you walked home from school, what tasks did you see adults doing that required hitting, turning, or fastening something?\' After learners share observations such as repairing a bicycle, fixing a door, or building a fence, the teacher asks them to point to which tool from the collection would be used for each task. This activates prior community knowledge and prepares learners to identify and safely use the correct driving tool for real tasks today.', '• Discuss pictures of driving tools in use and mention tasks observed in the community.', '• Identify and perform a task in the environment using the appropriate driving tool.', '', 'Today we identified community tasks that need driving tools and practised using them safely with the correct grip and posture. The teacher asks: \'If you saw someone using a hammer with a loose head, what hazard does that present and what should you do?\' Then asks: \'Show me with your hands the correct grip you would use to drive a screw with a screwdriver.\' These two questions check whether learners can identify tool hazards and demonstrate safe technique learned in this lesson.', '* Were all learners able to demonstrate the safe grip and posture for at least one driving tool during the practical task?\n* Did the discussion of community tasks help learners connect driving-tool skills to real careers like construction and mechanics, or do I need to make those links more explicit next time?\n* Which learners struggled with selecting the appropriate tool for a given task, and what additional guided practice do they need in the next lesson?', 'At home, learners should observe one adult family member or neighbour using any driving tool (hammer, screwdriver, or wrench) to complete a task, then write a short paragraph describing the task, the tool used, and whether the person followed safety practices such as checking the tool condition and using proper grip. They should bring this observation to the next lesson to share.', '2026-04-11 12:00:41', '2026-04-11 12:00:41'),
(57, 176, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.2 Driving Tools', '', '', NULL, '', NULL, 'a) Describe the procedures for maintaining driving tools (e.g., oiling, tightening).', 'b) Demonstrate safe storage practices for driving tools.', '', 'How can we ensure that driving tools remain safe, functional, and ready for use over a long period of time?', 'Critical thinking and problem solving: learners evaluate different driving tools (hammers, mallets, screwdrivers, wrenches) to determine the most suitable tool for a given fastening task.\nSelf-efficacy: learners confidently demonstrate correct grip, posture and technique when using driving tools on practical tasks.', 'Safety education: learners identify hazards of using damaged or incorrectly selected driving tools and describe precautions.\nOSH: learners apply occupational health and safety standards to driving-tool use in the workshop.\nCareer guidance: learners relate driving-tool skills to careers in construction, motor vehicle mechanics and manufacturing.', 'Responsibility: learners maintain driving tools in good working condition and store them correctly after use.\nCare: learners observe safety rules that protect themselves and their peers from tool-related injuries.\nIntegrity: learners report any defective or damaged tools immediately to prevent accidents.', '* Learners textbook\n* Actual driving tools (screwdrivers, hammers, mallets) borrowed from school workshop or community\n* Pictures or charts showing tool maintenance practices\n* Clean cloth, oil (cooking oil or machine oil), and water for demonstration\n* Storage containers or toolbox (or locally made alternatives)', 'The teacher displays a rusty screwdriver, a hammer with a loose head, and a well-maintained mallet on the demonstration table and asks learners to observe them carefully. Learners are then asked: \'Which of these three driving tools would you trust to use safely in the workshop today, and why?\' The teacher invites two or three learners to share their observations, highlighting that today\'s lesson will focus on how proper maintenance and storage keep driving tools safe and functional for a long time.', '• Study and discuss pictures on how to care for and maintain driving tools.', '• Answer questions regarding maintenance and storage.', '', 'The teacher summarises by reminding learners that regular maintenance such as oiling metal parts, tightening loose handles, and storing tools in dry, organized spaces prevents rust, accidents, and tool damage. The teacher then asks: \'What are two maintenance procedures you would perform on a hammer to keep it in good working condition?\' and \'Why is it important to store driving tools in a dry place after use?\' Learners respond briefly, and the teacher emphasizes the values of responsibility and care in tool maintenance.', '* Were all learners able to describe at least two procedures for maintaining driving tools such as oiling and tightening?\n* Did the pictures and discussion activity effectively help learners understand safe storage practices, or do I need to provide real tool examples next time?\n* Which learners struggled to connect maintenance procedures with safety, and how can I provide additional support or practical demonstrations for them?', 'Learners should observe any hand tools (hammer, hoe, panga, or screwdriver) at home or in their compound, identify one maintenance need (such as rust, loose handle, or dirt), and write a short paragraph describing what maintenance procedure they would apply and why. They should be ready to share their findings in the next lesson.', '2026-04-11 12:00:54', '2026-04-11 12:00:54'),
(58, 177, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.2 Driving Tools', '', '', NULL, '', NULL, 'a) Explain the necessity of driving tools in daily activities.', 'b) Assess understanding of driving tools through an individual exercise.', '', 'Why are driving tools necessary in our daily activities at home, school, and in our community?', 'Critical thinking and problem solving: learners evaluate different driving tools (hammers, mallets, screwdrivers, wrenches) to determine the most suitable tool for a given fastening task.\nSelf-efficacy: learners confidently demonstrate correct grip, posture and technique when using driving tools on practical tasks.', 'Safety education: learners identify hazards of using damaged or incorrectly selected driving tools and describe precautions.\nOSH: learners apply occupational health and safety standards to driving-tool use in the workshop.\nCareer guidance: learners relate driving-tool skills to careers in construction, motor vehicle mechanics and manufacturing.', 'Responsibility: learners maintain driving tools in good working condition and store them correctly after use.\nCare: learners observe safety rules that protect themselves and their peers from tool-related injuries.\nIntegrity: learners report any defective or damaged tools immediately to prevent accidents.', '* Learners textbook\n* Actual driving tools (hammer, mallet, screwdriver) borrowed from community or school workshop\n* Nails of different sizes\n* Pieces of wood or old timber\n* Stones used as improvised hammers in the community', 'The teacher displays a collection of actual driving tools brought to class: a hammer, screwdriver, mallet, and wrench (or shows pictures from a smartphone if actual tools are unavailable). The teacher asks learners to observe the tools and share one everyday activity they have seen someone perform at home or in their community using any of these tools, for example hammering nails to repair a fence, tightening bolts on a wheelbarrow, or fixing a door hinge. The teacher then poses the key inquiry question: Why are driving tools necessary in our daily activities at home, school, and in our community?', '• Discuss, in groups, the need for driving tools in the community.', '• Work individually on assessment exercise on driving tools.', '', 'The teacher summarizes that driving tools such as hammers, mallets, screwdrivers, and wrenches are essential because they enable us to fasten, tighten, loosen, and assemble materials safely and efficiently in many daily tasks at home, school, and in various careers like construction and motor vehicle mechanics. The teacher then asks: Can you name two driving tools and explain one daily activity where each is necessary? What safety precaution must you observe when using a damaged hammer or screwdriver?', '* Were all learners able to explain the necessity of driving tools in daily activities with relevant examples from their own community context?\n* Did the group discussions in step one engage all learners effectively, or did some groups dominate while others remained passive?\n* Which learners struggled with the individual assessment exercise on driving tools and what specific support do they need in the next lesson on handling these tools?', 'Learners should observe and list at least five different tasks performed at home or in their neighbourhood over the next two days that involve the use of any driving tool (hammer, screwdriver, mallet, or wrench), noting which tool was used and why it was necessary for that specific task. They should record their observations in their exercise books to share in the next lesson.', '2026-04-11 12:01:08', '2026-04-11 12:01:08'),
(59, 178, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Identify existing challenges within the local community.', 'b) Establish problems that can be solved using technical skills.', '', 'What problems in our community could we solve using the technical skills we are learning in school?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Notebooks and pens for recording observations\n* Camera or smartphone for documenting community challenges\n* Local community area (market, homes, school compound, farms)', 'The teacher begins by asking learners to think about a time in the past week when they or someone in their family struggled with a task or lacked something that would have made work easier at home, on the farm, or in the village. The teacher invites 3–4 learners to share their examples briefly, then explains that today they will explore the school locality and community to identify real problems that could be solved using the technical skills they have learned this term, such as working with tools, materials, and simple construction or production techniques.', '• Explore the locality to establish problems to be solved.', '• Present the identified problem findings in class.', '', 'The teacher summarises that learners have successfully explored their locality, identified real community challenges, and presented problems that can potentially be solved using technical skills learned in class. The teacher then asks: What is one specific problem you identified today that you think your group could solve using tools and materials available to you? How did listening to other groups\' findings help you think more deeply about problems in our community?', '* Were all learners able to identify at least one genuine community problem that connects to the technical skills covered in this strand?\n* Did the locality exploration activity engage all learners equally, or did some groups struggle to identify relevant problems during the walk?\n* Which group presentations showed the clearest link between identified problems and practical technical solutions, and how can I support other groups to strengthen this connection in the next lesson?', 'Learners should interview two adults at home or in their neighbourhood (a parent, guardian, farmer, or artisan) and ask them to describe one problem or challenge they face in their daily work that a simple tool, device, or product might solve. Learners should write down the problem and the person\'s occupation in their exercise book to share in the next lesson.', '2026-04-11 12:01:20', '2026-04-11 12:01:20'),
(60, 179, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Analyze identified problems in the locality.', 'b) Select the most suitable problem to address using available resources.', '', 'Which problems in our community can we solve using the skills we have learned in Pre-Technical Studies, and how do we decide which one is most suitable to address?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Chart paper or manila paper for listing problems\n* Markers or chalk for recording ideas\n* Sample community problems written on cards (water shortage, broken furniture, waste management, etc.)', 'The teacher displays or describes a common local problem (e.g., a broken classroom desk, difficulty carrying water, poor lighting in homes) and asks learners to recall the technical skills they have learned in previous lessons such as carpentry, metalwork, or electrical wiring. The teacher then poses the key inquiry question: \'Which problems in our community can we solve using the skills we have learned in Pre-Technical Studies, and how do we decide which one is most suitable to address?\' This creates curiosity and sets the stage for today\'s brainstorming and selection activity.', '• Brainstorm on the problems in the locality which can be solved using skills acquired.', '', '', 'The teacher summarizes that analyzing problems in the locality and selecting the most suitable one to address requires considering available skills, resources, time, and community impact. The teacher then asks: \'What are three factors you should consider when choosing which community problem to solve?\' and \'Why is it important to match the problem with the skills and resources we actually have?\' Learners respond briefly to demonstrate their understanding of the selection criteria.', '* Were all learners able to identify at least two relevant community problems that match the skills learned in Pre-Technical Studies?\n* Did the brainstorming activity generate sufficient diversity of ideas, or did learners need more prompting and examples?\n* Which groups struggled with selecting the most suitable problem, and what additional criteria or guidance do they need in the next lesson?', 'Learners should walk around their home or village and identify one additional problem not mentioned in class that could be solved using Pre-Technical Studies skills. They should write a brief description of the problem, the skills needed to solve it, and the materials required, then bring this to the next lesson for further discussion.', '2026-04-11 12:01:32', '2026-04-11 12:01:32'),
(61, 180, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Propose various handmade or digital items to solve the problem.', 'b) Identify the technical skills needed to make the selected item.', '', 'What handmade or digital items can we create to solve our identified community problem, and what technical skills do we need to make them?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Teacher\'s smartphone or tablet for research demonstration\n* Chart paper and markers for documenting proposals\n* Sample locally made items (baskets, tools, furniture) from the community\n* Writing materials for recording skills inventory', 'The teacher begins by reminding learners of the community problem they identified in previous lessons and asks them to think quietly for one minute about any product or item they have seen at home, in the market, or on their smartphone that could help solve a similar problem. The teacher then invites three learners to share their ideas aloud, writing the suggested items on the chalkboard. Finally, the teacher poses the key inquiry question: What handmade or digital items can we create to solve our identified community problem, and what technical skills do we need to make them?', '• Search for information on possible items to solve the identified problem.', '• Suggest the technical skills needed.', '', 'The teacher summarizes that today learners explored various handmade and digital items that could solve their community problem and identified the specific technical skills needed to create those items. The teacher then asks: What are two different items your group proposed to solve the problem, and which one did you select? What is one important technical skill you will need to learn or practice to make your selected item successfully?', '* Were all learners able to propose at least one relevant handmade or digital item to solve the identified community problem?\n* Did learners demonstrate clear understanding of the difference between naming an item and identifying the actual technical skills needed to make it?\n* Which groups struggled to connect their proposed items to realistic technical skills available in our school context, and how can I support them in the next lesson?', 'Learners should visit a local artisan, carpenter, tailor, or technician in their community and ask them what tools and skills are most important for making quality products in their trade. They should write down at least three skills mentioned and be ready to share how these might apply to their own project in the next lesson.', '2026-04-11 12:01:44', '2026-04-11 12:01:44'),
(62, 181, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Create freehand sketches of the selected project item.', 'b) Illustrate the features and dimensions of the item.', '', 'How can you accurately represent the features and measurements of your chosen project item using freehand sketching techniques?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Plain A4 or foolscap paper\n* Pencils (HB and 2B)\n* Erasers\n* Rulers for measuring dimensions', 'The teacher displays a simple locally-made item such as a wooden stool, hoe handle, or broom and asks learners to observe it carefully for 30 seconds. The teacher then covers the item and asks learners to describe from memory its main features, measurements (estimated height, width, length), and how the parts connect together. The teacher explains that today they will learn to create freehand sketches that accurately show the features and dimensions of their chosen project items, just as they tried to recall the features of the demonstrated object.', '• Make freehand sketches of the item selected.', '', '', 'Today we have learned to create freehand sketches that show the features and dimensions of our selected project items. The teacher asks: What are two important features you must include when making a freehand sketch of your project item? How does adding dimensions to your sketch help in the actual making of the project? The teacher reminds learners that accurate sketching is the first step in bringing their project ideas to reality.', '* Were all learners able to create freehand sketches that clearly showed at least three main features of their selected project item?\n* Did learners struggle with estimating and illustrating dimensions on their sketches, and what additional guidance or examples do they need in the next lesson?\n* Which learners need extra support with freehand sketching techniques, and how can I pair them with more skilled peers or provide individual assistance?', 'At home, learners should observe one useful item (such as a kitchen utensil, farm tool, or household furniture) and create a freehand sketch showing its main features and estimated dimensions in their exercise books. They should bring this sketch to the next lesson to share with their group members.', '2026-04-11 12:01:57', '2026-04-11 12:01:57'),
(63, 182, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Formulate the logical steps followed when making the item.', 'b) Note down the instructional steps for production.', '', 'How can we break down and document the step-by-step process of making an item in a clear, logical order that someone else can follow?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Sample completed projects from previous lessons\n* Chart paper or manila paper for documenting steps\n* Smartphones or tablets (teacher\'s) for photographing production stages\n* Pencils, erasers, and rulers for creating step diagrams', 'The teacher displays a completed project item made in a previous lesson (or a simple familiar item such as a broom, a clay pot, or a wooden stool) and asks learners: \'If you wanted to teach someone who has never made this item before, what is the very first step you would tell them?\' The teacher invites 3–4 quick responses, then explains that today learners will practice breaking down their own project into clear, ordered steps that anyone can follow, just like a recipe or instruction manual.', '• Find out and note down the steps followed when making the item.', '', '', 'The teacher reminds learners that writing clear, logical production steps is essential so that others can replicate their work and so that they themselves can remember and improve the process next time. The teacher then asks: \'What is the difference between listing materials and writing instructional steps?\' and \'Why is the order of steps important when documenting how to make an item?\' The teacher invites two learners to share their answers aloud.', '* Were all learners able to formulate and note down the production steps for their project item in a logical, sequential order?\n* Did learners struggle more with identifying the steps or with writing them down clearly, and what support strategies worked best?\n* Which groups or individual learners need additional guidance in breaking down complex tasks into simple, manageable instructional steps?', 'Learners should choose one simple household task they do at home (such as making tea, lighting a jiko, or sweeping a room) and write down 5–7 clear instructional steps in their exercise books, numbering each step in the correct order. They should be ready to share their steps in the next lesson.', '2026-04-11 12:02:10', '2026-04-11 12:02:10'),
(64, 183, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) List the specific materials and tools required for the project.', 'b) Identify locally available materials for the project.', '', 'What materials and tools do we need to successfully make our chosen project item, and which of these can we find or source locally in our community?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Sample projects or items selected in previous lessons\n* Chart paper and markers for listing materials\n* Community resource persons (carpenter, tailor, farmer) if available\n* Locally available materials (wood, fabric scraps, metal pieces, plant materials)', 'The teacher displays a simple finished project item from a previous class or brings a common locally-made item such as a broom, rope, or wooden stool to the front of the class. The teacher asks learners to observe the item carefully and call out what materials they think were used to make it and what tools might have been needed during its construction. The teacher then links this observation to today\'s lesson by explaining that every project requires careful planning of materials and tools, and that today learners will list exactly what they need for their own chosen projects and discover which materials are available locally.', '• Identify materials and tools for making the selected items.', '', '', 'The teacher summarises that successful project work depends on knowing exactly what materials and tools are needed and identifying which ones can be found in the local community to save cost and time. The teacher then asks: What is one material you need for your project that you can find locally in our community? What is one tool that your group must have to complete your project successfully? The teacher invites two or three learners to share their answers aloud before closing the lesson.', '* Were all learners able to clearly list the specific materials and tools required for their chosen project?\n* Did learners demonstrate the ability to distinguish between materials that are locally available and those that must be purchased or sourced from outside the community?\n* Which groups struggled with identifying appropriate local alternatives for materials, and what additional guidance or examples do they need in the next lesson?', 'Learners should visit their home compound or neighbourhood and identify at least three materials that could be used for their project, noting where exactly these materials can be found and whether they are free or must be purchased. They should record their findings in their exercise books and be ready to share with their group in the next lesson.', '2026-04-11 12:02:25', '2026-04-11 12:02:25'),
(65, 184, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Estimate the cost of materials for making the project item.', 'b) Calculate the total expenditure for the project.', '', 'How can we accurately estimate and calculate the total cost of materials and resources needed to complete our project item?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Sample project materials or list of materials used in previous lessons\n* Price lists from local shops or markets\n* Chart paper and markers for group cost estimation tables\n* Calculator or smartphone for calculations', 'The teacher displays a simple completed project item (or a picture of one from a previous class) and asks learners to quickly observe and name all the materials used to make it. Next, the teacher poses the question: \'If we wanted to make this item again, how would we know how much money we need to buy all these materials?\' This activates prior knowledge of materials identification and sets the stage for today\'s focus on cost estimation and calculation.', '• Estimate, in groups, the cost incurred to make the item.', '', '', 'Today we have learned how to estimate the cost of materials needed for our project items and how to calculate the total expenditure by adding all the individual costs together. Can you explain the difference between estimating and calculating the cost of materials? How would you adjust your project if the total cost exceeds your available budget?', '* Were all learners able to accurately estimate material costs and calculate the total expenditure for their project items?\n* Did the group work activity allow every learner to participate in the costing exercise, or did some learners dominate while others remained passive?\n* Which learners struggled with the calculation of total expenditure and what additional support or examples do they need in the next lesson?', 'Learners should visit a local shop or market and record the actual prices of at least three materials they plan to use in their project, then compare these real prices with their estimated costs and calculate any difference. They should write their findings in their exercise books and be ready to share in the next lesson.', '2026-04-11 12:02:36', '2026-04-11 12:02:36'),
(66, 185, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Determine a suitable selling price for the finished item.', 'b) Justify the price based on production costs and value.', '', 'How can we determine a fair and profitable selling price for our finished project item that covers all production costs and reflects its value?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Completed project items from previous lessons\n* Sample receipts or price lists from local shops or markets\n* Calculator or smartphone calculator\n* Chart paper and markers for displaying cost breakdown', 'The teacher displays a simple completed project item (such as a wooden stool, woven basket, or metal box made in previous lessons) and asks learners: \'If you wanted to sell this item you made, how much money would you ask for it?\' The teacher invites two or three learners to share their suggested prices and briefly explain why they chose that amount. The teacher then explains that today\'s lesson will help them learn a systematic way to determine a fair and profitable selling price that covers all costs and reflects the item\'s true value.', '• Determine the price for the item based on estimated costs.', '', '', 'The teacher summarises that a fair selling price must cover all production costs (materials, tools, labour, and overheads) plus a reasonable profit margin that reflects the item\'s quality and usefulness. The teacher then asks: \'What are the main costs you must include when calculating the selling price of your project item?\' and \'Why is it important to add a profit margin on top of the total production cost?\' The teacher invites brief responses and affirms that proper pricing ensures sustainability and rewards the maker\'s effort.', '* Were all learners able to accurately identify and list the different production costs for their finished project items?\n* Did learners understand the difference between covering costs and adding a profit margin, or did some confuse the two concepts?\n* Which learners struggled with the costing calculations and what additional support or simplified examples can I provide in the next lesson?', 'Learners should visit a local artisan, shopkeeper, or family member who makes and sells items (such as furniture, baskets, metalwork, or food products) and ask them how they decide the selling price for their products. Learners should write down at least three cost factors the person mentioned and bring this information to share in the next lesson.', '2026-04-11 12:02:48', '2026-04-11 12:02:48');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(67, 186, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Construct the project item using locally available materials.', 'b) Apply safety measures during the production process.', '', 'How can you safely construct your chosen project item using locally available materials and following your sketch design?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Locally available materials (wood, bamboo, clay, reeds, wire, fabric scraps, etc.)\n* Basic hand tools (hammer, saw, knife, pliers, nails, glue)\n* Safety gear (gloves, aprons, goggles if available)\n* Sketch/design from previous lesson', 'The teacher displays two or three locally available materials (e.g., sticks, bottle caps, wire, cardboard) on the demonstration table and asks learners to quickly share what project items they designed in their sketches last lesson and which of these materials they plan to use. The teacher then demonstrates one safety measure relevant to common tools (e.g., holding a cutting tool away from the body, wearing protective cloth over hands when handling sharp edges) and asks learners why safety is important when constructing items. This brief discussion connects their design plans to today\'s practical construction work and emphasizes safe handling before they begin.', '• Make the selected item using the sketch made while following instructional steps.', '', '', 'The teacher summarizes that today learners constructed their project items using locally available materials while applying important safety measures throughout the process. The teacher then asks: \'What is one safety measure you applied during construction today and why was it necessary?\' and \'Which locally available material did you use and how did it help you build your project item according to your sketch?\' These questions confirm learners\' understanding of safe construction practices and their ability to work with local materials.', '* Were all learners able to construct their project item using locally available materials as per their sketch design, or did some struggle with material selection or assembly techniques?\n* Did learners consistently apply safety measures during construction, and which specific safety practices need to be reinforced in the next lesson?\n* Which learners required additional support during the construction process and what specific challenges did they face with tools, materials or following their design sketch?', 'Learners should examine their partially or fully constructed project item at home, identify one part that needs improvement or strengthening, and write in their exercise book how they will improve it using available materials in the next construction session. They should also list any additional local materials they may need to complete their project.', '2026-04-11 12:03:01', '2026-04-11 12:03:01'),
(68, 187, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Construct the project item using locally available materials.', 'b) Apply safety measures during the production process.', '', 'How can you safely construct your selected project item using locally available materials while following the instructional steps from your sketch?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Locally available materials (wood, reeds, clay, wire, fabric, or recycled materials depending on project choice)\n* Basic hand tools (hammer, saw, knife, pliers, scissors, nails, glue)\n* Safety equipment (gloves, aprons, dust cloths)\n* Project sketches from previous lesson', 'The teacher displays two or three simple items made from locally available materials (e.g., a small broom made from twigs, a clay pot, or a woven mat) and asks learners to observe how they are constructed and what materials were used. The teacher then reminds learners that today they will begin constructing their own selected project items using their sketches from the previous lesson, emphasizing that they must follow their instructional steps carefully and observe all safety measures throughout the process.', '• Make the selected item using the sketch made while following instructional steps.', '', '', 'The teacher congratulates learners on beginning the construction of their project items and reminds them that following the sketch and instructional steps while staying safe are the keys to successful production. The teacher then asks: What is one safety measure you applied today during construction, and why was it important? What challenge did you face while following your instructional steps, and how did you solve it?', '* Were all learners able to begin constructing their project items using their sketches and locally available materials?\n* Which learners struggled with applying safety measures during the production process, and what additional demonstration or support do they need?\n* Did the instructional steps in the learners\' sketches prove clear enough to guide construction, or do some learners need help revising their plans in the next lesson?', 'Learners should observe at home one locally made item (such as a basket, broom, stool, or cooking tool) and write down in their exercise books the materials used and at least three steps they think were followed to make it. They should be ready to share their observations in the next lesson.', '2026-04-11 12:03:14', '2026-04-11 12:03:14'),
(69, 188, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Construct the project item using locally available materials.', 'b) Apply safety measures during the production process.', '', 'How can you safely construct your selected project item using locally available materials while following your sketch and instructional steps?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Sketch designs from previous lesson\n* Locally available materials (wood, bamboo, clay, metal scraps, fabric, wire, stones)\n* Basic hand tools (hammer, saw, knife, pliers, scissors)\n* Safety equipment (gloves, dust cloth, apron)', 'The teacher displays two or three project items from previous classes or brings a simple locally-made tool (such as a broom, wooden spoon, or woven basket) and asks learners to observe how it was constructed and what safety considerations were needed during its making. The teacher then reminds learners that today they will begin constructing their own selected project items using their sketches from the previous lesson, emphasizing that they must follow their instructional steps carefully and apply all safety measures learned. Learners are asked to take out their sketches and gather the locally available materials they identified for their projects.', '• Make the selected item using the sketch made while following instructional steps.', '', '', 'The teacher asks learners to pause their construction work and gather to summarize that successful project construction requires careful adherence to sketches, following step-by-step instructions, and consistently applying safety measures throughout the production process. The teacher then asks: What specific safety measures did you apply while constructing your project item today? How did following your sketch and instructional steps help you during the construction process?', '* Were all learners able to follow their sketches and instructional steps during the construction process, or did some struggle with translating their plans into actual work?\n* Which learners failed to consistently apply safety measures during production, and what additional demonstrations or reminders do they need in the next lesson?\n* Did learners have adequate access to the locally available materials they needed, and which groups need support in sourcing alternative materials for the next construction session?', 'Learners should observe and sketch one traditional handmade item at home (such as a cooking stick, rope, basket, or farming tool), noting what materials were used and what safety precautions the maker likely followed during construction. They should be ready to share how these observations can improve their own project construction in the next lesson.', '2026-04-11 12:03:27', '2026-04-11 12:03:27'),
(70, 189, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Construct the project item using locally available materials.', 'b) Apply safety measures during the production process.', '', 'How can we safely construct our project item using locally available materials while following the instructional steps from our sketch?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Sketch drawings from previous lesson\n* Locally available materials (wood, clay, wire, fabric, paper, cardboard, bottles, etc. depending on project choice)\n* Basic hand tools (saw, hammer, knife, scissors, glue, nails, string)\n* Safety equipment (gloves, aprons, dust cloths)', 'The teacher displays a finished sample project item (or a picture of one from previous learners) and asks learners to recall the sketch and instructional steps they prepared in the previous lesson. The teacher then poses the key inquiry question: \'How can we safely construct our project item using locally available materials while following the instructional steps from our sketch?\' Learners briefly share in pairs one safety rule they must observe during construction before the teacher transitions to the main activity.', '• Make the selected item using the sketch made while following instructional steps.', '', '', 'The teacher summarizes that successful project construction requires careful following of instructional steps from the sketch and consistent application of safety measures throughout the production process. The teacher then asks: \'What is one safety measure you applied today during construction, and why was it important?\' and \'How did following your sketch help you construct your project item accurately?\' Learners respond briefly, and the teacher emphasizes the importance of responsibility and care in completing quality project work.', '* Were all learners able to follow their instructional steps from the sketch to construct their project item using locally available materials?\n* Did learners consistently apply safety measures during the production process, and which safety aspect needs reinforcement in the next lesson?\n* Which learners or groups faced challenges with construction techniques, and what specific support or modification do they need to complete their project successfully?', 'Learners should observe their partially completed project item at home and write in their exercise books two improvements they could make to enhance its quality or functionality before the next lesson. They should also list any additional locally available materials they might need to bring to complete their project.', '2026-04-11 12:03:39', '2026-04-11 12:03:39'),
(71, 190, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Construct the project item using locally available materials.', 'b) Apply safety measures during the production process.', '', 'How can you safely construct your project item using locally available materials while following your sketch and instructional steps?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Sketch/design drawings from previous lessons\n* Locally available construction materials (wood offcuts, wire, fabric scraps, clay, bamboo, cardboard, nails, etc. depending on project choice)\n* Basic hand tools (hammer, saw, knife, pliers, scissors, rulers)\n* Safety equipment (gloves, dust cloths, aprons made from old fabric)', 'The teacher displays a sample project item (basket, simple toy, or tool) made from locally available materials and asks learners to observe how the parts are joined together and finished. The teacher then asks: \'What steps do you think were followed to make this item, and what safety measures were needed during construction?\' Learners share their observations for 2 minutes, activating their memory of their own project sketches and planned instructional steps from the previous lesson.', '• Make the selected item using the sketch made while following instructional steps.', '', '', 'The teacher summarizes that successful project construction requires following the sketch and instructional steps carefully while observing safety measures such as proper tool handling, wearing protective gear where needed, and keeping the workspace organized. The teacher then asks: \'What is one safety measure you applied today during construction, and why was it important?\' and \'Did you encounter any challenge that made you adjust your original sketch or steps, and how did you solve it?\' Three learners share their responses before the lesson ends.', '* Were all learners able to follow their sketches and instructional steps to construct their project items, or did some struggle with translating the plan into the actual product?\n* Did learners consistently apply safety measures throughout the construction process, and which safety practices need more emphasis in the next lesson?\n* Which learners or groups encountered material or technical challenges during construction, and what support strategies can I put in place to help them complete their projects successfully?', 'Learners should examine their partially or fully constructed project item at home and write down in their exercise books two improvements they could make to enhance its functionality, appearance, or durability. They should be ready to share these improvements and explain their reasoning in the next lesson.', '2026-04-11 12:03:52', '2026-04-11 12:03:52'),
(72, 191, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Construct the project item using locally available materials.', 'b) Apply safety measures during the production process.', '', 'How can you safely construct your project item using locally available materials while following your sketch and instructions?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Sketch/design from previous lesson\n* Locally available materials (wood, bamboo, clay, recycled materials, fabric, wire, etc. based on individual projects)\n* Basic hand tools (saw, hammer, nails, knife, scissors, glue)\n* Safety equipment (gloves, dust cloth, apron, water for first aid)', 'The teacher displays two or three locally available materials (such as sticks, bottle caps, wire, or cardboard) and asks learners to recall the project sketches they created in the previous lesson. The teacher then asks, \'What safety rules must we follow when cutting, joining, or shaping materials to turn our sketch into a real product?\' and allows 2–3 learners to share one safety measure each. The teacher emphasizes that today\'s lesson focuses on constructing the actual project item safely while following their sketch and instructions.', '• Make the selected item using the sketch made while following instructional steps.', '', '', 'The teacher asks learners to pause their construction work and observe their progress so far, noting that they have applied sketches and safety measures to begin building real products from locally available materials. The teacher then asks: \'What is one safety measure you applied during today\'s construction process?\' and \'How did your sketch guide the steps you followed when making your project item?\' The teacher reminds learners to store their partially completed projects safely and to clean their workspaces responsibly.', '* Were all learners able to construct their project item using locally available materials while following their sketch?\n* Which learners struggled with applying safety measures during the production process, and what additional support or demonstration do they need?\n* Did the instructional steps provided allow learners enough time and clarity to work safely and effectively, or should the construction phase be extended into the next lesson?', 'Learners should observe their home environment and identify one improvement or modification they can make to their project item based on materials they see at home. They should sketch this improvement in their exercise book and write two sentences explaining how it would make their project more functional or appealing.', '2026-04-11 12:04:04', '2026-04-11 12:04:04'),
(73, 192, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Present the finished item to the class for feedback.', 'b) Evaluate the quality of the item based on peer comments.', '', 'How can we use peer feedback to evaluate and improve the quality of our finished projects?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Finished items/projects made by learners\n* Evaluation checklist or criteria chart\n* Exercise books and pens for recording feedback', 'The teacher begins by holding up a finished project from a previous term (or showing a locally made item such as a broom, stool, or basket) and asks learners, \'What makes this item good quality? What could make it better?\' The teacher allows two or three learners to share their observations, then explains that today each group will present their finished project to the class and use peer feedback to evaluate and identify ways to improve the quality of their work.', '• Present the item made to the whole class and allow comments.', '', '', 'The teacher summarises that peer feedback helps us see our work through others\' eyes and discover strengths and areas for improvement we may have missed ourselves. The teacher then asks: \'What is one positive comment you received about your project today?\' and \'Based on peer feedback, what is one specific improvement you would make if you were to produce this item again?\' The teacher invites three to four learners to share brief answers.', '* Were all groups able to present their finished projects confidently and respond to peer comments constructively?\n* Did learners provide specific, helpful feedback rather than vague or negative comments, and how can I guide them to give better feedback in future?\n* Which learners or groups struggled to identify improvements based on peer comments, and what additional support or prompts do they need?', 'Learners should ask two adults at home (parent, guardian, or neighbour) to look at their finished project and share one thing they like and one suggestion for improvement. Learners write down these comments in their exercise books and bring them to the next lesson.', '2026-04-11 12:04:16', '2026-04-11 12:04:16'),
(74, 193, 'Grade 9', 'Pre-Technical Studies', '4.0 Tools and Production', '4.3 Project', '', '', NULL, '', NULL, 'a) Apply the produced item to solve the identified local problem.', 'b) Report on the effectiveness of the item in a real-life scenario.', '', 'How effectively does your produced item solve the identified local problem when applied in a real-life situation?', 'Creativity and imagination: learners design original, functional products that address real needs using materials and tools studied in the strand.\nCritical thinking and problem solving: learners evaluate their designs, identify limitations and propose improvements based on testing outcomes.\nCommunication and collaboration: learners work in groups to plan, assign roles, make and present their project, communicating progress and challenges throughout.\nSelf-efficacy: learners demonstrate the confidence and persistence to carry a project from idea to finished product.', 'Innovation and creativity: learners apply the design process to produce innovative, locally-relevant products.\nCareer guidance: project work introduces learners to the professional cycle of design, production and evaluation used in technical careers.\nESD: learners design products that consider material economy, environment impact and community value.\nEntrepreneurship: learners consider the market potential and costing of their project product.', 'Responsibility: learners take ownership of their project, meeting timelines and producing quality work.\nIntegrity: learners acknowledge the contributions of group members and present honest evaluations of their finished product.\nCare: learners handle tools and materials safely throughout the project and tidy the workspace after use.', '* Learners textbook\n* Completed project items from previous lessons\n* Observation notebook or recording sheets\n* Smartphone or camera (if available) for documenting application', 'The teacher displays or invites a learner to bring forward the item they produced in previous lessons (e.g. a rain harvesting gutter, a storage rack, a poultry feeder, a simple tool). The teacher asks: \'Who remembers what local problem this item was designed to solve? Today we will use your produced item in a real situation to see how well it actually works.\' The teacher briefly discusses one example of testing an item in the community or home, building excitement for the practical application learners will carry out.', '• Use the item made to solve the problem identified in your locality.', '', '', 'The teacher summarizes by stating that applying and testing a produced item in real-life is the most important step to know if a design truly solves a problem. The teacher asks: \'What did you observe when you used your item to solve the local problem today?\' and \'What one thing would you improve about your item based on how it performed?\' Learners share brief responses to confirm their understanding of real-world effectiveness and evaluation.', '* Were all learners able to apply their produced item to solve the identified local problem in a real-life scenario?\n* Did learners provide honest and detailed observations about the effectiveness of their items, or did they need more prompting and guidance?\n* Which groups or individuals struggled with reporting on their item\'s performance, and what support can I provide in the next lesson to improve their evaluation skills?', 'Learners should use their produced item at home or in the community for at least two more days, observe how well it works each time, and write down three specific observations about its strengths and weaknesses. They should be ready to share these observations in the next lesson.', '2026-04-11 12:04:29', '2026-04-11 12:04:29'),
(75, 194, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.1 Financial Services', '', '', NULL, '', NULL, 'a) Identify various financial institutions available in Kenya.', 'b) Search for information on the roles of different financial institutions.', '', 'What are the different financial institutions in Kenya and what specific roles do they play in helping individuals and businesses manage money?', 'Self-efficacy: learners develop confidence in managing personal finances and making informed decisions about savings, credit and investment.\nCritical thinking and problem solving: learners compare available financial services (bank accounts, mobile money, SACCOs, microfinance) and evaluate their suitability for different business needs.\nDigital literacy: learners explore mobile-banking and digital-payment platforms as business tools.', 'Financial literacy: learners study savings, credit, insurance, mobile money and investment as tools for business growth.\nLife skills education: learners develop decision-making skills related to personal and business financial management.\nCareer guidance: learners explore careers in banking, microfinance and financial technology (FinTech).', 'Integrity: learners appreciate the importance of honest financial record-keeping, repaying loans and honouring financial commitments.\nResponsibility: learners demonstrate responsible borrowing and saving behaviour.\nSocial justice: learners discuss equitable access to financial services and the role of cooperative societies in empowering communities.', '* Learners textbook\n* Chart paper and markers for group presentations\n* Sample bank statements, M-Pesa receipts, or SACCO forms from local community members\n* Teacher\'s smartphone or tablet for guided internet search (if available)', 'The teacher begins by holding up a mobile phone and asks learners to raise their hands if anyone in their family uses M-Pesa, Airtel Money or any mobile money service. After a show of hands, the teacher writes \'M-Pesa\' on the chalkboard and asks: \'Is Safaricom a bank? If not, what kind of financial institution is it?\' This question sparks curiosity and sets the stage for exploring the variety of financial institutions beyond traditional banks that Kenyans use daily.', '• Identify, in groups, financial institutions available in Kenya.', '• Search for information, in groups, on financial institutions and present findings.', '', 'Today we identified different financial institutions in Kenya including commercial banks, SACCOs, microfinance institutions, mobile money providers, and insurance companies, and we learned that each plays a specific role in helping people and businesses manage money. Now answer these two questions: Can you name at least three types of financial institutions we discussed today? What is one key difference between a bank and a SACCO based on what your group found?', '* Were all learners able to correctly identify at least four different types of financial institutions available in Kenya during the group activity?\n* Did the group presentations reveal any misconceptions about the roles of financial institutions, particularly the difference between banks, SACCOs and mobile money providers?\n* Which learners struggled to participate in the information search activity and what support strategies can I use in the next lesson to ensure they engage with comparing financial services?', 'Learners should interview one adult family member or neighbour about which financial institution they use most often (bank, SACCO, mobile money, chama, or microfinance) and ask why they prefer it. They should write down the name of the institution, the type it belongs to, and at least two reasons the person gave for using it, then bring this information to the next lesson.', '2026-04-11 12:04:42', '2026-04-11 12:04:42'),
(76, 195, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.1 Financial Services', '', '', NULL, '', NULL, 'a) Classify financial institutions into formal and informal categories.', 'b) Distinguish between banks, insurance companies, SACCOs, and micro-finance.', '', 'How can we group the different financial institutions in Kenya based on how they are organized and regulated?', 'Self-efficacy: learners develop confidence in managing personal finances and making informed decisions about savings, credit and investment.\nCritical thinking and problem solving: learners compare available financial services (bank accounts, mobile money, SACCOs, microfinance) and evaluate their suitability for different business needs.\nDigital literacy: learners explore mobile-banking and digital-payment platforms as business tools.', 'Financial literacy: learners study savings, credit, insurance, mobile money and investment as tools for business growth.\nLife skills education: learners develop decision-making skills related to personal and business financial management.\nCareer guidance: learners explore careers in banking, microfinance and financial technology (FinTech).', 'Integrity: learners appreciate the importance of honest financial record-keeping, repaying loans and honouring financial commitments.\nResponsibility: learners demonstrate responsible borrowing and saving behaviour.\nSocial justice: learners discuss equitable access to financial services and the role of cooperative societies in empowering communities.', '* Learners textbook\n* Chart paper and markers\n* Sample documents from local financial institutions (bank calendars, SACCO posters, M-Pesa agent signs)\n* Manila paper for group classification work', 'The teacher begins by asking learners to name any place or person where their parents or community members save money, borrow money, or get help when something bad happens (like illness or fire). As learners mention banks, mobile money agents, chamas, merry-go-rounds, SACCOs, or insurance companies, the teacher writes these on the chalkboard in a random list. The teacher then poses the key inquiry question: \'How can we group these different financial institutions based on how they are organized and regulated?\' to spark curiosity about classification.', '• Classify, in groups, financial institutions in Kenya.', '• Brainstorm the two classifications of financial institutions.', '', 'The teacher summarizes that financial institutions in Kenya can be classified into formal institutions (like banks, insurance companies, SACCOs, microfinance institutions that are regulated by government) and informal institutions (like chamas, merry-go-rounds, and rotating savings groups). The teacher then asks: \'If your family wanted to save money safely and earn interest, would you recommend a formal or informal institution, and why?\' and \'What is one key difference between a SACCO and a commercial bank?\'', '* Were all learners able to correctly classify at least three financial institutions into formal and informal categories during the group activity?\n* Did the brainstorming activity in groups allow every learner to participate, or did some learners dominate while others remained silent?\n* Which learners struggled to distinguish between banks, SACCOs, insurance companies and microfinance institutions, and what additional examples or explanations do they need?', 'Learners should interview two adults in their community (a parent, guardian, or neighbour) to find out which financial institutions they use for saving, borrowing, or insurance, and classify each institution as either formal or informal. They should write their findings in their exercise books and be ready to share in the next lesson.', '2026-04-11 12:04:55', '2026-04-11 12:04:55'),
(77, 196, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.1 Financial Services', '', '', NULL, '', NULL, 'a) Analyze various services offered by financial institutions through case studies.', 'b) Categorize financial services such as savings, credit, and insurance.', '', 'How do different financial institutions help individuals and businesses manage their money through the services they provide?', 'Self-efficacy: learners develop confidence in managing personal finances and making informed decisions about savings, credit and investment.\nCritical thinking and problem solving: learners compare available financial services (bank accounts, mobile money, SACCOs, microfinance) and evaluate their suitability for different business needs.\nDigital literacy: learners explore mobile-banking and digital-payment platforms as business tools.', 'Financial literacy: learners study savings, credit, insurance, mobile money and investment as tools for business growth.\nLife skills education: learners develop decision-making skills related to personal and business financial management.\nCareer guidance: learners explore careers in banking, microfinance and financial technology (FinTech).', 'Integrity: learners appreciate the importance of honest financial record-keeping, repaying loans and honouring financial commitments.\nResponsibility: learners demonstrate responsible borrowing and saving behaviour.\nSocial justice: learners discuss equitable access to financial services and the role of cooperative societies in empowering communities.', '* Learners textbook\n* Case study handouts or printed examples of financial institutions (bank, microfinance, SACCO)\n* Chart paper or manila papers for group presentations\n* Sample financial documents (bank statements, loan agreements, insurance policies) if available locally', 'The teacher begins by asking learners to raise their hands if they or their family members have ever saved money, borrowed money, or sent money to someone using a mobile phone. The teacher then displays or writes on the chalkboard the names of three local financial institutions (for example, a nearby bank, M-Pesa agent, and a local SACCO) and asks learners to share what they know about what these places do for people. This discussion should take 3–4 minutes and lead naturally into the day\'s exploration of the specific services financial institutions provide.', '• Analyse, in groups, a case study on financial institutions.', '• Note down in exercise books the services they offer and share findings.', '', 'The teacher summarizes that financial institutions offer various services including savings accounts, loans and credit, insurance, money transfers, and investment opportunities, and that different institutions serve different needs for individuals and businesses. The teacher then asks: \'Can you name three different types of financial services we categorized today?\' and \'Which financial service would be most useful for a small business owner who wants to expand their shop, and why?\' Learners respond briefly, demonstrating their understanding of today\'s case study analysis and categorization work.', '* Were all learners able to correctly categorize the financial services (savings, credit, insurance) identified in the case study?\n* Did the group work on analyzing case studies allow every learner to participate, or did some learners dominate while others remained passive?\n* Which learners struggled to distinguish between different financial services, and what additional examples or explanations might help them in the next lesson?', 'Learners should interview one adult family member or neighbour about which financial institution they use (bank, mobile money, SACCO, or chama) and write down two services that person uses and why they chose that particular institution. They should record their findings in their exercise books to share in the next lesson.', '2026-04-11 12:05:08', '2026-04-11 12:05:08'),
(78, 197, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.1 Financial Services', '', '', NULL, '', NULL, 'a) Identify specific financial services needed to start a small business.', 'b) Select appropriate financial institutions for business support in a given scenario.', '', 'What financial services and institutions would you need to successfully start and run a small business in your community?', 'Self-efficacy: learners develop confidence in managing personal finances and making informed decisions about savings, credit and investment.\nCritical thinking and problem solving: learners compare available financial services (bank accounts, mobile money, SACCOs, microfinance) and evaluate their suitability for different business needs.\nDigital literacy: learners explore mobile-banking and digital-payment platforms as business tools.', 'Financial literacy: learners study savings, credit, insurance, mobile money and investment as tools for business growth.\nLife skills education: learners develop decision-making skills related to personal and business financial management.\nCareer guidance: learners explore careers in banking, microfinance and financial technology (FinTech).', 'Integrity: learners appreciate the importance of honest financial record-keeping, repaying loans and honouring financial commitments.\nResponsibility: learners demonstrate responsible borrowing and saving behaviour.\nSocial justice: learners discuss equitable access to financial services and the role of cooperative societies in empowering communities.', '* Learners textbook\n* Chart paper or manila paper\n* Sample business registration forms or documents (if available from local cooperative or bank)\n* Printed or written list of local financial institutions (banks, SACCOs, microfinance)', 'The teacher asks learners to imagine they want to start a small poultry business selling eggs in their community and poses the question: \'Where would you keep the money you earn, and where would you get money to buy the first chicks and feed?\' Learners share their ideas in pairs for two minutes, then the teacher writes three or four responses on the chalkboard (e.g., saving at home, borrowing from family, using a bank, mobile money). The teacher then tells learners that today they will explore the different financial services and institutions that can help them successfully start and manage a real business.', '• Picture a scenario of starting a small business.', '• Identify financial services and institutions you would need.', '', 'The teacher summarises by reminding learners that different financial services such as savings accounts, mobile money, loans from SACCOs or microfinance institutions, and insurance all play important roles in starting and running a small business, and that choosing the right institution depends on the business needs and circumstances. The teacher then asks: \'Can you name three financial services a small business owner might need?\' and \'Why might a farmer choose a SACCO instead of a commercial bank for a loan?\' Learners respond orally and the teacher affirms correct answers.', '* Were all learners able to identify at least three specific financial services needed to start a small business?\n* Did the scenario-based activity help learners select appropriate financial institutions, or did some learners struggle to match services to business needs?\n* Which learners need additional support in understanding the differences between banks, SACCOs, mobile money providers and microfinance institutions?', 'Learners should interview one small business owner in their community (a shopkeeper, tailor, farmer or vendor) and ask which financial services or institutions they use and why they chose them. They write a short paragraph in their exercise books summarising what they learned to share in the next lesson.', '2026-04-11 12:05:21', '2026-04-11 12:05:21');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(79, 198, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.2 Government and Business', '', '', NULL, '', NULL, 'a) Explain the various reasons why the government gets involved in business.', 'b) Identify government roles in business from displayed flashcards.', '', 'Why does the government involve itself in business activities in Kenya?', 'Critical thinking and problem solving: learners analyse the impact of government taxation, licensing and regulation on small businesses and propose how entrepreneurs can operate within the law.\nCitizenship: learners appreciate the contribution of taxes to public services and the importance of legal business registration.\nCommunication and collaboration: learners debate government roles in supporting and regulating business in group discussions.', 'Citizenship education: learners study the legal and civic obligations of business operators in Kenya, including business licensing and tax compliance.\nFinancial literacy: learners understand the role of taxation, government levies and business facilitation funds.\nCareer guidance: learners explore careers in government regulatory bodies (KRA, KEBS, county business offices).', 'Patriotism: learners appreciate that taxes paid by businesses fund public services that benefit all Kenyans.\nIntegrity: learners commit to ethical business practices including accurate financial reporting, tax compliance and fair trade.\nResponsibility: learners understand the civic responsibility to register businesses and pay taxes as required by law.\nSocial justice: learners discuss how government regulation can protect consumers, employees and the environment.', '* Learners textbook\n* Flashcards showing government roles (made from manila paper or cardboard)\n* Charts with examples of government businesses (e.g. KenGen, Kenya Railways)\n* Markers or chalk for brainstorming notes', 'The teacher holds up a small item such as a locally sold packet of sugar or maize flour and asks learners: \'Who has seen the KEBS mark on products like this one, and why do you think the government puts that mark there?\' After a few responses, the teacher asks learners to mention any other ways they have seen the government involved in businesses around their community (such as business permits displayed in shops, KRA stickers on vehicles, or county health inspections). The teacher then tells learners that today they will explore the various reasons why the government involves itself in business activities in Kenya.', '• Brainstorming on the reason for government involvement in business.', '• Observe displayed flashcards on reasons for government involvement.', '', 'The teacher summarises by reminding learners that the government involves itself in business for several reasons including regulating quality and safety, collecting taxes to fund public services, creating employment, protecting consumers, and supporting local entrepreneurs. The teacher then asks: \'Can someone explain two reasons why the government regulates businesses in Kenya?\' and \'Why is it important for business owners to pay taxes and obtain licenses?\' The teacher listens to responses and affirms correct answers to reinforce the lesson\'s key learning outcomes.', '* Were all learners able to explain at least three reasons why the government involves itself in business activities in Kenya?\n* Did the displayed flashcards effectively help learners identify and remember the different government roles in business, or should I use more real-life examples from our local area?\n* Which learners struggled during the brainstorming activity and how can I provide additional support to help them understand government regulation and taxation concepts?', 'Learners should visit at least two local businesses (such as a shop, kiosk, or market stall) in their community and observe any visible government involvement such as business permits, KEBS marks on products, KRA tax stickers, or county health certificates. They should write down what they observed and be ready to share their findings in the next lesson.', '2026-04-11 12:05:35', '2026-04-11 12:05:35'),
(80, 199, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.2 Government and Business', '', '', NULL, '', NULL, 'a) Describe different ways the government involves itself in business activities.', 'b) Discuss government regulations imposed on businesses.', '', 'How does the government participate in and regulate business activities in Kenya?', 'Critical thinking and problem solving: learners analyse the impact of government taxation, licensing and regulation on small businesses and propose how entrepreneurs can operate within the law.\nCitizenship: learners appreciate the contribution of taxes to public services and the importance of legal business registration.\nCommunication and collaboration: learners debate government roles in supporting and regulating business in group discussions.', 'Citizenship education: learners study the legal and civic obligations of business operators in Kenya, including business licensing and tax compliance.\nFinancial literacy: learners understand the role of taxation, government levies and business facilitation funds.\nCareer guidance: learners explore careers in government regulatory bodies (KRA, KEBS, county business offices).', 'Patriotism: learners appreciate that taxes paid by businesses fund public services that benefit all Kenyans.\nIntegrity: learners commit to ethical business practices including accurate financial reporting, tax compliance and fair trade.\nResponsibility: learners understand the civic responsibility to register businesses and pay taxes as required by law.\nSocial justice: learners discuss how government regulation can protect consumers, employees and the environment.', '* Learners textbook\n* Chart paper and markers for group presentations\n* Examples of business licenses or permits from local businesses\n* Newspapers with business or economic news sections', 'The teacher asks learners to name any government offices or officers they have seen in their local market or town (for example, county inspectors, KRA officers, public health officers). The teacher then shows a real or drawn example of a business permit or licence (such as a county single business permit) and asks learners why they think the government requires businesses to have such documents. The teacher links these observations to today\'s key inquiry question: How does the government participate in and regulate business activities in Kenya?', '• Describe, in groups, ways of government involvement in business.', '• Discuss regulations the government imposes on business.', '', 'The teacher summarises that government involves itself in business through ownership of parastatals, provision of support services, and through regulations such as taxation, licensing, and standards enforcement to protect consumers and ensure fairness. The teacher asks: Can you name three ways the government regulates businesses in Kenya? Why is it important for business owners to comply with government regulations such as tax payment and licensing?', '* Were all learners able to describe at least three different ways the government involves itself in business activities in Kenya?\n* Did the group discussions on government regulations generate sufficient real-world examples from learners\' local context, or do I need to provide more concrete cases next time?\n* Which learners struggled to distinguish between government participation in business and government regulation of business, and how can I clarify this distinction in future lessons?', 'Learners should interview a local business owner (shopkeeper, kiosk operator, or trader) to find out what government permits or licences they hold and what taxes or levies they pay. They should write a short report (one page) summarizing their findings and present it in the next lesson.', '2026-04-11 12:05:47', '2026-04-11 12:05:47'),
(81, 200, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.2 Government and Business', '', '', NULL, '', NULL, 'a) Define the meaning of taxation in the Kenyan context.', 'b) Discuss the importance of citizens and businesses paying taxes.', '', 'Why is taxation important for both the government and citizens in Kenya?', 'Critical thinking and problem solving: learners analyse the impact of government taxation, licensing and regulation on small businesses and propose how entrepreneurs can operate within the law.\nCitizenship: learners appreciate the contribution of taxes to public services and the importance of legal business registration.\nCommunication and collaboration: learners debate government roles in supporting and regulating business in group discussions.', 'Citizenship education: learners study the legal and civic obligations of business operators in Kenya, including business licensing and tax compliance.\nFinancial literacy: learners understand the role of taxation, government levies and business facilitation funds.\nCareer guidance: learners explore careers in government regulatory bodies (KRA, KEBS, county business offices).', 'Patriotism: learners appreciate that taxes paid by businesses fund public services that benefit all Kenyans.\nIntegrity: learners commit to ethical business practices including accurate financial reporting, tax compliance and fair trade.\nResponsibility: learners understand the civic responsibility to register businesses and pay taxes as required by law.\nSocial justice: learners discuss how government regulation can protect consumers, employees and the environment.', '* Learners textbook\n* Sample tax receipts or KRA notices from local businesses (if available)\n* Chart paper and markers for group presentations\n* Examples of public services in the community (school, dispensary, roads)', 'The teacher begins by asking learners to look around the classroom and name things provided by the school or government (desks, chalkboard, textbooks, the building itself). The teacher then poses the key inquiry question: \'Where do you think the government gets money to build schools, hospitals, and roads?\' and allows 2–3 learners to share their thoughts. The teacher writes the word \'TAXATION\' on the chalkboard and explains that today\'s lesson will help them understand why paying taxes is important for both the government and all Kenyan citizens.', '• Discuss, in groups, the meaning and importance of paying taxes and share findings.', '', '', 'The teacher summarizes by stating that taxation means the government collecting money from citizens and businesses to provide essential public services like schools, hospitals, roads, and security, and that paying taxes is both a legal requirement and a civic duty that benefits all Kenyans. The teacher then asks: \'Can you define taxation in your own words?\' and \'Why is it important for businesses and citizens to pay taxes to the Kenyan government?\' The teacher invites 3–4 learners to respond and affirms correct answers.', '* Were all learners able to define taxation clearly in the Kenyan context and give at least two reasons why it is important?\n* Did the group discussions allow every learner to participate, or did some learners dominate while others remained quiet?\n* Which examples of public services funded by taxes resonated most with learners, and how can I use more local examples to deepen their understanding of tax benefits in their own community?', 'Learners should interview a family member or local business owner (shopkeeper, bodaboda operator, or farmer) and ask them what taxes or fees they pay to the government and why they think paying taxes is important. Learners should write a short paragraph (5–7 sentences) summarizing what they learned from the interview to share in the next lesson.', '2026-04-11 12:05:59', '2026-04-11 12:05:59'),
(82, 201, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.2 Government and Business', '', '', NULL, '', NULL, 'a) Identify the different types of taxes in Kenya (VAT, Income Tax, etc.).', 'b) Explain how different taxes are applied to businesses.', '', 'How do different types of taxes affect the way businesses operate and make profits in Kenya?', 'Critical thinking and problem solving: learners analyse the impact of government taxation, licensing and regulation on small businesses and propose how entrepreneurs can operate within the law.\nCitizenship: learners appreciate the contribution of taxes to public services and the importance of legal business registration.\nCommunication and collaboration: learners debate government roles in supporting and regulating business in group discussions.', 'Citizenship education: learners study the legal and civic obligations of business operators in Kenya, including business licensing and tax compliance.\nFinancial literacy: learners understand the role of taxation, government levies and business facilitation funds.\nCareer guidance: learners explore careers in government regulatory bodies (KRA, KEBS, county business offices).', 'Patriotism: learners appreciate that taxes paid by businesses fund public services that benefit all Kenyans.\nIntegrity: learners commit to ethical business practices including accurate financial reporting, tax compliance and fair trade.\nResponsibility: learners understand the civic responsibility to register businesses and pay taxes as required by law.\nSocial justice: learners discuss how government regulation can protect consumers, employees and the environment.', '* Learners textbook\n* Sample business receipts or invoices from local shops showing VAT\n* Chart paper and markers for group presentations\n* Teacher\'s smartphone to show Kenya Revenue Authority (KRA) information if available', 'The teacher begins by holding up a common item such as a packet of salt or sugar and asks learners to call out the price they would pay at a shop. The teacher then writes the price on the chalkboard and asks: \'Do you know that part of this money goes to the government? Why do you think the government collects money from businesses?\' After a few responses, the teacher explains that today\'s lesson will help them identify the different types of taxes businesses pay in Kenya and understand how these taxes are applied.', '• Discuss, in groups, types of taxes in Kenya and present to peers.', '', '', 'The teacher summarizes by reminding learners that businesses in Kenya pay different types of taxes such as VAT, Income Tax, and others, and that these taxes are calculated in different ways depending on the type of business and its income. The teacher then asks two closing questions: \'Can someone explain the difference between VAT and Income Tax?\' and \'If a shopkeeper sells goods worth 1,000 shillings and VAT is 16%, how much tax should they collect?\' The teacher invites two or three learners to respond and provides brief feedback.', '* Were all learners able to correctly identify at least three types of taxes applicable to businesses in Kenya during the group presentations?\n* Did the group discussions and presentations allow sufficient time for learners to explain how different taxes are applied, or did some groups struggle with clarity?\n* Which learners showed difficulty distinguishing between VAT and Income Tax, and what additional examples or support can I provide in the next lesson?', 'Learners should visit a local shop, kiosk, or business in their community and politely ask the owner which taxes they pay to the government and how often they pay them. They should write a short paragraph in their exercise books summarizing what they learned and bring it to the next lesson for sharing.', '2026-04-11 12:06:12', '2026-04-11 12:06:12'),
(83, 202, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.2 Government and Business', '', '', NULL, '', NULL, 'a) Analyze case studies on e-Government services used in business.', 'b) Interact with e-Government platforms using digital tools.', '', 'How can businesses in Kenya use e-Government platforms to improve their operations and compliance with government regulations?', 'Critical thinking and problem solving: learners analyse the impact of government taxation, licensing and regulation on small businesses and propose how entrepreneurs can operate within the law.\nCitizenship: learners appreciate the contribution of taxes to public services and the importance of legal business registration.\nCommunication and collaboration: learners debate government roles in supporting and regulating business in group discussions.', 'Citizenship education: learners study the legal and civic obligations of business operators in Kenya, including business licensing and tax compliance.\nFinancial literacy: learners understand the role of taxation, government levies and business facilitation funds.\nCareer guidance: learners explore careers in government regulatory bodies (KRA, KEBS, county business offices).', 'Patriotism: learners appreciate that taxes paid by businesses fund public services that benefit all Kenyans.\nIntegrity: learners commit to ethical business practices including accurate financial reporting, tax compliance and fair trade.\nResponsibility: learners understand the civic responsibility to register businesses and pay taxes as required by law.\nSocial justice: learners discuss how government regulation can protect consumers, employees and the environment.', '* Learners textbook\n* Teacher\'s smartphone or tablet with internet connection\n* Printed screenshots or handouts of e-Government platforms (eCitizen, iTax, NTSA portal)\n* Case study materials from textbook or local business examples\n* Chart paper and markers for group presentations', 'The teacher begins by asking learners to recall the last time they or their parents needed a government service (such as getting a national ID, birth certificate, or business permit) and how long it took. The teacher then asks: \'What if you could access these services from your phone or computer without traveling to government offices? Today we will explore how businesses in Kenya use e-Government platforms like eCitizen and iTax to save time and comply with regulations.\' The teacher writes \'e-Government\' on the chalkboard and invites two learners to share what they think the term means.', '• Discuss, in groups, a case study on e-government services in business.', '• Use ICT tools to access and interact with e-Government platforms.', '', 'The teacher summarizes by reminding learners that e-Government platforms such as eCitizen, iTax, and the Business Registration Service allow Kenyan businesses to register, pay taxes, renew licenses, and access permits online, improving efficiency and compliance. The teacher then asks: \'From the case study we discussed, what are two benefits businesses gain by using e-Government platforms?\' and \'Which e-Government platform would a small shop owner use to file monthly tax returns?\' The teacher invites three learners to respond and affirms correct answers.', '* Were all learners able to analyze the case study and identify at least two e-Government services used by businesses?\n* Did learners who interacted with e-Government platforms using my smartphone or tablet understand the registration and navigation process, or did some struggle with the digital interface?\n* Which learners need additional support in understanding how e-Government platforms improve business compliance, and how can I provide follow-up examples or simpler case studies?', 'Learners should visit a local business owner (shop, kiosk, or farm enterprise) and ask them if they use any e-Government services such as eCitizen or iTax, what challenges they face, and what benefits they have experienced. Learners should write a brief summary of their findings in their exercise books to share in the next lesson.', '2026-04-11 12:06:26', '2026-04-11 12:06:26'),
(84, 203, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.2 Government and Business', '', '', NULL, '', NULL, 'a) Explain the necessity of complying with government business regulations.', 'b) Evaluate understanding of government and business through an exercise.', '', 'Why is it important for business owners to comply with government regulations when running their businesses?', 'Critical thinking and problem solving: learners analyse the impact of government taxation, licensing and regulation on small businesses and propose how entrepreneurs can operate within the law.\nCitizenship: learners appreciate the contribution of taxes to public services and the importance of legal business registration.\nCommunication and collaboration: learners debate government roles in supporting and regulating business in group discussions.', 'Citizenship education: learners study the legal and civic obligations of business operators in Kenya, including business licensing and tax compliance.\nFinancial literacy: learners understand the role of taxation, government levies and business facilitation funds.\nCareer guidance: learners explore careers in government regulatory bodies (KRA, KEBS, county business offices).', 'Patriotism: learners appreciate that taxes paid by businesses fund public services that benefit all Kenyans.\nIntegrity: learners commit to ethical business practices including accurate financial reporting, tax compliance and fair trade.\nResponsibility: learners understand the civic responsibility to register businesses and pay taxes as required by law.\nSocial justice: learners discuss how government regulation can protect consumers, employees and the environment.', '* Learners textbook\n* Examples of business licenses or permits from local businesses (photocopies or real samples)\n* Chart paper and markers for summarizing key regulations\n* Local business registration documents or images on teacher\'s smartphone', 'The teacher asks learners to name any business they know in their village or nearby town, then asks: \'Have you ever seen a certificate or license displayed on the wall in a shop, salon, or hotel?\' Allow a few learners to share what they have observed. The teacher then asks the key inquiry question: \'Why is it important for business owners to comply with government regulations when running their businesses?\' and explains that today\'s lesson will help them understand the necessity of following government rules and evaluate their understanding through an exercise.', '• Discuss the need to comply with government regulations in business.', '• Work individually on assessment exercise.', '', 'The teacher summarizes that complying with government regulations such as business registration, licensing, and tax payment is both a legal requirement and a civic duty that helps fund public services like roads, schools, and hospitals that benefit all Kenyans. The teacher then asks: \'What are two reasons why a business owner must comply with government regulations?\' and \'How does paying taxes demonstrate patriotism and responsibility as a Kenyan citizen?\' The teacher invites two or three learners to respond before closing the lesson.', '* Were all learners able to explain at least two specific reasons why compliance with government business regulations is necessary?\n* Did the individual assessment exercise reveal any misconceptions about the relationship between government regulation and business operations that need to be addressed in the next lesson?\n* Which learners struggled with evaluating their understanding during the exercise and may need additional support or simpler examples of government regulations?', 'Learners should visit one registered business in their community (a shop, salon, restaurant, or any visible business) and respectfully ask the owner or manager what government licenses or permits they have and why they are important. Learners should write a short paragraph in their exercise books describing what they learned from the business owner about compliance.', '2026-04-11 12:06:37', '2026-04-11 12:06:37'),
(85, 204, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.3 Business Plan', '', '', NULL, '', NULL, 'a) Define the term \"Business Plan.\"', 'b) Discuss the importance of a business plan for an entrepreneur.', '', 'Why is a business plan important for an entrepreneur who wants to start or grow a business?', 'Critical thinking and problem solving: learners analyse market needs and competition, then design a viable business plan that addresses a real community opportunity.\nCreativity and imagination: learners develop innovative business ideas and create compelling, original business plans.\nSelf-efficacy: learners develop confidence in their entrepreneurial ability through the process of planning and presenting a business idea.\nCommunication and collaboration: learners work in groups to research, draft and pitch their business plan to peers or invited evaluators.', 'Entrepreneurship education: learners apply the full entrepreneurial process — idea generation, market research, financial planning, marketing and evaluation — in developing their business plan.\nCareer guidance: business plan development prepares learners for self-employment and entrepreneurial careers in technical fields.\nESD: learners incorporate environmental sustainability considerations into their business plan.\nLife skills education: learners develop research, writing, financial literacy and presentation skills through the business planning process.', 'Integrity: learners produce realistic, accurate financial projections and honestly assess the strengths and weaknesses of their business idea.\nResponsibility: learners take ownership of the planning process, meet deadlines and produce a well-organised plan.\nSocial justice: learners consider the social and environmental impact of their proposed business on the community.\nUnity: learners collaborate respectfully, valuing each team member\'s contribution to the business plan.', '* Learners textbook\n* Chart paper or manila paper\n* Markers or coloured chalk\n* Sample business plans from local entrepreneurs (if available)', 'The teacher brings to class a common item sold in the local market (e.g., a packet of maize flour, a bar of soap, or a bundle of vegetables) and asks learners: \'If you wanted to start selling this product in our community, what would you need to know and plan before you begin?\' After 2–3 learners share their thoughts, the teacher writes the term \'Business Plan\' on the chalkboard and explains that today\'s lesson will help them understand what a business plan is and why every entrepreneur needs one before starting or growing a business.', '• Brainstorm on the meaning and importance of a business plan.', '• Present findings in class.', '', 'The teacher summarises by stating: \'Today we have learned that a business plan is a written document that describes a business idea, its goals, and how those goals will be achieved, and we discussed why it is important for securing funding, guiding operations, and reducing business risks.\' The teacher then asks: \'Can someone define a business plan in their own words?\' and \'Mention two reasons why an entrepreneur needs a business plan before starting a business.\'', '* Were all learners able to clearly define the term \'business plan\' and explain its importance in their own words during class presentations?\n* Did the brainstorming activity generate sufficient learner engagement and diverse ideas, or did some groups struggle to identify the importance of a business plan?\n* Which learners need additional support in understanding how a business plan reduces business risks and helps secure funding, and what strategies can I use to reinforce this concept in the next lesson?', 'Learners should interview a local business owner (shopkeeper, tailor, farmer, or mechanic) in their community and ask whether they had a plan before starting their business and what challenges they faced. They should write a brief summary (one paragraph) of the interview in their exercise books to share in the next lesson.', '2026-04-11 12:06:49', '2026-04-11 12:06:49'),
(86, 205, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.3 Business Plan', '', '', NULL, '', NULL, 'a) Identify the key components of a business plan.', 'b) Describe the executive summary and business description components.', '', 'What are the essential components that make up a complete business plan, and why are the executive summary and business description important?', 'Critical thinking and problem solving: learners analyse market needs and competition, then design a viable business plan that addresses a real community opportunity.\nCreativity and imagination: learners develop innovative business ideas and create compelling, original business plans.\nSelf-efficacy: learners develop confidence in their entrepreneurial ability through the process of planning and presenting a business idea.\nCommunication and collaboration: learners work in groups to research, draft and pitch their business plan to peers or invited evaluators.', 'Entrepreneurship education: learners apply the full entrepreneurial process — idea generation, market research, financial planning, marketing and evaluation — in developing their business plan.\nCareer guidance: business plan development prepares learners for self-employment and entrepreneurial careers in technical fields.\nESD: learners incorporate environmental sustainability considerations into their business plan.\nLife skills education: learners develop research, writing, financial literacy and presentation skills through the business planning process.', 'Integrity: learners produce realistic, accurate financial projections and honestly assess the strengths and weaknesses of their business idea.\nResponsibility: learners take ownership of the planning process, meet deadlines and produce a well-organised plan.\nSocial justice: learners consider the social and environmental impact of their proposed business on the community.\nUnity: learners collaborate respectfully, valuing each team member\'s contribution to the business plan.', '* Learners textbook\n* Sample business plans from local businesses (posho mill, salon, agro-vet)\n* Chart paper and markers for group presentations\n* Teacher\'s smartphone/tablet to show a simple business plan template', 'The teacher begins by asking learners to imagine they want to start a small business selling mandazi or repairing bicycles in their community, then poses the question: \'If you needed to borrow money from someone to start this business, what information would they want to know before giving you the money?\' The teacher invites 3–4 learners to share their thoughts aloud, then explains that today they will learn about the business plan—a document that answers all these questions and more—and discover its essential parts, focusing especially on the executive summary and business description.', '• Identify, in groups, key components of a business plan and present findings.', '', '', 'The teacher summarises that a complete business plan has several key components working together, and that the executive summary gives a snapshot of the entire plan while the business description explains what the business does, who it serves, and what makes it unique. The teacher then asks: \'Can someone name at least four components of a business plan that we identified today?\' and \'Why is the executive summary called a summary, and where does it appear in the business plan even though it summarises everything?\'', '* Were all groups able to correctly identify at least four key components of a business plan during the group activity?\n* Did learners clearly understand the difference between the executive summary and the business description, or did some confuse the two?\n* Which learners or groups struggled with presenting their findings, and what support do they need in communicating business concepts?', 'Learners should identify one real business in their community (a shop, salon, garage, or farm) and write a short paragraph describing what that business does, who its customers are, and what makes it different from competitors—practising the business description component learned today.', '2026-04-11 12:07:01', '2026-04-11 12:07:01'),
(87, 206, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.3 Business Plan', '', '', NULL, '', NULL, 'a) Identify the specific sections of a business plan template.', 'b) Populate the business description and market analysis sections for a project.', '', 'What are the key sections of a business plan and how do you write a clear business description and market analysis for your project?', 'Critical thinking and problem solving: learners analyse market needs and competition, then design a viable business plan that addresses a real community opportunity.\nCreativity and imagination: learners develop innovative business ideas and create compelling, original business plans.\nSelf-efficacy: learners develop confidence in their entrepreneurial ability through the process of planning and presenting a business idea.\nCommunication and collaboration: learners work in groups to research, draft and pitch their business plan to peers or invited evaluators.', 'Entrepreneurship education: learners apply the full entrepreneurial process — idea generation, market research, financial planning, marketing and evaluation — in developing their business plan.\nCareer guidance: business plan development prepares learners for self-employment and entrepreneurial careers in technical fields.\nESD: learners incorporate environmental sustainability considerations into their business plan.\nLife skills education: learners develop research, writing, financial literacy and presentation skills through the business planning process.', 'Integrity: learners produce realistic, accurate financial projections and honestly assess the strengths and weaknesses of their business idea.\nResponsibility: learners take ownership of the planning process, meet deadlines and produce a well-organised plan.\nSocial justice: learners consider the social and environmental impact of their proposed business on the community.\nUnity: learners collaborate respectfully, valuing each team member\'s contribution to the business plan.', '* Learners textbook\n* Sample business plan templates (printed or drawn on manila paper)\n* Chart paper or manila paper for group work\n* Writing materials (pens, pencils, erasers)\n* Sample local business examples (e.g. kiosk, poultry, vegetable selling)', 'The teacher begins by asking learners to imagine they want to start a small business selling mandazi or repairing bicycles in their community, then poses the question: \'If you went to ask for a loan from a bank or a relative to start this business, what information would they want to know before giving you money?\' The teacher writes 3-4 learner responses on the chalkboard (such as \'How much money do you need?\', \'Who will buy?\', \'How will you make profit?\'), then explains that today they will learn how a business plan organizes all this information into clear sections, focusing specifically on describing the business and analyzing the market.', '• Identify, in pairs, the sections of a business plan template.', '• Fill in the business description and market analysis sections for a chosen project.', '', 'The teacher summarizes that a complete business plan has several key sections, and today learners practiced filling in two critical ones: the business description (what the business does, its goals and unique features) and market analysis (who the customers are, competitors and market opportunities). The teacher then asks: \'Which section tells potential investors exactly what product or service your business will offer?\' and \'Why is it important to identify your competitors in the market analysis section?\' before collecting learners\' drafts for review.', '* Were all learner pairs able to correctly identify at least five key sections of a business plan template from their textbooks or the examples provided?\n* Did learners demonstrate clear understanding of the difference between business description and market analysis when filling in their chosen project sections, or did they confuse the two?\n* Which pairs struggled with writing a realistic market analysis for their community context, and what additional support or examples do they need in the next lesson?', 'Learners should interview two local business owners (such as a shopkeeper, tailor, or farmer selling produce) and ask them: \'Who are your main customers?\' and \'Who else sells similar products in this area?\' Then write a short paragraph describing what they learned about real market analysis in their community, to share in the next lesson.', '2026-04-11 12:23:01', '2026-04-11 12:23:01'),
(88, 207, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.3 Business Plan', '', '', NULL, '', NULL, 'a) Complete the marketing plan and financial projection sections of the template.', 'b) Present the completed business plan to peers for review.', '', 'How can you effectively communicate the marketing strategy and financial viability of your business idea to convince potential investors or partners?', 'Critical thinking and problem solving: learners analyse market needs and competition, then design a viable business plan that addresses a real community opportunity.\nCreativity and imagination: learners develop innovative business ideas and create compelling, original business plans.\nSelf-efficacy: learners develop confidence in their entrepreneurial ability through the process of planning and presenting a business idea.\nCommunication and collaboration: learners work in groups to research, draft and pitch their business plan to peers or invited evaluators.', 'Entrepreneurship education: learners apply the full entrepreneurial process — idea generation, market research, financial planning, marketing and evaluation — in developing their business plan.\nCareer guidance: business plan development prepares learners for self-employment and entrepreneurial careers in technical fields.\nESD: learners incorporate environmental sustainability considerations into their business plan.\nLife skills education: learners develop research, writing, financial literacy and presentation skills through the business planning process.', 'Integrity: learners produce realistic, accurate financial projections and honestly assess the strengths and weaknesses of their business idea.\nResponsibility: learners take ownership of the planning process, meet deadlines and produce a well-organised plan.\nSocial justice: learners consider the social and environmental impact of their proposed business on the community.\nUnity: learners collaborate respectfully, valuing each team member\'s contribution to the business plan.', '* Learners textbook\n* Business plan templates (printed or handwritten copies)\n* Sample business plans from local enterprises\n* Chart paper or manila paper for presentations\n* Markers or colored chalk for visual aids', 'The teacher begins by asking learners to recall the business idea they have been developing over the previous lessons and to think about this question: \'If you had only two minutes to convince someone to invest money in your business, what would you tell them?\' The teacher invites 2-3 volunteers to share their answers, then explains that today they will complete the marketing and financial sections of their business plan—the parts that show investors exactly how the business will attract customers and make profit.', '• Complete the remaining sections of the business plan template in pairs.', '• Share the completed business plan with the class for feedback.', '', 'The teacher summarises by reminding learners that a complete business plan must clearly show both how customers will be reached (marketing strategy) and how the business will earn more than it spends (financial projections), because investors need proof that the idea is viable. The teacher then asks: \'What are the two main sections you completed in your business plan today?\' and \'Why is it important to present realistic financial projections rather than exaggerated numbers?\' before collecting sample plans for review.', '* Were all learner pairs able to complete both the marketing plan and financial projection sections with sufficient detail and accuracy?\n* During the peer presentation and feedback activity, did learners demonstrate understanding of how to assess the viability of a business idea, or did they struggle to give constructive comments?\n* Which pairs need additional support with financial calculations or marketing strategy concepts before finalising their business plans?', 'Learners should interview one local business owner (shop, kiosk, tailor, mechanic, farmer) in their community and ask them how they attract customers and how they keep track of money coming in and going out. They should write a half-page summary of what they learned to share in the next lesson.', '2026-04-11 12:23:15', '2026-04-11 12:23:15'),
(89, 208, 'Grade 9', 'Pre-Technical Studies', '5.0 Entrepreneurship', '5.3 Business Plan', '', '', NULL, '', NULL, 'a) Discuss how a business plan helps in solving common entrepreneurial challenges.', 'b) Evaluate personal understanding of business planning through a structured exercise.', '', 'How does a well-prepared business plan help entrepreneurs overcome challenges and achieve business growth?', 'Critical thinking and problem solving: learners analyse market needs and competition, then design a viable business plan that addresses a real community opportunity.\nCreativity and imagination: learners develop innovative business ideas and create compelling, original business plans.\nSelf-efficacy: learners develop confidence in their entrepreneurial ability through the process of planning and presenting a business idea.\nCommunication and collaboration: learners work in groups to research, draft and pitch their business plan to peers or invited evaluators.', 'Entrepreneurship education: learners apply the full entrepreneurial process — idea generation, market research, financial planning, marketing and evaluation — in developing their business plan.\nCareer guidance: business plan development prepares learners for self-employment and entrepreneurial careers in technical fields.\nESD: learners incorporate environmental sustainability considerations into their business plan.\nLife skills education: learners develop research, writing, financial literacy and presentation skills through the business planning process.', 'Integrity: learners produce realistic, accurate financial projections and honestly assess the strengths and weaknesses of their business idea.\nResponsibility: learners take ownership of the planning process, meet deadlines and produce a well-organised plan.\nSocial justice: learners consider the social and environmental impact of their proposed business on the community.\nUnity: learners collaborate respectfully, valuing each team member\'s contribution to the business plan.', '* Learners textbook\n* Sample business plan templates or examples (teacher-prepared handouts or drawn on chalkboard)\n* Charts showing common business challenges and solutions\n* Exercise books and pens', 'The teacher begins by holding up two pieces of paper: one blank and one with a simple hand-drawn map showing a route from school to the market. The teacher asks learners, \'If you were traveling to a new town to sell your products, which paper would help you succeed—the blank one or the map?\' After brief responses, the teacher connects this to today\'s lesson by explaining that just as a map guides a traveler and helps avoid getting lost, a business plan guides an entrepreneur and helps overcome challenges and grow the business.', '• Discuss, in groups, the role of a business plan in addressing business risks and growth.', '• Work individually on a summative assessment exercise on business plans.', '', 'The teacher summarizes by reminding learners that a well-prepared business plan is like a roadmap that helps entrepreneurs identify risks early, secure funding, guide daily decisions, and measure progress toward growth. The teacher then asks two questions: \'Can someone name two specific challenges that a business plan helps an entrepreneur overcome?\' and \'How does having financial projections in your business plan help you achieve business growth?\' The teacher invites three learners to respond and affirms correct answers.', '* Were all learners able to discuss at least two ways a business plan helps solve entrepreneurial challenges during the group discussion?\n* Did the summative assessment exercise reveal any common misconceptions about business planning that I need to address in the next lesson?\n* Which learners struggled with evaluating their own understanding during the individual exercise, and what additional support or scaffolding do they need?', 'Learners should interview one local business owner (shopkeeper, tailor, farmer, or artisan) in their community and ask them to describe one major challenge they faced when starting their business and whether they had any plan to address it. Learners should write a short paragraph summarizing the interview and explain how a proper business plan might have helped that entrepreneur overcome the challenge.', '2026-04-11 12:23:27', '2026-04-11 12:23:27'),
(91, 510, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.1 Whole Numbers', '', '', NULL, '', NULL, 'a) Determine the total value of digits in numbers up to millions.', 'b) Calculate the value of specific digits within a seven-digit figure.', '', 'How can we determine the value that each digit contributes to a number up to millions?', 'Critical thinking and problem solving - learners calculate digit values by applying place value concepts.', 'Social cohesion - learners work cohesively with peers to solve number problems.', 'Unity - learners harmoniously work in pairs or groups to identify digit values.', '* Learners textbook\r\n* Place value chart drawn on manila paper or chalkboard\r\n* Number cards made from cardboard (0-9)\r\n* Sticks or stones bundled in groups to represent place values', 'Recap of last lesson: reading and writing numbers up to millions. Who can remind us what we learned? Today\'s lesson is: Determining the total value of digits in numbers. Imagine you are counting money saved in a community fund. The total is a large number. How can we find out how much each digit, like the 5 or the 7, is actually worth?', 'Engage in an interactive demonstration of total value by responding to guiding questions and completing steps.', 'Perform or solve total value exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned today? Can someone give an example of finding a digit\'s value? Today we learned to determine the total value of digits in a number and calculate the value of specific digits in seven-digit figures. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did you calculate the total value of digits?* Did you find it easy to identify the value of a specific digit?* What was the most challenging part of the lesson?', 'At home, write down a seven-digit number from a newspaper or a family member. Using a piece of paper, calculate the total value of all its digits. Then, pick one digit and explain its value to someone in your household.', '2026-04-11 12:24:18', '2026-04-12 08:23:36');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(92, 511, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.1 Whole Numbers', '', '', NULL, '', NULL, 'a) Read numbers up to 100,000 in words correctly.', 'b) Write given figures up to 100,000 in word form with correct spelling.', '', 'How can we correctly read and write large numbers up to 100,000 in words?', 'Critical thinking and problem solving - learners form different numbers by rearranging digits', 'Social cohesion - learners work cohesively with peers to read and write numbers', 'Unity - learners harmoniously work in pairs or groups', '* Learners textbook\n* Number charts showing numbers up to 100,000\n* Chalkboard and chalk\n* Manila paper or cardboard for making number cards', 'Recap of last lesson: reading and writing numbers up to 10,000. Who can remind us what we learned? Today\'s lesson is: Reading and Writing Numbers up to 100,000 in Words. Imagine you hear a news report about a large crowd at a national event. The reporter says there were many thousands of people. How would you write that number down in words?', 'Engage in an interactive demonstration of reading and writing numbers by responding to guiding questions and completing steps.', 'Perform or solve writing exercises individually in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we practiced today? Can someone give an example of a number they wrote in words? Today we learned to correctly read and say large numbers, and to write their word forms with proper spelling. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How confident are you in reading numbers like 78,432 aloud?\n* Did you find any number words tricky to spell correctly?\n* Can you think of a real place where you might see numbers written in words?', 'Find numbers written in figures in an old newspaper, calendar, or product packaging at home. Choose three numbers between 10,000 and 100,000 and write them correctly in words in your exercise book.', '2026-04-11 12:24:33', '2026-04-12 08:23:48'),
(93, 512, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.1 Whole Numbers', '', '', NULL, '', NULL, 'a) Compare numbers up to 100,000 using symbols (<, >).', 'b) Arrange a set of numbers up to 100,000 in ascending order.', '', 'How can we use comparison symbols and ordering to show which numbers are greater or smaller when working with numbers up to 100,000?', 'Critical thinking and problem solving - learners compare and order numbers logically', 'Social cohesion - learners work cohesively with peers to order numbers', 'Unity - learners harmoniously work in pairs or groups', '* Learners textbook\n* Number cards (0-9) made from cardboard or paper\n* Chalkboard and chalk\n* Chart showing symbols <, >, = with examples', 'Recap of last lesson: reading and writing numbers up to 100,000. Who can remind us what we learned? Today\'s lesson is: comparing and ordering numbers up to 100,000. Imagine you are comparing the number of people in two different villages or the prices of two items in the market. How would you decide which number is bigger or smaller?', 'Engage in an interactive demonstration of ascending order by responding to guiding questions and completing steps.', 'Perform or solve ordering exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what the symbols < and > mean? Can someone give an example of two numbers in ascending order? Today we learned how to compare numbers using greater than and less than symbols, and how to arrange a set of numbers from smallest to largest. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly use the symbols < and >?* Could learners arrange numbers in ascending order?* Were learners able to explain their comparison steps?', 'At home, collect price lists from different shops or count items like maize cobs or stones. Write down five different numbers you find. Compare them using < and >, then arrange them in ascending order in your exercise book.', '2026-04-11 12:24:46', '2026-04-12 08:23:59'),
(94, 513, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.1 Whole Numbers', '', '', NULL, '', NULL, 'a) Arrange a set of numbers up to 100,000 in descending order.', 'b) Identify the largest and smallest numbers in a provided set.', '', 'How can we arrange numbers from greatest to smallest and identify which number is the largest or smallest in a set?', 'Critical thinking and problem solving - learners rearrange digits to form and order different numbers', 'Social cohesion - learners work cohesively with peers to order numbers', 'Unity - learners harmoniously work in pairs or groups to order numbers', '* Learners textbook\n* Number cards (0-9 digits written on cardboard pieces)\n* Chalkboard and chalk\n* Exercise books and pencils', 'Recap of last lesson: we were working with large numbers. Who can remind us what we learned about place value? Today\'s lesson is: Arranging numbers from greatest to smallest. Imagine you and your friends are comparing the number of steps you took to school. You each have a different count. How would you decide who took the most steps?', 'Engage in an interactive demonstration of descending order by responding to guiding questions and completing steps.', 'Perform or solve ordering exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what we learned to do with a set of numbers today? Can someone explain the steps to arrange numbers in descending order? Today we learned how to arrange numbers up to 100,000 from greatest to smallest and how to pick out the largest and smallest numbers. Remember to try the extended activity at home to practise this skill.', '* Did all learners correctly arrange numbers in descending order?\n* Were learners able to explain the process of comparing digits?\n* How can I support learners who struggled to identify the smallest number?', 'At home, collect different numbers from items like maize flour packets, newspaper dates, or radio station frequencies. Write down five different numbers you find and arrange them from the greatest to the smallest in your exercise book.', '2026-04-11 12:24:59', '2026-04-12 08:24:11'),
(95, 514, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.1 Whole Numbers', '', '', NULL, '', NULL, 'a) Identify the thousands digit and the rounding digit (hundreds).', 'b) Round off whole numbers up to 100,000 to the nearest thousands.', '', 'How can we round off whole numbers up to 100,000 to the nearest thousand?', 'Critical thinking and problem solving - learners apply a rule to round numbers accurately.', 'Social cohesion - learners work cohesively with peers to solve rounding exercises.', 'Unity - learners harmoniously work in pairs or groups during activities.', '* Learners textbook\n* Number charts showing place values up to hundred thousands\n* Chalkboard and chalk\n* Sticks or stones (for demonstrating grouping in thousands)', 'Recap of last lesson: reading and writing whole numbers up to 100,000. Who can remind us what we learned? Today\'s lesson is: rounding whole numbers to the nearest thousand. Imagine you are estimating the number of people at a large market. You might say \'about 12,000 people\' instead of an exact number. Why do you think we make such estimates?', 'Engage in an interactive demonstration of rounding to the nearest thousand by responding to guiding questions and completing steps.', 'Perform or solve rounding exercises individually in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step in rounding a number to the nearest thousand? Can someone give an example of a number they rounded today? Today we learned to identify the thousands digit and the hundreds digit, and then use the rule to round up or down. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly identify the thousands digit?* How well did learners apply the rounding rule?* Can learners explain why rounding is useful?', 'At home, look at numbers in newspapers, on product prices, or on signposts. Find five numbers between 10,000 and 100,000 and round each one to the nearest thousand. Write the original number and your rounded answer in your exercise book.', '2026-04-11 12:25:11', '2026-04-12 08:24:24'),
(96, 515, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.1 Whole Numbers', '', '', NULL, '', NULL, 'a) Identify the tens of thousand digit.', 'b) Round off whole numbers up to 100,000 to the nearest tens of thousand.', '', 'How can we round whole numbers to the nearest tens of thousands to make estimation easier in everyday situations?', 'Critical thinking - identify place value, Problem solving - round numbers', 'Social cohesion - work together, Safety - discuss road safety', 'Unity - collaborate to solve problems', '* Learners textbook\n* Number charts showing place value up to hundred thousands\n* Number cards (10,000 to 100,000)\n* Chalkboard and chalk\n* Manila paper or cardboard for making place value charts', 'Recap of last lesson: Whole numbers. Today\'s lesson is: Rounding numbers. Imagine shopping and needing to estimate prices. How do we round prices?', 'Engage in an interactive demonstration of rounding to the tens of thousands by responding to guiding questions and completing steps.', 'Perform or solve rounding exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what we learned today? Can someone give an example? Today we learned rounding numbers. As you go home, remember to complete the extended activity.', '* What is rounding? \n* Why round numbers? \n* Can you round a number?', 'Estimate prices of items at home by rounding numbers.', '2026-04-11 12:25:24', '2026-04-12 08:24:26'),
(97, 516, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.1 Whole Numbers', '', '', NULL, '', NULL, 'a) Multiply a whole number by itself to find its square.', 'b) Calculate the squares of whole numbers up to 100 accurately.', '', 'How can we find the result when a whole number is multiplied by itself?', 'Critical thinking and problem solving - learners calculate squares and solve related problems', 'Social cohesion - learners work cohesively to identify square roots', 'Unity - learners harmoniously work in pairs or groups', '* Learners textbook\n* Chalkboard and chalk\n* Multiplication tables chart\n* Exercise books and pencils\n* Squared paper or ruled exercise books for organizing calculations', 'Recap of last lesson: multiplication of whole numbers. Who can remind us what we learned? Today\'s lesson is: Finding the square of a whole number. Imagine a farmer plants maize in a square plot. Each side of the plot has the same number of plants. How can we find the total number of plants in the whole plot?', 'Engage in an interactive demonstration of squares by responding to guiding questions and completing steps.', 'Perform or solve square exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what we learned today? Can someone give an example of a square number? Today we learned how to multiply a number by itself to find its square, and we calculated squares of numbers up to 100. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly calculate squares up to 100?\n* How well did learners explain the concept of \'a number multiplied by itself\'?\n* Were learners able to connect squares to the real-life scenario?', 'At home, find square-shaped items like tiles or windows. Count the number of small squares along one side. Multiply this number by itself to find the total number of small squares. Record your findings.', '2026-04-11 12:25:38', '2026-04-12 08:24:38'),
(98, 517, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.1 Whole Numbers', '', '', NULL, '', NULL, 'a) Identify the square root of perfect squares up to 10,000.', 'b) Use the factor tree or inverse method to find square roots.', '', 'How can we find the original number when we know its square?', 'Critical thinking and problem solving - learners use factor trees to find square roots', 'Social cohesion - learners work cohesively to identify square roots', 'Unity - learners harmoniously work in pairs or groups', '* Learners textbook\n* Multiplication tables chart\n* Number cards (1-100)\n* Chalkboard and chalk\n* Exercise books', 'Recap of last lesson: squares of whole numbers. Who can remind us what we learned? Today\'s lesson is: Finding square roots of perfect squares. Imagine a farmer has a square plot of land with an area of 81 square metres. How can we find the length of one side of the plot? What operation would help us find this?', 'Engage in an interactive demonstration of square roots by responding to guiding questions and completing steps.', 'Perform or solve square root exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what we learned today? Can someone give an example of a perfect square and its square root? Today we learned to identify square roots of numbers up to 10,000 and use methods like factor trees to find them. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did learners identify perfect squares?* Did learners correctly use the factor tree method?* Were learners able to explain the inverse relationship?', 'At home, find 9 identical bottle caps or stones. Arrange them into a perfect square shape. Write down the total number of items and the number in each row. This is the square root. Try with 16 items.', '2026-04-11 12:25:50', '2026-04-12 08:24:49'),
(99, 518, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.1 Whole Numbers', '', '', NULL, '', NULL, 'a) Solve real-life problems involving whole numbers (place value, rounding, and squares).', 'b) Evaluate personal progress through a summary exercise.', '', 'How can we use our understanding of place value, rounding, and squares to solve problems we encounter in our daily lives?', 'Critical thinking and problem solving - learners form numbers by rearranging digits to solve problems', 'Social cohesion - learners work cohesively to identify square roots, Safety - learners discuss road safety using number charts', 'Unity - learners harmoniously identify total value using place value', '* Learners textbook\n* Chart paper or chalkboard for reviewing key concepts\n* Locally available items for real-life problem scenarios (stones for counting, sticks for grouping)\n* Exercise books and pencils', 'Recap of last lesson: whole numbers. Who can remind us what we learned about place value? Today\'s lesson is: Solving Real-Life Problems Using Whole Numbers. Imagine you are helping to count the number of bricks needed to build a classroom wall. You need to round the number and check if the total is a perfect square. How would you use your maths skills to solve this?', 'Engage in an interactive review of whole numbers by responding to guiding questions and completing steps.', 'Perform or solve a summary assessment exercise individually using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one real-life problem we solved today? Can someone explain how rounding helped? Today we learned to apply place value and rounding to solve problems, and we evaluated our own progress. Remember to complete the extended activity at home to practise these skills further.', '* Did I correctly apply place value to solve the problems?\n* How did rounding numbers make the problems easier to handle?\n* Can I explain what a square number is using an example?', 'At home, find a large number from a newspaper, receipt, or product packaging. Write it down, identify the place value of each digit, round it to the nearest hundred, and check if it is a square number. Share your findings.', '2026-04-11 12:26:04', '2026-04-12 08:25:02'),
(100, 519, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.2 Multiplication', '', '', NULL, '', NULL, 'a) Multiply a 4-digit number by a 1-digit number accurately.', '', '', 'How do we multiply a 4-digit number by a 1-digit number?', 'Creativity and imagination - learners make patterns using number cards for multiplication.', 'Self-esteem - learner builds confidence by estimating products through rounding.', 'Integrity - learner demonstrates honesty in their multiplication results.', '', 'Recap of last lesson: multiplying 3-digit numbers by 1-digit numbers. Who can remind us what we learned? Today\'s lesson is: Multiplying a 4-digit number by a 1-digit number. Imagine a farmer harvested 2,345 bags of maize and wants to store them equally in 3 stores. How would we find the total? What steps would you take?', 'Engage in an interactive demonstration of multiplication by responding to guiding questions and completing steps.', 'Perform or solve multiplication exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main steps we used for multiplication today? Can someone give an example of a 4-digit number multiplied by a 1-digit number? Today we learned to multiply a 4-digit number by a 1-digit number using place value and carrying over. Remember to complete the extended activity at home to practise what you have learned today.', '* Did I correctly use place value when multiplying?* How did I handle carrying over digits?* Can I explain the steps to a friend?', 'At home, use small stones or seeds to represent numbers. Create your own 4-digit number (e.g., 3,214) and multiply it by a 1-digit number (like 4) by grouping your items. Write down your calculation and answer in your exercise book.', '2026-04-11 12:26:18', '2026-04-12 08:25:15'),
(101, 520, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.2 Multiplication', '', '', NULL, '', NULL, 'a) Multiply a 4-digit number by a 2-digit number using long multiplication.', '', '', 'How can we use the long multiplication method to multiply a 4-digit number by a 2-digit number?', 'Creativity and imagination - learners make patterns with number cards involving multiplication.', 'Self-esteem - learner develops confidence by estimating products using rounding.', 'Integrity - learner demonstrates honesty in their multiplication results.', '* Learners textbook\r\n* Chalkboard and chalk\r\n* Exercise books and pencils\r\n* Place value cards made from cardboard', 'Recap of last lesson: multiplying 3-digit numbers. Who can remind us what we learned? Today\'s lesson is: Multiplying a 4-digit number by a 2-digit number using long multiplication. Imagine a farmer harvested 2,345 bags of maize and sells each bag for 45 shillings. How can we find the total money? What steps would we take?', 'Engage in an interactive demonstration of multiplication by responding to guiding questions and completing steps.', 'Perform or solve multiplication exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step in long multiplication for our lesson? Can someone explain why we write a zero in the second row? Today we learned to multiply a 4-digit number by a 2-digit number using the long multiplication method, aligning digits by place value and adding partial products. Remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly align numbers by place value?* Did learners understand the purpose of the zero placeholder?* Can learners explain the steps for adding partial products?', 'At home, find a large number, like the year or a page number from a book. Multiply it by a 2-digit number of your choice using long multiplication. Show your working in your exercise book.', '2026-04-11 12:26:31', '2026-04-12 08:25:27'),
(102, 521, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.2 Multiplication', '', '', NULL, '', NULL, 'a) Estimate products using the compatibility of numbers.', '', '', 'How can we use compatible numbers to estimate the product before multiplying?', 'Creativity and imagination - learners make patterns with number cards, Learning to learn - learners apply estimation strategies to simplify multiplication', 'Self-esteem - learner gains confidence from successful estimation', 'Integrity - learner demonstrates honesty in their calculation results', '* Learners textbook\n* Chalkboard and chalk\n* Number cards (0-9) made from cardboard or paper\n* Chart showing multiplication tables', 'Recap of last lesson: multiplying whole numbers. Who can remind us what we learned? Today\'s lesson is: Estimating Products Using Compatible Numbers. Imagine you are helping a shopkeeper quickly estimate the cost of 48 packets of sugar, each costing 23 shillings, without a calculator. How would you make the numbers easier to multiply in your head?', 'Engage in an interactive demonstration of multiplication by responding to guiding questions and completing steps.', 'Perform or solve multiplication exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about estimating products today? Can someone give an example of a compatible number pair? Today we learned to estimate products by rounding factors to compatible numbers that are easy to multiply mentally. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How did using compatible numbers make estimation easier?\n* What was a challenge when choosing compatible numbers?\n* How can you use this skill outside the classroom?', 'At home, find three items with prices (e.g., maize flour, soap). Estimate the total cost for 9 of each item by rounding the prices to compatible numbers. Record your estimates and the actual prices if possible.', '2026-04-11 12:26:43', '2026-04-12 08:25:40'),
(103, 522, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.2 Multiplication', '', '', NULL, '', NULL, 'a) Create patterns involving multiplication of numbers not exceeding 1,000.', '', '', 'How can we create and extend patterns using multiplication of numbers up to 1,000?', 'Creativity and imagination - learners design unique patterns using multiplication with number cards', 'Self-esteem - learners gain confidence by successfully creating and explaining their patterns', 'Integrity - learners demonstrate honesty in calculating and recording their pattern results', '* Learners textbook\n* Multiplication tables chart\n* Number cards (1-100) made from cardboard or paper\n* Exercise books and pencils\n* Chalkboard and chalk', 'Recap of last lesson: multiplication of whole numbers. Who can remind us what we learned? Today\'s lesson is: Creating patterns using multiplication. Imagine you are arranging seeds in rows to plant a garden. You plant 5 seeds in the first row, 10 in the next, and 15 in the next. What pattern do you see? How would you continue it?', 'Engage in an interactive demonstration of multiplication patterns by responding to guiding questions and completing steps.', 'Perform or solve pattern exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about patterns today? Can someone give an example of a multiplication pattern they created? Today we learned to create and extend patterns by multiplying numbers, using rules like \'multiply by 2\'. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners successfully create their own multiplication patterns?\n* Were learners able to explain the rule for extending their patterns?\n* Did the use of number cards enhance creativity in pattern-making?', 'At home, create a multiplication pattern using items like maize grains or stones. Arrange them in groups (e.g., 3, 6, 12, ...) and write the number pattern in your exercise book. Explain the multiplication rule you used to a family member.', '2026-04-11 12:26:55', '2026-04-12 08:25:53'),
(104, 523, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.3 Division', '', '', NULL, '', NULL, 'a) Identify the steps of dividing a 4-digit number by a 2-digit number.', 'b) Divide a 4-digit number by a 2-digit number without a remainder.', '', 'How can we break down dividing a large number into simple, manageable steps?', 'Communication and collaboration - learners discuss division steps and share answers in groups.', 'Safety - learners use local materials like seeds or stones carefully during division activities.', 'Unity - learners work together amicably in groups to solve division problems.', '* Learners textbook\n* Chalkboard and chalk\n* Multiplication tables chart\n* Exercise books and pencils', 'Recap of last lesson: dividing 3-digit numbers. Who can remind us what we learned? Today\'s lesson is: Dividing a 4-digit number by a 2-digit number. Imagine your school has collected 1,200 seeds to share equally among 24 clubs. How would you find out how many seeds each club gets? What steps would you take?', 'Engage in an interactive demonstration of division by responding to guiding questions and completing steps.', 'Perform or solve division exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step in dividing a 4-digit number by a 2-digit number? Can someone give an example of a problem we solved? Today we learned to identify the steps for long division and to divide a 4-digit number by a 2-digit number without a remainder. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly identify the division steps?* Did learners perform division accurately without remainders?* Were learners able to explain their working to peers?', 'At home, find a container with many small, similar items like beans or maize grains. Count out a large number (between 1000 and 9999) and practise dividing them into equal groups of a 2-digit number. Record your steps and answer.', '2026-04-11 12:27:09', '2026-04-12 08:26:06'),
(105, 524, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.3 Division', '', '', NULL, '', NULL, 'a) Divide a 4-digit number by a 2-digit number with a remainder.', 'b) State the quotient and the remainder correctly.', '', 'How can we find out how many groups of a 2-digit number fit into a 4-digit number, and what is left over?', 'Communication and collaboration - learners discuss division steps and share answers in groups.', 'Safety - learners use available resources like stones for counting responsibly.', 'Unity - learners work together amicably in groups to solve division problems.', '* Learners textbook\n* Chalkboard and chalk\n* Multiplication tables chart\n* Bundles of sticks (groups of 10s and 100s) for place value demonstration\n* Exercise books and pencils', 'Recap of last lesson: dividing 3-digit numbers by 2-digit numbers. Who can remind us what we learned? Today\'s lesson is: Dividing a 4-digit number by a 2-digit number with a remainder. Imagine a farmer has harvested a large number of maize seeds and wants to pack them into bags. How can we find out how many full bags they can make and what seeds are left over?', 'Engage in an interactive demonstration of division by responding to guiding questions and completing steps.', 'Perform or solve division exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the two main parts of an answer in today\'s division? Can someone explain what a remainder is? Today we learned the steps for dividing a 4-digit number by a 2-digit number and how to correctly state the quotient and remainder. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly identify the quotient and remainder?* How did working with a partner help me understand the steps?* Can I explain the link between multiplication and division?', 'At home, find a container like a cup or bowl. Count a large pile of small items like beans or stones (aim for over 1000). Practise dividing your total count by a 2-digit number, like 12 or 25, to find how many full groups you can make and what is left over.', '2026-04-11 12:27:22', '2026-04-12 08:26:20'),
(106, 525, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.3 Division', '', '', NULL, '', NULL, 'a) Divide a 4-digit number by a 3-digit number without a remainder.', 'b) Work out the steps of long division for 3-digit divisors accurately.', '', 'How can we use long division to solve problems involving sharing or grouping large quantities by hundreds?', 'Communication and collaboration - learners discuss division steps and answers in groups', 'Safety - learners use local materials like stones carefully during group activities', 'Unity - learners work together amicably to solve long division problems', '* Learners textbook\n* Chalkboard and chalk\n* Place value counters or stones (representing thousands, hundreds, tens, ones)\n* Multiplication tables chart', 'Recap of last lesson: dividing 3-digit numbers. Who can remind us what we learned? Today\'s lesson is: Dividing a 4-digit number by a 3-digit number. Imagine your school received a large donation of exercise books to be shared equally among all the classes. How would you figure out how many books each class gets?', 'Engage in an interactive demonstration of division by responding to guiding questions and completing steps.', 'Perform or solve division exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step in long division with a 3-digit divisor? Can someone give an example of a problem we solved today? Today we learned the steps for long division and how to divide a 4-digit number by a 3-digit number without a remainder. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly estimate the first quotient digit?* Did I follow all the steps of long division in order?* Can I explain the relationship between multiplication and division using today\'s example?', 'Find a large number of similar small items at home, like maize grains or stones. Count out a 4-digit quantity and practise dividing it into equal groups of a 3-digit number. Record your steps and answer in your exercise book.', '2026-04-11 12:27:36', '2026-04-12 08:26:33'),
(107, 526, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.3 Division', '', '', NULL, '', NULL, 'a) Divide a 4-digit number by a 3-digit number with a remainder.', 'b) Interpret remainders in real-life division scenarios.', '', 'How do we interpret and use remainders when dividing larger numbers in everyday situations like sharing items or distributing resources?', 'Communication and collaboration - learners discuss division procedures and check answers in pairs', 'Safety - learners handle and share physical counting materials responsibly', 'Unity - learners work together amicably in groups to solve division problems', '* Learners textbook\n* Chalkboard and chalk\n* Counters (beans, stones, or bottle caps)\n* Exercise books and pencils\n* Multiplication table chart', 'Recap of last lesson: dividing 3-digit numbers. Who can remind us what we learned? Today\'s lesson is: Dividing 4-digit numbers and interpreting remainders. Imagine your school has received 1,500 exercise books to share equally among 6 classes. How many books does each class get? What do you do with any books left over?', 'Engage in an interactive demonstration of division by responding to guiding questions and completing steps.', 'Perform or solve division exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the steps we used to divide a 4-digit number today? Can someone give an example of a real-life situation with a remainder? Today we learned to perform long division with larger numbers and how to explain what a remainder means in a practical context. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly calculate the quotient and remainder?* Can I explain what the remainder means in a sharing scenario?* How does multiplication help me check my division answer?', 'At home, find a packet of small items like beans or maize grains. Count out a large number (between 1000 and 2000) and divide them into equal groups for your family members. Record your division sentence and explain any remainder.', '2026-04-11 12:27:50', '2026-04-12 08:26:45'),
(108, 527, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.3 Division', '', '', NULL, '', NULL, 'a) Round off the dividend and divisor to the nearest ten.', 'b) Estimate quotients by dividing the rounded numbers.', '', 'How can rounding numbers help us estimate division answers quickly in everyday situations?', 'Communication and collaboration - learners discuss rounding strategies and estimated answers in groups', 'Safety - learners use everyday materials carefully during practical estimation activities', 'Unity - learners work together amicably in groups to estimate division answers', '* Learners textbook\n* Chalkboard and chalk\n* Number charts showing multiples of 10\n* Exercise books and pencils', 'Recap of last lesson: dividing whole numbers. Who can remind us what we learned? Today\'s lesson is: Estimating Quotients by Rounding. Imagine you are helping at a market stall and need to quickly figure out how many bags of maize you can fill from a large sack. You don\'t need the exact number, just a good estimate. How could you make a quick calculation?', 'Engage in an interactive demonstration of division by responding to guiding questions and completing steps.', 'Perform or solve division exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the two main steps we used today? Can someone give an example of numbers they rounded? Today we learned to round the dividend and divisor to the nearest ten, then divide to get an estimated quotient. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How did rounding make division easier?* When might an estimated quotient be more useful than an exact answer?* What was challenging about rounding both numbers?', 'At home, find a container like a tin or cup. Estimate how many cupfuls of water, soil, or maize grains it would take to fill a larger bucket or basin. Write down your rounded numbers and estimated answer.', '2026-04-11 12:28:03', '2026-04-12 08:26:57'),
(109, 528, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.3 Division', '', '', NULL, '', NULL, 'a) Identify the order of combined operations (BODMAS/PEMDAS).', 'b) Perform combined operations involving addition, subtraction, multiplication, and division.', '', 'How do we decide which operation to perform first when solving a problem with addition, subtraction, multiplication, and division all together?', 'Communication and collaboration - learners discuss the order of operations in groups', 'Safety - learners use available materials like sticks and stones as counters responsibly', 'Unity - learners work together amicably to solve combined operation problems', '* Learners textbook\n* Chalkboard and chalk\n* Chart showing BODMAS/PEMDAS order\n* Locally made flashcards with different operations symbols (+, −, ×, ÷, brackets)', 'Recap of last lesson: division of whole numbers. Who can remind us what we learned? Today\'s lesson is: Order of Combined Operations (BODMAS/PEMDAS). Imagine you are sharing sweets and then buying more with your friends. How do you figure out the total? What should you calculate first?', 'Engage in an interactive demonstration of division by responding to guiding questions and completing steps.', 'Perform or solve division exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the order of operations we learned today? Can someone give an example of a calculation using BODMAS? Today we learned the BODMAS rule and how to solve problems with addition, subtraction, multiplication, and division. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly identify the order of operations in a problem?* Did I successfully solve a combined operation using BODMAS?* Can I explain why division is done before addition in some cases?', 'At home, write a word problem for your family involving buying items and sharing change. Use at least three different operations (+, -, ×, ÷). Solve it using the BODMAS rule you learned.', '2026-04-11 12:28:15', '2026-04-12 08:27:09'),
(110, 529, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.4 Fractions', '', '', NULL, '', NULL, 'a) Define the term Least Common Multiple (LCM).', 'b) Identify the LCM of denominators in given sets of fractions.', '', 'How do we find the LCM of denominators in given fractions?', 'Learning to learn - learners work out multiples to find the LCM', 'Social cohesion - learners work together in groups to calculate LCMs', 'Unity - learners discuss and compare answers harmoniously', '', 'Recap of last lesson: adding and subtracting fractions. Who can remind us what we needed to do first? Today\'s lesson is: Finding the Least Common Multiple (LCM) of denominators. Imagine you and your friends want to share different amounts of ugali from different bowls fairly. To compare the shares, you need a common size for the pieces. What could that common size be?', 'Engage in an interactive demonstration of finding LCM by responding to guiding questions and completing steps.', 'Perform or solve LCM exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about the LCM today? Can someone give an example of two denominators and their LCM? Today we learned that the LCM is the smallest number that denominators can divide into, and we practiced finding it for sets of fractions. Remember to complete the extended activity at home to practise finding LCMs.', '* Did all learners correctly define the term LCM?* Were learners able to identify the LCM of given denominators?* Did the group activities help in understanding the procedure?', 'At home, find three different containers (e.g., cups, bowls). Using a small cup as a measure, determine how many small cups fill each container. Write these as fractions (e.g., 4/1 cups, 6/1 cups). Find the LCM of the denominators to see a common measure.', '2026-04-11 12:28:28', '2026-04-12 08:27:22'),
(111, 530, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.4 Fractions', '', '', NULL, '', NULL, 'a) Use the LCM to add proper fractions with different denominators.', 'b) Work out addition problems involving more than two fractions.', '', 'How can we add fractions with different denominators using the LCM?', 'Learning to learn - learner works out the LCM to add fractions', 'Social cohesion - learner works cohesively with others to calculate sums of fractions', 'Unity - learner works harmoniously with peers to discuss fraction addition', '* Learners textbook\n* Chalkboard and chalk\n* Rectangular and circular paper cut-outs (from old exercise books or newspapers)\n* Counters (stones, seeds, or bottle caps)', 'Recap of last lesson: adding fractions with the same denominator. Who can remind us what we learned? Today\'s lesson is: Adding Fractions with Different Denominators Using the LCM. Imagine you and a friend are sharing different portions of ugali from two separate bowls. To know how much you have altogether, you need to combine the fractions. How can we do that when the portions are not the same size?', 'Engage in an interactive demonstration of adding fractions by responding to guiding questions and completing steps.', 'Perform or solve addition exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step when adding fractions with different denominators? Can someone give an example of finding the LCM for two denominators? Today we learned to find the Least Common Multiple to make denominators the same before adding fractions, and we practised adding more than two fractions. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did you find the LCM for denominators?* Did you correctly convert fractions to equivalent forms?* Can you confidently add three proper fractions now?', 'At home, find three different small containers (like cups or bowls). Use soil, sand, or water to represent fractions like 1/2, 1/3, and 1/4 of each container. Combine them into one larger container and calculate the total fraction of the large container you have filled.', '2026-04-11 12:28:39', '2026-04-12 08:27:35'),
(112, 531, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.4 Fractions', '', '', NULL, '', NULL, 'a) Use the LCM to subtract proper fractions with different denominators.', 'b) Solve subtraction problems involving fractions in real-life contexts.', '', 'How can we use the Least Common Multiple to subtract fractions with different denominators in everyday situations?', 'Learning to learn - learners apply the LCM procedure to solve fraction problems', 'Social cohesion - learners work together in groups to solve subtraction exercises', 'Unity - learners discuss and share steps harmoniously in their groups', '* Learners textbook\n* Circular and rectangular cut-outs (paper or cardboard)\n* Chalkboard and chalk\n* Counters (bottle tops, stones, or seeds)', 'Recap of last lesson: adding fractions with different denominators. Who can remind us what we learned? Today\'s lesson is: Subtracting Fractions Using the Least Common Multiple. Imagine you have two jugs of milk, one with 3/4 litre and another with 1/6 litre. If you pour some from the smaller jug into the larger, how much milk would be left in the smaller jug? How can we find the answer?', 'Engage in an interactive demonstration of subtracting fractions by responding to guiding questions and completing steps.', 'Perform or solve subtraction exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step when subtracting fractions with different denominators? Can someone give an example of a real-life situation where we subtract fractions? Today we learned to find the LCM to get a common denominator and then subtract the numerators. We also applied this to solve simple word problems. Remember to complete the extended activity at home to practise what you have learned today.', '* Did I correctly find the LCM of the denominators?* Did I remember to subtract the numerators after making equivalent fractions?* Can I explain the steps to a family member?', 'At home, find two different containers (e.g., a cup and a bowl). Imagine they are partially filled with water (e.g., 1/2 and 1/3 full). Write and solve a subtraction problem to find the difference. Use the LCM method from today\'s lesson.', '2026-04-11 12:28:52', '2026-04-12 08:27:49'),
(113, 532, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.4 Fractions', '', '', NULL, '', NULL, 'a) Convert mixed numbers into improper fractions for addition.', 'b) Add mixed numbers by grouping whole numbers and fractions separately.', '', 'How can we add mixed numbers by converting them to improper fractions or by grouping whole numbers and fractions separately?', 'Learning to learn - learners work out procedures for adding mixed numbers', 'Social cohesion - learners work together in groups to calculate sums', 'Unity - learners work harmoniously with peers to discuss solutions', '* Learners textbook\n* Chalkboard and chalk\n* Rectangular paper cut-outs or cardboard pieces\n* Locally available counters (stones, seeds, or bottle caps)', 'Recap of last lesson: converting improper fractions to mixed numbers. Who can remind us what we learned? Today\'s lesson is: Adding Mixed Numbers. Imagine you have two small sacks of maize flour, one with 2 and a half kilos and another with 1 and a quarter kilos. How would you find the total amount of flour you have?', 'Engage in an interactive demonstration of adding mixed numbers by responding to guiding questions and completing steps.', 'Perform or solve addition exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the two methods we used to add mixed numbers today? Can someone give an example using one of the methods? Today we learned to add mixed numbers by converting to improper fractions and by grouping whole numbers and fractions separately. Remember to complete the extended activity at home to practise what you have learned today.', '* Did learners correctly convert mixed numbers to improper fractions for addition?\n* Were learners able to group whole numbers and fractions separately to find sums?\n* Did the practical activities using local materials improve understanding?', 'At home, find two different containers. Fill one with 2 and 1/3 cups of water and another with 1 and 1/2 cups. Use your knowledge of adding mixed numbers to calculate the total amount of water. Record your method and answer.', '2026-04-11 12:29:05', '2026-04-12 08:28:01'),
(114, 533, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.4 Fractions', '', '', NULL, '', NULL, 'a) Convert mixed numbers into improper fractions for subtraction.', 'b) Subtract mixed numbers accurately using the regrouping/borrowing method.', '', 'How can we subtract mixed numbers when the fraction part of the first number is smaller than the fraction part of the second number?', 'Learning to learn - learners work out steps for regrouping mixed numbers', 'Social cohesion - learners work together in groups to solve subtraction exercises', 'Unity - learners discuss and solve problems harmoniously with peers', '* Learners textbook\n* Chalkboard and chalk\n* Circular or rectangular paper cut-outs (for demonstrating fraction parts)\n* Exercise books and pencils', 'Recap of last lesson: subtracting mixed numbers with like fractions. Who can remind us what we learned? Today\'s lesson is: Subtracting Mixed Numbers by Regrouping. Imagine you have a bag of maize flour measured in mixed numbers. If you need to give a friend some, but your fraction part is too small, how do you subtract? How would you solve this problem?', 'Engage in an interactive demonstration of subtracting mixed numbers by responding to guiding questions and completing steps.', 'Perform or solve subtraction exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step when subtracting mixed numbers where the fraction part is too small? Can someone give an example of regrouping? Today we learned to convert mixed numbers to improper fractions and to use regrouping or borrowing to subtract them accurately. Remember to complete the extended activity at home to practise this new skill.', '* How well did I explain converting mixed numbers to improper fractions?\n* Did learners successfully use regrouping in their subtraction?\n* What common errors did I observe during the practice exercises?', 'At home, find two different containers (e.g., cups, bowls). Use them and any available grains or soil to model subtracting mixed numbers that require regrouping. Write down and solve two subtraction problems based on your models.', '2026-04-11 12:29:18', '2026-04-12 08:28:14');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(115, 534, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.4 Fractions', '', '', NULL, '', NULL, 'a) Define the term \"reciprocal\" of a fraction.', 'b) Identify and write the reciprocals of proper fractions up to a 2-digit number.', '', 'How can we find the reciprocal of a proper fraction and use it to solve problems?', 'Learning to learn - learner works out reciprocals of whole numbers before fractions', 'Social cohesion - learners work together to calculate reciprocals', 'Unity - learner works harmoniously with peers discussing reciprocals', '* Learners textbook\n* Chalkboard and chalk\n* Rectangular paper cut-outs or cardboard pieces\n* Exercise books and pencils', 'Recap of last lesson: multiplication of proper fractions. Who can remind us what we learned? Today\'s lesson is: Finding the reciprocal of a proper fraction. Imagine you have a piece of sugarcane to share equally among friends. If each friend gets a fraction of the whole, how can you find the number of friends? What do you think the reciprocal tells us?', 'Engage in an interactive demonstration of reciprocals by responding to guiding questions and completing steps.', 'Perform or solve reciprocal exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what a reciprocal is? Can someone give the reciprocal of a proper fraction like 3/5? Today we learned that the reciprocal of a fraction is found by swapping the numerator and denominator, and we practised finding reciprocals of proper fractions. Remember to complete the extended activity at home to practise what you have learned today.', '* How well did learners define the term reciprocal?* Did learners correctly identify reciprocals of proper fractions?* What challenges did learners face when writing reciprocals?', 'At home, find three proper fractions from items you use, like a fraction of a cup of water or a piece of fruit. Write each fraction and its reciprocal in your exercise book. Explain to a family member how you found the reciprocal.', '2026-04-11 12:29:32', '2026-04-12 08:28:28'),
(116, 535, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.4 Fractions', '', '', NULL, '', NULL, 'a) Multiply a fraction by itself to find its square.', 'b) Calculate squares of fractions with a 1-digit numerator and 2-digit denominator.', '', 'How do we find the square of a fraction by multiplying it by itself?', 'Learning to learn - learner works out the square of fractions through demonstrated procedures', 'Social cohesion - learners work together to calculate squares of fractions', 'Unity - learner works harmoniously with peers during group discussions', '* Learners textbook\n* Chalkboard and chalk\n* Fraction charts or rectangular paper cut-outs to show fractions\n* Exercise books and pencils', 'Recap of last lesson: multiplication of fractions. Who can remind us what we learned? Today\'s lesson is: Finding the square of a fraction. Imagine you have a small square plot of land that is only a fraction of a hectare. To find its total area, you multiply its side length by itself. How do you think we calculate the area when the side is a fraction?', 'Engage in an interactive demonstration of squares of fractions by responding to guiding questions and completing steps.', 'Perform or solve square exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about squaring fractions today? Can someone give an example of a fraction squared? Today we learned that to square a fraction, we multiply it by itself, and we practised calculating squares of fractions with different denominators. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How confident are you in multiplying a fraction by itself?* Did working in a group help you understand the procedure?* Can you explain why squaring a fraction gives a smaller number?', 'At home, find a small square object, like a tile or a piece of paper. Measure one side using a ruler marked in centimetres. If the side is a fraction of the whole centimetre, calculate the area by squaring that fraction. Record your findings.', '2026-04-11 12:29:44', '2026-04-12 08:28:42'),
(117, 536, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.4 Fractions', '', '', NULL, '', NULL, 'a) Define percentage as a fraction with a denominator of 100.', 'b) Convert given fractions into percentages accurately.', '', 'How can we express a fraction as a number out of 100?', 'Learning to learn - learners follow steps to convert fractions to percentages', 'Social cohesion - learners work together in groups to solve conversion exercises', 'Unity - learners discuss and share answers harmoniously in groups', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* 100-square grid drawn on paper or chalkboard (10×10 grid)\n* Fraction charts or circular cut-outs divided into parts', 'Recap of last lesson: converting fractions to decimals. Who can remind us what we learned? Today\'s lesson is: Converting Fractions to Percentages. Imagine you hear that 3 out of 5 learners in a class passed a test. How can we express this performance out of 100 to easily compare it? What would that be?', 'Engage in an interactive demonstration of converting fractions to percentages by responding to guiding questions and completing steps.', 'Perform or solve conversion exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what a percentage is? Can someone show us how to convert a fraction like 3/4 into a percentage? Today we learned that a percentage is a fraction with a denominator of 100, and we practised converting fractions by finding equivalent fractions. Remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly define percentage?* How well did learners convert fractions to percentages?* Did group work enhance understanding of the procedure?', 'At home, find three different fractions from items like a packet of sugar or a bunch of bananas. Convert each fraction into a percentage. Write your work and answers in your exercise book.', '2026-04-11 12:29:54', '2026-04-12 08:28:54'),
(118, 537, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.5 Decimals', '', '', NULL, '', NULL, 'a) Identify the place value of digits in decimals up to ten thousandths.', 'b) Read and write decimal numbers up to four decimal places correctly.', '', 'How can we name and describe the exact position of each digit in a decimal number like 0.2345?', 'Communication and collaboration - learners discuss and explain decimal place values to peers', 'Peer education - learners share strategies for adding decimals using place value apparatus', 'Responsibility - learners handle and take care of locally sourced place value materials', '* Learners textbook\n* Chalkboard and chalk\n* Place value chart drawn on chalkboard or manila paper\n* Exercise books and pencils', 'Recap of last lesson: we looked at decimal numbers up to hundredths. Who can remind us what a decimal point is? Today\'s lesson is: Place Value of Digits in Decimals up to Ten Thousandths. Imagine you are measuring a small amount of medicine or the thickness of a leaf. These very small measurements need precise numbers. How do we name each digit in a number like 0.2345?', 'Engage in an interactive demonstration of decimal place value by responding to guiding questions and completing steps on the chalkboard.', 'Perform or solve place value exercises in exercise books individually using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing they learned about decimal place values today? Can someone give an example of a digit in the thousandths place? Today we learned to identify the place value of digits up to ten thousandths and to read and write such numbers correctly. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did learners identify the ten thousandths place?\n* Did learners correctly read decimal numbers with four decimal places?\n* Were learners able to relate each decimal place to its value?', 'At home, find a small container like a bottle cap. Measure how many cupfuls of water or sand it takes to fill a larger cup, recording amounts like 0.125 or 0.0625 cups. Write these decimals and name the place value of each digit.', '2026-04-11 12:30:06', '2026-04-12 08:29:07'),
(119, 538, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.5 Decimals', '', '', NULL, '', NULL, 'a) Identify the rounding digit for the first decimal place (tenths).', 'b) Round off given decimals to 1 decimal place accurately.', '', 'How do we round off decimals to 1 decimal place?', 'Communication and collaboration - learners discuss place value and rounding rules in pairs.', 'Peer education - learners share and explain their rounding strategies with each other.', 'Responsibility - learners handle and share any locally used materials carefully.', '', 'Recap of last lesson: we were adding decimals. Who can remind us what we learned? Today\'s lesson is: Rounding off decimals to one decimal place. Imagine you are measuring the length of a stick with a ruler. The measurement might be a long decimal, like 12.36 cm. To report it simply, we round it. Why might we want to round such a number?', 'Engage in an interactive demonstration of rounding decimals by responding to guiding questions and completing steps.', 'Perform or solve rounding exercises in exercise books individually using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step in rounding a decimal to one decimal place? Can someone give an example of a number they rounded today? Today we learned to identify the digit in the tenths place and the digit to its right to decide whether to round up or down. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly identify the rounding digit?* Did I check the digit to the right correctly?* Can I explain the rounding rule to a friend?', 'At home, find three items and estimate their lengths or weights using decimals (e.g., a book is 2.37 cm thick). Write each measurement and practise rounding them off to one decimal place in your exercise book.', '2026-04-11 12:30:18', '2026-04-12 08:29:20'),
(120, 539, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.5 Decimals', '', '', NULL, '', NULL, 'a) Identify the rounding digit for the second decimal place (hundredths).', 'b) Round off given decimals to 2 decimal places accurately.', '', 'How can we decide which digit to keep when rounding a decimal number to two decimal places?', 'Communication and collaboration - learners discuss place value and rounding steps in groups', 'Peer education - learners share rounding strategies and check each other\'s work', 'Responsibility - learners handle and return any used place value materials carefully', '* Learners textbook\n* Place value charts drawn on manila paper or cardboard\n* Number cards made from cardboard showing decimals to 3 or 4 decimal places\n* Chalkboard for demonstrating rounding steps', 'Recap of last lesson: adding decimals up to four decimal places. Who can remind us what we learned? Today\'s lesson is: rounding decimals to two decimal places. Imagine you are at a market and a price is Ksh 345.678. How would you tell someone the price simply, using only shillings and cents? What steps would you take to make it a two-decimal number?', 'Engage in an interactive demonstration of rounding to two decimal places by responding to guiding questions and completing steps.', 'Perform or solve rounding exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main rule for rounding to two decimal places? Can someone give an example using a number like 7.1468? Today we learned to identify the hundredths digit as the rounding digit and the next digit to decide whether to round up or down. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly identify the hundredths digit?* Were they able to apply the rounding rule consistently?* Did group discussions improve understanding of the procedure?', 'Find three different prices or measurements written with many decimals at home or in a shop pamphlet. Round each price or measurement to two decimal places. Write the original number and your rounded answer in your exercise book.', '2026-04-11 12:30:30', '2026-04-12 08:29:33'),
(121, 540, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.5 Decimals', '', '', NULL, '', NULL, 'a) Identify the rounding digit for the third decimal place (thousandths).', 'b) Round off given decimals to 3 decimal places accurately.', '', 'How do we round off decimals to 3 decimal places?', 'Communication and collaboration - learners discuss place value and rounding steps with peers.', 'Peer education - learners share working strategies for rounding decimals with one another.', 'Responsibility - learners handle and take care of any place value apparatus used.', '', 'Recap of last lesson: rounding decimals to two decimal places. Who can remind us what we learned? Today\'s lesson is: Rounding Off Decimals to Three Decimal Places. Imagine you are helping a shopkeeper measure a very small amount of sugar, like 0.4567 kilograms. To make it simpler for pricing, we round it. How can we round such a number to three decimal places?', 'Engage in an interactive demonstration of rounding to three decimal places by responding to guiding questions and completing steps.', 'Perform or solve rounding exercises in exercise books individually using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main thing we learned today? Can someone give an example of rounding a number to three decimal places? Today we learned to identify the thousandths digit as the rounding digit and to round off decimals to three decimal places accurately. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did learners identify the thousandths digit?\n* Did learners correctly apply the rounding rule for the digit to the right?\n* Were learners able to explain their rounding steps to a partner?', 'At home, find three different measurements written on containers (e.g., weight, volume). Write down any numbers with more than three decimal places. Practise rounding each of these numbers to three decimal places in your exercise book.', '2026-04-11 12:30:44', '2026-04-12 08:29:46'),
(122, 541, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.5 Decimals', '', '', NULL, '', NULL, 'a) Identify the relationship between decimal places and denominators (10, 100, 1000, 10000).', 'b) Convert given decimals into fractions in their simplest form.', '', 'How do we convert decimals into fractions in their simplest form?', 'Communication and collaboration - learners discuss decimal place value and conversion steps.', 'Peer education - learners share conversion strategies and answers with one another.', 'Responsibility - learners handle and care for any place value apparatus used.', '', 'Recap of last lesson: we learned about place value of decimals up to ten thousandths. Who can remind us what we learned? Today\'s lesson is: Converting decimals into fractions. Imagine you have a length of rope measured as 0.75 metres. How could you express this as a fraction of a metre? What about a weight of 0.125 kg?', 'Engage in an interactive demonstration of decimal-to-fraction conversion by responding to guiding questions and completing steps.', 'Perform or solve conversion exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about converting decimals today? Can someone give an example of a decimal and its fraction? Today we learned the relationship between decimal places and denominators, and how to simplify the resulting fractions. Remember to complete the extended activity to practise what you have learned today.', '* How does the number of decimal places relate to the denominator?* What is the first step in converting a decimal like 0.36 to a fraction?* How do you know when a fraction like 25/100 is in its simplest form?', 'At home, find three items with decimal measurements, like a 0.5 litre bottle or 1.25 kg of flour. Convert each decimal into a fraction. Write the fractions in your exercise book and simplify them if possible.', '2026-04-11 12:30:56', '2026-04-12 08:29:58'),
(123, 542, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.5 Decimals', '', '', NULL, '', NULL, 'a) Use division of the numerator by the denominator to find a decimal.', 'b) Convert proper fractions into decimals accurately.', '', 'How can we write a fraction as a decimal number using division?', 'Communication and collaboration - learners discuss and explain the division process and decimal results in pairs.', 'Peer education - learners share their working strategies and answers when adding decimal places during conversion.', 'Responsibility - learners handle and share any locally collected materials, like sticks for counting, with care.', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Fraction cards made from cardboard or paper', 'Recap of last lesson: We were working with decimals. Who can remind us what a decimal number is? Today\'s lesson is: Converting proper fractions to decimals using division. Imagine you have a piece of sugarcane to share equally among 5 friends. You need to know what fraction each gets and then the decimal amount. How can we figure out the decimal for a fraction like 1/5?', 'Engage in an interactive demonstration of fraction-to-decimal conversion by responding to guiding questions and completing steps.', 'Perform or solve conversion exercises in exercise books individually using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main method we used today? Can someone give an example of a fraction we converted? Today we learned to convert proper fractions to decimals by dividing the numerator by the denominator. We practised this using the long division method. Remember to complete the extended activity at home to practise what you have learned today.', '* Did all learners correctly set up the division of numerator by denominator?* Were learners able to explain the connection between the remainder and adding zeros?* Did the conversion exercises reveal any persistent place value errors?', 'At home, find three different items you can share, like a cup of maize or a length of string. Write fractions to represent sharing them equally among 2, 4, or 5 family members. Convert each fraction into a decimal using division in your exercise book.', '2026-04-11 12:31:08', '2026-04-12 08:30:12'),
(124, 543, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.5 Decimals', '', '', NULL, '', NULL, 'a) Multiply a decimal by 100 to determine its percentage value.', 'b) Convert given decimals into percentages correctly.', '', 'How can we express decimals as percentages to compare and communicate values in everyday situations?', 'Communication and collaboration - learners discuss and explain conversion steps in groups', 'Peer education - learners share working strategies for converting decimals', 'Responsibility - learners handle and share any group materials carefully', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Number cards or small pieces of paper with decimals written on them', 'Recap of last lesson: adding decimals up to four decimal places. Who can remind us what we learned? Today\'s lesson is: converting decimals to percentages. Imagine you see a sale sign that says \'0.25 off\' or a test score of 0.85. How can we express these as percentages to understand them better? What does 0.25 represent as a part of 100?', 'Engage in an interactive demonstration of decimal-to-percentage conversion by responding to guiding questions and completing steps.', 'Perform or solve conversion exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main thing we learned today? Can someone give an example of a decimal they converted? Today we learned to multiply a decimal by 100 to find its percentage and correctly express decimals as percentages. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly multiply decimals by 100?* Were learners able to explain the conversion process?* Can learners relate decimal percentages to real-life situations?', 'At home, find three items with decimal numbers, like a recipe (0.5 kg) or a price (Ksh 0.75). Convert each decimal into a percentage. Write your answers and one example of where a percentage is more useful than a decimal.', '2026-04-11 12:31:19', '2026-04-12 08:30:25'),
(125, 544, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.5 Decimals', '', '', NULL, '', NULL, 'a) Divide a percentage by 100 to determine its decimal value.', 'b) Convert given percentages into decimals accurately.', '', 'How can we express percentages as decimals to make calculations and comparisons easier in everyday situations?', 'Communication and collaboration - learners discuss and explain the conversion procedure to peers', 'Peer education - learners share their working strategies for converting percentages', 'Responsibility - learners handle and share any classroom materials carefully', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Number cards (0-9) made from cardboard or paper\n* Place value chart drawn on manila paper or cardboard', 'Recap of last lesson: percentages and their meaning. Who can remind us what a percentage represents? Today\'s lesson is: Converting Percentages to Decimals. Imagine you see a sign saying 25% off at a shop. To calculate the discount, it\'s easier to use a decimal. How could we change that 25% into a number we can multiply with?', 'Engage in an interactive demonstration of percentage-to-decimal conversion by responding to guiding questions and completing steps.', 'Perform or solve conversion exercises in exercise books individually using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main rule we used today? Can someone give an example of converting a percentage like 8%? Today we learned that to convert a percentage to a decimal, we divide by 100, which moves the decimal point two places to the left. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly move the decimal point two places?* Were learners able to explain the \'divide by 100\' rule?* Can learners link decimal conversion to real-life uses like discounts?', 'Find three percentage values at home, for example on a maize flour packet or soap wrapper. Convert each percentage into a decimal in your exercise book. Write a sentence explaining how the decimal form might be used in a calculation.', '2026-04-11 12:31:32', '2026-04-12 08:30:38'),
(126, 545, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.5 Decimals', '', '', NULL, '', NULL, 'a) Align decimal points vertically for multi-digit addition.', 'b) Add decimals up to 4-decimal places accurately.', '', 'How can we accurately add amounts of money or measurements that have different numbers of decimal places?', 'Communication and collaboration - learners discuss place value and share addition strategies.', 'Peer education - learners share working strategies with one another during addition practice.', 'Responsibility - learners take care of place value apparatus made from local materials.', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Place value charts (drawn or teacher-made)\n* Number cards with decimal numbers', 'Recap of last lesson: reading and writing decimals. Who can remind us what we learned? Today\'s lesson is: Adding Decimals by Aligning Decimal Points. Imagine you are helping a shopkeeper add up the cost of different items from a list. The prices have different numbers of digits after the decimal point. How can we ensure we add them correctly?', 'Engage in an interactive demonstration of decimal addition by responding to guiding questions and completing steps.', 'Perform or solve addition exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the most important rule for adding decimals? Can someone show us how to align the numbers for 12.5 and 3.125? Today we learned to align decimal points vertically and add decimals up to four decimal places accurately. Remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly align decimal points before adding?\n* Were learners able to explain why place value is important when adding decimals?\n* Did the use of local materials help in understanding the concept?', 'At home, find three different containers (e.g., a bottle, jug, cup) and estimate their capacities in litres. Write down the amounts as decimals (e.g., 0.75L, 1.5L, 0.25L). Practise adding these amounts by aligning the decimal points correctly in your exercise book.', '2026-04-11 12:31:44', '2026-04-12 08:30:51'),
(127, 546, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.5 Decimals', '', '', NULL, '', NULL, 'a) Align decimal points vertically for multi-digit subtraction.', 'b) Subtract decimals up to 4-decimal places accurately.', '', 'How can we subtract decimal numbers accurately when they have different numbers of decimal places?', 'Communication and collaboration - learners discuss place value and subtraction strategies', 'Peer education - learners share working strategies for subtracting decimals', 'Responsibility - learners take care of any place value apparatus used', '* Learners textbook\n* Place value charts (drawn on manila paper or chalkboard)\n* Exercise books and pencils\n* Number cards with decimal numbers (teacher-made from cardboard)', 'Recap of last lesson: adding decimals with the same number of decimal places. Who can remind us what we learned? Today\'s lesson is: Subtracting Decimals with Different Decimal Places. Imagine you are buying sugar and the shopkeeper gives you change. The amounts involve decimals with different places. How can we find the correct change?', 'Engage in an interactive demonstration of decimal subtraction by responding to guiding questions and completing steps.', 'Perform or solve subtraction exercises in exercise books individually using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step when subtracting decimals? Can someone give an example of subtracting a 2-place decimal from a 4-place decimal? Today we learned to align decimal points vertically and subtract decimals up to four places accurately. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly align the decimal points before subtracting?\n* Were learners able to explain why we add zeros to make decimal places equal?\n* Can learners apply this skill to a real-life money scenario?', 'At home, find two different containers with volume labels in litres (e.g., 1.5L, 0.75L). Subtract the smaller decimal from the larger one to find the difference in capacity. Write the problem and solution in your exercise book.', '2026-04-11 12:31:58', '2026-04-12 08:31:03'),
(128, 547, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.6 Inequalities', '', '', NULL, '', NULL, 'a) Identify the inequality symbols (>, <, >=, <=).', 'b) Form simple inequalities in one unknown from given word statements.', '', 'How can we use symbols to show that one quantity is greater than, less than, or equal to another?', 'Self-efficacy - learner confidently works out simple inequalities.', 'Social cohesion - learner works with others to form inequalities.', 'Responsibility - learner uses IT devices carefully with peers.', '* Learners textbook\n* Chalkboard and chalk\n* Number cards made from cardboard (showing numbers 1-20)\n* Sticks or twigs (to form inequality symbols < and >)', 'Recap of last lesson: solving simple equations. Who can remind us what we learned? Today\'s lesson is: Identifying inequality symbols and forming simple inequalities. Imagine you and your friend are sharing some mangoes. You have more than your friend, but you want to share fairly. How can we use symbols to show who has more or less?', 'Engage in an interactive demonstration of forming inequalities by responding to guiding questions and completing steps using the chalkboard or tablet.', 'Perform or solve exercises in exercise books individually using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one inequality symbol we learned today? Can someone give an example of an inequality from a word statement? Today we learned to identify the symbols >, <, >=, and <=, and how to form simple inequalities from words. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly identify the four inequality symbols?\n* Were learners able to form inequalities from simple word statements?\n* Did the practical demonstration help in understanding the concept?', 'At home, find two different containers and fill them with water, sand, or stones. Compare their amounts and write three inequalities using the symbols >, <, or = to describe them in your exercise book.', '2026-04-11 12:32:10', '2026-04-12 08:31:15'),
(129, 548, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.6 Inequalities', '', '', NULL, '', NULL, 'a) Group like terms in a simple inequality expression.', 'b) Simplify inequalities in one unknown by adding or subtracting terms.', '', 'How do we simplify inequality expressions by grouping and combining like terms?', 'Self-efficacy - learner confidently works out simple inequalities involving one unknown', 'Social cohesion - learner works together with others harmoniously to form and simplify inequalities', 'Responsibility - as learner works with peers to use available materials carefully', '* Learners textbook\n* Chalkboard and chalk\n* Chart showing inequality symbols (<, >, ≤, ≥)\n* Exercise books and pencils', 'Recap of last lesson: solving simple inequalities. Who can remind us what we learned? Today\'s lesson is: Simplifying inequality expressions by grouping like terms. Imagine you are sharing a bag of maize with your siblings. You know your share must be more than two cups. How can we write and simplify an expression to show the total amount?', 'Engage in an interactive demonstration of simplifying inequalities by responding to guiding questions and completing steps.', 'Perform or solve simplification exercises individually or in groups in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we did to simplify an inequality today? Can someone give an example of a like term? Today we learned to group like terms and simplify inequalities by adding or subtracting. Remember to complete the extended activity to practise what you have learned today.', '* Did I correctly group all like terms in the expressions?\n* Can I explain the steps I used to simplify an inequality?\n* Where might I use this skill outside the classroom?', 'At home, use stones or seeds to represent terms in an inequality like 3x + 5 < 2x + 10. Group the like terms together and show how to simplify it by removing equal amounts from both sides. Write your final answer.', '2026-04-11 12:32:21', '2026-04-12 08:31:27'),
(130, 549, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.6 Inequalities', '', '', NULL, '', NULL, 'a) Apply inverse operations to solve for an unknown in an inequality.', 'b) Solve simple inequalities involving one step of calculation.', '', 'How can we use inverse operations to find the unknown value that makes an inequality true?', 'Self-efficacy - learner confidently works out simple inequalities involving one unknown.', 'Social cohesion - learner works together with others harmoniously to form and solve inequalities.', 'Responsibility - learner carefully uses and shares available materials with peers during activities.', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Number line drawn on chalkboard or ground', 'Recap of last lesson: solving equations with one unknown. Who can remind us what we learned? Today\'s lesson is: Solving simple inequalities using inverse operations. Imagine you and a friend are sharing mangoes. You know your friend has more than 5 mangoes, but you don\'t know the exact number. How could we write this as a mathematical statement?', 'Engage in an interactive demonstration of solving inequalities by responding to guiding questions and completing steps.', 'Perform or solve solving exercises individually in exercise books following demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about solving inequalities today? Can someone give an example of an inequality we solved? Today we learned to use inverse operations, like addition or subtraction, to find the unknown value that makes an inequality true. Remember to check your solution by substituting a number. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly use inverse operations to solve the inequalities?* Can I explain why the inequality sign stays the same when adding or subtracting?* How can I apply solving inequalities in a real-life situation at home?', 'At home, create two simple inequalities using items like stones or maize grains. For example, \'a pile of stones minus 3 is greater than 7\'. Solve your inequalities in your exercise book using inverse operations, showing all your steps.', '2026-04-11 12:32:35', '2026-04-12 08:31:40'),
(131, 550, 'Grade 6', 'Mathematics', '1.0 Numbers', '1.6 Inequalities', '', '', NULL, '', NULL, 'a) Solve real-life problems involving inequalities (e.g., age or price limits).', 'b) Evaluate proficiency in inequalities through a summary exercise.', '', 'How can we use inequalities to solve everyday problems such as determining age restrictions or checking if we have enough money to buy items?', 'Self-efficacy - learner confidently works out simple inequalities involving one unknown.', 'Social cohesion - learner works together with others harmoniously to form inequalities.', 'Responsibility - as learner works with peers to use IT devices carefully to simplify inequalities.', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Sample real-life scenarios written on paper (e.g., matatu fare limits, shop price lists, school age requirements)', 'Recap of last lesson: We learned about representing inequalities. Who can remind us what the symbols <, >, ≤, and ≥ mean? Today\'s lesson is: Solving Real-Life Problems Using Inequalities. Imagine you are at a shop and see a toy marked \'For ages 10 and above\'. How would you write that as an inequality? What does it tell us about who can buy it?', 'Engage in an interactive review of inequalities by responding to guiding questions and completing steps.', 'Perform or solve a summary assessment exercise individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one real-life situation where we can use an inequality? Can someone give an example of an inequality they solved today? Today we learned to write inequalities from everyday problems and to solve them to find possible answers. Remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly form inequalities from the given scenarios?* Were learners able to solve the inequalities to find the range of possible values?* Did the summary exercise show improved proficiency in solving inequalities?', 'At home, find two items with age restrictions (e.g., on a medicine bottle or game box). Write the restrictions as inequalities in your exercise book. Also, check prices of two items at a kiosk and write an inequality to show if you have enough money to buy both.', '2026-04-11 12:32:47', '2026-04-12 08:31:53'),
(132, 551, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Identify the millimetre (mm) marks on a ruler or tape measure.', 'b) Measure the length of small objects in millimetres accurately.', '', 'How can we measure very small objects accurately using the smallest marks on a ruler?', 'Creativity and imagination - learners sketch circles to measure diameter and radius practically', 'Environmental Education - learners choose appropriate units for measuring lengths of objects in the environment', 'Unity - learners work amicably with peers to determine lengths and discuss answers', '* Learners textbook\n* 30 cm rulers with millimetre markings\n* Small objects to measure (seeds, small leaves, thorns, needles, small sticks, pencil lead thickness)\n* Exercise books and pencils', 'Recap of last lesson: measuring length in centimetres. Who can remind us what we learned? Today\'s lesson is: Measuring Length in Millimetres. Imagine you need to measure the thickness of a leaf or the width of a maize seed. These are too small for centimetres. How can we measure such tiny objects accurately?', 'Engage in an interactive demonstration of measuring in mm by responding to guiding questions and completing steps.', 'Perform or solve measurement exercises individually using textbooks and rulers.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about millimetres today? Can someone show us how to measure a small object in mm? Today we learned to identify millimetre marks on a ruler and measure small objects accurately in millimetres. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners identify the mm marks on their rulers?\n* Were learners able to measure small objects accurately in millimetres?\n* Did group discussions help learners understand addition and subtraction of mm?', 'At home, find three very small objects like a grain of rice, a nail, or a seed. Use a ruler to measure and record their lengths in millimetres. Share your findings with a family member.', '2026-04-11 12:32:59', '2026-04-12 08:32:07'),
(133, 552, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) State the number of millimetres in one centimetre (1 cm = 10 mm).', 'b) Compare lengths given in mm and cm.', '', 'How can we measure and compare very small lengths accurately using millimetres and centimetres?', 'Creativity and imagination - learners sketch and measure circular objects practically', 'Environmental Education - learners choose appropriate units to measure objects in their environment', 'Unity - learners work amicably with peers to solve length problems', '* Learners textbook\n* Rulers marked with both centimetres and millimetres\n* Small classroom objects (pencils, erasers, chalk pieces, sticks, seeds)\n* Chalkboard and chalk for demonstrations', 'Recap of last lesson: measuring length in centimetres. Who can remind us what we learned? Today\'s lesson is: Understanding millimetres and centimetres. Imagine you need to measure the thickness of your pencil lead or the width of a leaf. Which unit would be better for such small measurements? Why do you think so?', 'Engage in an interactive demonstration of the relationship between mm and cm by responding to guiding questions.', 'Perform or solve comparison exercises in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about millimetres today? Can someone give an example of an object we would measure in mm? Today we learned that 1 centimetre equals 10 millimetres and how to compare lengths using both units. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did learners state the relationship between cm and mm?\n* Were learners able to accurately compare lengths given in different units?\n* Did the practical activities improve understanding of small measurements?', 'At home, find three small objects like a nail, a seed, or a grain of maize. Estimate and then measure their lengths in millimetres using a ruler. Record your measurements and compare them with a family member.', '2026-04-11 12:33:13', '2026-04-12 08:32:19'),
(134, 553, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Convert measurements from centimetres into millimetres.', 'b) Convert measurements from millimetres into centimetres.', '', 'How can we change length measurements from centimetres to millimetres and from millimetres to centimetres?', 'Creativity and imagination - learners sketch and label measured objects, Communication and collaboration - learners discuss conversion steps and answers', 'Environmental Education - learners choose appropriate units for measuring local objects', 'Unity - learners work amicably in peers to solve conversion problems', '* Learners textbook\n* Metre rule with both centimetre and millimetre markings\n* Exercise books\n* Chalkboard and chalk', 'Recap of last lesson: measuring length in centimetres and millimetres. Who can remind us what we learned? Today\'s lesson is: Converting between centimetres and millimetres. Imagine you are helping a tailor who has a piece of cloth measured in centimetres, but the pattern instructions are in millimetres. How would you help the tailor use the correct measurements?', 'Engage in an interactive demonstration of length conversion by responding to guiding questions and completing steps.', 'Perform or solve conversion exercises individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about converting centimetres? Can someone give an example of converting from millimetres? Today we learned to change centimetres to millimetres by multiplying by 10, and millimetres to centimetres by dividing by 10. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did learners convert cm to mm in exercises?\n* Did learners understand when to multiply or divide by 10?\n* Were learners able to explain the conversion process to a peer?', 'At home, find five small objects like a nail, a bean, or a bottle cap. Measure their lengths in millimetres using a ruler, then convert each measurement to centimetres. Record your findings in your exercise book.', '2026-04-11 12:33:27', '2026-04-12 08:32:32'),
(135, 554, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Align measurements in cm and mm for addition.', 'b) Add lengths involving centimetres and millimetres accurately.', '', 'How can we accurately combine measurements that have both centimetres and millimetres?', 'Creativity and imagination - learners sketch and measure objects practically', 'Environmental Education - learners choose appropriate local objects to measure', 'Unity - learners work amicably in groups to solve addition problems', '* Learners textbook\n* Rulers marked in centimetres and millimetres\n* Sticks or twigs of different lengths\n* Strips of paper or cardboard cut to various lengths', 'Recap of last lesson: measuring lengths in centimetres and millimetres. Who can remind us what we learned? Today\'s lesson is: Adding lengths in centimetres and millimetres. Imagine you are helping a carpenter join two wooden pieces. One piece is 15 cm 7 mm long, and the other is 8 cm 9 mm long. How would you find the total length?', 'Engage in an interactive demonstration of adding lengths by responding to guiding questions and completing steps.', 'Perform or solve addition exercises in groups or individually.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step in adding lengths with centimetres and millimetres? Can someone share an answer from today\'s group work? Today we learned to align the centimetres and millimetres separately before adding, and to convert any extra millimetres to centimetres. Remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly align cm and mm columns before adding?* Were learners able to convert 10 mm to 1 cm when the sum exceeded 9 mm?* Did group discussions help clarify the addition process?', 'At home, find three objects like a book, a spoon, and a pencil. Measure their lengths in cm and mm using a ruler. Write down two of these measurements and add them together to find the total length.', '2026-04-11 12:33:38', '2026-04-12 08:32:45'),
(136, 555, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Align measurements in cm and mm for subtraction.', 'b) Subtract lengths involving centimetres and millimetres including regrouping.', '', 'How do we subtract lengths accurately when we need to regroup millimetres and centimetres?', 'Communication and collaboration - learners discuss subtraction steps and answers with peers', 'Environmental Education - learners choose appropriate local objects to measure and subtract', 'Unity - learners work amicably in pairs to solve subtraction problems', '* Learners textbook\n* Rulers marked in centimetres and millimetres\n* Sticks or twigs of different lengths\n* Chalkboard and chalk for demonstration', 'Recap of last lesson: adding lengths in centimetres and millimetres. Who can remind us what we learned? Today\'s lesson is: Subtracting lengths in centimetres and millimetres with regrouping. Imagine you have a long stick and you cut off a shorter piece. To know how much is left, you need to subtract the lengths. What steps might you take to find the remaining length?', 'Engage in an interactive demonstration of subtracting lengths by responding to guiding questions and completing steps.', 'Perform or solve subtraction exercises individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what we learned today? Can someone give an example of a subtraction problem we solved? Today we learned to align measurements for subtraction and how to regroup millimetres when subtracting. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly align cm and mm in vertical subtraction?* How well did learners handle regrouping millimetres?* Can learners explain the regrouping process in their own words?', 'At home, find two different sticks or strings. Measure their lengths in centimetres and millimetres using a ruler. Subtract the shorter length from the longer one, showing your working with regrouping. Write the answer in your exercise book.', '2026-04-11 12:33:51', '2026-04-12 08:32:58');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(137, 556, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Multiply lengths in cm and mm by a single-digit whole number.', 'b) Express the product in both cm and mm where necessary.', '', 'How can we find the total length when we multiply a measurement in centimetres and millimetres by a whole number?', 'Creativity and imagination - learners sketch and measure practical objects', 'Environmental Education - learners choose appropriate units for measuring objects in their surroundings', 'Unity - learners work amicably in groups to solve multiplication problems', '* Learners textbook\n* Rulers marked in cm and mm\n* Sticks or twigs cut to specific lengths (e.g. 12 cm 5 mm)\n* Chalkboard and chalk for demonstration', 'Recap of last lesson: adding and subtracting lengths in centimetres and millimetres. Who can remind us what we learned? Today\'s lesson is: Multiplying lengths in centimetres and millimetres by a whole number. Imagine you need to cut three equal pieces of string, each 15 cm and 8 mm long. How would you find the total length of string needed? What steps would you take?', 'Engage in an interactive demonstration of multiplying lengths by responding to guiding questions and completing steps.', 'Perform or solve multiplication exercises individually or in groups.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what we learned today? Can someone give an example of multiplying a length in cm and mm? Today we learned to multiply lengths in centimetres and millimetres by a whole number and to express the answer correctly. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly multiply the centimetres and millimetres separately?* Did I remember to convert any extra millimetres to centimetres?* Can I explain the steps to a friend using a real-life example?', 'At home, find three straight sticks of similar length. Measure one in cm and mm. Multiply this measurement by 3 to find the total length if you laid all three sticks end-to-end. Record your work in your exercise book.', '2026-04-11 12:34:03', '2026-04-12 08:33:11'),
(138, 557, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Divide lengths in cm and mm by a single-digit whole number.', 'b) Apply division of length to solve real-life sharing problems.', '', 'How can we share or divide a given length equally among a number of people or parts?', 'Creativity and imagination - learners sketch and mark divided lengths practically.', 'Environmental Education - learners choose appropriate local objects to measure and divide.', 'Unity - learners work amicably in peers to solve division problems.', '* Learners textbook\n* Metre rule or tape measure\n* Ribbons, strings, or sticks of known lengths (measured in cm and mm)\n* Exercise books and pencils', 'Recap of last lesson: We learned about multiplying lengths. Who can remind us what we did? Today\'s lesson is: Dividing Lengths to Solve Sharing Problems. Imagine you have a long rope or a piece of sugarcane that needs to be shared equally among a group of friends. How would you ensure everyone gets a fair, equal piece?', 'Engage in an interactive demonstration of dividing length by responding to guiding questions and completing steps.', 'Perform or solve division exercises in exercise books following demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about dividing lengths today? Can someone give an example of a real-life sharing problem? Today we learned how to divide lengths in centimetres and millimetres by a whole number and apply it to solve sharing problems. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly divide lengths in cm and mm?* Can learners connect division of length to real-life sharing?* Were learners able to work together to discuss and check their answers?', 'At home, find a straight stick or a piece of string. Measure its total length. Imagine you need to share it equally among 3 or 4 family members. Calculate and mark the equal length each person would get.', '2026-04-11 12:34:17', '2026-04-12 08:33:24'),
(139, 558, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Identify the circumference, diameter, and radius of a circle.', 'b) Describe the relationship between the circumference and diameter of a circle.', '', 'How can we find and describe the different parts of a circle and discover the relationship between the distance around it and the distance across it?', 'Creativity and Imagination - learners sketch and measure circle parts practically', 'Environmental Education - learners measure lengths of circular objects in their environment', 'Unity - learners work amicably with peers to measure and discuss lengths', '* Learners textbook\n* Circular objects from the environment (plates, lids, buckets, bicycle wheels, coins)\n* Strings or flexible wires for measuring around circles\n* Metre rule or ruler\n* Exercise books and pencils', 'Recap of last lesson: measuring lengths of straight objects. Who can remind us what we learned? Today\'s lesson is: Parts of a Circle and their Relationship. Imagine you have a bicycle wheel. To know how far it travels in one turn, you need to know the distance around it. What parts of the wheel do you think we need to measure?', 'Engage in an interactive demonstration of circle parts by responding to guiding questions and completing steps.', 'Perform or solve identification exercises individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what we learned today? Can someone explain the relationship between the diameter and circumference? Today we learned to identify the circumference, diameter, and radius of a circle and discovered that the circumference is about three times the diameter. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly identify the radius and diameter?* How well did learners describe the circumference-diameter relationship?* Were learners creative in sketching and measuring different circles?', 'Find three circular objects at home (e.g., a plate, a lid, a coin). For each, use a string and ruler to measure its circumference and diameter. Record your measurements and calculate how many times the diameter fits into the circumference.', '2026-04-11 12:34:29', '2026-04-12 08:33:37'),
(140, 559, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Define the terms diameter and radius.', 'b) Calculate the diameter of a circle given the radius and vice versa.', '', 'How can we describe and measure the parts that run across and from the center of a circle?', 'Creativity and imagination - learners sketch circumference, diameter and radius practically', 'Environmental Education - learners choose appropriate units for measuring lengths of different objects', 'Unity - learner works amicably with peers to determine lengths and discuss answers', '* Learners textbook\n* Circular objects (lids, plates, bicycle wheels, coins)\n* Metre rule or ruler\n* String or thread\n* Chalk and chalkboard', 'Recap of last lesson: measuring lengths of straight objects. Who can remind us what we learned? Today\'s lesson is: Understanding Diameter and Radius. Imagine you are helping to make a round table for your home. You need to know how wide it is across the middle. What parts of the circle would you need to measure?', 'Engage in an interactive demonstration of circle properties by responding to guiding questions and completing steps on the chalkboard.', 'Perform or solve diameter and radius exercises individually in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the relationship between the radius and diameter? Can someone define radius in their own words? Today we learned to define diameter and radius, and how to calculate one from the other. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly define radius and diameter?\n* Could learners calculate diameter given the radius?\n* Were learners able to sketch and label the parts?', 'Find three circular objects at home (e.g., a plate, a lid). For each, use a string and ruler to measure the radius. Then, calculate the diameter. Record your findings in your exercise book.', '2026-04-11 12:34:40', '2026-04-12 08:33:49'),
(141, 560, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Measure the circumference and diameter of various circular objects using a string or tape.', 'b) Discover the constant relationship (pi) between circumference and diameter.', '', 'How can we find out if there is a special relationship between the distance around a circle and the distance across it?', 'Creativity and Imagination - learners sketch and measure circles practically, Learning to Learn - learners discover a mathematical constant through investigation', 'Environmental Education - learners choose appropriate circular objects from their surroundings for measurement', 'Unity - learners work amicably in groups to measure and discuss findings', '* Learners textbook\n* String or sisal twine\n* Tape measure or metre rule\n* Circular objects (plates, lids, tins, bicycle wheels, buckets)\n* Exercise books and pencils', 'Recap of last lesson: measuring lengths of straight objects. Who can remind us how we measured the length of our desks? Today\'s lesson is: Discovering the Relationship Between a Circle\'s Circumference and Diameter. Imagine you need to put a new rim on a bicycle wheel or a decorative border around a round table. How would you know how much material to get without measuring the whole way around?', 'Engage in an interactive demonstration of measuring circles by responding to guiding questions and completing steps.', 'Perform or solve relationship discovery exercises in groups using available circular objects.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the name of the special relationship we discovered today? Can someone explain how we found it? Today we learned that the circumference of a circle is always about three times its diameter, and we call this constant ratio pi. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all groups find a ratio close to 3?* What challenges did you face measuring with string?* How is this relationship useful in real life?', 'Find three different circular objects at home (e.g., a plate, a lid, a cup). Use a string and ruler to measure their circumference and diameter. Record your measurements and calculate the ratio for each object.', '2026-04-11 12:34:52', '2026-04-12 08:34:02'),
(142, 565, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.2 Area', '', '', NULL, '', NULL, 'a) Place circular objects on a square-grid paper.', 'b) Estimate the area of the circle by counting full and half-squares.', '', 'How can we find the area of a circular object when it does not fit perfectly into squares?', 'Creativity and imagination - learners devise a method to estimate area of circles', 'Self-esteem - learners confidently compare and discuss their area estimates', 'Love - learners work together respectfully to compare answers', '* Learners textbook\n* Square-grid paper (1 cm grid drawn on plain paper or chalkboard)\n* Circular objects of different sizes (bottle tops, lids, coins, bangles)\n* Rulers', 'Recap of last lesson: area of triangles. Who can remind us what we learned? Today\'s lesson is: Estimating the area of a circle using a square grid. Imagine you have a round plate and want to know how much space it covers on a table. How could you find out without a special formula?', 'Engage in an interactive demonstration of area estimation by responding to guiding questions and completing steps using the chalkboard grid.', 'Perform or solve estimation exercises individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the method we used today? Can someone explain why we count half-squares? Today we learned to estimate a circle\'s area by placing it on a grid and counting full and partial squares. Remember to complete the extended activity to practise what you have learned today.', '* How did counting squares help estimate the circle\'s area?\n* What was challenging about counting the half-squares?\n* Where else could you use this estimation method?', 'Find a circular object at home, like a lid or plate. Trace its outline on a piece of paper you have drawn squares on. Estimate its area by counting the full and half squares inside your tracing.', '2026-04-11 12:39:48', '2026-04-12 08:35:04'),
(143, 567, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.3 Capacity', '', '', NULL, '', NULL, 'a) Use the relationship 1 litre = 1000 cm3 in calculations.', 'b) Calculate capacity in litres given values in cubic centimetres.', '', 'How can we convert measurements between cubic centimetres and litres to solve real-life capacity problems?', 'Critical thinking and problem solving - learners work out conversions between cm³ and litres.', 'Environmental education - learners use and discuss containers from their environment for measuring capacity.', 'Peace - learners work together harmoniously in groups to measure and agree on answers.', '* Learners textbook\n* Containers of different sizes (bottles, cups, jerry cans)\n* Water or sand for measuring\n* Rulers or measuring tapes', 'Recap of last lesson: measuring capacity in millilitres and litres. Who can remind us what we learned? Today\'s lesson is: Converting between cubic centimetres and litres. Imagine you have a small medicine bottle measured in cm³ and a large water container measured in litres. How would you compare their capacities to know which holds more?', 'Engage in an interactive demonstration of unit conversion by responding to guiding questions and completing steps.', 'Perform or solve capacity exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the relationship between litres and cubic centimetres? Can someone explain how to convert 5000 cm³ into litres? Today we learned that 1 litre equals 1000 cubic centimetres and practised converting between these units. Remember to complete the extended activity at home to practise what you have learned today.', '* How well did you use the 1 litre = 1000 cm³ relationship?* What was challenging about converting from cm³ to litres?* Can you think of a real container where this conversion is useful?', 'Find three different containers at home (e.g., a cup, bottle, jug). Estimate their capacity in litres, then use a known small container (like a 500 ml bottle) to check. Convert your findings from millilitres to cubic centimetres.', '2026-04-11 12:40:01', '2026-04-12 08:35:32'),
(144, 568, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.3 Capacity', '', '', NULL, '', NULL, 'a) Identify the conversion factor between litres and millilitres.', 'b) Convert given capacity from litres into millilitres accurately.', '', 'How many millilitres make one litre and how can we use this to convert between the two units?', 'Critical thinking and problem solving - learners work out the relationship between litres and millilitres through practical measuring', 'Environmental education - learners use containers from the environment to measure and convert capacity', 'Peace - learners work together harmoniously to measure and agree on answers', '* Learners textbook\n* Empty 1-litre water bottles or containers with litre markings\n* Empty smaller containers (cups, bottles) with millilitre markings or labels\n* Water for demonstration purposes\n* Chalkboard and chalk for showing conversion steps', 'Recap of last lesson: measuring capacity in litres. Who can remind us what we learned? Today\'s lesson is: Converting litres to millilitres. Imagine you are helping at home to measure water for cooking. You have a 1-litre jug, but the recipe needs millilitres. How would you figure out the correct amount?', 'Engage in an interactive demonstration of converting litres to millilitres by responding to guiding questions and completing steps.', 'Perform or solve conversion exercises individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the relationship between litres and millilitres? Can someone give an example of a conversion we did? Today we learned that 1 litre equals 1000 millilitres and practised converting litres to millilitres by multiplying. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did learners identify the conversion factor?* Did learners accurately convert litres to millilitres?* Were learners able to work together harmoniously?', 'At home, find three different containers (e.g., a cup, bottle, jug). Estimate their capacity in litres or millilitres. Then, using a known measure like a 500ml soda bottle, check your estimates by counting how many times it fills your container. Record your findings.', '2026-04-11 12:40:08', '2026-04-12 08:35:44'),
(145, 569, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.3 Capacity', '', '', NULL, '', NULL, 'a) Identify the division factor needed to change millilitres to litres.', 'b) Convert given capacity from millilitres into litres accurately.', '', 'How many millilitres make one litre and how can we use this to convert between the two units?', 'Critical thinking and problem solving - learners work out the relationship between millilitres and litres through practical conversion.', 'Environmental education - learner converts capacities using knowledge of containers from the environment.', 'Peace - learner works together harmoniously in groups to measure and agree on answers.', '* Learners textbook\n* Empty 1-litre water bottles or soda bottles with labels\n* Smaller containers marked in millilitres (250ml cups, 500ml bottles)\n* Water for demonstration\n* Chart showing conversion factor (1000ml = 1L)', 'Recap of last lesson: converting litres to millilitres. Who can remind us what we learned? Today\'s lesson is: Converting millilitres into litres. Imagine you have a small bottle of medicine or a sachet of juice. The label says 500 ml. How would you tell someone its capacity in litres?', 'Engage in an interactive demonstration of converting ml to litres by responding to guiding questions and completing steps.', 'Perform or solve conversion exercises in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main thing we learned today? Can someone give an example of a conversion we did? Today we learned the division factor for converting millilitres to litres and practised the conversion. Remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly identify the division factor of 1000?\n* Were learners able to convert millilitres to litres accurately?\n* Did group work help learners understand the conversion process?', 'At home, find three different containers with labels showing capacity in millilitres (ml). Record their names and convert each capacity into litres (L) in your exercise book.', '2026-04-11 12:40:14', '2026-04-12 08:35:55'),
(146, 571, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.3 Capacity', '', '', NULL, '', NULL, 'a) Solve real-life word problems involving capacity units (cm3, ml, and litres).', 'b) Evaluate mastery of capacity through a summary exercise.', '', 'How can we use our knowledge of capacity units to solve everyday problems in our homes and community?', 'Critical thinking and problem solving - learners work out relationships between units and solve real-life problems.', 'Environmental education - learners use and think about common containers from their environment.', 'Peace - learners work together harmoniously to measure and agree on answers.', '* Learners textbook\n* Exercise books and pencils\n* Chalkboard and chalk\n* Sample containers (bottles, cups, jerrycans) with capacity labels\n* Chart showing conversion between cm³, ml, and litres', 'Recap of last lesson: converting between litres and millilitres. Who can remind us what we learned? Today\'s lesson is: Solving Real-Life Problems with Capacity. Imagine your family is buying cooking oil or fetching water for the home. You need to know how much a container holds. How can we use our knowledge of litres and millilitres to solve such problems?', 'Engage in an interactive review of capacity by responding to guiding questions and completing steps.', 'Perform or solve a summary assessment exercise individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we practised today? Can someone give an example of a real-life capacity problem? Today we learned to solve word problems involving litres, millilitres, and cubic centimetres, and we checked our understanding. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly convert units in the problems?* Did they apply the correct operation (addition, subtraction)?* Can they explain their problem-solving steps clearly?', 'At home, find three different containers (e.g., a cup, bottle, jug). Estimate and then find their capacity in millilitres or litres using a known measure, like a 500ml soda bottle. Write down your findings.', '2026-04-11 12:40:28', '2026-04-12 08:36:21'),
(147, 572, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.4 Mass', '', '', NULL, '', NULL, 'a) Identify the tonne (t) as a unit for measuring very heavy mass.', 'b) Name various commodities measured in tonnes in the community.', '', 'What objects or goods in our community are so heavy that we need to measure them in tonnes?', 'Digital Literacy - learner uses digital weighing machines to measure mass', 'Environmental Education - learner discusses mass of loaded lorries and their impact on roads', 'Integrity - learner honestly determines mass using different operations', '* Learners textbook\n* Pictures or labels from sacks of farm produce (maize, tea, coffee, fertilizer)\n* Chart showing tonne symbol (t) and examples\n* Community resource persons (farmer, lorry driver, or trader)', 'Recap of last lesson: measuring mass in kilogrammes. Who can remind us what we learned? Today\'s lesson is: Identifying the Tonne and Heavy Commodities. Imagine you see a large lorry full of sand or a tractor carrying many bags of maize. These are very heavy items. How do you think we measure the mass of such heavy things?', 'Engage in an interactive demonstration of large mass units by responding to guiding questions and completing steps.', 'Perform or solve identification exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about the tonne today? Can someone name a commodity measured in tonnes? Today we learned that the tonne (t) is a unit for very heavy mass and identified items like loaded lorries and building materials measured in tonnes. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly identify the tonne as a unit for heavy mass?\n* Could learners name at least three local commodities measured in tonnes?\n* Did the group discussions about heavy loads and roads show understanding?', 'At home, look for three very heavy items or goods in your community, like a water tank, a pile of firewood, or sacks of grain. List them and estimate which ones you think could have a mass of one tonne or more.', '2026-04-11 12:40:37', '2026-04-12 08:36:34'),
(148, 573, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.4 Mass', '', '', NULL, '', NULL, 'a) State the relationship between the kilogramme and the tonne (1 tonne = 1000 kg).', 'b) Compare masses given in kilogrammes and tonnes.', '', 'How can we express and compare very large masses using kilogrammes and tonnes?', 'Digital literacy - learner uses digital weighing machines to measure mass', 'Environmental education - learner discusses masses of loaded lorries and their impact on roads', 'Integrity - learner honestly determines mass using different mathematical operations', '* Learners textbook\n* Chalkboard and chalk\n* Chart showing 1 tonne = 1000 kg with examples (lorry, elephant, small car)\n* Exercise books and pencils', 'Recap of last lesson: measuring mass in kilogrammes. Who can remind us what we learned? Today\'s lesson is: Understanding the relationship between kilogrammes and tonnes. Imagine seeing a very heavy lorry loaded with sand or maize. How do you think we measure such a large mass? What unit would we use?', 'Engage in an interactive demonstration of the kg-to-tonne relationship by responding to guiding questions and completing steps.', 'Perform or solve relationship exercises in exercise books individually.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the relationship between a kilogramme and a tonne? Can someone give an example of an item measured in tonnes? Today we learned that 1 tonne equals 1000 kilogrammes and how to compare masses using these units. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly state that 1 tonne = 1000 kg?\n* Could learners successfully compare masses given in kg and tonnes?\n* Were learners able to solve the relationship exercises individually?', 'At home, look for items like a bag of maize flour or a sack of vegetables. Estimate their mass in kilogrammes. Then, calculate how many of those items would make up one tonne. Write your findings in your exercise book.', '2026-04-11 12:40:45', '2026-04-12 08:36:47'),
(149, 574, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.4 Mass', '', '', NULL, '', NULL, 'a) Estimate the mass of heavy items (e.g., a truckload of sand) in tonnes.', 'b) Compare estimated mass with actual recorded mass of community items.', '', 'How can we estimate the mass of very heavy items like a truckload of sand or building materials in our community?', 'Digital Literacy - learners use digital scales to measure reference masses for estimation', 'Environmental Education - learners discuss the impact of heavy loads, like lorries, on local roads', 'Integrity - learners honestly record and compare their estimated and actual masses', '* Learners textbook\n* Chart showing common heavy items and their approximate masses in tonnes (truck, tractor, water tank, bags of cement)\n* Exercise books and pencils for recording estimates\n* Pictures or drawings of heavy vehicles and items from the local community', 'Recap of last lesson: measuring mass in kilograms. Who can remind us what we learned? Today\'s lesson is: Estimating the Mass of Heavy Items in Tonnes. Imagine a lorry delivering sand for a new classroom. You need to estimate its weight to know if the ground can support it. How would you begin to make that estimate?', 'Engage in an interactive demonstration of mass estimation by responding to guiding questions and completing steps using real-life examples.', 'Perform or solve estimation exercises in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one method we used for estimation today? Can someone give an example of something we would measure in tonnes? Today we learned to estimate mass in tonnes and compare our estimates to actual measurements. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How confident are you in estimating mass in tonnes?* Did comparing your estimate to a known weight improve your accuracy?* Where else in our community can you apply this estimation skill?', 'At home, estimate the mass of a large item, like a full water drum or a sack of maize. Discuss with a family member how you made your estimate and what unit (kg or tonnes) you used.', '2026-04-11 12:40:52', '2026-04-12 08:37:00'),
(150, 575, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.4 Mass', '', '', NULL, '', NULL, 'a) Use the conversion factor to change kilogrammes into tonnes.', 'b) Convert given masses from kilogrammes to tonnes accurately.', '', 'How can we express very large masses measured in kilogrammes using tonnes to make them easier to understand and communicate?', 'Digital literacy - using digital scales to measure mass', 'Environmental education - discussing mass of heavy vehicles and road impact', 'Integrity - honestly performing mass conversions', '* Learners textbook\n* Chalkboard and chalk\n* Chart showing conversion factor (1 tonne = 1000 kg)\n* Real-life examples written on cards (e.g. mass of lorry, truck load of maize, water tank)', 'Recap of last lesson: We were measuring mass in kilogrammes. Who can remind us what we learned? Today\'s lesson is: Converting kilogrammes to tonnes. Imagine you see a lorry loaded with maize sacks. The driver says the load is 5000 kilogrammes. How can we describe this heavy load in a simpler way? What is another unit we can use?', 'Engage in an interactive demonstration of mass conversion by responding to guiding questions and completing steps on the chalkboard.', 'Perform or solve conversion exercises individually in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what we learned today? Can someone give an example of a conversion? Today we learned the conversion factor between kilogrammes and tonnes, and how to change kilogrammes into tonnes. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How many kilogrammes make one tonne?\n* What is the first step when converting kilogrammes to tonnes?\n* Why is using tonnes sometimes better than kilogrammes?', 'At home, find three heavy items like a bag of maize or a jerrican of water. Estimate their mass in kilogrammes, then convert your estimates to tonnes. Record your findings in your exercise book.', '2026-04-11 12:40:59', '2026-04-12 08:37:12'),
(151, 576, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.4 Mass', '', '', NULL, '', NULL, 'a) Use the conversion factor to change tonnes into kilogrammes.', 'b) Convert given masses from tonnes to kilogrammes accurately.', '', 'How can we use the relationship between tonnes and kilogrammes to convert large masses from one unit to the other?', 'Digital Literacy - learner uses digital weighing machines to measure mass', 'Environmental Education - learner discusses mass of loaded lorries and their impact on roads', 'Integrity - learner honestly determines mass using different operations', '* Learners textbook\n* Chalkboard and chalk\n* Chart showing conversion factor (1 tonne = 1000 kg)\n* Exercise books and pencils', 'Recap of last lesson: measuring mass in kilogrammes. Who can remind us what we learned? Today\'s lesson is: Converting tonnes to kilogrammes. Imagine a farmer has harvested maize and wants to sell it. The lorry driver says the load is measured in tonnes, but the buyer pays per kilogramme. How can the farmer figure out the weight in kilogrammes?', 'Engage in an interactive demonstration of mass conversion by responding to guiding questions and completing steps.', 'Perform or solve conversion exercises individually in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main thing we learned today? Can someone give an example of a conversion we did? Today we learned the conversion factor between tonnes and kilogrammes and practised changing tonnes into kilogrammes. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly use the conversion factor of 1000?* Were learners able to convert given tonnes into kilogrammes accurately?* How can I support learners who struggled with the multiplication?', 'Find three items at home whose mass you think could be measured in tonnes, like a sack of maize or a large container of water. Estimate their mass in tonnes, then convert your estimates into kilogrammes. Write your work in your exercise book.', '2026-04-11 12:41:07', '2026-04-12 08:37:25'),
(152, 579, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.4 Mass', '', '', NULL, '', NULL, 'a) Multiply mass in tonnes and kg by a single-digit whole number.', 'b) Carry out multiplication and convert kg to tonnes where necessary.', '', 'How do we multiply mass measurements in tonnes and kilograms by whole numbers and convert between these units when needed?', 'Digital literacy - learner uses digital weighing machines to measure mass', 'Environmental education - learner discusses mass of loaded lorries and their impact on roads', 'Integrity - learner honestly determines mass using multiplication operations', '* Learners textbook\n* Chalkboard and chalk\n* Chart showing conversion: 1 tonne = 1000 kg\n* Stones or sacks labeled with sample masses (e.g., 2 tonnes 500 kg, 3 tonnes 250 kg)', 'Recap of last lesson: adding and subtracting mass in tonnes and kilograms. Who can remind us what we learned? Today\'s lesson is: Multiplying mass in tonnes and kilograms. Imagine a farmer has sacks of maize, each with the same mass. To find the total mass of several sacks, you need to multiply. What steps do you think we should follow?', 'Engage in an interactive demonstration of multiplying mass by responding to guiding questions and completing steps.', 'Perform or solve multiplication exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step when multiplying mass in tonnes and kilograms? Can someone give an example of when we need to convert kilograms to tonnes? Today we learned to multiply mass by a whole number and to convert kilograms to tonnes after multiplication. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly multiply the mass by the whole number?* Did I remember to convert kilograms to tonnes when the total exceeded 1000 kg?* Can I explain the steps to a friend?', 'At home, find three similar items like stones or packets of flour. Estimate their mass in kilograms, then multiply by 3, 4, or 5 to find the total mass. Remember to convert your answer to tonnes and kilograms if needed.', '2026-04-11 12:41:29', '2026-04-12 08:38:06'),
(153, 581, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.4 Mass', '', '', NULL, '', NULL, 'a) Solve word problems involving mass units (kg and tonnes).', 'b) Evaluate mastery of mass through a summary assessment exercise.', '', 'How do we apply our knowledge of kilograms and tonnes to solve real-world problems involving mass?', 'Digital Literacy - learner uses digital weighing machines to measure mass', 'Environmental Education - learner discusses mass of loaded lorries and road impact', 'Integrity - learner honestly determines mass using correct operations', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Sample word problem scenarios written on cards or chart (e.g., truck loads, farm produce, construction materials)', 'Recap of last lesson: converting between kilograms and tonnes. Who can remind us what we learned? Today\'s lesson is: Solving Real-World Problems Involving Mass. Imagine you are helping a farmer load maize sacks onto a lorry. Some sacks weigh in kilograms, and the total load is measured in tonnes. How would you calculate if the lorry is overloaded?', 'Engage in an interactive review of mass by responding to guiding questions and completing steps.', 'Perform or solve a summary assessment exercise individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one type of real-world problem we solved today? Can someone give an example of when we use tonnes instead of kilograms? Today we learned to solve word problems involving kilograms and tonnes using different operations. We also assessed our own understanding. Remember to complete the extended activity at home to practise what you have learned today.', '* How well did you solve the mass word problems?\n* Did you correctly choose between kg and tonnes?\n* How can you apply this lesson outside school?', 'At home, find three items with their mass written on them, like a bag of flour or sugar. Create and solve two word problems using their masses. For example, calculate the total mass if you combine them.', '2026-04-11 12:41:44', '2026-04-12 08:38:32'),
(154, 582, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.5 Time', '', '', NULL, '', NULL, 'a) Identify the meaning of a.m. and p.m. in relation to the day.', 'b) Write time in a.m. and p.m. correctly from clock faces.', '', 'How can we tell whether a time on the clock is in the morning or in the afternoon?', 'Learning to learn - learner determines time in a.m. and p.m. from clocks', 'Citizenship - learners determine time durations from travel timetables', 'Integrity - learner observes time and is punctual for activities', '* Learners textbook\n* Teacher-made cardboard clock with movable hands\n* Chalkboard chart showing 24-hour day divided into a.m. and p.m.\n* Sample daily school timetable with a.m. and p.m. times', 'Recap of last lesson: telling time using the 12-hour clock. Who can remind us what we learned? Today\'s lesson is: Telling time in a.m. and p.m. Imagine you are waiting for a bus. The timetable says the bus arrives at 8:00. How do you know if it is 8:00 in the morning or 8:00 in the evening?', 'Engage in an interactive demonstration of a.m./p.m. by responding to guiding questions and completing steps using the tablet or chalkboard.', 'Perform or solve time writing exercises individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what the letters a.m. and p.m. stand for? Can someone give an example of a time in the afternoon? Today we learned that a.m. means before midday and p.m. means after midday. We also practiced writing times from clock faces correctly using a.m. and p.m. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly identify a.m. and p.m. times?* Can I write 11:30 a.m. on a clock face?* How will I use a.m. and p.m. to be punctual?', 'At home, observe and record three activities you do and the time you do them. Write each time correctly using a.m. or p.m. For example, \'I eat breakfast at 7:30 a.m.\'', '2026-04-11 12:41:51', '2026-04-12 08:38:46'),
(155, 584, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.5 Time', '', '', NULL, '', NULL, 'a) Convert time from the 12-hour system to the 24-hour system.', 'b) Convert time from the 24-hour system to the 12-hour system accurately.', '', 'How can we express the same moment in time using both the 12-hour and 24-hour systems?', 'Learning to learn - learner determines time in a.m. and p.m. from digital and analogue clocks.', 'Citizenship - learners determine time durations using travel timetables.', 'Integrity - learner observes time and is punctual in activities.', '* Learners textbook\n* Chalkboard and chalk\n* Chart showing 12-hour and 24-hour time comparison\n* Teacher\'s smartphone/tablet showing digital time displays', 'Recap of last lesson: reading and writing time. Who can remind us what we learned? Today\'s lesson is: Converting time between the 12-hour and 24-hour systems. Imagine you see a bus timetable with times like 14:00 and 3:00 PM. To plan your journey, you need to understand both. Why is it important to know these different ways of telling time?', 'Engage in an interactive demonstration of time conversion by responding to guiding questions and completing steps.', 'Perform or solve conversion exercises individually or in groups using the tablet or textbook.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we learned about converting time today? Can someone give an example of a 12-hour time they converted? Today we learned the rules for converting from 12-hour to 24-hour time and back again, focusing on times after 12 noon. Remember to complete the extended activity at home to practise what you have learned today.', '* How confident are you in converting 3:45 PM to 24-hour time?\n* What was the trickiest part about converting times after 12 noon?\n* Can you think of a real place where you might see 24-hour time used?', 'At home, look for any printed material like a newspaper, maize flour packet, or old bus ticket that shows a time. Write down any times you find and practise converting them between the 12-hour and 24-hour systems in your exercise book.', '2026-04-11 12:42:06', '2026-04-12 08:39:16'),
(156, 586, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.5 Time', '', '', NULL, '', NULL, 'a) Calculate time durations between departure and arrival using travel timetables.', 'b) Evaluate mastery of time concepts through a summary exercise.', '', 'How can we use travel timetables to calculate the time taken for journeys between different places?', 'Learning to learn - learners determine time durations from timetables.', 'Citizenship - learners determine time durations for travel within the country.', 'Integrity - learner observes and calculates time accurately for journeys.', '* Learners textbook\n* Sample travel timetables (bus, train, or matatu schedules from local transport)\n* Chalkboard and chalk\n* Exercise books and pencils', 'Recap of last lesson: reading and interpreting timetables. Who can remind us what a timetable shows? Today\'s lesson is: Calculating journey durations from travel timetables. Imagine you are planning a trip to visit a relative in another town using a bus. You have a timetable showing departure and arrival times. How would you figure out how long the journey will take?', 'Engage in an interactive review of time by responding to guiding questions and completing steps.', 'Perform or solve a summary assessment exercise individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main skill we practised today? Can someone explain the steps to find a journey\'s duration? Today we learned to subtract departure time from arrival time to calculate travel duration and practised this using timetable examples. Remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly calculate durations from the timetable?* Were learners able to convert between 12-hour and 24-hour clock formats?* Can learners explain the importance of accurate time calculation for travel?', 'At home, find a bus or train timetable from a newspaper, a poster, or ask a family member. Choose two different journeys and calculate their durations. Write your calculations in your exercise book.', '2026-04-11 12:42:19', '2026-04-12 08:39:40'),
(157, 587, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.6 Money', '', '', NULL, '', NULL, 'a) Identify the components of a price list.', 'b) Prepare a simple price list for items in the local community.', '', 'How do businesses organize and display their prices to help customers make buying decisions?', 'Communication and collaboration - learners discuss and create price lists in groups', 'Financial literacy - learners prepare price lists and discuss pricing', 'Integrity - learners assign honest and fair prices to items', '* Learners textbook\n* Sample price lists from local shops or markets\n* Manila paper or cardboard for creating price lists\n* Pictures or actual items from the local community (e.g., maize, beans, sugar, soap)', 'Recap of last lesson: We discussed profit and loss in simple business transactions. Who can remind us what we learned? Today\'s lesson is: Preparing a Simple Price List. Imagine you are at the local market and you see different items with prices written on cards. How does this help you decide what to buy? What information should be on those price cards?', 'Engage in an interactive demonstration of price lists by responding to guiding questions and completing steps.', 'Perform or solve price list exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing a good price list should have? Can someone give an example of an item and how you would price it? Today we learned to identify the components of a price list, like the item name and price, and how to prepare one. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly identify the components of a price list?\n* Were learners able to prepare a clear and organized price list?\n* How well did learners collaborate during the group activity?', 'At home, create a simple price list for five items in your kitchen or compound. Write the item name and a reasonable price for each. Use a piece of paper or your exercise book to display your list neatly.', '2026-04-11 12:42:28', '2026-04-12 08:39:52'),
(158, 588, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.6 Money', '', '', NULL, '', NULL, 'a) Define a budget and its importance in financial planning.', 'b) Prepare a simple budget for a given amount of money.', '', 'How can you plan to spend money wisely to meet your needs without running out?', 'Communication and collaboration - learners discuss budgeting plans and choices with peers', 'Financial literacy - learners plan a simple personal budget', 'Integrity - learners honestly allocate funds for needs in their budget', '* Learners textbook\n* Chalkboard and chalk\n* Sample price lists from local shops or markets\n* Exercise books and pens', 'Recap of last lesson: We learned about profit and loss. Who can remind us what we learned? Today\'s lesson is: Planning a simple budget. Imagine you have some money to buy things for school. You need to buy a pen, an exercise book, and maybe a snack. How would you decide what to buy so your money is enough for everything?', 'Engage in an interactive demonstration of budgeting by responding to guiding questions and completing steps using the tablet or chalkboard.', 'Perform or solve budgeting exercises individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing a budget helps us do? Can someone give an example of an item they would include in their budget? Today we learned that a budget is a plan for spending money and that it helps us spend wisely. As you go home, remember to complete the extended activity to practise what you have learned today.', '* What is a simple definition of a budget?\n* Why is creating a budget important?\n* Was your personal budget realistic for your needs?', 'At home, create a simple budget for 100 shillings. List three items you need and decide how much to spend on each. Write your budget in your exercise book to share tomorrow.', '2026-04-11 12:42:34', '2026-04-12 08:40:05');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(159, 590, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.6 Money', '', '', NULL, '', NULL, 'a) Identify situations where a loss is incurred in a transaction.', 'b) Calculate the loss realised from the sale of different items.', '', 'How can you tell if a business has made a loss and how much money was lost?', 'Communication and collaboration - learners discuss profit and loss in real-life situations', 'Financial literacy - learners discuss income and VAT as a form of tax', 'Integrity - learners honestly determine buying and selling prices', '* Learners textbook\n* Chart showing sample buying and selling prices\n* Real items with price tags (e.g. books, pens, fruits)\n* Exercise books and pencils', 'Recap of last lesson: We learned about profit in business. Who can remind us what profit is? Today\'s lesson is: Calculating Loss in Business Transactions. Imagine you buy a packet of sweets to sell at school. You pay 20 shillings for it, but you can only sell it for 15 shillings. What has happened in this situation?', 'Engage in an interactive demonstration of loss calculation by responding to guiding questions and completing steps.', 'Perform or solve loss exercises individually in exercise books following demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main thing we learned today? Can someone give an example of a situation where a loss occurs? Today we learned to identify when a business makes a loss and how to calculate the amount of money lost. Remember to complete the extended activity at home to practise your new skills.', '* How well did you calculate the loss in the exercises?\n* Can you explain to a friend what \'selling price\' and \'cost price\' mean?\n* Where might you see a loss happening in real life?', 'At home, ask a family member the price they bought an item like vegetables or fruits. Find out the price they sold it for or would sell it for. Calculate if there was a loss and how much.', '2026-04-11 12:42:46', '2026-04-12 08:40:31'),
(160, 592, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.6 Money', '', '', NULL, '', NULL, 'a) Solve real-life word problems involving profit, loss, and budgets.', 'b) Evaluate proficiency in money concepts through a summary assessment.', '', 'How can we use profit, loss, and budgeting knowledge to solve everyday money problems in our homes and community?', 'Communication and collaboration - learners discuss profit and loss in real-life situations', 'Financial literacy - learners discuss income and VAT as a form of tax', 'Integrity - learners honestly determine buying and selling prices', '* Learners textbook\n* Exercise books and pencils\n* Sample word problems written on chalkboard (market scenarios, small business, household budgets)\n* Local price examples (maize, milk, vegetables from nearby market)', 'Recap of last lesson: We learned about profit and loss. Who can remind us what we learned? Today\'s lesson is: Solving real-life money problems. Imagine your family is planning to buy items for the home. You have a budget, but the prices might change. How would you decide what to buy and ensure you don\'t lose money?', 'Engage in an interactive review of money by responding to guiding questions and completing steps.', 'Perform or solve a summary assessment exercise individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we practiced today? Can someone explain how to find profit? Today we learned to solve word problems involving profit, loss, and budgets. We also completed an assessment to check our understanding. Remember to try the extended activity at home to practise these skills further.', '* Did I correctly calculate profit and loss in the assessment?* How can I apply budgeting to a real situation at home?* What was the most challenging part of solving the money problems?', 'At home, create a simple budget for a small task, like buying ingredients for a meal. List the items, their estimated costs, and the total. Discuss with a family member how you would adjust if the prices were higher than your budget.', '2026-04-11 12:43:02', '2026-04-12 08:40:55'),
(161, 593, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.1 Lines', '', '', NULL, '', NULL, 'a) Identify and name different types of lines (straight, curved, horizontal, vertical).', 'b) Draw examples of each type of line in the environment.', '', 'Where can we find different types of lines in our classroom and school compound?', 'Creativity and imagination - learners draw examples of lines from their environment', 'Safety - learners use geometrical instruments with caution', 'Responsibility - learners share resources carefully during drawing activities', '* Learners textbook\n* Chalkboard and chalk\n* 30 cm rulers\n* Sticks or straight edges from the environment', 'Recap of last lesson: we looked at basic shapes. Who can remind us what we learned? Today\'s lesson is: Identifying and drawing different types of lines. Imagine you are looking at the horizon, the trunk of a tree, or the path to the river. What kind of lines do you see in these things?', 'Identify types of lines around the school compound and in the classroom.', 'Draw examples of each type of line in exercise books and share with the class.', '', 'Who can tell us one type of line we identified today? Can someone give an example of a vertical line we found? Today we learned to identify and name straight, curved, horizontal, and vertical lines, and we drew examples from our environment. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly identify the four main line types?* Were learners able to find and draw examples from the environment?* Did the activities help learners understand the difference between horizontal and vertical?', 'At home, look for and list five different objects that show straight, curved, horizontal, or vertical lines. Draw two of these objects in your exercise book, clearly labelling the type of line you see.', '2026-04-11 12:43:09', '2026-04-12 08:41:07'),
(162, 594, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.1 Lines', '', '', NULL, '', NULL, 'a) Define parallel lines.', 'b) Identify parallel lines in shapes and the environment.', '', 'Where can we find examples of parallel lines in our classroom and everyday surroundings?', 'Creativity and imagination - learners draw and identify parallel lines in the environment', 'Safety - learners use geometrical instruments with caution', 'Responsibility - learners carefully share resources during activities', '* Learners textbook\n* Chalkboard and chalk\n* 30 cm rulers\n* Classroom objects (desks, windows, door frames, floor tiles)', 'Recap of last lesson: properties of lines. Who can remind us what we learned? Today\'s lesson is: Identifying Parallel Lines. Imagine you are looking at the railway tracks near our village. The two rails never meet, no matter how far you look. Where else do you see lines that are always the same distance apart?', 'Identify parallel lines in classroom structures and objects.', 'Draw parallel lines freehand and share examples with the class.', '', 'Who can tell us what parallel lines are? Can someone give an example from our classroom? Today we learned that parallel lines never meet and are always the same distance apart. We also identified them in shapes and around us. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did learners define parallel lines?\n* Were learners able to identify real-world examples?\n* Did learners share resources responsibly during the activity?', 'At home, find and list five different examples of parallel lines. Look at furniture, walls, windows, or items in your compound. Draw a simple sketch of one example in your exercise book.', '2026-04-11 12:43:18', '2026-04-12 08:41:18'),
(163, 595, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.1 Lines', '', '', NULL, '', NULL, 'a) Define perpendicular lines.', 'b) Identify perpendicular lines in shapes and structures.', '', 'Where do we find perpendicular lines in our everyday surroundings and how can we verify they are truly perpendicular?', 'Creativity and imagination - learners identify perpendicular lines in everyday surroundings', 'Safety - learners exercise caution when using geometrical instruments like set squares', 'Responsibility - learners carefully share and handle drawing instruments', '* Learners textbook\n* Set square or right-angled cardboard template\n* Ruler (30 cm)\n* Examples from classroom: corners of desks, windows, doors, blackboard edges', 'Recap of last lesson: lines and angles. Who can remind us what we learned? Today\'s lesson is: Identifying and verifying perpendicular lines. Look at the corner where two walls meet. It looks like a perfect \'L\' shape. Where else in this room or outside can you see such sharp, square corners?', 'Identify perpendicular lines in corners of rooms and objects.', 'Draw perpendicular lines and verify using a set square.', '', 'Who can tell us one thing we learned about perpendicular lines today? Can someone give an example from our classroom? Today we learned that perpendicular lines meet at a 90-degree angle, and we can check this using a set square or a corner of a book. Remember to complete the extended activity to practise finding perpendicular lines at home.', '* Did I correctly identify perpendicular lines in the classroom?* Was I able to verify the angle using a set square?* Can I draw two lines that are perpendicular to each other?', 'At home, find and list five different places where you see perpendicular lines. Examples could be a window frame, a table corner, or a door. Sketch one example in your exercise book.', '2026-04-11 12:43:24', '2026-04-12 08:41:30'),
(164, 596, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.1 Lines', '', '', NULL, '', NULL, 'a) Draw parallel lines using a ruler and set square.', 'b) Draw perpendicular lines using a ruler and set square.', '', 'How can we use a set square and ruler to draw lines that never meet and lines that cross at right angles?', 'Creativity and imagination - learners bisect lines using ruler and set square', 'Safety - learners handle geometrical instruments with caution', 'Responsibility - learners share and handle drawing tools carefully', '* Learners textbook\n* Ruler (30 cm)\n* Set square\n* Pencils and erasers\n* Chalkboard ruler and set square for demonstration', 'Recap of last lesson: We learned about different types of lines. Who can remind us what parallel and perpendicular lines are? Today\'s lesson is: Drawing parallel and perpendicular lines using a ruler and set square. Imagine you are designing a fence for a garden. The posts must be straight and the crossbars must be fixed at perfect right angles. How can we use our tools to draw these lines accurately?', 'Draw parallel and perpendicular lines using a ruler and set square in exercise books.', 'Compare drawings with classmates and correct errors.', '', 'Who can tell us the two main types of lines we practiced drawing today? Can someone explain the difference between them? Today we learned how to use a ruler and set square to draw parallel lines that never meet and perpendicular lines that cross at right angles. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I draw parallel lines correctly using the set square?\n* Were my perpendicular lines at a perfect 90-degree angle?\n* How can I use these skills in a real-life design?', 'Look for parallel and perpendicular lines in your home environment, like on windows, doors, or furniture. Using a straight edge like a book and a corner of a paper as a guide, try to sketch these lines in your exercise book. Label them as parallel or perpendicular.', '2026-04-11 12:43:31', '2026-04-12 08:41:43'),
(165, 597, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.1 Lines', '', '', NULL, '', NULL, 'a) Identify parallel and perpendicular lines in 2-D shapes.', 'b) Count and categorise the types of lines in given shapes.', '', 'How do we identify parallel and perpendicular lines in 2-D shapes?', 'Creativity and imagination - learners bisect lines using ruler and compasses', 'Safety - learners exercise caution when using geometrical instruments', 'Responsibility - learners carefully share resources during activities', '', 'Recap of last lesson: We learned about different types of lines. Who can remind us what we learned? Today\'s lesson is: Identifying and counting parallel and perpendicular lines in 2-D shapes. Look around the classroom at the windows, doors, and books. Can you see any lines that run side by side or meet at a corner? How would you describe them?', 'Categorise lines in cut-out 2-D shapes as parallel or perpendicular.', 'Record findings in a table and share with the class.', '', 'Who can tell us one thing we learned about lines today? Can someone give an example of a shape with perpendicular lines? Today we learned how to identify parallel and perpendicular lines in shapes and how to count them. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did you identify parallel lines in shapes?\n* What was challenging about counting perpendicular lines?\n* Can you name a real-life object with both line types?', 'At home, find three different objects or surfaces (e.g., a book, a window frame, a floor tile). Draw their outlines in your exercise book and label all the parallel and perpendicular lines you can see. Count how many of each type are in each shape.', '2026-04-11 12:43:39', '2026-04-12 08:41:55'),
(166, 598, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.1 Lines', '', '', NULL, '', NULL, 'a) Relate types of lines to real-life structures and patterns.', 'b) Evaluate mastery of lines through a summary exercise.', '', 'How are parallel and perpendicular lines used in the structures and objects we see around us every day?', 'Creativity and imagination - learners relate lines to real-life structures and patterns.', 'Safety - learners handle geometrical instruments with caution.', 'Responsibility - learners share resources carefully during activities.', '* Learners textbook\n* Chalkboard and chalk\n* Rulers and straight edges\n* Examples from school environment (buildings, windows, doors, desks, fences)', 'Recap of last lesson: constructing parallel lines. Who can remind us what we learned? Today\'s lesson is: Using Parallel and Perpendicular Lines in Real Life. Look at the walls of this classroom. The lines where the walls meet the floor are straight and meet at corners. Where else do you see lines that never meet or lines that cross at right angles around you?', 'Identify uses of parallel and perpendicular lines in everyday structures.', 'Complete a summary exercise individually and receive feedback.', '', 'Who can tell us one place we find parallel lines in our environment? Can someone name a structure that uses perpendicular lines? Today we learned to identify parallel and perpendicular lines in real-world structures and evaluated our understanding through an exercise. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly identify parallel lines in structures?\n* Did I accurately find perpendicular lines in patterns?\n* How can I use this knowledge to describe other objects?', 'At home, find and sketch three different objects or parts of your house that show parallel lines. Then, find and sketch three that show perpendicular lines. Label each sketch with the type of line you identified.', '2026-04-11 12:43:46', '2026-04-12 08:42:07'),
(167, 599, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.2 Angles', '', '', NULL, '', NULL, 'a) Define an angle and identify its parts (arms and vertex).', 'b) Classify angles as acute, right, obtuse, straight, or reflex.', '', 'What makes one angle different from another angle?', 'Self-efficacy - learners confidently identify and classify angles.', 'Environmental education - learners identify angles from objects in their surroundings.', 'Unity - learners work harmoniously to compare angle sizes.', '* Learners textbook\n* Rulers\n* Pencils\n* Classroom objects (corners of books, desks, windows, door frames, clock hands)', 'Recap of last lesson: properties of shapes. Who can remind us what we learned? Today\'s lesson is: Defining and classifying angles. Look at the corners of your desk or the roof of the classroom. These corners form angles. What do you notice about the sizes of these different corners?', 'Identify different types of angles in the classroom environment.', 'Draw and label examples of each type of angle in exercise books.', '', 'Who can tell us one type of angle we identified today? Can someone give an example of a right angle in our classroom? Today we learned to define an angle with its arms and vertex, and to classify angles as acute, right, obtuse, straight, or reflex. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did learners define an angle?* Did learners correctly classify the angles they found?* What was challenging about drawing reflex angles?', 'At home, find and list five different angles. For each, name the object and classify the angle (e.g., acute, right). Draw two of these angles in your exercise book and label the arms and vertex.', '2026-04-11 12:43:53', '2026-04-12 08:42:19'),
(168, 600, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.2 Angles', '', '', NULL, '', NULL, 'a) Identify the parts of a protractor.', 'b) Measure given angles using a protractor accurately.', '', 'How can we accurately measure the size of any angle using a protractor?', 'Self-efficacy - learners confidently use a new tool to measure angles.', 'Environmental Education - learners identify and measure angles in man-made structures.', 'Unity - learners work in pairs to read scales and compare measurements.', '* Learners textbook\n* Protractors (one per learner or pair)\n* Worksheets with pre-drawn angles of different sizes\n* Rulers\n* Chalkboard angles drawn for demonstration', 'Recap of last lesson: We learned about different types of angles. Who can name one? Today\'s lesson is: Identifying parts of a protractor and measuring angles. Imagine you and a friend are building a simple wooden stool. To make it strong and level, you need to cut the legs at the correct angle. How could you check if your angles are correct?', 'Practise reading the protractor scale in pairs.', 'Measure angles drawn on worksheets and record measurements in exercise books.', '', 'Who can tell us one part of a protractor we learned today? Can someone share one tip for measuring an angle accurately? Today we learned to identify the centre hole and the scale on a protractor, and how to align it to measure angles. Remember to complete the extended activity at home to practise your new skill.', '* Did all learners correctly identify the centre and baseline of the protractor?\n* Were learners able to read both the inner and outer scales accurately?\n* How confident were learners in recording their angle measurements?', 'At home, find three different angles made by objects like a book corner, a roof, or a window. Sketch them in your exercise book. Use your protractor to measure and label each angle\'s size. Share your findings tomorrow.', '2026-04-11 12:44:01', '2026-04-12 11:30:44'),
(169, 602, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.2 Angles', '', '', NULL, '', NULL, 'a) Identify and name angles in triangles and quadrilaterals.', 'b) Measure the angles of given polygons and record the results.', '', 'What is the sum of the interior angles in different triangles and quadrilaterals, and does it change with their shape or size?', 'Self-efficacy - learners confidently measure and sum angles practically', 'Environmental Education - learners use local objects to explore angle properties', 'Unity - learners work harmoniously in groups to compare results', '* Learners textbook\n* Protractors\n* Rulers\n* Pencils and erasers\n* Chart paper or exercise books for recording measurements', 'Recap of last lesson: We learned about different types of angles. Who can name one? Today\'s lesson is: Finding the Sum of Angles in Triangles and Quadrilaterals. Imagine you are helping a carpenter check if the corners of a wooden picture frame are square. How could you use your knowledge of angles to help?', 'Measure all interior angles of drawn triangles and quadrilaterals.', 'Record sums of angles and discuss findings in groups.', '', 'Who can tell us one thing we discovered about triangles today? Can someone share what they found for a rectangle? Today we learned to measure interior angles and found their sums are constant. Remember to complete the extended activity to practise what you have learned today.', '* Did all groups find the same sum for triangles?\n* How did measuring help you understand the angle sum?\n* Can you name a quadrilateral found in our classroom?', 'At home, find a triangular or four-sided object, like a slice of bread or a book. Use a folded paper corner as a guide to estimate its angles. Record your estimates and find their total sum.', '2026-04-11 12:44:14', '2026-04-12 11:31:06'),
(170, 603, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.2 Angles', '', '', NULL, '', NULL, 'a) Identify angles in real-life structures (rooftops, doors, road intersections).', 'b) Estimate and verify the size of angles in familiar objects.', '', 'How can you find and measure angles in the structures and objects around your school?', 'Self-efficacy - learner confidently establishes angle sizes in real objects', 'Environmental education - learner practically finds angles in different objects from the environment', 'Unity - learner works harmoniously with others to compare angles', '* Learners textbook\n* Protractors\n* Rulers\n* Exercise books and pencils\n* School structures (buildings, doors, windows, rooftops, fences, road junctions)', 'Recap of last lesson: we looked at different types of angles. Who can name one? Today\'s lesson is: Finding and Measuring Angles in Our Environment. Imagine you are helping a carpenter build a roof. He needs to know the angles at the corners to cut the wood correctly. How can we find these angles around our school?', 'Search for angles in the school environment and estimate their sizes.', 'Record and verify estimates using a protractor.', '', 'Who can tell us one place we found angles today? Can someone share how they estimated an angle\'s size? Today we learned to identify angles in real structures and to estimate and verify their sizes using a protractor. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did you estimate angles before measuring?* What was the most interesting angle you found?* Why is knowing about angles useful in building?', 'At home, find three different angles in your compound, like on a fence, a window, or a cooking pot stand. Sketch them in your exercise book and write your estimate of their size next to each one.', '2026-04-11 12:44:21', '2026-04-12 11:31:17'),
(171, 604, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.2 Angles', '', '', NULL, '', NULL, 'a) Solve problems involving classification and measurement of angles.', 'b) Evaluate mastery of angles through a summary exercise.', '', 'How can I accurately identify, classify, and measure different types of angles to solve real-world problems?', 'Self-efficacy - learner confidently solves angle measurement problems.', 'Environmental Education - learner identifies angles from different objects in the environment.', 'Unity - learner works harmoniously with others to compare angle sizes.', '* Learners textbook\n* Protractors\n* Rulers\n* Geometric sets\n* Teacher-prepared summary exercise worksheets', 'Recap of last lesson: angles. Who can remind us what we learned about classifying angles? Today\'s lesson is: Solving problems by classifying and measuring angles. Imagine you are helping a carpenter check if the corners of a wooden frame are square. How could you use your knowledge of angles to help?', 'Complete a summary exercise classifying and measuring angles.', 'Receive feedback and correct any misconceptions.', '', 'Who can tell us one type of angle we worked with today? Can someone give an example of where we might find this angle? Today we learned to classify angles like acute and obtuse, and practised measuring them to solve problems. Remember to complete the extended activity at home to practise what you have learned today.', '* Did all learners correctly classify the angles in the exercise?* Did learners use the protractor correctly to measure angles?* Can learners explain how to identify a right angle in their environment?', 'At home, find three different angles made by objects like doors, windows, or roof edges. Sketch them in your exercise book and label each one as acute, right, or obtuse based on your estimation.', '2026-04-11 12:44:30', '2026-04-12 11:31:27'),
(172, 605, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.3 3-D Objects', '', '', NULL, '', NULL, 'a) Identify and name common 3-D objects (cube, cuboid, cylinder, sphere, cone, pyramid).', 'b) Relate 3-D objects to real-life examples.', '', 'What objects around us have shapes like cubes, cuboids, cylinders, spheres, cones, and pyramids?', 'Creativity and imagination - learners visualize and open up nets of 3-D objects', 'Social cohesion - learners discuss shapes on nets and respect each other\'s views', 'Patriotism - learners collect and safely keep 3-D objects for environmental conservation', '* Learners textbook\n* Collection of 3-D objects from the environment (boxes, tins, balls, bottles, funnel, stones)\n* Real-life items: matchbox, milk packet, toilet roll, orange, traditional hats, roof models\n* Chart showing names of 3-D shapes', 'Recap of last lesson: 2-D shapes. Who can remind us what we learned? Today\'s lesson is: Identifying 3-D objects in our environment. Look around the classroom and outside. What objects can you see that are not flat? Which ones can you hold and feel from all sides?', 'Collect 3-D objects from the environment and name them.', 'Match objects to their geometric names and share with the class.', '', 'Who can name one 3-D object we learned about today? Can you give a real-life example of a cylinder? Today we learned to identify and name cubes, cuboids, cylinders, spheres, cones, and pyramids. We also found examples of these shapes around us. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly match objects like a chalk box to \'cuboid\'?\n* Were learners able to find and name a cone in the environment?\n* How well did groups discuss and respect each other\'s views?', 'At home, find and collect five different 3-D objects. Draw a simple table in your exercise book. List each object, its geometric name (e.g., cube), and where you found it.', '2026-04-11 12:44:36', '2026-04-12 11:31:39'),
(173, 606, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.3 3-D Objects', '', '', NULL, '', NULL, 'a) Count and record the number of faces, edges, and vertices of given 3-D objects.', 'b) Compare properties of different 3-D objects.', '', 'How can we identify and compare the faces, edges, and vertices of different 3-D objects we use every day?', 'Creativity and Imagination - learners open up nets of cuboids, cubes and cylinders.', 'Social Cohesion - learners discuss shapes on nets and respect each other\'s views.', 'Patriotism - learners collect and safely keep 3-D objects for environmental conservation.', '* Learners textbook\n* Empty boxes (matchboxes, chalk boxes, soap boxes)\n* Tin cans and cylindrical containers\n* Stone or clay pyramids (locally made)\n* Balls or spheres (fruit, stones)', 'Recap of last lesson: 2-D shapes. Who can remind us what we learned? Today\'s lesson is: Identifying Faces, Edges, and Vertices of 3-D Objects. Look around the classroom or outside. Many items we use, like boxes or tins, are 3-D objects. They have different flat and curved surfaces. What can you see that is a 3-D object?', 'Handle 3-D objects and count faces, edges, and vertices.', 'Record findings in a table and compare with other groups.', '', 'Who can tell us one thing they learned about a cube? Can someone name a 3-D object we looked at and its properties? Today we learned to count and record the number of faces, edges, and vertices of 3-D objects like cubes and cuboids. We also compared their properties. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly count the faces, edges, and vertices?* How well did groups compare the properties of different objects?* Can learners identify 3-D objects from their nets?', 'At home, find five different 3-D objects (e.g., a matchbox, a soda bottle, a ball). Create a table and record the name, number of faces, edges, and vertices for each object. Bring your findings to the next lesson.', '2026-04-11 12:44:43', '2026-04-12 11:31:52'),
(174, 607, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.3 3-D Objects', '', '', NULL, '', NULL, 'a) Group 3-D objects by shared properties (flat or curved faces).', 'b) Justify the classification of each object.', '', 'What properties can we use to group different 3-D objects into families?', 'Creativity and imagination - learners open up nets to visualize 3-D shapes, Communication and collaboration - learners present and justify their classifications', 'Social cohesion - learners discuss shapes on nets and respect each other\'s views', 'Patriotism - learners collect and safely keep objects as part of environmental conservation', '* Learners textbook\n* Collection of 3-D objects from the environment (boxes, tins, balls, bottles, cones made from paper)\n* Chart paper or large sheets for grouping objects\n* Locally made models of cubes, cuboids, cylinders, pyramids, and spheres using cardboard or clay', 'Recap of last lesson: 3-D objects. Who can name a 3-D object we looked at? Today\'s lesson is: Grouping 3-D Objects by Their Properties. Imagine you are helping to sort items in a shop. You have boxes, tins, and balls. How would you decide which items are similar?', 'Sort a collection of 3-D objects by their properties.', 'Present and justify classifications to the class.', '', 'What was one property we used to group objects today? Can you name a 3-D object with only curved faces? Today we learned to group 3-D objects by their faces and to justify our classifications. Remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly group objects by flat or curved faces?\n* Were learners able to justify their classifications clearly?\n* Did the use of real objects help in understanding the properties?', 'At home, find five different 3-D objects like a cup, box, or fruit. Group them by whether their faces are flat or curved. Draw or list the objects in your two groups in your exercise book.', '2026-04-11 12:44:51', '2026-04-12 11:32:03'),
(175, 608, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.3 3-D Objects', '', '', NULL, '', NULL, 'a) Identify the net of a cube and a cuboid.', 'b) Cut out and fold nets to form 3-D objects.', '', 'How can we open up a cube or cuboid box to see all its faces at once?', 'Creativity and imagination - learners cut and fold nets to form 3-D objects', 'Social cohesion - learners discuss shapes on nets and respect each other\'s views', 'Patriotism - learners collect and safely keep 3-D objects for environmental conservation', '* Learners textbook\n* Cardboard or manila paper for drawing and cutting nets\n* Scissors and rulers\n* Empty cartons or boxes (matchboxes, soap boxes, tea packets)\n* Pencils and erasers', 'Recap of last lesson: properties of 3-D objects. Who can name a 3-D shape we see around us? Today\'s lesson is: Creating nets for cubes and cuboids. Imagine you have a small cardboard box. To recycle it, you must flatten it. What shape does it become when you open it up completely?', 'Draw, cut, and fold nets to make cubes and cuboids.', 'Verify that the folded net forms the correct 3-D shape.', '', 'Who can tell us one thing we did with nets today? Can someone show us their folded cube? Today we learned to identify nets of cubes and cuboids and how to fold them into 3-D shapes. Remember to complete the extended activity at home to practise what you have learned today.', '* Did I correctly identify the net for a cube?\n* Can I explain why a shape is not a net for a cuboid?\n* Did I safely handle the materials while cutting and folding?', 'At home, find a small cardboard box, like a matchbox or tea packet. Carefully cut along its edges to open it up flat. Draw the shape you get—this is its net. Try to fold it back together.', '2026-04-11 12:47:42', '2026-04-12 11:32:14'),
(176, 610, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.3 3-D Objects', '', '', NULL, '', NULL, 'a) Solve problems involving properties and nets of 3-D objects.', 'b) Evaluate mastery of 3-D objects through a summary exercise.', '', 'How can we use our understanding of 3-D object properties and nets to solve real-world problems involving containers?', 'Creativity and imagination - learners sketch nets of real containers', 'Social cohesion - learners discuss shapes on nets and respect each other\'s views', 'Patriotism - learners collect and safely keep 3-D objects for environmental conservation', '* Learners textbook\n* Sample nets of cuboids, cubes, and cylinders (from previous lessons or drawn on manila paper)\n* Actual 3-D objects (boxes, tins, cylindrical containers from the community)\n* Chalkboard and chalk for reviewing common errors', 'Recap of last lesson: properties and nets of 3-D objects. Who can describe one property of a cylinder? Today\'s lesson is: Solving real-world problems with 3-D objects and nets. Imagine you need to pack some harvested maize into a storage container. You have different box shapes and need to choose the best one. What properties of the boxes would you consider?', 'Complete a summary exercise on 3-D object properties and nets.', 'Receive feedback and review common errors.', '', 'Who can share one problem we solved today? Can someone explain how a net helps us understand a container? Today we learned to use properties like faces and edges to solve problems, and we practiced drawing nets. Remember to complete the extended activity at home to practise what you have learned today.', '* Did learners correctly identify the properties of cubes, cuboids, and cylinders in the exercise?\n* Were learners able to sketch the correct net for a given real-world container?\n* Did the feedback session clarify common errors with 3-D object properties?', 'Find three different containers at home (e.g., a cereal box, a tin, a milk packet). Sketch the net for one of them in your exercise book. Label the shapes (rectangles, squares, circles) you see on your net.', '2026-04-11 12:47:55', '2026-04-12 11:32:37'),
(177, 611, 'Grade 6', 'Mathematics', '4.0 Data Handling', '4.1 Bar Graphs', '', '', NULL, '', NULL, 'a) Define data and give examples of data collected in daily life.', 'b) Use tally marks to record data from a survey.', '', 'How can we collect and record information about our classmates using tally marks?', 'Creativity and imagination - learners discuss and collect data, then organise it using tally marks.', 'Non-formal education - learner collects data from immediate environment to address community issues.', 'Integrity - learner uses tally marks to honestly represent collected data.', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Chart paper or large piece of paper (for class tally display)', 'Recap of last lesson: We have been learning about different ways to show information. Who can remind us what a graph is? Today\'s lesson is: Collecting and Recording Data Using Tally Marks. Imagine your class wants to know the favourite fruit of learners. You ask each person and need a quick way to write down their answers. How would you keep track of everyone\'s choice?', 'Conduct a simple class survey and record responses using tally marks.', 'Share tally results with the class and discuss.', '', 'Who can tell us what tally marks are used for? Can someone give an example of data we collected today? Today we learned that data is information, and we can collect and record it using tally marks. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly define data?\n* Were learners able to accurately use tally marks to record survey responses?\n* How can tally marks help us organise information honestly?', 'At home, collect data from your family. Ask them their favourite type of food. Record their answers using tally marks in your exercise book. Bring your tally chart to the next lesson.', '2026-04-11 12:48:03', '2026-04-12 11:32:48'),
(178, 612, 'Grade 6', 'Mathematics', '4.0 Data Handling', '4.1 Bar Graphs', '', '', NULL, '', NULL, 'a) Transfer tally marks into a frequency table.', 'b) Identify the highest and lowest frequencies in the table.', '', 'How do we change tally marks into numbers and find which item appears most and least often?', 'Creativity and imagination - learners discuss and organise collected data into a frequency table', 'Non-formal education - learner collects data from the immediate home environment', 'Integrity - learner honestly counts and records data in the table', '* Learners textbook\n* Tally data collected in Lesson 1\n* Exercise books and pencils\n* Chalkboard and chalk\n* Ruler for drawing frequency table', 'Recap of last lesson: collecting and recording data using tally marks. Who can remind us what we learned? Today\'s lesson is: Changing tally marks into numbers and finding the highest and lowest. Imagine your class wants to know the most common type of tree in the school compound. You have counted them and made tally marks. How can you turn those marks into clear numbers to see which tree is most common?', 'Convert tally data from Lesson 1 into a frequency table.', 'Identify and discuss the highest and lowest values.', '', 'Who can tell us the first step we did today? Can someone explain how we find the highest and lowest number in our table? Today we learned to transfer tally marks into a frequency table and to identify the item with the highest and lowest frequency. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly convert tally marks to numbers?\n* Could learners explain how to find the highest frequency?\n* Did the activity help learners understand data representation?', 'At home, collect data on a simple topic, like types of utensils in your kitchen. Use tally marks to count them, then create a frequency table from your tallies. Identify which utensil you have the most and least of.', '2026-04-11 12:48:10', '2026-04-12 11:32:59'),
(179, 613, 'Grade 6', 'Mathematics', '4.0 Data Handling', '4.1 Bar Graphs', '', '', NULL, '', NULL, 'a) Identify the title, axes, labels, and scale of a bar graph.', 'b) Describe the purpose of each component of a bar graph.', '', 'Why does a bar graph need a title, axes, labels, and scale to be useful?', 'Creativity and imagination - learners discuss and organize data using graphs', 'Non-formal education - learner collects data from the immediate environment', 'Integrity - learner honestly represents data using graph components', '* Learners textbook\n* Sample bar graphs from newspapers or health posters\n* Manila paper or chalkboard for drawing a large bar graph\n* Ruler for drawing straight lines and axes', 'Recap of last lesson: We learned about collecting and organizing data. Who can remind us what we did? Today\'s lesson is: Identifying and describing the parts of a bar graph. Imagine you see a chart showing the number of trees planted by different classes. Without a title or labels, would you understand it? What makes a graph easy to read?', 'Label the parts of a given bar graph using provided terms.', 'Discuss why each component is important for reading the graph.', '', 'Who can tell us the four main parts of a bar graph we learned today? Can you explain why the scale is important? Today we learned to identify the title, axes, labels, and scale of a bar graph and described why each part is necessary. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Can I label the axes on a bar graph?* Why must a bar graph have a title?* How does a scale help us read data?', 'At home, find a simple set of data, like the number of spoons, cups, and plates in your kitchen. Draw a bar graph to show this data. Remember to include a title, labeled axes, and a clear scale.', '2026-04-11 12:48:16', '2026-04-12 11:33:08'),
(180, 614, 'Grade 6', 'Mathematics', '4.0 Data Handling', '4.1 Bar Graphs', '', '', NULL, '', NULL, 'a) Choose an appropriate scale for a vertical bar graph.', 'b) Draw and label a vertical bar graph from a frequency table.', '', 'How do we choose the right scale to clearly show our survey data on a vertical bar graph?', 'Creativity and imagination - learners design and draw their own bar graphs, Communication and collaboration - learners discuss scale choices in pairs', 'Non-formal education - learner collects and graphs data from their home environment', 'Integrity - learner accurately represents data using the chosen scale', '* Learners textbook\n* Manila paper or newsprint for drawing large bar graphs\n* Rulers (at least one per group)\n* Frequency table from class survey (prepared in previous lesson)\n* Chalkboard and chalk for demonstration', 'Recap of last lesson: collecting and organising data into frequency tables. Who can remind us what a frequency table shows? Today\'s lesson is: Choosing a scale and drawing a vertical bar graph. Imagine your class surveyed favourite fruits. To draw a clear graph, you must decide how tall each bar should be. How would you choose a scale to make your graph easy to read?', 'Draw a vertical bar graph from the class survey frequency table.', 'Ensure title, labels, and scale are included.', '', 'Who can tell us the two main things we did in today\'s lesson? Can someone explain why choosing the right scale is important? Today we learned how to choose an appropriate scale for a bar graph and how to draw and label the graph correctly. Remember to complete the extended activity at home to practise what you have learned today.', '* Did I choose a scale that made my graph clear?\n* Are my graph\'s title and labels correct?\n* Can I explain my scale choice to a friend?', 'At home, conduct a simple survey (e.g., types of utensils in your kitchen). Create a frequency table. Then, on a piece of paper, choose a scale and draw a vertical bar graph to show your data. Remember to include a title and labels.', '2026-04-11 12:48:23', '2026-04-12 11:33:19'),
(181, 615, 'Grade 6', 'Mathematics', '4.0 Data Handling', '4.1 Bar Graphs', '', '', NULL, '', NULL, 'a) Choose an appropriate scale for a horizontal bar graph.', 'b) Draw and label a horizontal bar graph from a frequency table.', '', 'How do you choose the right scale to accurately represent data on a horizontal bar graph?', 'Creativity and imagination - learners discuss and organise collected data into graphs', 'Non-formal education - learner collects data from the immediate home environment', 'Integrity - learner honestly represents data using an accurate scale', '* Learners textbook\n* Chalkboard and chalk\n* Ruler\n* Sample frequency tables (from local contexts like crop harvest, school attendance, favorite sports)\n* Exercise books and pencils', 'Recap of last lesson: drawing vertical bar graphs. Who can remind us what we learned? Today\'s lesson is: Choosing a scale and drawing a horizontal bar graph. Imagine your class wants to show the favourite fruits of learners in Grade 6. You have a table of numbers. How would you draw a graph to show this information clearly? What is the first thing you need to decide?', 'Draw a horizontal bar graph from a provided frequency table.', 'Compare the horizontal and vertical formats and discuss.', '', 'Who can tell us one thing we learned about drawing a bar graph today? Can someone explain why choosing the right scale is important? Today we learned how to select an appropriate scale for a horizontal bar graph and how to draw and label it from a frequency table. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I choose an appropriate scale for my graph?* Is my horizontal bar graph clearly labelled?* Can I explain why my chosen scale is accurate?', 'At home, collect data on a simple topic, like the number of doors or windows in each room. Create a frequency table. Choose a suitable scale and draw a horizontal bar graph to represent your data in your exercise book.', '2026-04-11 12:48:29', '2026-04-12 11:33:29'),
(182, 616, 'Grade 6', 'Mathematics', '4.0 Data Handling', '4.1 Bar Graphs', '', '', NULL, '', NULL, 'a) Read values from bars on a given bar graph.', 'b) Answer questions based on information shown in a bar graph.', '', 'How do we read and interpret information presented in a bar graph to answer questions?', 'Communication and Collaboration - learners discuss and compare their answers, Creativity and Imagination - learners interpret data to understand real situations', 'Non-Formal Education - learners interpret data relevant to their community from graphs', 'Integrity - learners read and report graph values honestly', '* Learners textbook\n* Bar graph charts drawn on manila paper or chalkboard showing real-life data (school enrollment, crop harvests, weekly market prices)\n* Printed or teacher-drawn bar graph worksheets\n* Exercise books and pencils', 'Recap of last lesson: collecting and organising data. Who can remind us what we did? Today\'s lesson is: Reading and Interpreting Bar Graphs. Imagine your class wants to know the most popular fruit sold at the local market. A bar graph could show this information clearly. How do you think we find the answers from the graph?', 'Read and answer questions from a given bar graph in exercise books.', 'Discuss answers as a class and correct errors.', '', 'Who can tell us one thing we did today? Can someone explain how to find the value of a bar? Today we learned how to read values directly from a bar graph and use that information to answer questions. Remember to complete the extended activity at home to practise your new skills.', '* Did all learners correctly read values from the bars?\n* Were learners able to interpret the graph to answer questions?\n* How can I support learners who struggled with the scale?', 'At home, look for a simple bar graph in a newspaper, textbook, or on a product package. Read the graph and write down three pieces of information you learn from it. Be ready to share your findings in the next lesson.', '2026-04-11 12:48:36', '2026-04-12 11:33:39'),
(183, 617, 'Grade 6', 'Mathematics', '4.0 Data Handling', '4.1 Bar Graphs', '', '', NULL, '', NULL, 'a) Compare two sets of data displayed on the same bar graph.', 'b) Draw conclusions from comparisons made on the bar graph.', '', 'What can we learn by comparing two sets of data shown on the same bar graph?', 'Creativity and imagination - learners discuss and organise data using pictographs', 'Non-formal education - learner collects data from immediate environment to address community issues', 'Integrity - learner piles objects honestly to represent data', '* Learners textbook\n* Chart paper or manila paper with pre-drawn bar graphs showing two data sets\n* Chalkboard and chalk\n* Exercise books and pencils', 'Recap of last lesson: drawing bar graphs. Who can remind us what a bar graph shows? Today\'s lesson is: comparing data on bar graphs. Imagine you have two bar graphs showing the number of mangoes and oranges sold at the market this week. By looking at them together, what can we find out? What do you think the tallest bar tells us?', 'Compare two bar graphs showing similar categories and discuss differences.', 'Write two conclusions from the comparison in exercise books.', '', 'Who can tell us one thing we learned about comparing bar graphs today? Can someone give an example of a conclusion we can draw? Today we learned to compare two sets of data on the same graph and draw conclusions from the differences we see. As you go home, remember to complete the extended activity to practise comparing data.', '* Did learners correctly identify which category had more items?* Could learners explain the difference between two bars?* Were learners able to write two clear conclusions?', 'At home, create two simple bar graphs on the same topic, like types of trees near your home. Use sticks or stones to represent the data. Compare your graphs and write two sentences about what you notice.', '2026-04-11 12:48:43', '2026-04-12 11:33:49');
INSERT INTO `lesson_plans` (`id`, `sow_id`, `grade`, `learning_area`, `strand`, `sub_strand`, `school_name`, `teacher_name`, `date_taught`, `duration`, `num_learners`, `slo1`, `slo2`, `slo3`, `key_inquiry_question`, `core_competencies`, `pcis`, `values_attit`, `resources`, `introduction`, `step1`, `step2`, `step3`, `conclusion`, `reflection`, `extended_activity`, `created_at`, `updated_at`) VALUES
(184, 619, 'Grade 6', 'Mathematics', '4.0 Data Handling', '4.1 Bar Graphs', '', '', NULL, '', NULL, 'a) Extract data from a word problem to create a frequency table.', 'b) Draw a bar graph from the extracted data.', '', 'How can we extract and organise information from a real-life story to display it visually using a bar graph?', 'Creativity and imagination - learners discuss and organise data into pictographs and graphs', 'Non-formal education - learners collect data from their immediate home environment', 'Integrity - learners honestly represent data using accurate scales and piles', '* Learners textbook\n* Chart paper or manila paper for drawing bar graphs\n* Rulers for drawing straight lines and axes\n* Sample word problems written on the chalkboard', 'Recap of last lesson: collecting and organising data. Who can remind us what we learned? Today\'s lesson is: Extracting data from a story to draw a bar graph. Imagine your class wants to know the favourite fruit of learners in your grade. You hear a story about a market survey. How could we organise this information to see the results clearly?', 'Extract data from a provided word problem and draw the bar graph.', 'Compare bar graphs drawn by different groups and discuss.', '', 'Who can tell us the first step we took today? Can someone explain why we use a frequency table? Today we learned how to extract data from a word problem, create a frequency table, and draw a bar graph from it. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly extract data from the word problem?* Were the bar graphs drawn with accurate and honest scales?* Can learners explain the steps from story to graph?', 'At home, collect data on a simple topic, like the number of different utensils in your kitchen. Create a frequency table and use it to draw a bar graph in your exercise book. Use items like stones or seeds to represent your data honestly.', '2026-04-11 12:48:57', '2026-04-12 11:34:10'),
(185, 620, 'Grade 6', 'Mathematics', '4.0 Data Handling', '4.1 Bar Graphs', '', '', NULL, '', NULL, 'a) Solve real-life problems by drawing and reading bar graphs.', 'b) Evaluate mastery of bar graphs through a summary exercise.', '', 'How can you use a bar graph to solve a problem you might face in your school or community?', 'Creativity and imagination - learners discuss and organise collected data into a graph', 'Non-formal education - learner collects data from the immediate environment to address issues', 'Integrity - learner honestly represents data in their drawn bar graph', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Rulers\n* Sample data sets (class attendance, crops harvested, school items sold)', 'Recap of last lesson: bar graphs. Who can remind us what we learned? Today\'s lesson is: Solving real-life problems using bar graphs. Imagine your class wants to know the most common type of tree around the school to plant more. You could count them and show the results. How would a bar graph help you make a decision?', 'Complete a summary task: draw, label, and answer questions from a bar graph.', 'Receive feedback and review errors.', '', 'Who can tell us one thing we practiced today? Can someone explain why labeling a bar graph is important? Today we learned to draw bar graphs from data and use them to answer questions and solve problems. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners correctly label their bar graph axes?\n* Could learners use their graph to answer the summary questions?\n* Did learners connect the graph to a real community problem?', 'At home, collect data on one thing (e.g., types of utensils in your kitchen, colours of shirts). Draw a neat bar graph on paper to show your findings. Bring it to class to share how your graph tells a story.', '2026-04-11 12:49:03', '2026-04-12 11:34:20'),
(228, 562, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Evaluate mastery of conversion, addition, and subtraction of length units.', 'b) Review common errors in measuring small objects.', '', 'How can we check our accuracy and avoid common mistakes when measuring and calculating with different units of length?', 'Creativity and imagination - learner sketches circles to practically understand circumference, diameter and radius', 'Environmental Education - learner chooses appropriate units for measuring lengths of different objects in the environment', 'Unity - learner works amicably with peers to determine lengths and discuss answers', '* Learners textbook\n* Metre rule or tape measure\n* Small objects from the classroom (pencils, erasers, small sticks)\n* Chalkboard and chalk\n* Exercise books', 'Recap of last lesson: We practiced converting between units of length. Who can remind us what we learned? Today\'s lesson is: Reviewing Accuracy in Measuring and Calculating Length. Imagine you are helping a carpenter cut a piece of wood. He has measured it in metres, but needs the length in centimetres to be precise. How can we ensure our calculations are correct to avoid mistakes?', 'Engage in an interactive review of length concepts by responding to guiding questions and completing steps.', 'Perform or solve a summary assessment exercise individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we did to check our accuracy today? Can someone give an example of a common measuring mistake we discussed? Today we reviewed how to convert between units like cm and mm, and how to avoid errors in addition and subtraction of lengths. Remember to complete the extended activity at home to practise what you have learned today.', '* Did I correctly convert all length units in my calculations?\n* Did I double-check my addition and subtraction of different units?\n* Did I use the most appropriate unit when measuring small objects?', 'At home, find three small objects like a nail, a spoon, and a book. Measure their lengths in both centimetres and millimetres. Record your measurements and check your accuracy by converting the units for each object.', '2026-04-12 07:48:28', '2026-04-12 08:34:28'),
(234, 591, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.6 Money', '', '', NULL, '', NULL, 'a) Identify Income Tax and Value Added Tax (VAT).', 'b) Discuss the importance of paying taxes for national development.', '', 'Why do we pay taxes and how do businesses collect VAT and individuals pay Income Tax?', 'Communication and collaboration - learners discuss tax types and their importance in groups', 'Financial literacy - learners identify and discuss Income Tax and VAT', 'Integrity - learners honestly discuss the importance of paying taxes', '* Learners textbook\n* Sample receipts or price tags from local shops showing VAT\n* Manila paper and markers for tax charts\n* Teacher\'s smartphone (if available) to show digital tax examples', 'Recap of last lesson: profit and loss in business. Who can remind us what we learned? Today\'s lesson is: Identifying Income Tax and VAT. Imagine your parent buys a new radio from a shop. The price includes an extra charge called VAT. Also, part of your parent\'s salary is deducted every month. Why do you think the government collects this money?', 'Engage in an interactive demonstration of tax types by responding to guiding questions and completing steps.', 'Perform or solve tax identification exercises individually or in groups.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can name the two types of tax we discussed today? Can you give one reason why paying taxes is important? Today we learned to identify Income Tax and Value Added Tax (VAT), and discussed how taxes help in building roads, schools, and hospitals. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How did you identify VAT in the shop activity?* What is one important use of taxes you discussed?* How does paying Income Tax show integrity?', 'At home, ask a family member to show you a receipt from a recent purchase. Look for the VAT amount listed. Discuss with them one local project, like a road or water point, that taxes have helped to build.', '2026-04-12 07:49:18', '2026-04-12 08:40:43'),
(291, 561, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.1 Length', '', '', NULL, '', NULL, 'a) Solve word problems involving the conversion of mm, cm, and m.', 'b) Apply measurement skills to estimate lengths of school structures.', '', 'How can we use our knowledge of converting millimetres, centimetres, and metres to solve everyday problems in our school and community?', 'Creativity and imagination - learners sketch and measure circular objects practically', 'Environmental Education - learners choose appropriate units to measure objects in their surroundings', 'Unity - learners work amicably with peers to solve length problems', '* Learners textbook\n* Metre rule or tape measure\n* Chalkboard and chalk\n* Exercise books and pencils\n* School structures (classroom walls, doors, windows, desks)', 'Recap of last lesson: converting between millimetres, centimetres, and metres. Who can remind us what we learned? Today\'s lesson is: Solving word problems and estimating lengths. Imagine you are helping to plan a new garden for the school. You need to measure the length of the fence and the width of the beds. How would you decide which units to use for each measurement?', 'Engage in an interactive demonstration of real-life length applications by responding to guiding questions and completing steps.', 'Perform or solve word problems individually in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing we practised today? Can someone give an example of a problem we solved? Today we learned to solve word problems by converting between mm, cm, and m, and we applied this to estimate real lengths. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did you convert units in the word problems?\n* Did you find estimating lengths easier or harder than solving written problems?\n* How did working with a peer help you understand the conversions?', 'At home, find three different objects (e.g., a book, a window, a stool). Estimate their lengths in centimetres, then measure them accurately. Convert your measurements into millimetres and metres. Record your findings in your exercise book.', '2026-04-12 08:34:15', '2026-04-12 08:34:15'),
(293, 563, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.2 Area', '', '', NULL, '', NULL, 'a) Identify the base and the height of a right-angled triangle.', 'b) Calculate the area of a triangle using the formula A = 1/2 x base x height.', '', 'How can we find the area of a right-angled triangle using what we know about rectangles?', 'Creativity and imagination - learners derive the triangle area formula from a rectangle.', 'Self-esteem - learners confidently establish the area relationship between a rectangle and a triangle.', 'Love - learners share and compare their answers and methods with peers.', '* Learners textbook\n* Rectangular paper cut-outs (from old newspapers or exercise book pages)\n* Scissors\n* Rulers\n* Chalkboard and chalk', 'Recap of last lesson: area of rectangles. Who can remind us what we learned? Today\'s lesson is: Finding the Area of a Right-Angled Triangle. Imagine you are helping to make a triangular flag for a school event. You have a piece of rectangular cloth. How could you cut it to make two identical triangular flags?', 'Engage in an interactive demonstration of the area formula by responding to guiding questions and completing steps.', 'Perform or solve area exercises individually in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the formula we used today? Can someone explain why we multiply by half? Today we learned to identify the base and height of a triangle and calculate area using A = ½ x base x height. Remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly identify the base and height in different triangle orientations?\n* Could learners explain the relationship between a rectangle and a triangle\'s area?\n* Were learners able to apply the formula to solve problems independently?', 'Find three right-angled objects at home, like the corner of a book or table. Sketch them, label the base and height in centimetres, and calculate their area using the formula. Record your findings.', '2026-04-12 08:34:40', '2026-04-12 08:34:40'),
(294, 564, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.2 Area', '', '', NULL, '', NULL, 'a) Break down a combined shape into simple squares and rectangles.', 'b) Calculate the total area of combined shapes accurately.', '', 'How can we find the total area of a shape made up of rectangles and squares?', 'Creativity and imagination - learners dissect combined shapes into simpler parts', 'Self-esteem - learners confidently calculate and share their total area solutions', 'Love - learners work together respectfully and compare answers to help each other', '* Learners textbook\n* Cardboard or manila paper cut into rectangles and squares of different sizes\n* Rulers\n* Chalkboard grid drawn with 1 cm squares\n* Exercise books', 'Recap of last lesson: we learned how to calculate the area of rectangles and squares. Who can remind us of the formula? Today\'s lesson is: Finding the Total Area of Combined Shapes. Imagine you are helping to plan a small garden with two rectangular flower beds and a square path. How would you figure out the total space needed for the whole garden?', 'Engage in an interactive demonstration of dissecting shapes by responding to guiding questions and completing steps.', 'Perform or solve combined area exercises in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step to find the area of a combined shape? Can someone give an example of a shape we can break down? Today we learned to break down combined shapes into simpler rectangles and squares, then add their individual areas to find the total area. Remember to complete the extended activity to practise what you have learned today.', '* How well did you break down the combined shapes?\n* Did you remember to add all the individual areas?\n* Can you think of a real-life use for this skill?', 'At home, find a floor plan in a magazine or draw a simple map of your compound. Identify shapes made of rectangles and squares. Calculate the total area of one combined section, like a house outline.', '2026-04-12 08:34:52', '2026-04-12 08:34:52'),
(296, 566, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.3 Capacity', '', '', NULL, '', NULL, 'a) Define the unit cubic centimetre (cm3).', 'b) Establish the relationship between cm3, millilitres, and litres.', '', 'How can we use cubic centimetres to measure and compare the capacity of different containers?', 'Critical thinking and problem solving - learners work out unit relationships through practical measurement', 'Environmental education - learners use and discuss containers from their local environment', 'Peace - learners work together harmoniously to measure and agree on answers', '* Learners textbook\n* Small cubic containers (1 cm³ boxes made from cardboard or matchboxes)\n* Transparent containers of different sizes (bottles, cups, jars)\n* Water or sand for filling\n* Graduated cylinders or measuring cups marked in millilitres', 'Recap of last lesson: measuring capacity in litres and millilitres. Who can remind us what we learned? Today\'s lesson is: Understanding Cubic Centimetres and their Relationship to Millilitres and Litres. Imagine you have a small medicine bottle and a large water jerrican. How can we use the same small unit to measure the space inside both containers? What unit could we use?', 'Engage in an interactive demonstration of capacity units by responding to guiding questions and completing steps on the chalkboard.', 'Perform or solve unit relationship exercises in exercise books individually using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing they learned about a cubic centimetre? Can someone give an example of how many cm³ are in a litre? Today we learned that 1 cm³ is equal to 1 millilitre, and 1000 cm³ or millilitres make 1 litre. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners understand that 1 cm³ equals 1 ml?* Were learners able to practically measure and convert between cm³, ml, and L?* Did group work help learners agree on measurements and conversions?', 'Find three different containers at home, like a cup, a small bottle, and a bowl. Using a small cup or spoon you know holds 100 ml or 250 ml, estimate their capacity in millilitres. Then, write down what their capacity would be in cubic centimetres and litres.', '2026-04-12 08:35:18', '2026-04-12 08:35:18'),
(300, 570, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.3 Capacity', '', '', NULL, '', NULL, 'a) Convert cubic centimetres (cm3) to millilitres and vice versa.', 'b) Solve simple capacity conversion problems involving cm3 and ml.', '', 'How can we show that one cubic centimetre is equal to one millilitre?', 'Critical thinking and problem solving - learners work out the relationship between cm³ and ml through practical measurement.', 'Environmental education - learners use and measure with containers from their local environment.', 'Peace - learners work together harmoniously to measure and agree on answers.', '* Learners textbook\n* Transparent containers or bottles with ml markings\n* Small cube-shaped boxes or containers measuring 1 cm × 1 cm × 1 cm\n* Water\n* Rulers', 'Recap of last lesson: measuring capacity in millilitres and litres. Who can remind us what we learned? Today\'s lesson is: Converting cubic centimetres to millilitres. Imagine you have a small medicine bottle and a cube-shaped container. How could you find out if they hold the same amount of water?', 'Engage in an interactive demonstration of the 1:1 relationship between cm3 and ml by responding to guiding questions and completing steps.', 'Perform or solve relationship exercises individually in exercise books.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the relationship between a cubic centimetre and a millilitre? Can someone give an example of a conversion you did? Today we learned that one cubic centimetre equals one millilitre and how to convert between them. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did all learners understand that 1 cm³ equals 1 ml?* Were learners able to solve the conversion problems correctly?* Did the practical demonstration with water and containers clarify the concept?', 'At home, find a small container like a bottle cap. Use a syringe or small spoon to see how many millilitres of water it holds. Then, estimate its volume in cubic centimetres and write down your findings.', '2026-04-12 08:36:08', '2026-04-12 08:36:08'),
(307, 577, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.4 Mass', '', '', NULL, '', NULL, 'a) Align mass measurements in tonnes and kilogrammes for addition.', 'b) Add masses involving tonnes and kilogrammes accurately.', '', 'How do we add masses that are measured in both tonnes and kilogrammes?', 'Digital Literacy - learner uses digital weighing machines to measure mass', 'Environmental Education - learner discusses mass of loaded lorries and road impact', 'Integrity - learner honestly determines mass using different operations', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Chart showing conversion between tonnes and kilogrammes (1 tonne = 1000 kg)', 'Recap of last lesson: converting between tonnes and kilogrammes. Who can remind us what we learned? Today\'s lesson is: Adding Masses in Tonnes and Kilogrammes. Imagine a farmer has two sacks of maize. One sack\'s mass is written in tonnes and the other in kilogrammes. How can the farmer find the total mass to know how much to sell? What steps would you take?', 'Engage in an interactive demonstration of adding mass by responding to guiding questions and completing steps.', 'Perform or solve addition exercises in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step when adding masses in tonnes and kilogrammes? Can someone give an example of an addition we did today? Today we learned to align the tonnes and kilogrammes columns correctly before adding, and to convert any extra kilogrammes back to tonnes. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly align tonnes and kg columns?* Were learners able to convert 1000kg to 1 tonne?* Can learners explain the addition steps to a friend?', 'At home, find two items with mass written in kg (e.g., flour, sugar). Pretend one mass is in tonnes by dividing it by 1000. Practise adding these two masses together, aligning the tonnes and kilogrammes correctly in your exercise book.', '2026-04-12 08:37:39', '2026-04-12 08:37:39'),
(308, 578, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.4 Mass', '', '', NULL, '', NULL, 'a) Align mass measurements for subtraction including regrouping from tonnes to kg.', 'b) Subtract masses involving tonnes and kilogrammes accurately.', '', 'How do we subtract masses when the kilograms we have are not enough and we need to regroup from tonnes?', 'Digital Literacy - learner uses digital weighing machines to measure mass', 'Environmental Education - learner discusses mass of loaded lorries and road impact', 'Integrity - learner honestly determines mass using subtraction operations', '* Learners textbook\n* Chalkboard and chalk\n* Chart showing tonne to kilogram conversion (1 tonne = 1000 kg)\n* Exercise books and pencils', 'Recap of last lesson: adding masses in tonnes and kilogrammes. Who can remind us what we learned? Today\'s lesson is: Subtracting Masses by Regrouping from Tonnes. Imagine a loaded lorry carrying sand arrives at a construction site. Some sand is unloaded, but the driver needs to know how much remains. How can we find the remaining mass if we need to borrow from the tonnes column?', 'Engage in an interactive demonstration of subtracting mass by responding to guiding questions and completing steps.', 'Perform or solve subtraction exercises individually in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the first step when subtracting masses and the kilograms are not enough? Can someone explain why we regroup from tonnes? Today we learned to align mass measurements correctly and subtract by regrouping 1 tonne as 1000 kg. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did learners correctly align tonnes and kg in vertical subtraction?* Did learners successfully regroup 1 tonne as 1000 kg when needed?* Can learners explain the regrouping process in their own words?', 'At home, find two items with their masses written in tonnes and kg, like on a maize flour sack or a fertilizer bag. Create your own subtraction problem where you need to regroup from tonnes. Solve it in your exercise book.', '2026-04-12 08:37:53', '2026-04-12 08:37:53'),
(310, 580, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.4 Mass', '', '', NULL, '', NULL, 'a) Divide mass in tonnes and kg by a single-digit whole number.', 'b) Apply division of mass to solve real-life distribution problems.', '', 'How do we share or divide large masses measured in tonnes and kilograms fairly among groups or into equal parts?', 'Digital Literacy - learner uses digital weighing machines to measure mass, Communication and Collaboration - learner discusses problem-solving steps with peers', 'Environmental Education - learner discusses the mass of loaded lorries and their impact on roads', 'Integrity - learner honestly performs and records division calculations', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Sample problems written on cards or paper (e.g. truck loads, harvest distribution, construction materials)', 'Recap of last lesson: dividing mass in kilograms. Who can remind us what we learned? Today\'s lesson is: Dividing Mass in Tonnes and Kilograms. Imagine a farmer has harvested a large sack of maize and needs to share it equally among several families. How can we figure out how much each family gets? What steps would we take?', 'Engage in an interactive demonstration of dividing mass by responding to guiding questions and completing steps.', 'Perform or solve division exercises individually in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us the main skill we practiced today? Can someone give an example of a situation where we might need to divide mass? Today we learned how to divide masses given in tonnes and kilograms by a single-digit number and apply it to solve sharing problems. As you go home, remember to complete the extended activity to practise what you have learned today.', '* Did I correctly convert tonnes to kilograms before dividing?\n* Can I explain the steps for dividing a combined mass like 3 tonnes 150 kg?\n* How can I use this skill to solve a real-life sharing problem?', 'At home, find a bag of maize flour, rice, or sugar. Check its mass in kilograms. Imagine you need to share it equally among 3 or 4 family members. Calculate how much each person would get in kilograms and grams. Write your calculations.', '2026-04-12 08:38:20', '2026-04-12 08:38:20'),
(313, 583, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.5 Time', '', '', NULL, '', NULL, 'a) Describe the 24-hour clock system and its advantages.', 'b) Relate a.m. and p.m. times to their corresponding 24-hour values.', '', 'How can we use the 24-hour clock system to avoid confusion between morning and afternoon times?', 'Learning to learn - learner determines time in a.m. and p.m. from digital and analogue clocks', 'Citizenship - learners determine time durations using travel timetables', 'Integrity - learner observes time and is punctual in activities', '* Learners textbook\n* Chalkboard and chalk\n* Teacher\'s smartphone or watch showing time\n* Sample timetables or schedules from the school', 'Recap of last lesson: reading and writing time in a.m. and p.m. Who can remind us what we learned? Today\'s lesson is: Understanding the 24-hour clock system. Imagine a truck driver is told to deliver goods at 2 o\'clock. Without knowing if it is morning or afternoon, the driver could be very late. How can we write the time to avoid this confusion?', 'Engage in an interactive demonstration of the 24-hour clock by responding to guiding questions and completing steps on the chalkboard.', 'Perform or solve time relationship exercises individually in exercise books using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one advantage of the 24-hour clock system? Can someone give an example of converting 3:00 p.m. to 24-hour time? Today we learned how the 24-hour clock works and how to convert between a.m./p.m. and 24-hour times to avoid confusion. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did you convert a.m. times to 24-hour format?\n* How well did you convert p.m. times to 24-hour format?\n* Can you explain one advantage of the 24-hour clock?', 'At home, use a radio or ask an adult for the time of a favourite programme from a schedule. Write down the programme time in both a.m./p.m. and the corresponding 24-hour clock time in your exercise book.', '2026-04-12 08:39:02', '2026-04-12 08:39:02'),
(315, 585, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.5 Time', '', '', NULL, '', NULL, 'a) Identify the components of a travel timetable (departure/arrival times).', 'b) Interpret travel information from a given bus or train timetable.', '', 'How can we use a travel timetable to find out when buses or trains arrive and depart?', 'Learning to learn - learners interpret time from timetables', 'Citizenship - learners determine travel durations within the country', 'Integrity - learner observes time and is punctual', '* Learners textbook\n* Sample bus or matatu timetables (from local bus stations or created by teacher)\n* Train timetable samples (printed or drawn on manila paper)\n* Chalkboard and chalk for demonstration', 'Recap of last lesson: reading and writing time in 12-hour and 24-hour formats. Who can remind us what we learned? Today\'s lesson is: Interpreting a Travel Timetable. Imagine you are planning a trip to visit a relative in another town. You need to know when the bus leaves and when it will arrive. How would you find this information from a bus schedule?', 'Engage in an interactive demonstration of reading timetables by responding to guiding questions and completing steps.', 'Perform or solve timetable interpretation exercises in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us one thing they learned about reading a timetable? Can someone explain what \'departure time\' means? Today we learned to identify parts of a travel timetable and how to find arrival and departure times. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did you identify departure and arrival times?* What was challenging about interpreting the timetable?* How can you use this skill in real life?', 'Look at a newspaper or ask a family member for a bus or train timetable. Choose one route and write down the departure time from your nearest town and the arrival time at the destination. Share your findings in the next lesson.', '2026-04-12 08:39:28', '2026-04-12 08:39:28'),
(319, 589, 'Grade 6', 'Mathematics', '2.0 Measurement', '2.6 Money', '', '', NULL, '', NULL, 'a) Define the terms \"buying price\" and \"selling price\".', 'b) Calculate profit made from the sale of various items.', '', 'How do you calculate the profit a trader makes when they sell an item for more than they bought it?', 'Communication and collaboration - learners discuss profit and loss in real-life situations', 'Financial literacy - learners discuss income and VAT as a form of tax', 'Integrity - learners honestly determine prices in their model shop', '* Learners textbook\n* Sample items with clearly marked buying and selling prices (e.g. pencils, erasers, exercise books from school shop or brought from home)\n* Chart showing buying price, selling price, and profit formula\n* Real or play money (coins and notes) for demonstration', 'Recap of last lesson: We learned about different units of measurement. Who can remind us what we learned? Today\'s lesson is: Calculating Profit. Imagine your parent sells tomatoes at the market. They buy a crate for one price and sell each tomato for another. How do you think they know if they have made money?', 'Engage in an interactive demonstration of profit calculation by responding to guiding questions and completing steps.', 'Perform or solve profit exercises individually or in groups using demonstrated procedures.', 'Receive assessment and feedback to improve understanding and performance.', 'Who can tell us what we learned today? Can someone give an example of how to calculate profit? Today we learned the meaning of buying price and selling price, and how to calculate profit by subtracting the buying price from the selling price. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did learners define buying and selling price?* Did learners correctly calculate profit in the exercises?* Can learners relate profit to a real-life market scenario?', 'At home, ask a family member about an item they sell or buy, like vegetables or charcoal. Find out the buying price and selling price. Calculate the profit they make on one item. Share your findings in the next lesson.', '2026-04-12 08:40:17', '2026-04-12 08:40:17'),
(331, 601, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.2 Angles', '', '', NULL, '', NULL, 'a) Draw a baseline and mark a vertex.', 'b) Construct angles of given sizes using a protractor.', '', 'How can you accurately construct angles of different sizes using a protractor?', 'Self-efficacy - learner confidently constructs angles using a protractor', 'Environmental Education - learner uses locally available materials to understand geometric concepts', 'Unity - learner works harmoniously with a partner to compare and correct angles', '* Learners textbook\n* Protractors\n* Rulers\n* Pencils and erasers\n* Exercise books', 'Recap of last lesson: We were learning about different types of angles. Who can name one? Today\'s lesson is: Constructing Angles Using a Protractor. Imagine you are a carpenter and need to cut a piece of wood to fit a corner. You need to know the exact angle. How would you measure and draw that angle accurately?', 'Construct angles of specified degrees in exercise books.', 'Compare constructed angles with a partner and correct errors.', '', 'Who can tell us the first step in constructing an angle? What must you do after placing the protractor\'s centre on the vertex? Today we learned how to draw a baseline, mark a vertex, and use a protractor to construct an angle of a given size. Remember to complete the extended activity at home to practise your new skill.', '* Did I correctly align the protractor\'s baseline with my drawn line?* Did I read the inner or outer scale correctly for my angle?* How can I help my partner improve their angle construction?', 'At home, find a flat surface like a wall or a book. Use a ruler to draw a straight line. Then, try to construct a 60-degree and a 120-degree angle from that line using your protractor. Show your work to a family member.', '2026-04-12 11:30:55', '2026-04-12 11:30:55'),
(339, 609, 'Grade 6', 'Mathematics', '3.0 Geometry', '3.3 3-D Objects', '', '', NULL, '', NULL, 'a) Name everyday items that correspond to specific 3-D shapes.', 'b) Sketch the 3-D shape for a given real-life object.', '', 'What 3-D shapes can we identify in the objects we use every day at home and in school?', 'Creativity and imagination - learners sketch 3-D shapes from real objects', 'Social cohesion - learners discuss shapes and respect each other\'s views', 'Patriotism - learners collect and safely keep objects for environmental conservation', '* Learners textbook\n* Collection of everyday objects (boxes, balls, tins, bottles, cups, cones from packaging)\n* Pictures or photographs of common items (buildings, water tanks, balls, dice, tents)\n* Chalkboard and chalk for demonstration sketching', 'Recap of last lesson: 2-D shapes. Who can remind us what we learned? Today\'s lesson is: Identifying and sketching 3-D shapes from everyday objects. Look around our classroom. You see a chalkboard duster, a water bottle, and a box. These objects are not flat; they have length, width, and height. What other objects in this room look like solid shapes?', 'Match photographs of real objects to their 3-D geometric forms.', 'Sketch and label the geometric shapes found in everyday items.', '', 'Who can tell us one 3-D shape we identified today? Can someone name a real object that is a cylinder? Today we learned to name everyday items as specific 3-D shapes and to sketch the geometric shape of an object. As you go home, remember to complete the extended activity to practise what you have learned today.', '* How well did you match objects to shapes?\n* Was sketching a 3-D shape easy or difficult?\n* Can you find more shapes at home?', 'At home, find five different objects that are 3-D shapes like a cube, cuboid, or cylinder. In your exercise book, list each object and sketch its geometric shape next to it.', '2026-04-12 11:32:25', '2026-04-12 11:32:25'),
(348, 618, 'Grade 6', 'Mathematics', '4.0 Data Handling', '4.1 Bar Graphs', '', '', NULL, '', NULL, 'a) Identify the category with the highest and lowest values.', 'b) Calculate the difference between values shown in a bar graph.', '', 'How can you compare different categories in a bar graph to find the highest, lowest, and the difference between values?', 'Creativity and imagination - learners discuss and interpret data from graphs, Communication and collaboration - learners check answers and discuss in pairs', 'Non-formal education - learners interpret data from their immediate environment', 'Integrity - learners honestly read and compare the values on the graph', '* Learners textbook\n* Sample bar graphs drawn on charts or chalkboard showing different real-life data (e.g. crop harvest, school attendance, market prices)\n* Exercise books and pencils\n* Ruler for reading bar graph values accurately', 'Recap of last lesson: drawing bar graphs. Who can remind us what we learned? Today\'s lesson is: Comparing values in a bar graph. Imagine your class collected data on favourite fruits. You have a bar graph showing the results. How could you tell which fruit is most popular and which is least popular?', 'Answer a set of comprehension questions from a bar graph individually.', 'Check answers in pairs and discuss any discrepancies.', '', 'Who can tell us one thing we learned about reading bar graphs today? Can someone explain how to find the difference between two bars? Today we learned to identify the highest and lowest categories on a bar graph and calculate the difference between their values. Remember to complete the extended activity to practise these skills at home.', '* Did learners correctly identify the highest and lowest bars?* Could learners calculate the difference between two values?* How well did pair discussions resolve discrepancies in answers?', 'At home, find a simple bar graph in a newspaper, magazine, or textbook. Identify the category with the highest value and the one with the lowest value. Calculate the difference between these two values and write it down.', '2026-04-12 11:34:00', '2026-04-12 11:34:00');
INSERT INTO `scheme_of_work` (`id`, `learning_area_id`, `week`, `lesson`, `strand`, `sub_strand`, `slo_cd`, `slo_sow`, `le_cd`, `le_sow`, `key_inquiry`, `resources`, `assessment`, `remarks`, `created_at`, `updated_at`, `term`) VALUES
(125, 1, 2, 1, '1.0 Foundations of Pre-Technical Studies', '1.1 Safety on Raised Platforms', 'd) appreciate the need for observing safety while working on raised platforms', 'a) Explain the significance of observing safety protocols while working at heights.\nb) Justify the use of Personal Protective Equipment (PPE) on raised platforms.', '• discuss the importance of observing safety when working on raised platforms.', '• Discuss in groups, the need for observing safety while working on raised platforms and share findings in class.', 'Why is it critical to observe safety protocols and use Personal Protective Equipment when working on raised platforms?', '* Learners textbook\n* Pictures or illustrations of workers on scaffolding, ladders, or rooftops (from textbook or teacher\'s smartphone)\n* Sample PPE items or pictures (helmets, harnesses, gloves, safety boots)\n* Chart paper and markers for group presentations', '* Oral questions during and after group discussions to assess understanding of safety significance\n* Written exercise where learners list and justify at least three PPE items for working at heights\n* Observation of group participation and quality of arguments during presentations', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(126, 1, 2, 2, '1.0 Foundations of Pre-Technical Studies', '1.1 Safety on Raised Platforms', 'd) appreciate the need for observing safety while working on raised platforms', 'a) Evaluate personal understanding of safety on raised platforms through an assessment.', '• visit the locality to observe safety precautions taken when working on raised platforms.', '• Work individually on assessment exercise on safety on raised platforms.', 'How effectively can I demonstrate my understanding of safety practices and precautions when working on raised platforms?', '* Learners textbook\n* Assessment question papers/worksheets\n* Chalkboard and chalk\n* Exercise books and pens', '* Written exercise\n* Self-assessment\n* Rubrics', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(127, 1, 2, 3, '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', 'a) identify hazardous substances found in the environment', 'a) Define the term \"hazardous substances.\"\nb) Identify common hazardous substances found in the school environment.\nc) Describe how specific local substances can cause harm.', '• use print or digital media to search for information on hazardous substances.\n• explore the environment to identify hazardous substances.', '• Define what are hazardous substances thro question and answer.\n• Identify hazardous substances found in the environments, in groups.\n• Mention hazardous substances found in the locality and how they cause harm.', 'What substances in our school and local environment can cause harm to our health and safety, and how do they cause this harm?', '* Learners textbook\n* Samples or pictures of common hazardous substances (bleach, acids, pesticides, batteries, paraffin)\n* Chart paper and markers for group presentations\n* Empty labeled containers of cleaning agents from school stores', '* Oral questions during definition and group discussion\n* Written exercise identifying hazardous substances and describing how they cause harm\n* Observation of group participation during identification activity', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(128, 1, 2, 4, '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', 'b) classify hazardous substances found in the locality', 'a) Categorize hazardous substances into poisonous, flammable, and corrosive groups.\nb) Distinguish between different classes of hazardous materials based on their properties.', '• group hazardous substances into poisonous, flammable or corrosive.', '• Group hazardous substances, in groups (Flammable, Corrosive and Poisonous substances).', 'How can we group hazardous substances found in our homes, schools, and community according to the dangers they pose?', '* Learners textbook\n* Empty containers or labels from household products (kerosene, bleach, battery acid, pesticides, matchboxes)\n* Chart paper or manila paper for group classification charts\n* Pictures or printed symbols of hazard warning signs (poison, flammable, corrosive)', '* Observation during group classification activity using a checklist\n* Written exercise where learners categorize given hazardous substances and explain their properties\n* Peer assessment of group charts showing correct categorization', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(129, 1, 3, 1, '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', 'c) describe safe ways of handling hazardous substances in the environment', 'a) Discuss safe methods for handling hazardous substances.\nb) Identify appropriate Personal Protective Equipment (PPE) for handling chemicals.', '• discuss safe ways of handling hazardous substances in the environment.', '• Discuss in groups, safe ways of handling hazardous substances and share findings with the class.', 'How can we protect ourselves and others when handling hazardous substances in our homes, schools, and communities?', '* Learners textbook\n* Pictures or labels from common household chemicals (bleach, pesticides, detergents, battery acid)\n* Chart paper and markers for group presentations\n* Sample PPE items or pictures (gloves, goggles, masks, aprons)', '* Oral questions during and after group discussions on safe handling methods\n* Observation using a checklist as groups present their findings on hazardous substance handling and PPE identification', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(130, 1, 3, 2, '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', 'c) describe safe ways of handling hazardous substances in the environment', 'a) Interpret safety instructions and conditions for use on chemical labels.\nb) Explain the meaning of various safety symbols found on hazardous containers.', '• read and interpret instructions on the conditions for use of hazardous substances.', '• Interpret, in groups, safety instructions on conditions for using hazardous substances and share findings with class.', 'How can we stay safe when using hazardous substances by understanding the safety symbols and instructions on their labels?', '* Learners textbook\n* Empty containers with labels (detergents, insecticides, batteries, fertilizers, paints)\n* Teacher\'s smartphone/tablet (to show images of common hazard symbols)\n* Chart paper and markers for group presentations', '* Oral questions during group presentations on meaning of safety symbols and instructions\n* Written exercise interpreting safety labels and matching symbols to their meanings\n* Observation of group work and participation in interpreting safety instructions', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(131, 1, 3, 3, '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', 'd) handle hazardous substances safely in the environment', 'a) Demonstrate safe ways of handling hazardous substances through a simulated activity.\nb) Critique the handling techniques used by peers during the practice.', '• visit the locality to learn about safe handling of poisonous, flammable and corrosive substances.\n• practise safe handling of substances in the environment.', '• Practise, in groups, safe ways of handling hazardous substances and allow other learners to ask questions after the play.', 'How can we safely handle hazardous substances to protect ourselves and others from harm?', '* Learners textbook\n* Labels and markers for creating hazard warning signs\n* Empty containers (bottles, tins) to represent hazardous substances\n* Locally available materials to simulate protective equipment (cloth pieces for gloves, paper masks)\n* Chart showing common hazard symbols and safety procedures', '* Observation using a checklist during the simulated handling activity\n* Peer assessment of handling techniques demonstrated by different groups\n* Oral questions on safety procedures and hazard identification', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(132, 1, 3, 4, '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', 'e) appreciate the importance of observing safety when handling hazardous substances', 'a) Explain the importance of following safety protocols when handling hazardous materials.\nb) Propose ways to promote safety awareness in the community.', '• discuss the importance of observing safety when handling hazardous substances.', '• Discuss in groups, the importance of observing safety when handling hazardous substances and present their findings.', 'Why is it critical to follow safety protocols when handling hazardous substances, and how can we promote safety awareness in our community?', '* Learners textbook\n* Pictures or labels from hazardous household products (bleach, pesticides, rat poison, kerosene containers)\n* Community health worker or local safety volunteer as guest speaker\n* Chart paper and markers for group presentations', '* Oral questions during group discussions on the importance of safety protocols\n* Observation of group presentations using a checklist (clarity, relevance of safety measures proposed, community awareness strategies)\n* Written exercise where learners propose three practical ways to promote safety awareness in their community', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(133, 1, 4, 1, '1.0 Foundations of Pre-Technical Studies', '1.2 Handling Hazardous Substances', 'e) appreciate the importance of observing safety when handling hazardous substances', 'a) Evaluate personal proficiency in safety procedures through a structured assessment exercise.', '• visit the locality to learn about safe handling.', '• Work individually on assessment exercise on handling hazardous substances.', 'How can I demonstrate that I can safely identify, handle, and respond to hazardous substances in everyday situations?', '* Learners textbook\n* Sample labels and pictures of common hazardous substances (cleaning products, pesticides, chemicals)\n* Assessment worksheets or printed scenario cards\n* Chart showing hazard symbols and safety procedures', '* Written exercise (structured assessment on identifying hazards, safety procedures, and emergency responses)\n* Self-assessment (learners evaluate their own understanding using a checklist of safety competencies)\n* Rubrics (teacher evaluates learner responses against criteria for hazard identification, procedure application, and safety judgment)', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(134, 1, 4, 2, '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', 'a) explain ways of nurturing talents and abilities for self-development', 'a) Define the terms \"talents\" and \"abilities.\"\nb) Discuss various ways of nurturing talents and abilities.\nc) Outline how talent development contributes to self-growth.', '• discuss and present on ways of nurturing talents and abilities.', '• Discuss in groups, ways of nurturing talents and abilities.\n• Share findings with the class.', 'How can you identify and develop your own talents and abilities to support your personal growth and future career?', '* Learners textbook\n* Chart paper or manila paper and markers\n* Examples of local role models (invited guest or teacher story)\n* Learners\' exercise books', '* Oral questions during group discussions to assess understanding of talents and abilities\n* Written exercise listing personal talents and ways to nurture them\n* Peer assessment of group presentations on talent development', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(135, 1, 4, 3, '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', 'b) relate talents and abilities to career pathways', 'a) Identify different career pathways available in Senior School.\nb) Relate specific talents and abilities to their corresponding career pathways.', '• make a list of talents and abilities and their corresponding career pathways.', '• Relate, in groups, talents and abilities to career pathways.\n• Share talent and ability in class and mention the career pathway.', 'How can you match your personal talents and abilities to the career pathways available in Senior School?', '* Learners textbook\n* Chart paper or manila paper\n* Markers or crayons\n* Sample career pathway charts (teacher-prepared or textbook reference)', '* Oral questions during group discussions and class sharing\n* Observation of group participation and ability to relate talents to career pathways\n* Self-assessment of personal talents and chosen career pathway', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(136, 1, 4, 4, '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', 'b) relate talents and abilities to career pathways', 'a) List various career opportunities related to specific talents.\nb) Evaluate information from a resource person regarding career progression.', '• engage with a resource person on career opportunities related to talents and abilities.', '• Make a list of talents and corresponding career pathways.\n• Engage with a resource person (guest, video, or article) on career opportunities.', 'How can you match your personal talents with real career opportunities and pathways available in your community and beyond?', '* Learners textbook\n* Chart paper and markers for listing talents and careers\n* Invited resource person from the community (teacher, health worker, artisan, entrepreneur, or farmer)\n* Sample career information materials (newspaper clippings, printed articles, or smartphone for video if available)', '* Written exercise: Learners create a personal talent-career matching chart identifying at least three of their talents and corresponding career pathways\n* Oral questions: Assess learners\' ability to explain career progression information shared by the resource person\n* Self-assessment: Learners reflect on how the resource person\'s information has influenced their understanding of career opportunities', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(137, 1, 5, 1, '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', 'c) analyse ethical and unethical practices related to the use of talents and abilities', 'a) Analyze case studies on the use of talents and abilities.\nb) Distinguish between ethical and unethical practices in the application of talents.', '• discuss a case scenario on ethical and unethical practices related to the use of talents and abilities.', '• Discuss, in groups, case studies on ethical and unethical practices related to the use of talents and abilities and share with the class.', 'How can talents and abilities be used ethically or unethically, and what are the consequences of each choice?', '* Learners textbook\n* Case study handouts or written scenarios (prepared by teacher or from textbook)\n* Chart paper and markers for group presentations\n* Examples from local community (sports persons, artisans, business people)', '* Oral questions during group discussions and class presentations\n* Written exercise analyzing a case study and distinguishing ethical from unethical use of talents\n* Peer assessment using a checklist during group presentations', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(138, 1, 5, 2, '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', 'd) choose a career based on talents and abilities for self-development', 'a) Select a preferred career based on personal talents and abilities.\nb) Explain the reasons for the chosen career in relation to self-development.', '• make presentations on careers of choice based on talents and abilities.', '• Choose, in groups, careers based on talents and abilities.\n• Share chosen careers with the class.', 'How can understanding your personal talents and abilities guide you in selecting a career path that supports your self-development?', '* Learners textbook\n* Chart paper or newsprint for group presentations\n* Markers or colored chalk\n* Sample career profiles or posters (teacher-prepared or from newspapers/magazines)', '* Observation during group discussions and career selection process\n* Oral presentation assessment using a rubric (clarity of career choice, connection to personal talents, reasoning for self-development)\n* Self-assessment reflection on personal talents and career alignment', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(139, 1, 5, 3, '1.0 Foundations of Pre-Technical Studies', '1.3 Self-Exploration and Career Development', 'd) choose a career based on talents and abilities for self-development', 'a) Evaluate personal career goals through a self-exploration assessment exercise.', '• make presentations on careers of choice.', '• Work individually on assessment exercise on self-exploration and career development.', 'How can understanding your strengths, interests, and values help you make informed decisions about your future career path?', '* Learners textbook\n* Self-exploration assessment worksheets or questionnaires\n* Exercise books and pens\n* Chart showing different career pathways and required skills', '* Self-assessment using a structured self-exploration tool or checklist\n* Written exercise evaluating personal career goals based on assessment results\n* Rubrics to assess the depth of self-reflection and career goal alignment', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(140, 1, 5, 4, '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', 'a) explain the characteristics of oblique drawing in technical fields', 'a) Define the term \"oblique projection.\"\nb) Identify different types of oblique drawings (Cavalier and Cabinet).\nc) Explain the use of oblique drawings in technical fields.', '• use print or digital media to search for information on the characteristic of oblique drawings.', '• Search for information on meaning of oblique projection, examples of oblique drawings, and characteristics.\n• Share findings with the class.', 'How can we represent three-dimensional objects on a flat surface using oblique projection to communicate technical ideas clearly?', '* Learners textbook\n* Rectangular boxes or cartons (matchboxes, chalk boxes)\n* Ruler and pencil\n* Samples of technical drawings or diagrams from textbooks showing oblique views', '* Oral questions to test understanding of oblique projection and its types\n* Written exercise requiring learners to differentiate between Cavalier and Cabinet projections and explain their uses', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(141, 1, 6, 1, '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', 'a) explain the characteristics of oblique drawing in technical fields', 'a) Describe the key characteristics of oblique drawings (sloping axes and front face).\nb) Distinguish between oblique and other pictorial drawings.', '• brainstorm on the characteristic of oblique drawings.', '• Brainstorm, in groups, on the characteristics of oblique drawings and share with the class.', 'What makes an oblique drawing different from other types of pictorial drawings you have seen?', '* Learners textbook\n* Chalkboard and chalk\n* Geometric set (ruler, set squares)\n* Cardboard boxes or wooden blocks of different shapes\n* Manila papers and pencils', '* Oral questions during group presentations on characteristics identified\n* Written exercise distinguishing oblique drawings from isometric and orthographic projections\n* Observation of group brainstorming and participation', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(142, 1, 6, 2, '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', 'b) sketch given drawings in oblique projection', 'a) Identify the starting point for sketching an oblique drawing.\nb) Sketch simple shaped blocks in oblique projection using freehand.', '• draw given drawings in oblique projection without using instruments.', '• Sketch drawings in oblique projection without using instruments.', 'How can you represent the depth and three-dimensional form of a simple block object on a flat surface using oblique projection?', '* Learners textbook\n* Chalkboard and chalk\n* Plain paper or exercise books\n* Pencils\n* Simple rectangular wooden blocks or small cardboard boxes', '* Observation during freehand sketching practice\n* Practical work - assess learners\' oblique sketches for correct starting point and proportions\n* Peer assessment of sketched oblique drawings', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(143, 1, 6, 3, '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', 'b) sketch given drawings in oblique projection', 'a) Refine freehand oblique sketches for proportion and clarity.\nb) Sketch complex shaped blocks in oblique projection.', '• draw given drawings in oblique projection without using instruments.', '• Sketch more complex shaped blocks in oblique projection without using instruments.', 'How can you accurately sketch complex shaped blocks in oblique projection freehand while maintaining correct proportions and clarity?', '* Learners textbook\n* Chalkboard and chalk\n* Exercise books and pencils\n* Erasers\n* Rulers (for checking proportions, not for drawing)', '* Observation during freehand sketching practice\n* Rubrics assessing proportion, clarity, and oblique projection principles in learners\' sketches\n* Peer assessment using a checklist for oblique projection features', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(144, 1, 6, 4, '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', 'c) draw shaped blocks in oblique projection', 'a) Outline the step-by-step procedure for drawing oblique blocks.\nb) Discuss the importance of using a 45-degree set square in oblique drawing.', '• discuss the steps for drawing shaped blocks in oblique projection.', '• Discuss, in pairs, the steps for drawing shaped blocks in oblique projection.', 'How do we use the 45-degree angle and a step-by-step procedure to accurately draw shaped blocks in oblique projection?', '* Learners textbook\n* Geometric set (45-degree set square, ruler, compass, protractor)\n* Drawing paper or exercise books\n* Pencils and erasers\n* Chalkboard and chalk for demonstration', '* Observation during pair discussions on the steps for drawing oblique blocks\n* Practical work: learners draw oblique blocks following the outlined procedure using a 45-degree set square\n* Written exercise: learners list the step-by-step procedure for drawing oblique blocks', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(145, 1, 7, 1, '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', 'c) draw shaped blocks in oblique projection', 'a) Construct accurate oblique drawings of shaped blocks using a geometrical set.\nb) Demonstrate the correct use of drawing instruments for cabinet projection.', '• use geometrical set drawing instruments to draw shaped blocks in oblique projection (cabinet).', '• Draw, in pairs, shaped blocks in oblique projection using drawing instruments.', 'How can we accurately represent three-dimensional shaped blocks on a two-dimensional surface using oblique projection with correct proportions and angles?', '* Learners textbook\n* Geometrical set (ruler, set squares, compass, protractor, divider)\n* Drawing paper or graph paper\n* Pencils (HB and 2H)\n* Eraser', '* Observation during pair work on correct use of drawing instruments and application of cabinet projection principles\n* Practical work assessment using a checklist to evaluate accuracy of angles, proportions, and overall construction of oblique drawings', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(146, 1, 7, 2, '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', 'c) draw shaped blocks in oblique projection', 'a) Construct individual figures in oblique projection with precision.\nb) Apply line types correctly (outlines and construction lines) in oblique drawings.', '• use geometrical set drawing instruments to draw shaped blocks.', '• Work individually, using appropriate drawing instruments, draw figures in oblique projection.', 'How can you accurately represent three-dimensional objects on a flat surface using oblique projection while applying correct line types?', '* Learners textbook\n* Drawing board or firm cardboard backing\n* Geometric set (ruler, set squares, protractor, compass)\n* Drawing paper or squared paper\n* Pencils (HB and 2H) and eraser', '* Observation during drawing to check correct use of instruments and application of line types\n* Practical work assessment using a rubric focusing on accuracy of oblique projection, correct angles, and proper line types (continuous lines for outlines, dashed/light lines for construction)', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(147, 1, 7, 3, '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', 'd) appreciate the application of oblique projection on drawing', 'a) Analyze how oblique projection is applied in technical communication.\nb) Discuss the advantages of using oblique projection over other drawing methods.', '• walk around the locality to observe the use of oblique drawings.', '• Discuss the application of oblique projection in technical communication and present findings.', 'How does oblique projection help technicians and engineers communicate their design ideas clearly, and what makes it more useful than other drawing methods in certain situations?', '* Learners textbook\n* Chart paper or manila paper\n* Samples of technical drawings from textbooks or magazines\n* Ruler and pencil\n* Teacher\'s smartphone/tablet (for showing real-world technical drawings if available)', '* Oral questions during and after group discussions on advantages of oblique projection\n* Written exercise where learners compare oblique projection with other methods and list its applications\n* Rubric to assess group presentation of findings on oblique projection applications', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(148, 1, 7, 4, '2.0 Communication in Pre-Technical Studies', '2.1 Oblique Projection', 'd) appreciate the application of oblique projection on drawing', 'a) Evaluate personal drawing skills through a practical assessment exercise.', '• walk around the locality to observe the use of oblique drawings.', '• Work individually on assessment exercise on oblique projection.', 'How well can I apply the principles of oblique projection to accurately represent three-dimensional objects in my technical drawings?', '* Learners textbook\n* Drawing sheets or plain pages\n* Pencils (HB and 2H)\n* Ruler and set squares\n* Eraser', '* Practical work (graded oblique projection drawings)\n* Self-assessment (using rubric to evaluate own drawing against technical criteria)\n* Rubrics (assessing accuracy of angles, proportions, and projection standards)', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(149, 1, 8, 1, '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', 'a) explain the application areas of visual programming software in solving problems', 'a) Define the term \"visual programming.\"\nb) Identify various application areas of visual programming in problem-solving.\nc) Outline the benefits of visual programming over text-based coding.', '• use print or digital media to search for information on the application areas of visual programming.', '• Search for information on application area of visual programming.\n• Write short notes and give examples of websites and mobile applications.', 'How does visual programming help people solve everyday problems differently from traditional text-based coding?', '* Learners textbook\n* Teacher\'s smartphone or tablet (for demonstrating visual programming examples if internet available)\n* Manila papers and markers for creating visual programming concept maps\n* Sample screenshots or printed images of visual programming interfaces (Scratch, Blockly, MIT App Inventor)', '* Oral questions to assess understanding of visual programming definition and application areas\n* Written exercise where learners outline benefits of visual programming and give examples of websites and mobile applications', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(150, 1, 8, 2, '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', 'a) explain the application areas of visual programming software in solving problems', 'a) Identify examples of mobile applications developed using visual programming.\nb) Discuss how web development utilizes visual programming tools.', '• discuss the application areas of visual programming software.', '• Discuss, in groups, the application areas in visual programming - Mobile programming and Web development.', 'How do visual programming tools make it easier to create mobile applications and websites that we use every day?', '* Learners textbook\n* Teacher\'s smartphone or tablet with sample visual programming apps (e.g. MIT App Inventor, Scratch)\n* Charts showing screenshots of visual programming interfaces\n* Examples of popular mobile apps (WhatsApp, M-PESA) written on the chalkboard', '* Oral questions during and after group discussions about mobile and web applications\n* Written exercise listing examples of mobile apps developed using visual programming and explaining web development tools', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(151, 1, 8, 3, '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', 'b) create an application using visual programming software', 'a) Demonstrate how to download and install Scratch on a digital device.\nb) Identify the system requirements for running visual programming software.', '• watch a video on how to develop an application using visual programming software.', '• How to download and install Scratch in a device.\n• Watch a video of a resource person.', 'How can we download and install Scratch software on a digital device to create visual programs?', '* Learners textbook\n* Teacher\'s smartphone or tablet with internet connection\n* Projector or large screen (if available, otherwise device passed around)\n* Scratch installation guide (printed or displayed)\n* Sample screenshots of Scratch interface drawn on chart paper', '* Oral questions on system requirements and installation steps\n* Observation during demonstration of downloading and installation process\n* Checklist to verify learners can identify key system requirements', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(152, 1, 8, 4, '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', 'b) create an application using visual programming software', 'a) Identify the components of the Scratch user interface (Stage, Sprites, Blocks Palette).\nb) Describe the functions of different interface areas.', '• develop interactive stories, games and animations using visual programming software.', '• Familiarise yourself with Scratch programming, in groups.\n• Explore the Scratch interface.', 'How do the different parts of the Scratch user interface work together to help us create programs?', '* Learners textbook\n* Teacher\'s smartphone or tablet with Scratch installed (offline or online)\n* Chart paper and markers to draw interface components\n* Exercise books for sketching and note-taking', '* Oral questions to describe functions of Stage, Sprites, and Blocks Palette\n* Observation during group exploration of the Scratch interface\n* Written exercise labeling and describing interface components', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(153, 1, 9, 1, '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', 'b) create an application using visual programming software', 'a) Categorize Scratch blocks based on their colors and functions (Motion, Events, Control).\nb) Demonstrate how to snap blocks together to form a script.', '• develop interactive stories, games and animations using visual programming software.', '• Familiarise yourself with Scratch programming environment.', 'How can we organize and combine different colored blocks in Scratch to create instructions that make a sprite perform actions?', '* Learners textbook\n* Smartphone or tablet with Scratch app (teacher\'s device for demonstration)\n* Chart paper and colored markers (to draw and label block categories)\n* Printed screenshots of Scratch interface (if available from textbook or pre-printed)', '* Oral questions asking learners to identify block categories by color and state their functions\n* Written exercise where learners draw and label different Scratch blocks and show how they connect to form a simple script\n* Observation during hands-on practice as learners snap blocks together on available devices or simulate on paper', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(154, 1, 9, 2, '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', 'b) create an application using visual programming software', 'a) Formulate a logical sequence of steps (algorithm) for a simple game.\nb) Write down the planned steps for a personal game project.', '• develop interactive stories, games and animations using visual programming software.', '• Write down the steps to follow to develop your game.', 'How can you break down a game into a clear, step-by-step sequence that a computer can follow?', '* Learners textbook\n* Exercise books and pencils\n* Sample game examples (drawn or described on paper)\n* Chart paper or manila paper for displaying algorithm steps', '* Written exercise: Learners write algorithm steps for their game project\n* Peer assessment: Learners exchange algorithms and check for logical sequence and completeness\n* Observation: Teacher monitors clarity and logical flow of documented steps', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(155, 1, 9, 3, '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', 'b) create an application using visual programming software', 'a) Construct a simple interactive game using Motion and Events blocks.\nb) Test and play the game to ensure functionality.', '• develop interactive stories, games and animations using visual programming software.', '• Create and play a fun game, following steps.\n• Develop, in groups, interactive games using Scratch.', 'How can you use motion and event blocks in Scratch to create an interactive game that responds to player actions?', '* Learners textbook\n* Smartphones or tablets with Scratch installed (shared in groups)\n* Computer lab (if available) or teacher\'s device with projector/screen sharing\n* Exercise books for planning game flowcharts and pseudocode\n* Chart paper and markers for designing game storyboards', '* Observation during group game development and testing\n* Practical work assessment using a checklist (game has motion blocks, event blocks, interactivity, and functions correctly)\n* Peer assessment where groups play and evaluate each other\'s games', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(156, 1, 9, 4, '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', 'b) create an application using visual programming software', 'a) Construct an interactive story using conversation (Say) blocks and multiple backdrops.\nb) Demonstrate the story to peers for feedback.', '• develop interactive stories, games and animations using visual programming software.', '• Write down steps to follow to develop the story.\n• Develop interactive stories using Scratch.', 'How can you use visual programming blocks to create a story that responds to user interaction and changes scenes?', '* Learners textbook\n* Teacher\'s smartphone or tablet with Scratch installed\n* Exercise books and pencils for story planning\n* Chalkboard and chalk for demonstrating block sequences', '* Observation during story construction and use of Say blocks and backdrops\n* Peer assessment during story demonstration and feedback session\n* Checklist to verify inclusion of conversation blocks, multiple backdrops, and interactivity', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(157, 1, 10, 1, '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', 'b) create an application using visual programming software', 'a) Apply \"Costumes\" and \"Sound\" blocks to create a simple animation.\nb) Demonstrate the finished animation to the class.', '• develop interactive stories, games and animations using visual programming software.', '• Develop, in groups, animations using visual programming.\n• Play the animation for the class to see.', 'How can you use costumes and sound blocks in visual programming to tell a story or show movement through animation?', '* Learners textbook\n* Computer lab or teacher\'s smartphone/tablet with Scratch or similar visual programming app\n* Projector or screen for demonstration (or learners gather around device)\n* Exercise books for planning animation storyboards', '* Observation during group animation development and application of costume and sound blocks\n* Practical demonstration of the finished animation to the class\n* Peer assessment using a simple checklist (animation runs smoothly, costumes change appropriately, sound is included)', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(158, 1, 10, 2, '2.0 Communication in Pre-Technical Studies', '2.2 Visual Programming', 'c) embrace the use of visual programming in the day-to-day life', 'a) Discuss how visual programming can be used to solve real-life challenges.\nb) Evaluate personal understanding of programming through an assessment exercise.', '• practise using visual programming applications to solve problems in day-to-day life.', '• Discuss the uses of visual programming.\n• Work individually on assessment exercise on visual programming.', 'How can visual programming be applied to solve everyday challenges in our homes, schools, and communities?', '* Learners textbook\n* Teacher\'s smartphone or tablet with visual programming app (e.g. Scratch, Blockly)\n* Charts showing visual programming blocks and examples\n* Exercise books and pens', '* Oral questions on real-life applications of visual programming\n* Written assessment exercise on visual programming concepts\n* Self-assessment of understanding of visual programming', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 1),
(159, 1, 10, 3, '3.0 Materials for Production', '3.1 Wood', 'a) classify wood according to physical characteristics', 'a) Identify available types of wood in the local environment.\nb) Describe the physical properties of different wood types.\nc) Distinguish between softwood and hardwood.', '• use print or digital media to search for information on types of wood.\n• discuss the physical characteristics of wood (soft and hard wood).\n• use a checklist to sort wood as either softwood or hardwood.', '• Search for information on types of wood available, physical property of each type of wood and example of each type of wood.\n• Share findings with the class.\n• Walk around the school or community and identify the trees in the environment while observing physical characteristics.', 'What different types of wood can we find in our local environment, and how can we tell softwood from hardwood by observing their physical properties?', '* Learners textbook\n* Samples of different wood types from the local environment (branches, timber offcuts, firewood pieces)\n* Chart paper or chalkboard for recording observations\n* Access to trees in the school compound and surrounding community', '* Observation during the nature walk as learners identify trees and describe physical characteristics of wood\n* Oral questions asking learners to distinguish between softwood and hardwood samples and explain the differences\n* Written exercise where learners list types of wood found locally and describe their physical properties', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(160, 1, 10, 4, '3.0 Materials for Production', '3.1 Wood', 'b) describe the preparation of wood for use in the production of items', 'a) Describe the process of wood conversion.\nb) Illustrate different wood conversion methods through drawing.', '• discuss methods of wood preparation (conversion and seasoning).', '• Discuss, in groups, methods of wood preparation - Conversion.\n• Draw images, individually, to represent each conversion method.', 'How is a tree trunk converted into usable timber for construction and furniture making?', '* Learners textbook\n* Drawing materials (pencils, rulers, erasers)\n* Sample wood pieces or logs from the school compound\n* Charts or diagrams showing wood conversion methods', '* Oral questions during group discussions on wood conversion processes\n* Written exercise evaluating accuracy and labeling of drawn wood conversion methods\n* Observation of learners\' participation in group discussions', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(161, 1, 11, 1, '3.0 Materials for Production', '3.1 Wood', 'b) describe the preparation of wood for use in the production of items', 'a) Describe the process of wood seasoning.\nb) Explain the importance of seasoning wood before production.', '• discuss methods of wood preparation (conversion and seasoning).', '• Discuss, in groups, methods of wood preparation - Seasoning.\n• Share findings with the class.', 'Why is it necessary to season wood before using it to make furniture or other products?', '* Learners textbook\n* Samples of seasoned and unseasoned wood pieces from the local environment\n* Chart showing wood seasoning methods\n* Sticks or timber offcuts from local carpentry workshop', '* Oral questions during and after group discussions on wood seasoning methods and importance\n* Written exercise describing the wood seasoning process and explaining its importance in production', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(162, 1, 11, 2, '3.0 Materials for Production', '3.1 Wood', 'c) relate types of wood to their uses in the community', 'a) Identify the uses of specific wood types in the community.\nb) Relate various wood types to specific trades and industries.', '• brainstorm on the uses of wood in different trades.\n• develop charts to match types of wood to their uses.', '• Brainstorm on the uses of specific wood, in groups.\n• Brainstorm on the uses of wood in various trades and share findings.', 'How do different types of wood serve specific purposes in our community\'s trades and industries?', '* Learners textbook\n* Sample wood pieces from the local community (mango, pine, eucalyptus, mvule, cypress, etc.)\n* Chart paper or manila papers for group presentations\n* Resource persons (local carpenter, furniture maker, or woodworker)', '* Oral questions during group brainstorming sessions\n* Written exercise matching wood types to their uses in specific trades\n* Observation of group discussions and participation', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(163, 1, 11, 3, '3.0 Materials for Production', '3.1 Wood', 'd) value the importance of wood in day-to-day life', 'a) Explain the socio-economic importance of wood in daily life.\nb) Evaluate the importance of wood conservation.', '• discuss the importance of wood in day-to-day life.', '• Discuss, in groups, the importance of wood in day-to-day life.', 'Why is wood important in our community and how can we ensure it remains available for future generations?', '* Learners textbook\n* Sample wood products from the community (furniture piece, tool handle, firewood, charcoal)\n* Chart paper or chalkboard for group presentations\n* Tree branches or wood samples from the school compound', '* Oral questions during and after group discussions on socio-economic importance of wood\n* Written exercise evaluating wood conservation strategies and their relevance to the local context\n* Observation of participation and contribution during group discussions using a checklist', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(164, 1, 11, 4, '3.0 Materials for Production', '3.1 Wood', 'd) value the importance of wood in day-to-day life', 'a) Assess personal understanding of wood properties and preparation through an exercise.', '• visit the locality to explore the uses of wood.', '• Work individually on assessment exercise on wood.', 'How well do I understand the properties, types, seasoning methods, defects, and preparation processes of wood for production?', '* Learners textbook\n* Previous notes and exercises on wood properties\n* Sample wood pieces showing different properties and defects\n* Assessment exercise sheets or questions written on chalkboard', '* Written exercise\n* Self-assessment\n* Marking rubric', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(165, 1, 12, 1, '3.0 Materials for Production', '3.2 Handling Waste Materials', 'a) identify waste materials found in the environment', 'a) Identify different types of waste materials in the school environment.\nb) List the identified waste materials in categories.', '• walk around the school compound to identify waste materials (plastic, glass, metal, wood waste, electronic waste, construction waste).', '• Walk around the school compound, in groups, to identify waste materials.\n• Write the waste materials you see in exercise book and read the list in class.', 'What different types of waste materials can we find in our school environment and how can we group them?', '* Learners textbook\n* Exercise books and pencils\n* Waste materials found in the school compound (paper, plastics, organic matter, metals, glass)\n* Containers or baskets for collecting samples', '* Observation during the school compound walk and group identification activity\n* Written exercise reviewing the categorized lists in learners\' exercise books\n* Oral questions during class presentation of waste material lists', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(166, 1, 12, 2, '3.0 Materials for Production', '3.2 Handling Waste Materials', 'b) describe ways of handling waste materials safely in the environment', 'a) Identify safe ways of handling different waste materials.\nb) Describe the methods of reducing, reusing, and recycling waste.', '• use print or digital media to search for information on safe ways of handling waste materials.\n• discuss safe ways of handling waste materials (reduce, reuse, recycle, compost and burn).', '• Search for information on safe handling of waste materials and discuss findings in class.', 'How can we handle different types of waste materials safely and apply the 3Rs (reduce, reuse, recycle) to manage waste in our homes and school?', '* Learners textbook\n* Samples of different waste materials from school compound (plastic bottles, paper scraps, organic waste, metal cans)\n* Chart paper or chalkboard for recording findings\n* Gloves or pieces of cloth for safe handling demonstration', '* Oral questions during class discussion on safe handling practices and the 3Rs methods\n* Written exercise where learners describe safe handling procedures and give examples of reducing, reusing, and recycling waste\n* Observation during group presentations of research findings', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(167, 1, 12, 3, '4.0 Tools and Production', '4.1 Holding Tools', 'a) identify holding tools used in day-to-day life', 'a) Identify common holding tools used in the environment.\nb) Illustrate various holding tools through drawing.\nc) Label the parts of identified holding tools.', '• use visual aids or real objects to identify holding tools.', '• Identify, in groups, the pictures of holding tools in the environment.\n• Draw and name the identified tools.', 'What tools are commonly used in our homes and workshops to hold, grip, or clamp materials during work, and how are they designed?', '* Learners textbook\n* Actual holding tools from school workshop or borrowed from community (pliers, vice, clamps, tongs, tweezers)\n* Chart paper and markers for group presentations\n* Rulers for accurate drawing', '* Observation during group identification and discussion of holding tools\n* Written exercise: drawing, naming and labeling parts of at least three holding tools\n* Peer assessment of drawings and labels for accuracy and completeness', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(168, 1, 12, 4, '4.0 Tools and Production', '4.1 Holding Tools', 'b) select holding tools for performing given tasks', 'a) Choose the most appropriate holding tool for a specific task.\nb) Justify the selection of a holding tool based on the nature of the work.', '• choose holding tools for different tasks.\n• discuss uses of different types of holding tools (pliers, clamps, tongs, clips, vice).', '• Choose, in groups, holding tools for different tasks.\n• Select the most appropriate tools for given tasks and give reasons for the choice.', 'How do you decide which holding tool is best suited for a particular task?', '* Learners textbook\n* Assorted holding tools (pliers, vice, clamps, tweezers, tongs borrowed from workshop or home)\n* Work samples or materials to be held (wood pieces, metal strips, wires, fabric)\n* Charts or pictures showing different holding tools and their uses', '* Observation during group selection and justification activities\n* Oral questions on reasons for choosing specific holding tools for given tasks\n* Written exercise matching holding tools to appropriate tasks with justifications', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2);
INSERT INTO `scheme_of_work` (`id`, `learning_area_id`, `week`, `lesson`, `strand`, `sub_strand`, `slo_cd`, `slo_sow`, `le_cd`, `le_sow`, `key_inquiry`, `resources`, `assessment`, `remarks`, `created_at`, `updated_at`, `term`) VALUES
(169, 1, 13, 1, '4.0 Tools and Production', '4.1 Holding Tools', 'c) use holding tools to perform given tasks', 'a) Describe tasks being performed using holding tools from visual aids.\nb) Outline safe procedures for using pliers, clamps, and vices.', '• use print or digital media to search for information on safe use of holding tools.\n• demonstrate safe use of holding tools when performing different types of tasks.', '• Study pictures, in groups, of people using different holding tools and describe the tasks.\n• Search for information or watch a video on how to safely use holding tools.', 'How can we safely use different holding tools to perform specific tasks in our workshops and daily activities?', '* Learners textbook\n* Pictures or charts showing people using pliers, clamps, and vices\n* Actual samples of holding tools (pliers, clamps, vices) if available from school workshop or borrowed from community\n* Teacher\'s smartphone/tablet for showing videos on safe use of holding tools', '* Oral questions during group discussions on tasks performed using different holding tools\n* Written exercise where learners outline safe procedures for using pliers, clamps, and vices\n* Observation of learner participation during group work and information search activities', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(170, 1, 13, 2, '4.0 Tools and Production', '4.1 Holding Tools', 'c) use holding tools to perform given tasks', 'a) Demonstrate the correct use of a specific holding tool to perform a practical task.\nb) Apply safety measures while using holding tools in the environment.', '• demonstrate safe use of holding tools.', '• Identify suitable tasks in the environment that require holding tools.\n• Perform the identified task using the most appropriate holding tool.', 'How can we safely select and use the right holding tool to complete different tasks in our workshop and environment?', '* Learners textbook\n* Assorted holding tools (pliers, clamps, vices, tongs, tweezers)\n* Work pieces or materials to hold (wood pieces, metal rods, wires, fabric)\n* Safety gloves and goggles\n* Workshop or practical area', '* Observation using a checklist during practical demonstration of tool use and safety measures\n* Practical work assessment where learners perform a specific task using the appropriate holding tool\n* Oral questions on safety measures and tool selection criteria', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(171, 1, 13, 3, '4.0 Tools and Production', '4.1 Holding Tools', 'd) care for holding tools used in day-to-day life', 'a) Describe methods for cleaning and maintaining holding tools.\nb) Demonstrate proper storage of holding tools to prevent damage.', '• clean and safely store holding tools.', '• Study and discuss pictures or videos on how to care for and maintain tools.\n• Share findings with the class on maintenance practices.', 'How can we ensure that holding tools remain safe, functional, and ready for use over a long period of time?', '* Learners textbook\n* Actual holding tools (pliers, clamps, vices, tongs) from school workshop or borrowed from community\n* Cleaning materials (cloth rags, wire brush, old toothbrush, water, oil)\n* Tool storage examples (toolbox, wall racks, cloth wraps)', '* Oral questions on cleaning and maintenance methods for different holding tools\n* Practical demonstration of cleaning and proper storage of at least two holding tools\n* Observation checklist during hands-on maintenance activities', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(172, 1, 13, 4, '4.0 Tools and Production', '4.1 Holding Tools', 'e) appreciate the importance of holding tools in day-to-day life', 'a) Explain the significance of holding tools in community trades.\nb) Evaluate personal proficiency in using holding tools through an exercise.', '• share experiences on the use of holding tools.', '• Discuss, in groups, the importance of holding tools in the community.\n• Share experiences and work individually on assessment exercise.', 'Why are holding tools essential for quality work and safety in different trades practiced in our community?', '* Learners textbook\n* Sample holding tools from the community (pliers, clamps, vices, tongs, tweezers, or locally made holding devices)\n* Examples of work pieces or materials that require holding tools (wood offcuts, metal pieces, fabric)\n* Chart paper and markers for group presentation', '* Oral questions during group discussion on importance of holding tools in community trades\n* Written assessment exercise evaluating personal proficiency in using holding tools\n* Self-assessment of individual skill level with different holding tools', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(173, 1, 14, 1, '4.0 Tools and Production', '4.2 Driving Tools', 'a) identify driving tools used in day-to-day life', 'a) Identify pictures of driving tools used in the community.\nb) State where various driving tools are commonly found.', '• use visual aids or realia to identify driving tools in the community.', '• Identify, in groups, pictures of driving tools used in the community.\n• Mention where these tools can be found within the locality.', 'What tools do people in our community use to drive or force objects together, and where can we find them being used?', '* Learners textbook\n* Pictures or actual samples of driving tools (hammers, mallets, nails, screwdrivers)\n* Chart paper or chalkboard for group presentations\n* Local carpentry workshop or construction site (for field observation or inviting a craftsperson)', '* Oral questions during group discussions on identification and location of driving tools\n* Observation using a checklist during group work to assess learners\' ability to identify and state where driving tools are found', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(174, 1, 14, 2, '4.0 Tools and Production', '4.2 Driving Tools', 'b) select driving tools for performing given tasks', 'a) Match driving tools to specific tasks on flashcards.\nb) Defend the choice of a specific driving tool for a given task.', '• discuss uses of driving tools for different tasks (hammer, screwdriver, spanner, punches, mallets).', '• Select the most appropriate driving tools for tasks shown on flashcards.\n• Give reasons for the choice of tool selected in each case.', 'How do you decide which driving tool is best for a specific task?', '* Learners textbook\n* Flashcards showing different tasks (hammering nails, tightening screws, prying boards, etc.)\n* Actual driving tools or pictures (hammer, screwdrivers - flat and star, mallet, nail punch)\n* Chart showing driving tools and their uses', '* Oral questions asking learners to justify their tool choices for given tasks\n* Observation using a checklist during flashcard matching activity\n* Written exercise where learners match tools to tasks and explain their reasoning', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(175, 1, 14, 3, '4.0 Tools and Production', '4.2 Driving Tools', 'c) use driving tools to perform given tasks', 'a) Identify tasks observed in the community that require driving tools.\nb) Demonstrate the safe use of a driving tool to perform a specific task.', '• use print or digital devices to search and watch a video clip on the safe use of driving tools.\n• demonstrate safe use of driving tools.', '• Discuss pictures of driving tools in use and mention tasks observed in the community.\n• Identify and perform a task in the environment using the appropriate driving tool.', 'How can we safely use driving tools to accomplish tasks we see in our homes and community?', '* Learners textbook\n* Assorted driving tools (hammers, mallets, screwdrivers from school workshop or borrowed from community)\n* Nails, screws, and wood pieces\n* Pictures or drawings of driving tools in use from magazines or drawn on charts', '* Observation during practical demonstration of safe tool use\n* Oral questions on identifying community tasks requiring driving tools\n* Checklist for safety procedures and correct tool handling', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(176, 1, 14, 4, '4.0 Tools and Production', '4.2 Driving Tools', 'd) care for driving tools used in day-to-day', 'a) Describe the procedures for maintaining driving tools (e.g., oiling, tightening).\nb) Demonstrate safe storage practices for driving tools.', '• clean and safely store driving tools.', '• Study and discuss pictures on how to care for and maintain driving tools.\n• Answer questions regarding maintenance and storage.', 'How can we ensure that driving tools remain safe, functional, and ready for use over a long period of time?', '* Learners textbook\n* Actual driving tools (screwdrivers, hammers, mallets) borrowed from school workshop or community\n* Pictures or charts showing tool maintenance practices\n* Clean cloth, oil (cooking oil or machine oil), and water for demonstration\n* Storage containers or toolbox (or locally made alternatives)', '* Oral questions on maintenance procedures and safe storage practices\n* Observation during demonstration of tool care and storage\n* Practical work where learners demonstrate cleaning, oiling, or proper storage of a driving tool', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(177, 1, 15, 1, '4.0 Tools and Production', '4.2 Driving Tools', 'e) acknowledge the importance of driving tools in day-to-day life', 'a) Explain the necessity of driving tools in daily activities.\nb) Assess understanding of driving tools through an individual exercise.', '• share experiences on the use of driving tools.', '• Discuss, in groups, the need for driving tools in the community.\n• Work individually on assessment exercise on driving tools.', 'Why are driving tools necessary in our daily activities at home, school, and in our community?', '* Learners textbook\n* Actual driving tools (hammer, mallet, screwdriver) borrowed from community or school workshop\n* Nails of different sizes\n* Pieces of wood or old timber\n* Stones used as improvised hammers in the community', '* Oral questions during group discussion on the necessity of driving tools\n* Written exercise assessing individual understanding of driving tools and their applications', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(178, 1, 15, 2, '4.0 Tools and Production', '4.3 Project', 'a) identify a problem in the locality that can be solved using the skills acquired in Pre-Technical Studies', 'a) Identify existing challenges within the local community.\nb) Establish problems that can be solved using technical skills.', '• explore the locality to identify problems that can be solved using the skills acquired in Pre-Technical Studies.', '• Explore the locality to establish problems to be solved.\n• Present the identified problem findings in class.', 'What problems in our community could we solve using the technical skills we are learning in school?', '* Learners textbook\n* Notebooks and pens for recording observations\n* Camera or smartphone for documenting community challenges\n* Local community area (market, homes, school compound, farms)', '* Observation during community exploration walk\n* Oral presentation of identified problems and findings\n* Checklist to verify identification of community challenges and technical solution possibilities', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(179, 1, 15, 3, '4.0 Tools and Production', '4.3 Project', 'a) identify a problem in the locality', 'a) Analyze identified problems in the locality.\nb) Select the most suitable problem to address using available resources.', '• brainstorm on the possible solutions to the identified problems.', '• Brainstorm on the problems in the locality which can be solved using skills acquired.', 'Which problems in our community can we solve using the skills we have learned in Pre-Technical Studies, and how do we decide which one is most suitable to address?', '* Learners textbook\n* Chart paper or manila paper for listing problems\n* Markers or chalk for recording ideas\n* Sample community problems written on cards (water shortage, broken furniture, waste management, etc.)', '* Oral questions to evaluate learners\' understanding of problem analysis criteria\n* Observation during brainstorming and problem selection discussions\n* Written exercise where learners justify their choice of problem to address', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(180, 1, 15, 4, '4.0 Tools and Production', '4.3 Project', 'b) select an item that can be made to solve the identified problem', 'a) Propose various handmade or digital items to solve the problem.\nb) Identify the technical skills needed to make the selected item.', '• search for information on possible items to solve the identified problem.\n• discuss possible items that can be made.', '• Search for information on possible items to solve the identified problem.\n• Suggest the technical skills needed.', 'What handmade or digital items can we create to solve our identified community problem, and what technical skills do we need to make them?', '* Learners textbook\n* Teacher\'s smartphone or tablet for research demonstration\n* Chart paper and markers for documenting proposals\n* Sample locally made items (baskets, tools, furniture) from the community\n* Writing materials for recording skills inventory', '* Oral questions to evaluate learners\' understanding of the link between proposed items and the problem\n* Written exercise where learners list proposed items and their corresponding technical skills\n* Peer assessment of proposed solutions using a simple checklist', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(181, 1, 16, 1, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified using locally available materials', 'a) Create freehand sketches of the selected project item.\nb) Illustrate the features and dimensions of the item.', '• sketch the item to be made using the skills acquired.', '• Make freehand sketches of the item selected.', 'How can you accurately represent the features and measurements of your chosen project item using freehand sketching techniques?', '* Learners textbook\n* Plain A4 or foolscap paper\n* Pencils (HB and 2B)\n* Erasers\n* Rulers for measuring dimensions', '* Observation of sketching technique and dimensioning accuracy\n* Rubrics assessing sketch quality, proportion, and completeness of features and dimensions\n* Peer assessment of freehand sketches', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(182, 1, 16, 2, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) Formulate the logical steps followed when making the item.\nb) Note down the instructional steps for production.', '• discuss possible items that can be made to solve the identified problem.', '• Find out and note down the steps followed when making the item.', 'How can we break down and document the step-by-step process of making an item in a clear, logical order that someone else can follow?', '* Learners textbook\n* Sample completed projects from previous lessons\n* Chart paper or manila paper for documenting steps\n* Smartphones or tablets (teacher\'s) for photographing production stages\n* Pencils, erasers, and rulers for creating step diagrams', '* Written exercise: Learners write down the instructional steps for producing their chosen item in logical sequence\n* Peer assessment: Learners exchange their documented steps and evaluate whether they are clear, complete, and in correct order', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(183, 1, 16, 3, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) List the specific materials and tools required for the project.\nb) Identify locally available materials for the project.', '• use locally available materials and tools to make the identified item.', '• Identify materials and tools for making the selected items.', 'What materials and tools do we need to successfully make our chosen project item, and which of these can we find or source locally in our community?', '* Learners textbook\n* Sample projects or items selected in previous lessons\n* Chart paper and markers for listing materials\n* Community resource persons (carpenter, tailor, farmer) if available\n* Locally available materials (wood, fabric scraps, metal pieces, plant materials)', '* Written exercise: Learners prepare a complete materials and tools list for their chosen project\n* Checklist: Verify learners have identified at least three locally available materials for their project\n* Oral questions: Learners explain why specific tools are needed and where materials can be sourced locally', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(184, 1, 16, 4, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) Estimate the cost of materials for making the project item.\nb) Calculate the total expenditure for the project.', '• estimating the cost of materials for making the project item.', '• Estimate, in groups, the cost incurred to make the item.', 'How can we accurately estimate and calculate the total cost of materials and resources needed to complete our project item?', '* Learners textbook\n* Sample project materials or list of materials used in previous lessons\n* Price lists from local shops or markets\n* Chart paper and markers for group cost estimation tables\n* Calculator or smartphone for calculations', '* Observation during group estimation activities and calculations\n* Written exercise showing itemized cost breakdown and total expenditure\n* Checklist to verify accuracy of cost estimation and calculation steps', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(185, 1, 17, 1, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) Determine a suitable selling price for the finished item.\nb) Justify the price based on production costs and value.', '• estimate the cost to determine the price for the item.', '• Determine the price for the item based on estimated costs.', 'How can we determine a fair and profitable selling price for our finished project item that covers all production costs and reflects its value?', '* Learners textbook\n* Completed project items from previous lessons\n* Sample receipts or price lists from local shops or markets\n* Calculator or smartphone calculator\n* Chart paper and markers for displaying cost breakdown', '* Written exercise: Learners calculate selling price for their project item showing cost breakdown and profit margin\n* Oral questions: Learners justify their proposed selling price based on production costs, time, and market value\n* Peer assessment: Learners evaluate if classmates\' prices are reasonable and competitive', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(186, 1, 17, 2, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) Construct the project item using locally available materials.\nb) Apply safety measures during the production process.', '• use locally available materials and tools to make the identified item.', '• Make the selected item using the sketch made while following instructional steps.', 'How can you safely construct your chosen project item using locally available materials and following your sketch design?', '* Learners textbook\n* Locally available materials (wood, bamboo, clay, reeds, wire, fabric scraps, etc.)\n* Basic hand tools (hammer, saw, knife, pliers, nails, glue)\n* Safety gear (gloves, aprons, goggles if available)\n* Sketch/design from previous lesson', '* Observation using checklist (safety measures, following sketch, proper tool use, construction techniques)\n* Practical work assessment (quality of constructed item, functionality, craftsmanship)', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(187, 1, 17, 3, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) Construct the project item using locally available materials.\nb) Apply safety measures during the production process.', '• use locally available materials and tools to make the identified item.', '• Make the selected item using the sketch made while following instructional steps.', 'How can you safely construct your selected project item using locally available materials while following the instructional steps from your sketch?', '* Learners textbook\n* Locally available materials (wood, reeds, clay, wire, fabric, or recycled materials depending on project choice)\n* Basic hand tools (hammer, saw, knife, pliers, scissors, nails, glue)\n* Safety equipment (gloves, aprons, dust cloths)\n* Project sketches from previous lesson', '* Observation using a checklist during the construction process focusing on correct technique, safety adherence, and use of materials\n* Practical work assessment of the completed project item against the original sketch and design specifications', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(188, 1, 17, 4, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) Construct the project item using locally available materials.\nb) Apply safety measures during the production process.', '• use locally available materials and tools to make the identified item.', '• Make the selected item using the sketch made while following instructional steps.', 'How can you safely construct your selected project item using locally available materials while following your sketch and instructional steps?', '* Learners textbook\n* Sketch designs from previous lesson\n* Locally available materials (wood, bamboo, clay, metal scraps, fabric, wire, stones)\n* Basic hand tools (hammer, saw, knife, pliers, scissors)\n* Safety equipment (gloves, dust cloth, apron)', '* Observation during construction process using safety checklist\n* Practical work assessment of the finished project item against the sketch design\n* Rubrics for quality, functionality, and safety adherence', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(189, 1, 18, 1, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) Construct the project item using locally available materials.\nb) Apply safety measures during the production process.', '• use locally available materials and tools to make the identified item.', '• Make the selected item using the sketch made while following instructional steps.', 'How can we safely construct our project item using locally available materials while following the instructional steps from our sketch?', '* Learners textbook\n* Sketch drawings from previous lesson\n* Locally available materials (wood, clay, wire, fabric, paper, cardboard, bottles, etc. depending on project choice)\n* Basic hand tools (saw, hammer, knife, scissors, glue, nails, string)\n* Safety equipment (gloves, aprons, dust cloths)', '* Observation using a checklist (construction process, technique application, safety practices)\n* Practical work (quality and functionality of completed project item)\n* Rubric (craftsmanship, adherence to sketch, safety compliance, finish quality)', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(190, 1, 18, 2, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) Construct the project item using locally available materials.\nb) Apply safety measures during the production process.', '• use locally available materials and tools to make the identified item.', '• Make the selected item using the sketch made while following instructional steps.', 'How can you safely construct your project item using locally available materials while following your sketch and instructional steps?', '* Learners textbook\n* Sketch/design drawings from previous lessons\n* Locally available construction materials (wood offcuts, wire, fabric scraps, clay, bamboo, cardboard, nails, etc. depending on project choice)\n* Basic hand tools (hammer, saw, knife, pliers, scissors, rulers)\n* Safety equipment (gloves, dust cloths, aprons made from old fabric)', '* Observation using a checklist during construction (proper use of tools, following sketch, application of safety measures)\n* Practical assessment using rubrics (quality of finished item, adherence to design specifications, craftsmanship, functionality)', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(191, 1, 18, 3, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) Construct the project item using locally available materials.\nb) Apply safety measures during the production process.', '• use locally available materials and tools to make the identified item.', '• Make the selected item using the sketch made while following instructional steps.', 'How can you safely construct your project item using locally available materials while following your sketch and instructions?', '* Learners textbook\n* Sketch/design from previous lesson\n* Locally available materials (wood, bamboo, clay, recycled materials, fabric, wire, etc. based on individual projects)\n* Basic hand tools (saw, hammer, nails, knife, scissors, glue)\n* Safety equipment (gloves, dust cloth, apron, water for first aid)', '* Observation using a checklist (quality of construction, following sketch, use of tools, safety practices)\n* Practical work assessment (functionality and finish of the constructed item)\n* Self-assessment (learners reflect on challenges faced and safety measures applied)', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(192, 1, 18, 4, '4.0 Tools and Production', '4.3 Project', 'c) make an item to solve the problem identified', 'a) Present the finished item to the class for feedback.\nb) Evaluate the quality of the item based on peer comments.', '• present the finished items for feedback.', '• Present the item made to the whole class and allow comments.', 'How can we use peer feedback to evaluate and improve the quality of our finished projects?', '* Learners textbook\n* Finished items/projects made by learners\n* Evaluation checklist or criteria chart\n* Exercise books and pens for recording feedback', '* Peer assessment using feedback forms or criteria checklist\n* Self-assessment reflection on how learners incorporated feedback to evaluate their work\n* Observation of presentation skills and ability to receive constructive criticism', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(193, 1, 19, 1, '4.0 Tools and Production', '4.3 Project', 'd) utilise skills acquired in Pre-Technical Studies to solve problems in day-to-day life', 'a) Apply the produced item to solve the identified local problem.\nb) Report on the effectiveness of the item in a real-life scenario.', '• utilise skills acquired in Pre-Technical Studies to solve problems in day-to-day life.', '• Use the item made to solve the problem identified in your locality.', 'How effectively does your produced item solve the identified local problem when applied in a real-life situation?', '* Learners textbook\n* Completed project items from previous lessons\n* Observation notebook or recording sheets\n* Smartphone or camera (if available) for documenting application', '* Observation during field application of the item\n* Oral questions on effectiveness and challenges encountered\n* Written report on real-life performance of the item', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 2),
(194, 1, 19, 2, '5.0 Entrepreneurship', '5.1 Financial Services', 'a) identify financial institutions available in Kenya', 'a) Identify various financial institutions available in Kenya.\nb) Search for information on the roles of different financial institutions.', '• use print or digital media to search for information on financial institutions available in Kenya.', '• Identify, in groups, financial institutions available in Kenya.\n• Search for information, in groups, on financial institutions and present findings.', 'What are the different financial institutions in Kenya and what specific roles do they play in helping individuals and businesses manage money?', '* Learners textbook\n* Chart paper and markers for group presentations\n* Sample bank statements, M-Pesa receipts, or SACCO forms from local community members\n* Teacher\'s smartphone or tablet for guided internet search (if available)', '* Oral questions during group presentations to assess identification of financial institutions and understanding of their roles\n* Rubric to evaluate group research findings and presentation quality', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(195, 1, 19, 3, '5.0 Entrepreneurship', '5.1 Financial Services', 'b) classify financial institutions in Kenya', 'a) Classify financial institutions into formal and informal categories.\nb) Distinguish between banks, insurance companies, SACCOs, and micro-finance.', '• discuss and present the types of financial institutions in Kenya (banks, insurance, SACCOs, micro finance).', '• Classify, in groups, financial institutions in Kenya.\n• Brainstorm the two classifications of financial institutions.', 'How can we group the different financial institutions in Kenya based on how they are organized and regulated?', '* Learners textbook\n* Chart paper and markers\n* Sample documents from local financial institutions (bank calendars, SACCO posters, M-Pesa agent signs)\n* Manila paper for group classification work', '* Observation during group classification activity\n* Written exercise classifying given financial institutions into formal and informal categories', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(196, 1, 19, 4, '5.0 Entrepreneurship', '5.1 Financial Services', 'c) analyse services offered by financial institutions in Kenya', 'a) Analyze various services offered by financial institutions through case studies.\nb) Categorize financial services such as savings, credit, and insurance.', '• use a case study to discuss services offered by financial institutions in Kenya.', '• Analyse, in groups, a case study on financial institutions.\n• Note down in exercise books the services they offer and share findings.', 'How do different financial institutions help individuals and businesses manage their money through the services they provide?', '* Learners textbook\n* Case study handouts or printed examples of financial institutions (bank, microfinance, SACCO)\n* Chart paper or manila papers for group presentations\n* Sample financial documents (bank statements, loan agreements, insurance policies) if available locally', '* Oral questions during group presentations on categorization of financial services\n* Written exercise in exercise books categorizing savings, credit, and insurance services from case studies\n* Rubrics to assess group analysis and presentation of case study findings', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(197, 1, 20, 1, '5.0 Entrepreneurship', '5.1 Financial Services', 'd) utilise financial services for entrepreneurial development', 'a) Identify specific financial services needed to start a small business.\nb) Select appropriate financial institutions for business support in a given scenario.', '• engage in a discussion with a resource person on the utilisation of financial services for entrepreneurial development.', '• Picture a scenario of starting a small business.\n• Identify financial services and institutions you would need.', 'What financial services and institutions would you need to successfully start and run a small business in your community?', '* Learners textbook\n* Chart paper or manila paper\n* Sample business registration forms or documents (if available from local cooperative or bank)\n* Printed or written list of local financial institutions (banks, SACCOs, microfinance)', '* Oral questions on types of financial services and their purposes\n* Written exercise where learners match financial services to appropriate institutions for a given business scenario\n* Observation during group discussion of business scenarios', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(198, 1, 20, 2, '5.0 Entrepreneurship', '5.2 Government and Business', 'a) explain the reasons for government involvement in business', 'a) Explain the various reasons why the government gets involved in business.\nb) Identify government roles in business from displayed flashcards.', '• brainstorm and present on the reasons for government involvement in business in Kenya.', '• Brainstorming on the reason for government involvement in business.\n• Observe displayed flashcards on reasons for government involvement.', 'Why does the government involve itself in business activities in Kenya?', '* Learners textbook\n* Flashcards showing government roles (made from manila paper or cardboard)\n* Charts with examples of government businesses (e.g. KenGen, Kenya Railways)\n* Markers or chalk for brainstorming notes', '* Oral questions during and after brainstorming session\n* Written exercise identifying reasons for government involvement in business from given scenarios', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(199, 1, 20, 3, '5.0 Entrepreneurship', '5.2 Government and Business', 'b) describe ways of government involvement in business', 'a) Describe different ways the government involves itself in business activities.\nb) Discuss government regulations imposed on businesses.', '• use print or digital media to search for information on ways of Government involvement in business.', '• Describe, in groups, ways of government involvement in business.\n• Discuss regulations the government imposes on business.', 'How does the government participate in and regulate business activities in Kenya?', '* Learners textbook\n* Chart paper and markers for group presentations\n* Examples of business licenses or permits from local businesses\n* Newspapers with business or economic news sections', '* Oral questions during group discussions on government involvement and regulations\n* Written exercise listing and explaining government business regulations\n* Observation of group participation and understanding during presentations', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(200, 1, 20, 4, '5.0 Entrepreneurship', '5.2 Government and Business', 'c) explore types of taxes in Kenya', 'a) Define the meaning of taxation in the Kenyan context.\nb) Discuss the importance of citizens and businesses paying taxes.', '• discuss and present on the meaning and importance of paying taxes in Kenya.', '• Discuss, in groups, the meaning and importance of paying taxes and share findings.', 'Why is taxation important for both the government and citizens in Kenya?', '* Learners textbook\n* Sample tax receipts or KRA notices from local businesses (if available)\n* Chart paper and markers for group presentations\n* Examples of public services in the community (school, dispensary, roads)', '* Oral questions during and after group discussions\n* Written exercise defining taxation and listing at least three reasons why paying taxes is important', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(201, 1, 21, 1, '5.0 Entrepreneurship', '5.2 Government and Business', 'c) explore types of taxes in Kenya', 'a) Identify the different types of taxes in Kenya (VAT, Income Tax, etc.).\nb) Explain how different taxes are applied to businesses.', '• discuss types of taxes in Kenya (income tax, VAT, corporate tax, fuel levy, excise duty).', '• Discuss, in groups, types of taxes in Kenya and present to peers.', 'How do different types of taxes affect the way businesses operate and make profits in Kenya?', '* Learners textbook\n* Sample business receipts or invoices from local shops showing VAT\n* Chart paper and markers for group presentations\n* Teacher\'s smartphone to show Kenya Revenue Authority (KRA) information if available', '* Oral questions during group discussions on types of taxes and their application\n* Peer assessment of group presentations using a simple checklist\n* Written exercise identifying and explaining different taxes from sample business scenarios', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(202, 1, 21, 2, '5.0 Entrepreneurship', '5.2 Government and Business', 'd) analyse e-Government services in business', 'a) Analyze case studies on e-Government services used in business.\nb) Interact with e-Government platforms using digital tools.', '• discuss a case scenarios on e-Government services in business.\n• use digital devices to access and interact with e-Government platform in Kenya.', '• Discuss, in groups, a case study on e-government services in business.\n• Use ICT tools to access and interact with e-Government platforms.', 'How can businesses in Kenya use e-Government platforms to improve their operations and compliance with government regulations?', '* Learners textbook\n* Teacher\'s smartphone or tablet with internet connection\n* Printed screenshots or handouts of e-Government platforms (eCitizen, iTax, NTSA portal)\n* Case study materials from textbook or local business examples\n* Chart paper and markers for group presentations', '* Oral questions during group discussions on case study analysis\n* Observation of learners\' ability to navigate and interact with e-Government platforms\n* Written exercise analyzing benefits and challenges of e-Government services for businesses', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(203, 1, 21, 3, '5.0 Entrepreneurship', '5.2 Government and Business', 'e) acknowledge the need to comply with Government regulations in business', 'a) Explain the necessity of complying with government business regulations.\nb) Evaluate understanding of government and business through an exercise.', '• acknowledge the need to comply with Government regulations in business.', '• Discuss the need to comply with government regulations in business.\n• Work individually on assessment exercise.', 'Why is it important for business owners to comply with government regulations when running their businesses?', '* Learners textbook\n* Examples of business licenses or permits from local businesses (photocopies or real samples)\n* Chart paper and markers for summarizing key regulations\n* Local business registration documents or images on teacher\'s smartphone', '* Oral questions during class discussion on compliance with government regulations\n* Written exercise evaluating understanding of government and business relationship', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(204, 1, 21, 4, '5.0 Entrepreneurship', '5.3 Business Plan', 'a) explain the importance of a business plan in entrepreneurship', 'a) Define the term \"Business Plan.\"\nb) Discuss the importance of a business plan for an entrepreneur.', '• brainstorm and present on the meaning and importance of a business plan.', '• Brainstorm on the meaning and importance of a business plan.\n• Present findings in class.', 'Why is a business plan important for an entrepreneur who wants to start or grow a business?', '* Learners textbook\n* Chart paper or manila paper\n* Markers or coloured chalk\n* Sample business plans from local entrepreneurs (if available)', '* Oral questions during brainstorming and class discussion\n* Written exercise defining business plan and listing its importance', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(205, 1, 22, 1, '5.0 Entrepreneurship', '5.3 Business Plan', 'b) describe the components of a business plan in financial management', 'a) Identify the key components of a business plan.\nb) Describe the executive summary and business description components.', '• brainstorm and present on the components of a business plan.', '• Identify, in groups, key components of a business plan and present findings.', 'What are the essential components that make up a complete business plan, and why are the executive summary and business description important?', '* Learners textbook\n* Sample business plans from local businesses (posho mill, salon, agro-vet)\n* Chart paper and markers for group presentations\n* Teacher\'s smartphone/tablet to show a simple business plan template', '* Oral questions during group presentations on business plan components\n* Observation of group work using a checklist for participation and accuracy\n* Written exercise describing executive summary and business description', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(206, 1, 22, 2, '5.0 Entrepreneurship', '5.3 Business Plan', 'c) fill in a business plan template for a given business project', 'a) Identify the specific sections of a business plan template.\nb) Populate the business description and market analysis sections for a project.', '• complete a business plan template.', '• Identify, in pairs, the sections of a business plan template.\n• Fill in the business description and market analysis sections for a chosen project.', 'What are the key sections of a business plan and how do you write a clear business description and market analysis for your project?', '* Learners textbook\n* Sample business plan templates (printed or drawn on manila paper)\n* Chart paper or manila paper for group work\n* Writing materials (pens, pencils, erasers)\n* Sample local business examples (e.g. kiosk, poultry, vegetable selling)', '* Observation during pair work to check correct identification of business plan sections\n* Written exercise evaluating the completed business description and market analysis sections using a checklist\n* Peer assessment of populated business plan sections', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(207, 1, 22, 3, '5.0 Entrepreneurship', '5.3 Business Plan', 'c) fill in a business plan template', 'a) Complete the marketing plan and financial projection sections of the template.\nb) Present the completed business plan to peers for review.', '• complete a business plan template.', '• Complete the remaining sections of the business plan template in pairs.\n• Share the completed business plan with the class for feedback.', 'How can you effectively communicate the marketing strategy and financial viability of your business idea to convince potential investors or partners?', '* Learners textbook\n* Business plan templates (printed or handwritten copies)\n* Sample business plans from local enterprises\n* Chart paper or manila paper for presentations\n* Markers or colored chalk for visual aids', '* Peer assessment using a checklist for business plan completeness and clarity\n* Rubrics to evaluate the quality of marketing plan, financial projections, and presentation skills\n* Oral questions during and after presentations to assess understanding of business concepts', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
(208, 1, 22, 4, '5.0 Entrepreneurship', '5.3 Business Plan', 'd) embrace the use of a business plan in entrepreneurship', 'a) Discuss how a business plan helps in solving common entrepreneurial challenges.\nb) Evaluate personal understanding of business planning through a structured exercise.', '• engage with a resource person on the use of a business plan in entrepreneurship.\n• discuss how a business plan solves problems.', '• Discuss, in groups, the role of a business plan in addressing business risks and growth.\n• Work individually on a summative assessment exercise on business plans.', 'How does a well-prepared business plan help entrepreneurs overcome challenges and achieve business growth?', '* Learners textbook\n* Sample business plan templates or examples (teacher-prepared handouts or drawn on chalkboard)\n* Charts showing common business challenges and solutions\n* Exercise books and pens', '* Oral questions during group discussions on the role of business plans in addressing risks\n* Written summative assessment exercise evaluating understanding of business planning\n* Rubrics to assess quality of responses on how business plans solve entrepreneurial challenges', '', '2026-04-10 16:42:56', '2026-04-11 13:23:56', 3),
